-- Poems batch 187
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('56b3aea4-a8b0-4d52-9fb8-f63134b35026','樓大參囑珣起宗索孤山舊藁  其二','釋居簡','宋','宋诗','song-poetry','','[]','鄉來文字洶濤瀾，淼淼回淵攪不渾。',64,'全唐诗/poet.song.180000.json','["鄉來文字洶濤瀾，淼淼回淵攪不渾。", "鼎鼐飽參梅子熟，雪霜不見竹枝蕃。", "媿無攻處心尤小，力丐歸時德更尊。", "雲靜八紘天在水，華風煖處見春痕。"]'),
('466edd0a-8034-41a1-9f06-31ce219a7c9d','圓無外一春不歸蘭猶有花','釋居簡','宋','宋诗','song-poetry','','[]','一春寂寞無人問，不爲無人不謹初。',32,'全唐诗/poet.song.180000.json','["一春寂寞無人問，不爲無人不謹初。", "猶有兩花藏葉底，隙簷三見月如梳。"]'),
('9fc161b5-5a81-40fb-b1d5-e0d388573a9c','韓寺遺墟','釋居簡','宋','宋诗','song-poetry','','[]','十年秋傍故山零，一塢殘雲夜不扃。',32,'全唐诗/poet.song.180000.json','["十年秋傍故山零，一塢殘雲夜不扃。", "土偶向人猶作祟，相傳不似舊時靈。"]'),
('f32b64f1-a170-4ba4-a3d0-ade674c0cb68','書荆公訪僧圖','釋居簡','宋','宋诗','song-poetry','','[]','長鬚瘦蹇策深雲，來就蒲團到夕曛。',32,'全唐诗/poet.song.180000.json','["長鬚瘦蹇策深雲，來就蒲團到夕曛。", "疇曩山中無此畫，至今猿鶴怨移文。"]'),
('9bb9f2c9-3f35-4c66-a865-ca6646da3401','冷灣','釋居簡','宋','宋诗','song-poetry','','[]','怪雨盲風塞冷灣，破頭艇子出湖灘。',32,'全唐诗/poet.song.180000.json','["怪雨盲風塞冷灣，破頭艇子出湖灘。", "平生無地酬忠信，獨向風波險處看。"]'),
('b46193d7-037c-4cfb-a445-67fd97da35f3','趙節推挂冠  其一','釋居簡','宋','宋诗','song-poetry','','[]','不爲鱸魚不爲蓴，只思天際九華青。',64,'全唐诗/poet.song.180000.json','["不爲鱸魚不爲蓴，只思天際九華青。", "心關幽事惟招隠，脚到榮途亟引齡。", "營掾廨成纔燕賀，笑虞羅巧嘆鴻冥。", "樂閑趁得身强健，振厲仙源擅德馨。"]'),
('93ea9776-47ca-45c7-9396-9af68842d77d','趙節推挂冠  其二','釋居簡','宋','宋诗','song-poetry','','[]','虛舟所至信浮沉，揭厲何曾較淺深。',64,'全唐诗/poet.song.180000.json','["虛舟所至信浮沉，揭厲何曾較淺深。", "堅不可磨惟定見，去終難挽是歸心。", "書生豈但青衫債，俗子安知綠綺音。", "神武門頭舊時月，照人如鏡古猶今。"]'),
('665301ac-195c-4917-8dd1-6e59aca7b9df','國清寺絕頂更好亭下古梅','釋居簡','宋','宋诗','song-poetry','','[]','花開更好亭前枝，亭曰更好花更奇。',384,'全唐诗/poet.song.180000.json','["花開更好亭前枝，亭曰更好花更奇。", "我猶未到春已到，春不到此將焉歸。", "千山萬山儼環抱，一樹兩樹藏嶔𡼭。", "曉粧弗受朱粉污，老去自著莓苔衣。", "澹交霜髯與蒼玉，雅宜茅舍橫疎籬。", "雲英風味有餘裕，石鯨鱗甲饒華滋。", "恍然羅浮月中見，髿髿紺髮森冰肌。", "又如大窖凍不死，凜凜素節無瑕疵。", "紛紛紅紫不解事，與春角逐何遲遲。", "待文作興不足道，凡民碌碌終奚爲。", "孤芳拔俗千萬丈，未暇相與論襟期。", "貞姿皓態美無度，幽意獨許鮮風知。", "悠然憑高一披拂，僧窗處處開晴霏。", "窗間跏趺擁風葉，照几碧眸岩電馳。", "淵淵方寸湛古井，一漚不動清漣漪。", "天香閟此無盡藏，潜於鼻觀通幾微。", "水流山空但自笑，理與神遇端如斯。", "鄉來孤山水清淺，龜膚鶴膝相參差。", "青銅盤屈破香雪，紫鐵矯揉駢明璣。", "膏肓泉石政爲此，冠冕草木今其誰。", "天公亦復加靳惜，闊著湖水無邊涯。", "八篇只遣處士賦，一點不放紅塵飛。", "是中泉石固深秀，惜欠晴湖山四圍。", "客如我輩亦不惡，擬賡疎影橫斜詩。"]'),
('7469aeaf-fe0d-491f-9fe1-a134d954d34b','小圃即事四首  其一','釋居簡','宋','宋诗','song-poetry','','[]','粉紅蓓蕾弗禁吹，盡拾鮮英綴舊枝。',32,'全唐诗/poet.song.180000.json','["粉紅蓓蕾弗禁吹，盡拾鮮英綴舊枝。", "欲賦惜春麾巽二，形容不到未開時。"]'),
('674587ed-c991-4d87-90d0-54287189ae42','小圃即事四首  其二','釋居簡','宋','宋诗','song-poetry','','[]','恰則夭夭看小桃，靚粧撚指九分消。',32,'全唐诗/poet.song.180000.json','["恰則夭夭看小桃，靚粧撚指九分消。", "丁寧更耐明朝雨，款曲隨風送落潮。"]'),
('a0617c55-73b5-4848-b01e-38a750fc20be','小圃即事四首  其三','釋居簡','宋','宋诗','song-poetry','','[]','練帨新裁襯縞衣，暝雲垂地擁瑶姬。',32,'全唐诗/poet.song.180000.json','["練帨新裁襯縞衣，暝雲垂地擁瑶姬。", "自知素潔難諧俗，只赴梨花淡月期。"]'),
('344041b7-7708-4932-9a68-e42d53018b24','小圃即事四首  其四','釋居簡','宋','宋诗','song-poetry','','[]','白白紅紅短短籬，自鉏芳逕簡繁枝。',32,'全唐诗/poet.song.180000.json','["白白紅紅短短籬，自鉏芳逕簡繁枝。", "羲皇向上淵明老，此段家風說與誰。"]'),
('82dc120c-12f4-4056-80d7-08398a64a745','移椶櫚次蓬山兄韻','釋居簡','宋','宋诗','song-poetry','','[]','藂拍蒼柄頂春寒，詩史題名勝得仙。',64,'全唐诗/poet.song.180000.json','["藂拍蒼柄頂春寒，詩史題名勝得仙。", "剪出鱗皴仍節節，何曾擁腫到便便。", "更無曲處連黄壤，只欠橫枝架老禪。", "來歲子魚分樹藝，簷前清影賦聯綿。"]'),
('590c0189-6ac4-455d-acb3-47ee5b56943b','菴居即事','釋居簡','宋','宋诗','song-poetry','','[]','欲過東家怕渡橋，欲題黄葉怕隨潮。',32,'全唐诗/poet.song.180000.json','["欲過東家怕渡橋，欲題黄葉怕隨潮。", "經旬不踏門前路，陡頓蒼苔綠色饒。"]'),
('0ea7c099-9ec3-459f-bf86-df554b9fe5a8','聞陳無却辭錢丞相道堂','釋居簡','宋','宋诗','song-poetry','','[]','挂堂錢了不求餘，熟處工夫放得疎。',64,'全唐诗/poet.song.180000.json','["挂堂錢了不求餘，熟處工夫放得疎。", "逐客未行丞相令，絕交先作孔方書。", "富非貧樂人皆笑，去似留輕絮不如。", "采采蕨薇歌日暮，也勝彈鋏嘆無魚。"]'),
('9635e1a7-3e1b-4235-8222-fd40429df8e2','送周教授兼簡劉左史薛寺丞  其一','釋居簡','宋','宋诗','song-poetry','','[]','舍選諸生出，侯藩博士歸。',48,'全唐诗/poet.song.180000.json','["舍選諸生出，侯藩博士歸。", "一官甘獨冷，千仞看群飛。", "苦學丹心古，春風泮水肥。", "傳衣觀歲晚，先使識摳衣。"]'),
('0c395feb-7c5e-4790-9332-4b11a35a78b0','送周教授兼簡劉左史薛寺丞  其二','釋居簡','宋','宋诗','song-poetry','','[]','霜趁殘秋肅，寒侵薄暮生。',48,'全唐诗/poet.song.180000.json','["霜趁殘秋肅，寒侵薄暮生。", "帆開吳浪急，鴻挾楚雲橫。", "客裏常加飯，人歸得寄聲。", "爲詢劉與薛，江漢幾長城。"]'),
('f6c014ff-d5b0-4e68-9cee-468ecc24d607','揖山樓','釋居簡','宋','宋诗','song-poetry','','[]','谿陰留雲雲不留，樓在五雲之上游。',132,'全唐诗/poet.song.180000.json','["谿陰留雲雲不留，樓在五雲之上游。", "青天一握浄如洗，好山四面清涵秋。", "主人亦有大白浮，揖遜群峯相獻酬。", "巖中野逸皆名流，農隙頗復登臨不。", "何當天風吹袖寒颼飀，披衡跨霍迤邐崑崙丘。", "悠悠按轡雙龍湫，泠然爲君上上頭。", "樓頭風物須盟主，風騷之外吾無取。", "猛拍闌干撫寥泬，不問青天問華月。"]'),
('324e5cc4-a16d-464e-b53d-a779fa17722f','雙溪潮水清','釋居簡','宋','宋诗','song-poetry','','[]','滅影雙溪死便燒，年年楓落見清潮。',32,'全唐诗/poet.song.180000.json','["滅影雙溪死便燒，年年楓落見清潮。", "淛江亭下晴翻雪，卷作渾濤怒不消。"]'),
('030d4ed0-c715-4a66-b436-319bd742c244','朴翁約效誠齋分題得月色','釋居簡','宋','宋诗','song-poetry','','[]','霜晴如此月明何，獨恨空庭著不多。',32,'全唐诗/poet.song.180000.json','["霜晴如此月明何，獨恨空庭著不多。", "窗外樓頭都有了，其餘四散盡從它。"]'),
('145360f2-dd28-41e7-b1fa-e87851b6160f','贈心上人','釋居簡','宋','宋诗','song-poetry','','[]','一抹新霜雁背寒，滿庭疎雨客衣單。',32,'全唐诗/poet.song.180000.json','["一抹新霜雁背寒，滿庭疎雨客衣單。", "苦心莫負韋編絕，歲晚歸來語夜闌。"]'),
('0ca02a92-dc65-428f-9dd7-e507d7d2c03c','聞濟妙高爲善浄攘其居兼簡楊守慈湖  其一','釋居簡','宋','宋诗','song-poetry','','[]','俗習翻新樣，民生先故吾。',48,'全唐诗/poet.song.180000.json','["俗習翻新樣，民生先故吾。", "緇雲忘揖遜，何處有廉隅。", "戛戛難窮鼠，紛紛莫辨烏。", "多應風化首，坐嘯答歌襦。"]'),
('9c57aebe-b06b-4986-b7f2-26776aab7146','聞濟妙高爲善浄攘其居兼簡楊守慈湖  其二','釋居簡','宋','宋诗','song-poetry','','[]','聽鼓噇簞食，逢山辦把茅。',48,'全唐诗/poet.song.180000.json','["聽鼓噇簞食，逢山辦把茅。", "霧窗閑自挂，月檻許誰敲。", "戰蟻翻侯國，驅鳩入鵲巢。", "先生河漢辯，何以解人嘲。"]'),
('6f1064fc-2a6f-4649-8d54-7e4b4d55f633','酬雲卧白雞','釋居簡','宋','宋诗','song-poetry','','[]','冠染丹砂雪剪翎，不因風雨廢常鳴。',32,'全唐诗/poet.song.180000.json','["冠染丹砂雪剪翎，不因風雨廢常鳴。", "有時失度無人醒，只有劉琨與祖生。"]'),
('db7fb9bc-bb4d-4d67-8f56-8ce566afe961','謁樊將軍舞陽侯廟','釋居簡','宋','宋诗','song-poetry','','[]','蕭曹筆削宏楷橅，良平智略吞萬夫。',208,'全唐诗/poet.song.180000.json','["蕭曹筆削宏楷橅，良平智略吞萬夫。", "巍壇既登跨下士，貢帳謾悅驪山徒。", "龍爭虎鬭爪牙備，劉怯項勇天淵殊。", "鹿雖未果死誰手，鼎已潜知開漢圖。", "將軍最先得所託，亭長之外無貞符。", "逸群拔萃一人耳，屠城斬將群雄俱。", "鴻門直入緩危急，虎口僅免纔斯須。", "宴安鴆毒寤主意，排闥紫禁當前驅。", "奮身不顧但愛死，嬰鱗未了仍編鬚。", "帝雖寡恩少善後，吾寧守義如厥初。", "匈奴無故遺嫚書，在廷如堵方囁嚅。", "將軍裂眥不願餘，請十萬衆行匈奴。", "不知十萬行匈奴，果與衛霍功何如。"]'),
('9c0d5054-73de-4582-a4be-9e4a9177dc6c','酬王哦松八景  其一','釋居簡','宋','宋诗','song-poetry','','[]','橫玉臨江展碧紈，馮夷庭院水晶寒。',32,'全唐诗/poet.song.180000.json','["橫玉臨江展碧紈，馮夷庭院水晶寒。", "天教兩賦酬風雅，不謂人閒作畫看。"]'),
('67b4897c-d5aa-4f32-9e78-2fd4b918a05a','酬王哦松八景  其二','釋居簡','宋','宋诗','song-poetry','','[]','欲從山北駐晴霏，先與山南淡掃眉。',32,'全唐诗/poet.song.180000.json','["欲從山北駐晴霏，先與山南淡掃眉。", "見說商周遺俗在，試尋康俗未來時。"]'),
('d349aa4e-e2bf-4c80-b27a-c8f76d03d6e0','酬王哦松八景  其三','釋居簡','宋','宋诗','song-poetry','','[]','雨歇江空錦瑟鳴，亟圖清絕些湘靈。',32,'全唐诗/poet.song.180000.json','["雨歇江空錦瑟鳴，亟圖清絕些湘靈。", "斯須雲歛便有月，更著數峯江上青。"]'),
('a6bfba67-90a8-4835-b68c-41a6f7f2ce8f','酬王哦松八景  其四','釋居簡','宋','宋诗','song-poetry','','[]','噎噎梅花煖響初，曉來痕綠到蘼蕪。',32,'全唐诗/poet.song.180000.json','["噎噎梅花煖響初，曉來痕綠到蘼蕪。", "鶚沈鸚鵡千年恨，指舊江山忍按圖。"]'),
('be4512d2-a23c-45ba-b1b9-f79d44513397','酬王哦松八景  其五','釋居簡','宋','宋诗','song-poetry','','[]','浩然直養老益壯，吐作跨水晴虹飛。',32,'全唐诗/poet.song.180000.json','["浩然直養老益壯，吐作跨水晴虹飛。", "三萬頃秋天貼水，不禁依約冩煙霏。"]'),
('c2259c36-cc6c-4e36-94c9-557495f32f08','酬王哦松八景  其六','釋居簡','宋','宋诗','song-poetry','','[]','素車白馬作前驅，壘雪屯雲擬不如。',32,'全唐诗/poet.song.180000.json','["素車白馬作前驅，壘雪屯雲擬不如。", "尺紙忽翻千尺練，斷魂强弩控弦初。"]'),
('3fabf970-4bbb-43d0-9e61-901124454f5e','酬王哦松八景  其七','釋居簡','宋','宋诗','song-poetry','','[]','雨後雙螺對綰青，采毫曾此蘸中泠。',32,'全唐诗/poet.song.180000.json','["雨後雙螺對綰青，采毫曾此蘸中泠。", "冩成九派分流勢，不冩當年瘞鶴銘。"]'),
('e833cb83-4b88-4ae1-a1d7-12bb46ae2f49','酬王哦松八景  其八','釋居簡','宋','宋诗','song-poetry','','[]','羨他蓑笠度年華，盡把風烟付賀家。',32,'全唐诗/poet.song.180000.json','["羨他蓑笠度年華，盡把風烟付賀家。", "盤礴細搜吟意緒，明波一曲小菱花。"]'),
('11b98ca5-4304-43bc-a354-c74008ff9d9c','酬樂清陳簿雪中平反','釋居簡','宋','宋诗','song-poetry','','[]','用恕存存坐照姦，姦如挾纊弗知寒。',64,'全唐诗/poet.song.180000.json','["用恕存存坐照姦，姦如挾纊弗知寒。", "天雖有二無偏覆，網既開三亦甚寬。", "疑欲惟輕刑自省，死終弗怨枕方安。", "雪中小試陽和力，天地生成却不難。"]'),
('8212c63d-79f0-4587-a498-5e8b858d3ae4','過張氏水亭','釋居簡','宋','宋诗','song-poetry','','[]','到岸不多遥，晴初雪未消。',48,'全唐诗/poet.song.180000.json','["到岸不多遥，晴初雪未消。", "茆簷雖傍水，人影不隨潮。", "鵲占寒枝喜，魚從落日跳。", "丹楓莫吹盡，我欲繫蘭橈。"]'),
('50c348f6-b7a8-4a7f-b6cf-e099df72febd','三錫堂下接桃  其一','釋居簡','宋','宋诗','song-poetry','','[]','前度劉郎去不來，炫晴灼灼又花開。',32,'全唐诗/poet.song.180000.json','["前度劉郎去不來，炫晴灼灼又花開。", "蟠桃著子三千歲，一歲從他熟一回。"]'),
('b164ff16-3223-4671-9112-56edd42056e3','三錫堂下接桃  其二','釋居簡','宋','宋诗','song-poetry','','[]','接枝換骨勝刀圭，臉暈嬌風滿舊蹊。',32,'全唐诗/poet.song.180000.json','["接枝換骨勝刀圭，臉暈嬌風滿舊蹊。", "有問春工在誰手，避秦人在武陵溪。"]'),
('600e9791-ffa8-4324-967d-2420ba215b41','烏𣡶角行','釋居簡','宋','宋诗','song-poetry','','[]','村村花柳春菲菲，烏𣡶聲動清晝遲。',246,'全唐诗/poet.song.180000.json','["村村花柳春菲菲，烏𣡶聲動清晝遲。", "梅花噎噎不成弄，黄鍾大呂相因依。", "川平野闊牛背穩，水坳山曲人煙稀。", "一聲一聲斷復續，十十五五喧牧兒。", "四郊喚得墮農起，不作陽關腸斷聲。", "凄其道傍駐馬遠，游子往往不減陽關悲。", "此聲豈解令人悲，朝燕暮越遠別離。", "亦復豈能使人喜，蕢桴土鼓相酣嘻。", "於戲此樂吾獨知，尚記天台委羽破雨開林扉。", "自鞭觳觫耦沮溺，白水沒膝同扶犁。", "是非利害不到耳，終日聽此嗚嗚吹。", "風淳調古相浹洽，不與市道趨澆漓。", "朅來脚踏軟紅陌，不聞此曲聞此詩。", "借翁語險久不和，邇來作者如塤箎。", "塤箎雖美與時背，豈若烏𣡶方適時。"]'),
('fa1f63ce-cf74-4a5e-99d2-12a90e5d6cbd','泊港口','釋居簡','宋','宋诗','song-poetry','','[]','港闊風初霽，潮平夜欲分。',48,'全唐诗/poet.song.180000.json','["港闊風初霽，潮平夜欲分。", "半江都是月，一點不留雲。", "東去舟無數，南飛鵲戀群。", "疎鍾何處寺，隔浦最先聞。"]'),
('45e51bce-ba6b-4839-b75c-ae8334ebe067','趙禪菴','釋居簡','宋','宋诗','song-poetry','','[]','面面蒼崖似削瓜，濤翻鼉鼓半天撾。',32,'全唐诗/poet.song.180000.json','["面面蒼崖似削瓜，濤翻鼉鼓半天撾。", "依稀劉阮曾行處，無數水邊桃未花。"]'),
('c19f7161-6d6f-4be9-b61f-f8b907311cfd','送謝司令通守嚴陵','釋居簡','宋','宋诗','song-poetry','','[]','訪竹凌霜後，尋梅趁臘前。',48,'全唐诗/poet.song.180000.json','["訪竹凌霜後，尋梅趁臘前。", "春風方委曲，別乘忽騰騫。", "處士不入府，客星仍受廛。", "密齋容膝外，何處著壺天。"]'),
('2df3704d-09bc-4a7d-b03e-577aad692c40','拆桐花','釋居簡','宋','宋诗','song-poetry','','[]','葉底秋聲急雨催，人言滿樹是愁媒。',32,'全唐诗/poet.song.180000.json','["葉底秋聲急雨催，人言滿樹是愁媒。", "九回百斷渠何與，自是愁人做得來。"]'),
('be30cf3b-335f-4e46-9ad7-d8933893cec1','新月','釋居簡','宋','宋诗','song-poetry','','[]','澹掃蛾眉雨後天，天容澄潔稱嬋娟。',64,'全唐诗/poet.song.180000.json','["澹掃蛾眉雨後天，天容澄潔稱嬋娟。", "弦雖未上終持滿，璧反胡爲尚不全。", "只鄉生時看最好，莫於缺處斲成圓。", "人間夢事紛如蟻，著眼何曾到汝邊。"]'),
('9d463cdf-ec88-49a0-ad64-db72253ada44','雪中登西菩寺參寥舊居分月閣聞讀書聲','釋居簡','宋','宋诗','song-poetry','','[]','誰平讀書琅琅然，四山響答皆清圓。',128,'全唐诗/poet.song.180000.json','["誰平讀書琅琅然，四山響答皆清圓。", "山空無人渡雙澗，更與流水相潺湲。", "凍雲壓山吹不皺，雲際稜稜展瑶甃。", "廣庭萬舞亂零飛，老枝檠重如僧瘦。", "吞蟾縞夜洞八窗，弗煩凍手挑殘釭。", "蠅頭萬字不足數，冏冏寒入青眸雙。", "辨才昔與參寥子，秣馬問途端自此。", "要汝勇追龍象躅，爲我辛勤十年讀。"]'),
('d4451da6-d08c-4d0c-9117-306300d11395','嘯雲','釋居簡','宋','宋诗','song-poetry','','[]','胡笳未奏邊雲悄，長嘯一聲山月小。',64,'全唐诗/poet.song.180000.json','["胡笳未奏邊雲悄，長嘯一聲山月小。", "狂虜歸思悲夜老，身未到家心已到。", "山雲不似塞雲腥，雲中倚闌時一聲。", "悠然清聞四十里，何獨重圍空萬騎。"]'),
('6bf94ad7-1993-46a7-90cd-9699ac1f85f5','問訊方岩侍郎  其一','釋居簡','宋','宋诗','song-poetry','','[]','翳盡珠明萬象空，壺中只著小玲瓏。',64,'全唐诗/poet.song.180000.json','["翳盡珠明萬象空，壺中只著小玲瓏。", "鄉來冀北藐群馬，此去斗南能幾翁。", "淵默但知藏霹靂，清寧何必友崆峒。", "方城屹立青如削，萬壑千巖在下風。"]'),
('705f8784-3660-4665-80dc-0d1df18f46ef','問訊方岩侍郎  其二','釋居簡','宋','宋诗','song-poetry','','[]','用亦無心舍亦輕，歲寒只有竹忘形。',64,'全唐诗/poet.song.180000.json','["用亦無心舍亦輕，歲寒只有竹忘形。", "水村容與吹黄葉，溪圃耘耔課白丁。", "細草遠連三徑綠，好山長借兩眸青。", "浚池小貯連天碧，待與人間洗濁涇。"]'),
('c6fddae3-06d2-405f-a66d-8e4be4cd9bc1','招遇野','釋居簡','宋','宋诗','song-poetry','','[]','葉響初疑夜霰微，曉看連玉幻屏帷。',32,'全唐诗/poet.song.180000.json','["葉響初疑夜霰微，曉看連玉幻屏帷。", "令人憶煞天台遇，白盡蓑衣喚不歸。"]'),
('2f52a6b2-4f56-42f9-9095-108300270c95','辯才鐘','釋居簡','宋','宋诗','song-poetry','','[]','井龍欲振茲山靈，忍使夜旦鐘不聲。',192,'全唐诗/poet.song.180000.json','["井龍欲振茲山靈，忍使夜旦鐘不聲。", "西京舊賜禁猶在，即山鑄得蒲牢鳴。", "虛文破壁儼如故，縣官正令今重新。", "身歸柱後惠文手，加以束縛投諸囹。", "夜囹熖發照城闕，燎原不足方其明。", "民皆呼吏捄回祿，駿奔稽顙祈玄冥。", "及乎鄉邇寂無覩，更欲炙手嗟無因。", "朝聞夕報事從貸，雨濡露濯恩如春。", "鄉來光亦上牛斗，九疇分野當豐城。", "干將獨往莫耶在，延平濤浪今猶腥。", "何如坎井蟄不死，雨晹答響如谷神。", "百年逸事付僧史，不然簨簴重刊銘。"]'),
('7b67156f-da01-425b-919a-eaf3239f2cc4','鴈來紅','釋居簡','宋','宋诗','song-poetry','','[]','夜夜燈花巧勝裁，家書準擬傍秋開。',32,'全唐诗/poet.song.180000.json','["夜夜燈花巧勝裁，家書準擬傍秋開。", "鴈來紅葉都紅了，目斷西風鴈不來。"]'),
('cb0095ea-650d-49f5-9603-47ece7575e56','田舍即事  其一','釋居簡','宋','宋诗','song-poetry','','[]','刺水綠針抽，田低水退流。',48,'全唐诗/poet.song.180000.json','["刺水綠針抽，田低水退流。", "未饑先作午，圖飽預占秋。", "井遠缾罌重，陂荒繭栗浮。", "靜思田舍樂，却爲素餐羞。"]'),
('e6544757-8ff0-48f6-a5ee-21be6683042f','田舍即事  其二','釋居簡','宋','宋诗','song-poetry','','[]','斷壠收殘麥，晴風卷宿雲。',48,'全唐诗/poet.song.180000.json','["斷壠收殘麥，晴風卷宿雲。", "盪泥諳馬力，煮繭策蠶勳。", "野色如秋霽，山謳送夕曛。", "悠然觀歲事，不負一春勤。"]'),
('c02365d6-435a-4738-8678-0a31f12a26d7','長門怨  其一','釋居簡','宋','宋诗','song-poetry','','[]','拜月歸來剪絳燈，誤占燈喜望承恩。',32,'全唐诗/poet.song.180000.json','["拜月歸來剪絳燈，誤占燈喜望承恩。", "斷魂薄命如初月，缺盡團團只一痕。"]'),
('f9fe20b4-f123-4490-89aa-c530e8112386','長門怨  其二','釋居簡','宋','宋诗','song-poetry','','[]','菊到秋時獨擅奇，怕秋嫌唱菊花詞。',32,'全唐诗/poet.song.180000.json','["菊到秋時獨擅奇，怕秋嫌唱菊花詞。", "花頭又似金錢小，不把金錢鬭葉兒。"]'),
('d8ce7bdc-d735-4972-8597-f10945bf8156','長門怨  其三','釋居簡','宋','宋诗','song-poetry','','[]','拍拍官溝碧卷羅，影窺明玉歛青娥。',32,'全唐诗/poet.song.180000.json','["拍拍官溝碧卷羅，影窺明玉歛青娥。", "回頭趁撲雙雙蝶，恨殺春風獨管它。"]'),
('476bd3c6-0278-4771-a895-5ada01ce96ff','長門怨  其四','釋居簡','宋','宋诗','song-poetry','','[]','夢到昭陽與夢回，楚天雲雨隔陽臺。',32,'全唐诗/poet.song.180000.json','["夢到昭陽與夢回，楚天雲雨隔陽臺。", "壁粘鹺鹵花如雪，賺殺羊車不入來。"]'),
('4a256132-888b-4cab-a881-e7f9afffe640','柳絮','釋居簡','宋','宋诗','song-poetry','','[]','麻姑米白玉床丹，老去慵將狡獪看。',32,'全唐诗/poet.song.180000.json','["麻姑米白玉床丹，老去慵將狡獪看。", "却愛一川風絮好，就船做得雪團乾。"]'),
('b66f6bc6-70bc-439e-9ff5-c2aa5f34fc4c','日者','釋居簡','宋','宋诗','song-poetry','','[]','惡月懸弧豈好兒，衣冠聊復換伽黎。',32,'全唐诗/poet.song.180000.json','["惡月懸弧豈好兒，衣冠聊復換伽黎。", "聽言易感人人信，不信田文善相齊。"]'),
('24a3e029-a4d4-4e10-86e1-ebef352b5595','翠掃','釋居簡','宋','宋诗','song-poetry','','[]','小樓却立青林端，有水有竹仍有山。',96,'全唐诗/poet.song.180000.json','["小樓却立青林端，有水有竹仍有山。", "微風徐來皺池面，濃翠澹掃開煙鬟。", "九岡獻狀飛蜿蜒，悠然赴壑挽不還。", "玄珠湛影不走盤，嵐浮霧煖相縈環。", "曲闌巧當環抱間，愛山聊復倚曲闌。", "亦有零瀣供朝餐，崇朝挂眼雙孱顔。"]'),
('958ae030-2a16-4117-a1dd-339d4d252788','送詵老歸千頃山','釋居簡','宋','宋诗','song-poetry','','[]','老詵愛山不知了，何事衝寒下巍峭。',128,'全唐诗/poet.song.180000.json','["老詵愛山不知了，何事衝寒下巍峭。", "歸裝只有一囊詩，冏冏陸離還自照。", "自言峯頂摩九霄，五月六月雪不消。", "松風蕭蕭吹泬寥，千岩萬壑酣笙簫。", "前山後山畬可燒，黄精雜錯黄獨苗。", "飯家田米可卒歲，亦有旨蓄延漁樵。", "人間自有楊州鶴，詵也云胡甘寂寞。", "笑云樂去悲相隨，吾非惡此而逃之。"]'),
('090ffbbe-f89f-47d8-a68c-4920a0e508ac','錢百六錄參入新宅得子','釋居簡','宋','宋诗','song-poetry','','[]','千憶子孫昌，衣傳衮綉光。',48,'全唐诗/poet.song.180000.json','["千憶子孫昌，衣傳衮綉光。", "厦成觀賀燕，筆喜誤書麞。", "桂熟霜前子，梅騰雪後芳。", "不須瞻岐嶷，定肖白眉良。"]'),
('5ed226b9-c850-4ebf-97ec-61367a7e3e7e','寄陳黄巖','釋居簡','宋','宋诗','song-poetry','','[]','梅霖纔自歇𩃎𩃱，又復油然注上河。',64,'全唐诗/poet.song.180000.json','["梅霖纔自歇𩃎𩃱，又復油然注上河。", "水繞百畦雖喜足，雨當六月不嫌多。", "甑雖未及炊先種，頭已先低粒晚禾。", "歲事莫於田祖卜，只於堂下聽絃歌。"]'),
('5fcd1526-7890-4503-ad92-1fbc86ec38b1','劉檢詳新除','釋居簡','宋','宋诗','song-poetry','','[]','南北分疆後，關河氣不清。',168,'全唐诗/poet.song.180000.json','["南北分疆後，關河氣不清。", "有才皆瑣屑，臨事少崢嶸。", "嵩華俱崷崒，岷峨獨抗衡。", "卯金重耀德，藜杖復尋盟。", "火老隨秋灺，凉深伴月生。", "虛凝仙掌泫，縹緲慶雲明。", "肯室高名節，寬西舊老成。", "空群嘉駿産，跨竈大家聲。", "問望公輿論，芬香藹旦評。", "尺書賢十部，全璧藐連城。", "一歲尋佳處，重陽欠好晴。", "風輕茱未紫，露重菊初榮。", "春玉新嘗稻，挼香試剪橙。", "滿城風雨句，不足配餐英。"]'),
('debe413e-d137-4ffc-9063-136873aaa052','閏月九日劉檢詳入山問近作','釋居簡','宋','宋诗','song-poetry','','[]','北磵尋新築，東籬管舊香。',240,'全唐诗/poet.song.180000.json','["北磵尋新築，東籬管舊香。", "雨交前九月，晴到後重陽。", "蟻慕無羊肉，鴻謀缺稻糧。", "餐英聊自笑，辟穀竟何傷。", "心遠喧常寂，山深拙可藏。", "息陰慙惡木，同調友孤芳。", "藂蓧緣苔砌，閑花蔓蘚牆。", "寒枝繁鳥雀，落照下牛羊。", "綠欠荷檠雨，青知橘未霜。", "歲華驚過鳥，秋思老吟螿。", "老子便幽事，深雲僦睡鄉。", "指呼閑部曲，嘯詠嬾封疆。", "率爾鳴天籟，泠然似野航。", "汲溪酬欵乃，濯足詠滄浪。", "蟻爲誰開國，蜂如我敬王。", "俗休嘲賦杼，騷謾吊沉湘。", "蘭茝新紉佩，芙蓉嫩製裳。", "不知元亮醉，何似接輿狂。", "更復求三益，何須饋五漿。", "龍山在何許，雲水渺相望。"]'),
('70b87554-2ef0-47fa-b7f0-4c71353ddd8f','酬南宕諸友','釋居簡','宋','宋诗','song-poetry','','[]','歲閏黄楊厄，年豐白晝長。',48,'全唐诗/poet.song.180000.json','["歲閏黄楊厄，年豐白晝長。", "獨居無一事，兩度見重陽。", "野饋同誰餉，閑花各自芳。", "貰將今夜月，藉手送秋光。"]'),
('39ba616b-817b-4ff4-a5f2-b1cbc8b69929','唐人劉長卿送徹上人歸越云禪客無心杖錫還沃洲深處草堂閑身隨弊履經殘雪手綻寒衣入舊山獨向青山依樹下空留明月在人間那堪別後長相憶雲水蒼蒼但閑關洪義二上人請次韻歸山陰','釋居簡','宋','宋诗','song-poetry','','[]','行雲流水去仍還，多費清游少費閑。',64,'全唐诗/poet.song.180000.json','["行雲流水去仍還，多費清游少費閑。", "缺處欲修前夜月，燒痕旋補去年山。", "榻仍拂拭懸空壁，猿自歸來守半閒。", "寂寞東家老茅屋，平安幾日到松關。"]'),
('160d63b4-4f0e-448c-af59-6e8a1d44e5fd','江心寺步月諸公用甄監簿雲卿韻','釋居簡','宋','宋诗','song-poetry','','[]','愛此憑闌夜不眠，欲將風馭作泠然。',64,'全唐诗/poet.song.180000.json','["愛此憑闌夜不眠，欲將風馭作泠然。", "呼蟾駕起三更月，展鏡攤開萬頃天。", "亦有山靈回俗駕，可無蕙帳著胎仙。", "試看拍岸濤翻雪，幾許驪珠碎又圓。"]'),
('deba3f4a-67be-40d7-bbc0-289cdeb47aaf','菜花','釋居簡','宋','宋诗','song-poetry','','[]','花芥開常晚，今年九月開。',48,'全唐诗/poet.song.180000.json','["花芥開常晚，今年九月開。", "直攙寒露過，弗待小春回。", "後乘猶追菊，前驅不遜梅。", "休誇太早計，老圃解栽培。"]'),
('f6cce6c2-1c42-47c2-8495-d84ae6e53d44','冷水谷桃花未開次竹岩韻','釋居簡','宋','宋诗','song-poetry','','[]','山行兩袖皆華風，游人未多花未紅。',128,'全唐诗/poet.song.180000.json','["山行兩袖皆華風，游人未多花未紅。", "堂堂春去已無幾，晴趁一日來山中。", "山人寸金酬天地，都種芳菲留客醉。", "粉桃商略待緋桃，坐令羯鼓催無計。", "怱怱歸興如酒濃，零落斷雲流水蹤。", "明朝乘興尚可再，應笑武陵蓑笠翁。", "判花大手今燕許，收拾是中春一塢。", "小待巴東製錦歸，盡吹紅雨爲霖雨。"]'),
('52ea5e88-546a-46e0-afee-74399cd54c27','酬姜貧樂','釋居簡','宋','宋诗','song-poetry','','[]','我欲淵明伯仲間，爲誰乾沒靜中閑。',64,'全唐诗/poet.song.180000.json','["我欲淵明伯仲間，爲誰乾沒靜中閑。", "直將目送孤鴻度，橫截湖飛短艇還。", "稍閒便同搜萬象，更忙亦可看孤山。", "是閒真隠多餘地，玄豹何嘗肯露斑。"]'),
('bb824203-4a3f-4e71-9be4-d8ceb0452e3c','立可則禮思復雪中見過','釋居簡','宋','宋诗','song-poetry','','[]','花翻雲葉舞風回，新好繽繽带雨開。',64,'全唐诗/poet.song.180000.json','["花翻雲葉舞風回，新好繽繽带雨開。", "團破小龍寒未瀹，客如兩鶴瘦飛來。", "白灰宿火雖同擁，黄獨無苗各自煨。", "苕霅扁舟明日去，小須門外玉山頹。"]'),
('42241090-7ae3-4ceb-b0e1-e8de5c39c520','殘雪','釋居簡','宋','宋诗','song-poetry','','[]','前水花新霽，暾雲日未升。',48,'全唐诗/poet.song.180000.json','["前水花新霽，暾雲日未升。", "簷聲都是雨，筧溜半成冰。", "幌冷疑眠月，窗虛罷續燈。", "獨餘林杪塔，猶自隠觚稜。"]'),
('0e876052-a97f-4b1c-94b3-2c9c4d7b9764','酬方岩','釋居簡','宋','宋诗','song-poetry','','[]','大溪小溪沙水明，濁可濯足清濯纓。',96,'全唐诗/poet.song.180000.json','["大溪小溪沙水明，濁可濯足清濯纓。", "淵淵寸田湛古井，澄濁與之俱忘形。", "綠野菜花三四畮，不圖娛客猶供口。", "舊種庭前三樹槐，更有門前五株柳。", "時拊碧雲歌碧雲，婆娑鵠羽青綸巾。", "不妨別調吟梁甫，收拾乾坤浩蕩春。"]'),
('eab66aa9-9cae-494d-aadf-b5f64bbc3f37','書雪湖寄張高沙詩卷後','釋居簡','宋','宋诗','song-poetry','','[]','大篇如建瓴，小篇如扞城。',120,'全唐诗/poet.song.180000.json','["大篇如建瓴，小篇如扞城。", "執此能事柄，凌奪造物真。", "雪湖坐此徹骨貧，致貧之具猶示人。", "鏗鏘應是我輩語，饑鳶悲苦哦清新。", "高沙舊日春風手，也是乘槎丈人後。", "紅蓮開幕著詩人，此段風流少人有。", "飛聲郎署知聞舊，掃門謾惜千金箒。", "不圖願與丈人厚，要看雲錦三千首。"]'),
('c4a7529a-db1f-4f9f-99bf-0618535e15fd','復齋奚左藏挂冠  其一','釋居簡','宋','宋诗','song-poetry','','[]','趁得身輕便挂冠，翩翩出岫白雲閑。',64,'全唐诗/poet.song.180000.json','["趁得身輕便挂冠，翩翩出岫白雲閑。", "村疎一日是兩日，心廣半間如萬間。", "聊把大門標俗子，別開荒徑友佳山。", "羲皇向上多餘地，時對清風一破顔。"]'),
('80f6d364-893c-49c8-a390-39a1df40e738','復齋奚左藏挂冠  其二','釋居簡','宋','宋诗','song-poetry','','[]','特操剛明與俗乖，谿山亦復外形骸。',64,'全唐诗/poet.song.180000.json','["特操剛明與俗乖，谿山亦復外形骸。", "子狂正作豈矯世，我醉欲眠聊縱懷。", "勇賦一歸尤果决，光寒千文不沉埋。", "從來林下何曾見，僅有先生闥可排。"]'),
('533ca893-ad6b-47b8-8532-4fbeb04fa0f7','送錢竹岩宰常熟  其一','釋居簡','宋','宋诗','song-poetry','','[]','無日游天竺，新除問補陁。',48,'全唐诗/poet.song.180000.json','["無日游天竺，新除問補陁。", "兩回抽竹策，一語定弦歌。", "懸應如虛谷，靈通豈祝鮀。", "只依彭澤樣，條具不須多。"]'),
('457a46a2-3690-4409-88ce-61e669c516e2','送錢竹岩宰常熟  其二','釋居簡','宋','宋诗','song-poetry','','[]','淵默戰紛華，清吟日又斜。',48,'全唐诗/poet.song.180000.json','["淵默戰紛華，清吟日又斜。", "尊中常有酒，堂下可施罝。", "琴響家家月，春酣處處花。", "平章風物手，小屈課桑麻。"]'),
('a36f845a-df93-4942-80dd-019eae3a0d96','贈鶴鳴馮高士','釋居簡','宋','宋诗','song-poetry','','[]','靜對深爐養白砂，又從活火剪黄芽。',64,'全唐诗/poet.song.180000.json','["靜對深爐養白砂，又從活火剪黄芽。", "蛻塵與世羽凡骨，看鏡爲誰開曉霞。", "萬里脚頭元自穩，一毫心事不曾差。", "何時采藥天台去，爛醉桃源幾樹花。"]'),
('c2e5aace-7b30-4d4d-a0ed-9e5fd9cdfb69','賀宇文樞使','釋居簡','宋','宋诗','song-poetry','','[]','伊洛正音聞者寡，邪說異端難並駕。',160,'全唐诗/poet.song.180000.json','["伊洛正音聞者寡，邪說異端難並駕。", "春風不到六經堂，和煦無由藹天下。", "卓然人物既興起，浩然一氣均陶冶。", "橫秋霽月耿東南，勁草疾風知用舍。", "隄障狂瀾如砥柱，淵源理學扶宗社。", "伊周文憲復精明，漢唐述作俱陵跨。", "論道經邦坐策勳，彈冠束带無遺野。", "遂令四海九州內，三尺兒童恥言伯。", "太山盤石固無疆，亂臣賊子胡爲者。", "今日樞庭拜宇文，還似前朝相司馬。"]'),
('cafe62d5-9943-4065-bb54-359ee129ff50','盆蘭','釋居簡','宋','宋诗','song-poetry','','[]','采采芳根綠綴苔，一莖只放一花開。',64,'全唐诗/poet.song.180000.json','["采采芳根綠綴苔，一莖只放一花開。", "畹中好惡非同調，林下薰蕕各有才。", "惜此國香無地種，知它楚些爲誰哀。", "小留鶴帳梅梢月，倘伴高情入夢來。"]'),
('577c0e0a-db09-46b6-8be7-b21b4b5383d7','送黄郡博之官高郵  其一','釋居簡','宋','宋诗','song-poetry','','[]','一曲占晴湖，樓居豈俗居。',48,'全唐诗/poet.song.180000.json','["一曲占晴湖，樓居豈俗居。", "人雖增境勝，鷺不與鷗疎。", "古錦投明月，春風入絳幮。", "好詩頻遣寄，莫遣不情書。"]'),
('4f94c9d0-68d8-4985-b8d3-e566f0a24e57','送黄郡博之官高郵  其二','釋居簡','宋','宋诗','song-poetry','','[]','貴作橫金客，才如切玉刀。',48,'全唐诗/poet.song.180000.json','["貴作橫金客，才如切玉刀。", "長城堅未下，大敵勇難鏖。", "老兔明千里，垂虹綠半篙。", "何時醉醽醁，伴我讀離騷。"]'),
('427c2c88-2bef-422c-9974-585bfec1b5c1','送譙回菴作江東憲','釋居簡','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','千騎前驅擁旆旌，鳥啼花發近清明。',64,'全唐诗/poet.song.180000.json','["千騎前驅擁旆旌，鳥啼花發近清明。", "斯文自是域中大，廷尉舊持天下平。", "春到十連皆化日，風清萬竅只秋聲。", "廬山面目無人識，應喜重來爲主盟。"]'),
('0f532393-4285-4940-bf17-f9232552f1e1','續舞馬行','釋居簡','宋','宋诗','song-poetry','','[]','見說開元天寶間，登床百駿俱回旋。',128,'全唐诗/poet.song.180000.json','["見說開元天寶間，登床百駿俱回旋。", "一曲傾杯萬人看，一顧群空四十萬。", "梨園部曲能窮奇，踣鐵矯揉楊柳枝。", "不直玉環一解頤，更走瀘戎生荔枝。", "天上人間反覆手，故態忽生亂離後。", "將軍入眼可曾有，誤駿爲妖不足咎。", "於戲唐虞全盛時，百獸率舞鳳鳥儀。", "雍熙之和乃其效，何用區區教坊教。"]'),
('47739ca8-b7d2-47d8-b3b7-3bf31eb51c93','韜光菴','釋居簡','宋','宋诗','song-poetry','','[]','洛下僧歸未寂寥，餘光還向此中韜。',64,'全唐诗/poet.song.180000.json','["洛下僧歸未寂寥，餘光還向此中韜。", "入千峯杪從它笑，放一頭低儘自高。", "客至坐凉分樹影，雲開冩望到江濤。", "夜遥月冷風初霽，萬籟無聲亦怒號。"]'),
('2e128c5d-d714-4a06-ba81-cfa8b30105c2','謝盤野黄文昌  其一','釋居簡','宋','宋诗','song-poetry','','[]','易入亞夫營，難收四海名。',48,'全唐诗/poet.song.180000.json','["易入亞夫營，難收四海名。", "兩全無可媿，獨以退爲榮。", "蕭灑霜髯古，敷腴玉色明。", "神仙在平地，跬步到鈞衡。"]'),
('2b3fc4b5-f4b7-4355-8799-826da1544321','謝盤野黄文昌  其二','釋居簡','宋','宋诗','song-poetry','','[]','日課芳菲譜，歸來手自栽。',48,'全唐诗/poet.song.180000.json','["日課芳菲譜，歸來手自栽。", "有詩隨意好，無日不花開。", "鷗鷺論心事，雲山入酒杯。", "綺羅簾幕靜，處處小蓬萊。"]'),
('4a3b4fdd-2dcb-4096-aa3e-00ddfae51aed','十四夜月','釋居簡','宋','宋诗','song-poetry','','[]','幾望滄浪月，裴回獨自看。',48,'全唐诗/poet.song.180000.json','["幾望滄浪月，裴回獨自看。", "小虧修未了，忒滿怕持難。", "篆冷檀煙濕，衣單桂露乾。", "丁寧橋下水，明夜印團團。"]'),
('f76427b2-7568-4f4d-85a4-10556c2f63b8','代竹岩送史侍郎  其一','釋居簡','宋','宋诗','song-poetry','','[]','曾泛東湖載月船，不將人物等閑看。',64,'全唐诗/poet.song.180000.json','["曾泛東湖載月船，不將人物等閑看。", "二靈千古獨鍾秀，五岳三光空自寒。", "跨竈極知從古少，爲兄端恐自君難。", "故家別有單于調，付與鴒原次第彈。"]'),
('93a09b87-713f-4f43-b05e-84cc4967c9c6','代竹岩送史侍郎  其二','釋居簡','宋','宋诗','song-poetry','','[]','荷橐風高北固秋，黄童白叟擁行舟。',64,'全唐诗/poet.song.180000.json','["荷橐風高北固秋，黄童白叟擁行舟。", "舊盟不冷在群鷺，歸興絕攀回萬牛。", "傳自教明南國後，可容寇借一年不。", "旌麾小試經綸手，此惠何煩歛壹州。"]'),
('647dcedf-9e02-4902-9b83-5c66d67052f3','昭君行','釋居簡','宋','宋诗','song-poetry','','[]','楚山有美傾人國，家傍江城逐臣宅。',160,'全唐诗/poet.song.180000.json','["楚山有美傾人國，家傍江城逐臣宅。", "逐臣賦並日月明，琵琶遣入穹廬鳴。", "哀彈不作胡兒語，冩漢遺音吊亡楚。", "泪如鉛水濕春風，苦心只與春風訴。", "曲中愁緒亂風絲，因風寄鴈雲南飛。", "漢家彈作昭君怨，試問昭君別怨誰。", "天生尤物天還如，仰天自笑蛾眉誤。", "不如强醉枕琵琶，暫時栩栩夢還家。", "昭陽未有承恩地，閼氏孰與寧胡貴。", "不須頻下思家泪，漢女雄猜如阿雉。"]'),
('1fa9a6bb-6c02-4014-a632-62735a376fb8','白鷄謝靜講師湖州舊舘','釋居簡','宋','宋诗','song-poetry','','[]','素羽剪零雲，冠裁辰錦新。',48,'全唐诗/poet.song.180000.json','["素羽剪零雲，冠裁辰錦新。", "德如潮有信，雄壓牝無晨。", "物化寤非蝶，蟻酣驚代隣。", "莫教風雨暝，緘口却羞人。"]'),
('ce4ea815-9e55-40fa-84c5-e8a804f98707','苕溪多楮三伏最茂','釋居簡','宋','宋诗','song-poetry','','[]','朱實燉空密幄成，曾陰無地暍行人。',64,'全唐诗/poet.song.180000.json','["朱實燉空密幄成，曾陰無地暍行人。", "風枝雨幹彫零後，玉板雲英制作新。", "傳得文章貽後晉，忍隨竹帛禍先秦。", "西凉葉葉秋聲樹，學到先生是效顰。"]'),
('a54f8467-9168-4ca6-ac1e-7a228f9ebc08','寄漫塘劉平國索竹岩錢德載挽章','釋居簡','宋','宋诗','song-poetry','','[]','一從神武挂衣冠，千載華風去不還。',64,'全唐诗/poet.song.180000.json','["一從神武挂衣冠，千載華風去不還。", "閑愜清寧羞宦巧，靜闚奔競識天慳。", "高於少室從它售，捷似終南各自扳。", "我欲西風問無恙，不知著得幾鷗閑。"]'),
('75337e6c-f718-425b-a236-b4aa150a2236','西余庭犀合抱强半不下西湖劉寺雙桂已厄於嘉定十二年打十方之初信夫主僧元粹之忍也余在北山作詩援之云翠華幾度樹邊來手壓芳枝內苑栽且看傳燈金粟面小留殘馥點蒼苔兩唐律賦西余吊劉寺云  其一','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','亭亭領袖晚風光，吹盡西凉不盡香。',64,'全唐诗/poet.song.180000.json','["亭亭領袖晚風光，吹盡西凉不盡香。", "勒麝蘭薰回俗駕，動龍蛇影轉回廊。", "老持素節芳仍潔，碎點蒼苔綠襯黄。", "自把胡床低處著，高舂盤礴到斜陽。"]'),
('27229366-093d-43e7-bb39-5faa574947a3','西余庭犀合抱强半不下西湖劉寺雙桂已厄於嘉定十二年打十方之初信夫主僧元粹之忍也余在北山作詩援之云翠華幾度樹邊來手壓芳枝內苑栽且看傳燈金粟面小留殘馥點蒼苔兩唐律賦西余吊劉寺云  其二','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蛻俗風標與月分，競攀爭擷到仍雲。',64,'全唐诗/poet.song.180000.json','["蛻俗風標與月分，競攀爭擷到仍雲。", "弗知薌國有喬木，大似幽居無此君。", "葉密聽他嫌不韻，根盤如許合空羣。", "四朝雨露金刀寺，兩樹前年夭斧斤。"]'),
('6e75768f-973e-45db-8974-13ce4a39f190','初度','釋居簡','宋','宋诗','song-poetry','','[]','苕溪初度思親泪，滴盡依前不及泉。',64,'全唐诗/poet.song.180000.json','["苕溪初度思親泪，滴盡依前不及泉。", "借使無言還自壽，便教有法與誰傳。", "五窮各自爭爲祟，百巧還他弗解禪。", "爲問季秋幾望月，幾回照我未生前。"]'),
('645835f5-aa22-45b8-ba11-ae8a949655b3','送袁狀元別駕','釋居簡','宋','宋诗','song-poetry','','[]','碧苕秋晶晶，君子尚此潔。',180,'全唐诗/poet.song.180000.json','["碧苕秋晶晶，君子尚此潔。", "淵淵方寸地，上善固一轍。", "白蘋對紅蓼，亦各振清冽。", "况復芬陁利，穆若謝炎熱。", "譬彼寒水玉，溫其出冰雪。", "其中富涵蓄，其響亦疎越。", "有德必有用，無瑕更無缺。", "允屬清廟器，合在東序設。", "君家聖賢學，擬續鄒魯絕。", "正音久不作，倩君木爲舌。", "風月小鴻溝，矧乃龍首傑。", "偉茲真富貴，弗與顔原別。", "輝輝近芳日，朣朣袖華月。", "餘光散遐隠，四海俟昭晰。", "遺直在山林，放言敢辭拙。"]'),
('5b487123-c7ee-424b-b650-36db5baa0768','和竹岩游虎丘','釋居簡','宋','宋诗','song-poetry','','[]','山低秋欲雨，樹老晚藏煙。',48,'全唐诗/poet.song.180000.json','["山低秋欲雨，樹老晚藏煙。", "劍試道邊石，花飛臺外天。", "暝雲埋古甃，嵌竇漲新泉。", "欲借松風鼎，煎茶些玉川。"]'),
('85f88566-616d-43e5-b01c-6b1a9611ce1d','九日姑蘇臺酬盧蒲江趙靜齋錢竹岩諸名勝','釋居簡','宋','宋诗','song-poetry','','[]','歲晚登臨似仲宣，可勝來此拍闌干。',64,'全唐诗/poet.song.180000.json','["歲晚登臨似仲宣，可勝來此拍闌干。", "水圍綠野日將夕，露浥紫萸秋未寒。", "欲雨天痕雲氣濕，不風庭樹子聲乾。", "悠然吊古無窮恨，付與西風一永嘆。"]'),
('9be63cb9-5f07-4754-85ed-02af97b17ae2','雪中寄趙湖州容齋','釋居簡','宋','宋诗','song-poetry','','[]','慶兆三回白，祥開嗣歲春。',120,'全唐诗/poet.song.180000.json','["慶兆三回白，祥開嗣歲春。", "精求方懇懇，懸應忽逡逡。", "化母非無待，玄冥却有神。", "夜窗疑是月，曉砌不生塵。", "麰麥占年熟，郊原見日新。", "柳塘吹漠漠，銀浦剪繽繽。", "鶴幹勝寒重，猨枝撼落頻。", "折腰嗟勁節，低首吊蒼鱗。", "池草生吟思，溪梅寄遠人。", "不知吟嘯地，何似灞橋親。"]'),
('d5d16193-116a-45ef-a99b-cd2aa0272835','開元觀乃何畏齋施地張練師開山','釋居簡','宋','宋诗','song-poetry','','[]','何必過流沙，潯溪種道芽。',48,'全唐诗/poet.song.180000.json','["何必過流沙，潯溪種道芽。", "雄開獻王地，勝傍覺皇家。", "雲侶呼朝斗，星壇數扣牙。", "胎仙翔集後，底處蟄靈蛇。"]'),
('369be709-1ee8-4ce9-80ad-6c3b9ba3d685','舟中遇雪寄宋使君  其一','釋居簡','宋','宋诗','song-poetry','','[]','數點雨中飄，蕭騷響近郊。',48,'全唐诗/poet.song.180000.json','["數點雨中飄，蕭騷響近郊。", "霰微疑旋集，篷破省初敲。", "乾沒高連下，平鋪凸到凹。", "懸知天地力，瑕穢頼并包。"]'),
('e963d83b-6806-4e68-911e-e57cade81317','舟中遇雪寄宋使君  其二','釋居簡','宋','宋诗','song-poetry','','[]','急舞隨風亂，繽飛度竹遲。',51,'全唐诗/poet.song.180000.json','["急舞隨風亂，繽飛度竹遲。", "松埋巢鶴頂，藤重挂猨枝。", "螟{虫忒}頻年死，烏鳶盡日饑。", "婁豐書野史，雙展使君眉。"]'),
('32a2d444-dc48-435d-92f2-4b56a76f32b1','代人與荆襄李制帥','釋居簡','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','桃花武陵原，千騎訪舊游。',240,'全唐诗/poet.song.180000.json','["桃花武陵原，千騎訪舊游。", "舊題鬼神護，苔蘚封蛟虬。", "是時原中花，炫晝爛不收。", "稚耄相懽呼，再拜羅道周。", "一聞謦咳聲，曰似吾故侯。", "侯今飛上天，盟在滄江鷗。", "公來席未溫，玉帳凉生秋。", "粘天洞庭北，襄楚當襟喉。", "小屈經綸手，平分宵旰憂。", "風清鸚鵡洲，月滿黄鶴樓。", "黄鶴去不返，萬竈棲貔貅。", "白羽青綸巾，坐寢淮南謀。", "文武固一道，貂蟬出兜鍪。", "致身須黄閣，看鏡方黑頭。", "故家邁種德，台輔不足酬。", "頹支鄒魯瀾，末障洙泗流。", "載觀統有宗，抑使俗不浮。", "古道復大明，殊俗皆蒙休。", "况夫蜀文章，眉獨稱雄酋。", "多應峩眉月，只照東家丘。"]'),
('95fe3d1d-0fdf-458c-97d6-f43f797f022e','徐提刑挽章','釋居簡','宋','宋诗','song-poetry','','[]','衣冠忽蛻塵，桃下是仙津。',48,'全唐诗/poet.song.180000.json','["衣冠忽蛻塵，桃下是仙津。", "身與吳天遠，恩沾楚澤新。", "授官寧後子，退己不先人。", "盡是無私處，何慙第五倫。"]'),
('2d1297fe-3816-49b1-9584-e47436797c07','盧君挽章','釋居簡','宋','宋诗','song-poetry','','[]','禍淫福善信前聞，話到斯人只斷魂。',64,'全唐诗/poet.song.180000.json','["禍淫福善信前聞，話到斯人只斷魂。", "心豈眢丹遺冏冏，電雖藏碧鑑昏昏。", "欲將書卷酬青紫，不啻籝金富子孫。", "後夜黄龍洞前月，小留殘照側金盆。"]'),
('dc2ce9d3-1dba-478d-8b89-842992889a97','黄龍洞','釋居簡','宋','宋诗','song-poetry','','[]','玄窞蜿蜒宅，苔痕到底青。',48,'全唐诗/poet.song.180000.json','["玄窞蜿蜒宅，苔痕到底青。", "鑿深連地軸，設險訝山靈。", "路斗風烟濕，風酸草木腥。", "丁寧休勒駕，更欲上新亭。"]'),
('b67b18c0-faff-4b6b-9f4b-1eed94a33cb7','舊館夜雪投靜上人','釋居簡','宋','宋诗','song-poetry','','[]','雪重官塘滑，堆篷掃不消。',48,'全唐诗/poet.song.180000.json','["雪重官塘滑，堆篷掃不消。", "聞鐘尋近寺，轉港識飛橋。", "膚粟寒初起，衣稜煖不朝。", "主人無木佛，泥佛不中燒。"]'),
('abc9f222-aad1-426c-977a-e0b08a88c693','謝陸少監分惠渭南劍南家集','釋居簡','宋','宋诗','song-poetry','','[]','故家騷雅傳，翼翼見芳繼。',240,'全唐诗/poet.song.180000.json','["故家騷雅傳，翼翼見芳繼。", "况如孫仲謀，不敗乃翁事。", "圭殘入裒拾，璧斷歸次第。", "自成一家學，忍使隻字棄。", "若翁喻蜀時，名勝各超詣。", "初從漢西京，綿綿振末裔。", "相如子雲後，經術奮多士。", "巋然今隴蜀，淵乎古洙泗。", "馮劉振風霆，劉李渺涯涘。", "况復有小李，雋永出大胾。", "翁來試掉鞅，平地快奔駟。", "逸駕相後先，六月乃一稅。", "渭南問風俗，劍南看形勢。", "岷峩連蓬婆，風賦達駢儷。", "雕鎸到微茫，抉剔逮菑翳。", "連絡數十城，八萬四千偈。", "彬彬奐文采，爛爛存表制。", "分甘成暗投，效顰更拙計。", "瓊琚報木李，美齊詔當世。", "乃今得瓊琚，何以答佳惠。"]'),
('74cd11d7-3d9b-438c-8ad5-6cc535aecd3c','葛無懷訃至  其一','釋居簡','宋','宋诗','song-poetry','','[]','飲羽闚天巧，御枚戒夜嚴。',48,'全唐诗/poet.song.180000.json','["飲羽闚天巧，御枚戒夜嚴。", "采荼寧自苦，課蜜爲誰甜。", "閣令看山檻，亭空竝水簷。", "懷哉雙宿鷺，日日望鈎簾。"]'),
('3ce0caca-191c-44cb-86ff-22befa8d9d9e','葛無懷訃至  其二','釋居簡','宋','宋诗','song-poetry','','[]','靜勝知天定，虛明悟物齊。',48,'全唐诗/poet.song.180000.json','["靜勝知天定，虛明悟物齊。", "略伸嗟屈蠖，欲吐喪晴霓。", "夜雨燈侵幌，春風柳竝堤。", "漫天吹絮盡，一點不沾泥。"]'),
('829f1124-8b89-4949-b32a-637db40672e2','杲無外枝巢','釋居簡','宋','宋诗','song-poetry','','[]','樹下無三宿，人間僦一單。',48,'全唐诗/poet.song.180000.json','["樹下無三宿，人間僦一單。", "房新蜂最樂，巢舊燕知難。", "雲幌涵秋冷，蟾枝踏月殘。", "朱門空鎖宅，多是別人看。"]'),
('da30cd50-e172-4c64-a462-576451efc3fa','即事','釋居簡','宋','宋诗','song-poetry','','[]','遥夜遲眠替夙興，細聽牆角打風稜。',64,'全唐诗/poet.song.180000.json','["遥夜遲眠替夙興，細聽牆角打風稜。", "白灰未冷已無火，紅燼欲殘猶有燈。", "天做雪時先自雨，水通潮處可曾冰。", "有詩只些孤山月，不恨梅花喚不譍。"]'),
('dd7e74e1-d26a-4c93-85ec-a5da5d5fa308','分歲','釋居簡','宋','宋诗','song-poetry','','[]','辦得分年供，清哉亦稱懷。',48,'全唐诗/poet.song.180000.json','["辦得分年供，清哉亦稱懷。", "野槃均柿串，草具爨松釵。", "指冷柑初破，灰紅芋旋埋。", "火邊相枕藉，火盡又添柴。"]'),
('4182ae5b-2dac-4fd8-950e-234506730dd8','讀岳鄂王傳','釋居簡','宋','宋诗','song-poetry','','[]','百鈞不挽射羿弓，朔望酹酒馬鬣封。',384,'全唐诗/poet.song.180000.json','["百鈞不挽射羿弓，朔望酹酒馬鬣封。", "從來知子莫若父，許以徇國輸精忠。", "相州去謁大元帥，是時元帥方潛龍。", "華風忽與慶雲遇，千載一德明良同。", "南薰門外衆制寡，鐵路步上雌决雄。", "浮屠連牆望塵靡，枴子如山隨手空。", "僞齊可紿不可殺，兀朮可間毋庸攻。", "寇連諸道解如瓦，氣吐千丈長於虹。", "聲先到處皆春風，桀驁怙很摧枯蓬。", "中原跂踵戴舊德，蕭牆稔禍基元凶。", "當時劍握不倒置，直北馬首無由東。", "全尺寸地有餘刃，半九十里隳奇功。", "老羆既陷百尺穽，長城遂摧千丈墉。", "群姦尾摇蜂蠆毒，一蟇吻納蟾蜍宮。", "强胡妄冀脫虎口，殘喘忽重甦犬戎。", "難平者事有成算，可投之機無再逢。", "鄉來望諸報燕惠，無怨無怒方雍容。", "其誰掩卷輒慟哭，主父偃與齊蒯通。", "黄金臺圮置勿論，問之胡不達四聰。", "昔人已矣不可作，後來更復將焉從。", "審如機括發必中，誠與日月昭而融。", "將軍碧電摇百步，跨竈英勇尤折衝。", "乾坤不朽忠義骨，光騰抔土方朣朣。", "春秋不書六月雪，是日集霰回泠風。"]'),
('9c975893-7d8c-4d91-b781-470436b3c069','楂菴嚴教主塔','釋居簡','宋','宋诗','song-poetry','','[]','黄金扶膝起沉潜，一屈何須爲老嚴。',64,'全唐诗/poet.song.180000.json','["黄金扶膝起沉潜，一屈何須爲老嚴。", "掃逕雪苔封古甃，舉頭花雨落疎簷。", "楂酸如橘尤多澀，語苦如荼久自甜。", "新霽林光浄如洗，僧窗處處有孤蟾。"]'),
('d6c9a3c2-8f4c-490c-850f-5ec74fc2010c','送侃侍者歸靈鷲','釋居簡','宋','宋诗','song-poetry','','[]','莫將平淡覓陶潛，紀律嚴於玉帳嚴。',64,'全唐诗/poet.song.180000.json','["莫將平淡覓陶潛，紀律嚴於玉帳嚴。", "要得瀾翻聯石鼎，也須雪立到茅簷。", "太虛自笑花無蔕，佳境誰云蔗不甜。", "如此工夫隨分到，靈犀無夜不吞蟾。"]'),
('eb7bc03d-46d0-4fd5-af70-36be9bcff637','索笑','釋居簡','宋','宋诗','song-poetry','','[]','屋角飄香樹，何曾解倩兮。',48,'全唐诗/poet.song.180000.json','["屋角飄香樹，何曾解倩兮。", "倚春和露瘦，闖曉待蟾低。", "背俗高標致，從他浪品題。", "若非林處士，冷面覷清溪。"]'),
('d43ed53c-5a35-4186-9201-2f204b27bdde','有客','釋居簡','宋','宋诗','song-poetry','','[]','雨止雲猶黑，春寒草未青。',48,'全唐诗/poet.song.180000.json','["雨止雲猶黑，春寒草未青。", "打門無俗客，勒駕有山靈。", "彷彿斜川路，裴回曲水亭。", "落梅都著子，點點六花零。"]'),
('84ecf46f-fdf5-4d19-ab19-0563ef617c66','鶴唳','釋居簡','宋','宋诗','song-poetry','','[]','九皋清響漏殘時，想見松間露濕衣。',32,'全唐诗/poet.song.180000.json','["九皋清響漏殘時，想見松間露濕衣。", "弱水弗關雲外路，乘軒終不似橫飛。"]'),
('d5b007d5-15e7-426b-81a4-9224f8996c3a','蘋洲萊菔脆甚','釋居簡','宋','宋诗','song-poetry','','[]','藕生玉井何曾見，梨屬張公不見分。',32,'全唐诗/poet.song.180000.json','["藕生玉井何曾見，梨屬張公不見分。", "安得脆瓊萊菔子，蘋洲南畔種殘雲。"]'),
('1c1eea96-252b-4cbf-a668-30bceb196d5f','寄陳宣州中書  其一','釋居簡','宋','宋诗','song-poetry','','[]','霽月橫陳幾許秋，拍肩小謝老風流。',64,'全唐诗/poet.song.180000.json','["霽月橫陳幾許秋，拍肩小謝老風流。", "開尊孰愈暫挂榻，視草曷如高卧樓。", "舊有鳳銜新紫詔，今無鶴似古楊州。", "潁川只說黄丞相，更爲行春得小留。"]'),
('62168ad7-017f-4b3b-b613-7c897f44de1f','寄陳宣州中書  其二','釋居簡','宋','宋诗','song-poetry','','[]','夷惠清和不尚同，直將兩手袖春風。',64,'全唐诗/poet.song.180000.json','["夷惠清和不尚同，直將兩手袖春風。", "婁豐從勸三農始，初度重書二月中。", "欲與大年分殿最，試於小知擊倥侗。", "雖云弱水歸溟渤，自向西流不自東。"]'),
('c8af122e-99e2-4281-b46a-d26bf7184970','佛眼侍者祖元血書華嚴八十卷以報母細而楷花石綱初得之藏諸塔寺後復失之復得之於京師','釋居簡','宋','宋诗','song-poetry','','["\u8861\u5c71"]','楚雲血指書法華，藏諸衡山竺僊家。',256,'全唐诗/poet.song.180000.json','["楚雲血指書法華，藏諸衡山竺僊家。", "自言剖匣待慈氏，凡指試觸轟雷車。", "思谿不落衡山後，行綴蠅頭三十九。", "停勻瘦勁妙鍾王，初終一字亡差謬。", "阿元曾透龍門去，失却登門最初步。", "筆端佛語血滴滴，直下發明根本部。", "一塵具有一卷經，破塵出經不動塵。", "塵塵剎剎盡三昧，一字一行皆正因。", "靜想生初常反照，雱然母血知多少。", "一支餘瀝何足云，貝葉悉書酬不了。", "蓮花七卷六萬言，浄明海眼伯仲間。", "諸經一寫復屢寫，大經血脈俱相關。", "六丁疇曩曾搜索，青氊解后銅駝陌。", "千金購得喜欲顛，十襲載歸花石船。", "恍如光焰騰雙劍，夜奪龍光寒不焰。", "遂令合浦有還珠，毋令滄海有遺珠。"]'),
('ee5b4ac2-956c-459c-a48c-2ffe1f2b6ec7','劉學諭挽章','釋居簡','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','大信難於淺俗謀，楚人然諾久無酬。',64,'全唐诗/poet.song.180000.json','["大信難於淺俗謀，楚人然諾久無酬。", "盡攄素藴知難售，空抱遺經自反求。", "數曲短屏林屋曉，半規殘壁洞庭秋。", "焚舟自是諸郎事，接武東廂兩勝流。"]'),
('b168f891-ee5d-463b-b71d-96121be30f77','題水墨萱草水仙  其一','釋居簡','宋','宋诗','song-poetry','','[]','草欲忘憂蔓更滋，望雲長在蜀天西。',32,'全唐诗/poet.song.180000.json','["草欲忘憂蔓更滋，望雲長在蜀天西。", "蕭蕭風木添新恨，謄錄精神答噬臍。"]'),
('73ee8074-9385-48e0-9e93-fc0e16019f36','題水墨萱草水仙  其二','釋居簡','宋','宋诗','song-poetry','','[]','綠玉纖扶水玉腴，華風披拂度華裾。',32,'全唐诗/poet.song.180000.json','["綠玉纖扶水玉腴，華風披拂度華裾。", "却從壞色衣中賦，不把高情託子虛。"]'),
('54be3ad1-98c5-45a4-808c-1e588a1e7ddf','讀南遷錄','釋居簡','宋','宋诗','song-poetry','','[]','垂垂胡運風燈掣，不悟鼎中猶鱍剌。',208,'全唐诗/poet.song.180000.json','["垂垂胡運風燈掣，不悟鼎中猶鱍剌。", "後庭玉樹不摇春，只看婆娑雙勃脫。", "提刀策馬兆自南，夢中宿憤方深銜。", "子生母死託諸母，禍既滋蔓難夷芟。", "骨肉相殘甚於寇，倒把太阿歸女手。", "寧能同死不同生，掎角亟圖鄰壤捄。", "奮戈禿體空無前，傾巢倒穴成播遷。", "飄零左衽餘南冠，孫又生子罹腥羶。", "回頭九十年中事，水淺蓬萊人換世。", "順昌之捷金刀回，商虢破竹丘山頹。", "韓劉亦復不世出，英勇棄捐如擲礫。", "短檠伴語南遷話，泪眼不晴徹遥夜。", "應是天歸古汴都，却教胡羯先驅除。"]'),
('c94c0f00-fcd7-4db2-8514-dd7174a61211','讀泣蘄錄','釋居簡','宋','宋诗','song-poetry','','[]','蘄當淮楚衝，虜騎如雲隤。',168,'全唐诗/poet.song.180000.json','["蘄當淮楚衝，虜騎如雲隤。", "書生膽如斗，激烈生風雷。", "備禦盡吾力，力殫心不灰。", "誓與城存亡，不遣疋馬回。", "忍死不忍屈，視死猶去來。", "一州同一心，忠憤鐵石開。", "舍生貴取義，肯顧兒女哀。", "話頭素講明，餘刃方恢恢。", "視古不愧今，落落俱雄才。", "援師窘於兔，趑趄山澤隈。", "遂使破賊手，不復殲渠魁。", "儀刑古睢陽，觀闕雙崔嵬。", "傳後韓愈書，芒寒燉九垓。", "不知蘄州傳，大手今誰哉。"]'),
('4a06396f-316e-49d8-b17f-01f1c9fa56b6','送高菊磵訪方岩侍郎','釋居簡','宋','宋诗','song-poetry','','[]','塵漲軟紅深，髯高獨訪尋。',48,'全唐诗/poet.song.180000.json','["塵漲軟紅深，髯高獨訪尋。", "貧交難偶俗，生事不關心。", "米貴甘餐玉，樓寬苦僦金。", "霞標連雁蕩，款款度岑崟。"]'),
('d57e9768-515a-4be6-8d63-eb47c1116ee8','酬趙山中','釋居簡','宋','宋诗','song-poetry','','[]','壺公雲雨上，秀整壓全吳。',48,'全唐诗/poet.song.180000.json','["壺公雲雨上，秀整壓全吳。", "白眼嫌人俗，玄裳笑鶴癯。", "對吟酬蟋蟀，獨酌泛茱萸。", "待賦歸來後，商量覓鏡湖。"]'),
('4e54b293-5cc6-4024-a041-0571db5c1cdb','塘西寺聞蛙','釋居簡','宋','宋诗','song-poetry','','[]','器小易彭亨，聲連踸踔群。',48,'全唐诗/poet.song.180000.json','["器小易彭亨，聲連踸踔群。", "三更萬籟息，兩部一池分。", "語海嗟難合，窺天亦浪云。", "尋無杜鵑處，得此不堪聞。"]'),
('ebb61623-9e2b-40f9-a965-4d9b8bb636f8','方岩許送紙不至','釋居簡','宋','宋诗','song-poetry','','[]','巾山高出慈恩寺，蜀叟貧於鄭廣文。',64,'全唐诗/poet.song.180000.json','["巾山高出慈恩寺，蜀叟貧於鄭廣文。", "卷盡長廊無一葉，尚餘潑筆振孤軍。", "蒼筠嫩殺空懷古，明玉方裁欠策勳。", "惆悵洛陽收賈後，欲書重吊楮生文。"]'),
('64843650-37eb-4c67-b453-438321da81cb','謝周和州叔子','釋居簡','宋','宋诗','song-poetry','','[]','陰陰濃綠成新幄，荼蘼試粧催芍藥。',128,'全唐诗/poet.song.180000.json','["陰陰濃綠成新幄，荼蘼試粧催芍藥。", "緩鞚青絲果下騮，時與華風相領略。", "風乎不違主人意，吹開宿酲換新醉。", "玉山自起不須扶，隠若長城一萬里。", "和州歸來賈如玉，高著十連酬不足。", "倚闌目送斷鴻飛，閑按新聲翻舊曲。", "疇曩方岩丈人厚，話到君侯布衣舊。", "不知灞上故將軍，何如細柳真將軍。"]'),
('82256476-c86f-4d4d-ac3d-2e2805b74e4b','和趙湖州見寄','釋居簡','宋','宋诗','song-poetry','','[]','拙速詼諧與巧遲，約三章法赴吟期。',64,'全唐诗/poet.song.180000.json','["拙速詼諧與巧遲，約三章法赴吟期。", "一從鷗鷺忘情後，都是池塘入夢時。", "星履盍酬高步武，竹符聊試小施爲。", "凜然心事明如日，况是從來畏四知。"]'),
('d8e44846-8484-47b8-a3cf-39293f28b5c9','泊然菴','釋居簡','宋','宋诗','song-poetry','','[]','白日靜中消，忘言賦解嘲。',48,'全唐诗/poet.song.180000.json','["白日靜中消，忘言賦解嘲。", "葉疎猶可幄，雲淺亦堪巢。", "清擬聖人酒，澹於君子交。", "悠然無藉在，簷鐸聽風敲。"]'),
('7c0bdc48-67ca-421a-a1cf-7be97be89209','平望徐監酒新樓','釋居簡','宋','宋诗','song-poetry','','[]','水際樓居入眼新，傍窗橫榻款詩人。',64,'全唐诗/poet.song.180000.json','["水際樓居入眼新，傍窗橫榻款詩人。", "早彫杜老雙蓬鬢，晚賞徐卿兩石麟。", "濃綠已摇三丈線，殘紅恰有一釐春。", "閑情直與眉霄壤，也爲春歸作小顰。"]'),
('daf9d91a-a449-4bb4-918d-d435b0cca136','次韻宣州使君陳中書見寄','釋居簡','宋','宋诗','song-poetry','','[]','聽紫芝歌問綺園，橘中果有幾何天。',64,'全唐诗/poet.song.180000.json','["聽紫芝歌問綺園，橘中果有幾何天。", "試原雪夜玉堂夢，更了江春符竹緣。", "新漲溢池荷葉小，煖風掠面柳花鮮。", "大邦屏翰風騷地，應有詩人受一廛。"]'),
('6e180d06-7c6f-457d-ae37-e195401fc527','白蘋洲新樓曰溪山偉觀','釋居簡','宋','宋诗','song-poetry','','[]','溪頭烟煖蘋花春，豈獨滿渚亦滿汀。',192,'全唐诗/poet.song.180000.json','["溪頭烟煖蘋花春，豈獨滿渚亦滿汀。", "春城綺綉艷溪曲，柔玉摻摻歌采蘋。", "采采芳鮮日將暮，玉盌瓊盂旋分貯。", "水晶闕冷禁城寬，蘭櫂夷猶緩歸去。", "鄉來小亭橫水滸，雨震風凌日榛莽。", "山鬼嘯梁猿嘯渚，寂寞風烟向誰訴。", "仙槎忽從銀浦來，吟疆開拓搜吟才。", "眼前有句未暇著，只著畫樓臨水開。", "一雙浮圖筆插架，層級高低與樓亞。", "從來天巧不曾藏，紛紛俗眼空茫羊。", "賦此須還造樓手，大蘇小杜相先後。", "柳惲才華更有餘，那堪一等愛樓居。"]'),
('520ce03f-9bcd-4873-bddb-eb202d7e5f24','瀘南玉帳曹國博再知類省舉','釋居簡','宋','宋诗','song-poetry','','[]','除却倚門憔悴兄，關心國子老先生。',64,'全唐诗/poet.song.180000.json','["除却倚門憔悴兄，關心國子老先生。", "近看西蜀群仙籍，遠赴南豐一瓣盟。", "久矣倚公如敵國，懷哉得士勝長城。", "蜀江萬派朝宗水，峭絕瀘川砥柱橫。"]'),
('255eefcf-94a3-4889-a717-6500daba94f1','竹院','釋居簡','宋','宋诗','song-poetry','','[]','種得碧參差，開門綠打圍。',48,'全唐诗/poet.song.180000.json','["種得碧參差，開門綠打圍。", "金鋪寧免碎，玉瘦不禁肥。", "雨過風梢重，晴初露葉晞。", "弗須關月戶，我欲款烟霏。"]'),
('7ea5434b-5b1a-4ab1-a705-4b169b65cc70','題粲書記作雙鴝鵒並宿梅花上','釋居簡','宋','宋诗','song-poetry','','[]','金線單絃餘睡思，黲茸亂羽欠春聲。',32,'全唐诗/poet.song.180000.json','["金線單絃餘睡思，黲茸亂羽欠春聲。", "立殘參子黄昏月，猶傍梅花瘦影明。"]'),
('572ce25f-dc66-4349-9ea8-8289d13df83c','林酒仙祠','釋居簡','宋','宋诗','song-poetry','','["\u592a\u6e56"]','百丈古規繩，蹉訛尺到尋。',48,'全唐诗/poet.song.180000.json','["百丈古規繩，蹉訛尺到尋。", "可曾知稼穡，多是少叢林。", "有蹟從人議，無心與俗沉。", "太湖吞弗盡，哆口到如今。"]'),
('0dbeec49-1bbf-4a3b-a354-be34f6ea3840','酬李如山見寄','釋居簡','宋','宋诗','song-poetry','','[]','俗棼須盡掃，掃盡又紛華。',48,'全唐诗/poet.song.180000.json','["俗棼須盡掃，掃盡又紛華。", "喧避蟻爭市，靜看蜂報衙。", "竹梢斑殞籜，蘋渚素浮花。", "自把閑消遣，從容日又斜。"]'),
('ed04a7cc-4104-42b5-b826-5e62719a7445','問訊陸秘讀','釋居簡','宋','宋诗','song-poetry','','[]','曾並籃輿上峭巍，先將鸞尾掃烟霏。',64,'全唐诗/poet.song.180000.json','["曾並籃輿上峭巍，先將鸞尾掃烟霏。", "步從歸鳥上頭去，雲在倚闌低處飛。", "古錦尚餘前日句，秋荷重製北山衣。", "蓬萊直與人間遠，猶得清苕訪采薇。"]'),
('e3062fe0-b6cd-49cc-84d9-2f7f0a134693','經筵賜茶楊文昌席上得貴字','釋居簡','宋','宋诗','song-poetry','','[]','龍泓薦春甘，茶荈絕衆卉。',144,'全唐诗/poet.song.180000.json','["龍泓薦春甘，茶荈絕衆卉。", "屑瓊作玄玉，不惜萬金費。", "厥貢來四方，特立建溪貴。", "諸儒方重席，飄飄凌雲氣。", "方圭與團璧，錫自一經既。", "得從稽古力，不敵稽古味。", "小苦政不惡，回甘亦差慰。", "雪漲忽翻乳，珠碎僅成璣。", "月團三百片，下下敢髣髴。", "宏功適胥稱，厚享可無謂。", "餘瀝逮蔬筍，疏瀹固所畏。", "悠然記新分，嘉定次癸未。"]'),
('23069b87-9498-4381-b585-b15601de63fb','楊文昌得古方壺於巴子國','釋居簡','宋','宋诗','song-poetry','','[]','大巧出天姿，何年幻怪奇。',48,'全唐诗/poet.song.180000.json','["大巧出天姿，何年幻怪奇。", "身輕成俗蛻，調古弗時宜。", "方外雖圭角，宏中填側欹。", "同盟今幾輩，郜鼎與宗彝。"]'),
('753a976e-8471-4c7e-a8b2-935b1afb9753','書薛符谿詩卷','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三峩孕元氣，直與喬嶽侔。',264,'全唐诗/poet.song.180000.json','["三峩孕元氣，直與喬嶽侔。", "因依幾何年，藴藉六十州。", "芃芃擢楩楠，碌碌生琳璆。", "潢污化清泠，仄陋發炳彪。", "岩岩鍾人才，出輒第一流。", "或爲德淵藪，或擅文雄酋。", "或赴功名期，或於名節收。", "嶄然薛符溪，餘地出一頭。", "高寒蓬婆雪，翠掃山月秋。", "黑頭當策勳，青綬曷足酬。", "得年雖不多，得名端不浮。", "遺墨見絕少，六丁方隠搜。", "曩聞桃花爲，强悍繄公柔。", "篇什富襲藏，零殘皆萃裒。", "牛腰幾卷軸，棘心懷松楸。", "心聲出誠素，瑶肪謝雕鎪。", "往年詩寄爲，趣爲買歸舟。", "爲無一簪直，自衒富寡儔。", "倒橐僅如此，貧祟何時瘳。", "昨從西子湖，來訪蘋花洲。", "請續梁甫聲，使貽齊大羞。", "惆悵貂不足，非類何足求。"]'),
('37d136b9-44f2-4b01-8223-ddcd61ed79c4','盆竹','釋居簡','宋','宋诗','song-poetry','','[]','老瓦新淇奧，清風小渭川。',48,'全唐诗/poet.song.180000.json','["老瓦新淇奧，清風小渭川。", "有孫皆抱節，無地可行鞭。", "不肉甘吾瘦，敲扉僦榻眠。", "多君不受暑，移傍枕帷邊。"]'),
('fdc885ee-bb87-4201-9930-2846c2ae45fb','石上叢竹','釋居簡','宋','宋诗','song-poetry','','[]','斗石森微幹，杯泓託茂林。',48,'全唐诗/poet.song.180000.json','["斗石森微幹，杯泓託茂林。", "不多猶絕俗，雖小亦虛心。", "風噎纖纖玉，蟾低瑣瑣金。", "胸中渺千畝，尺許對曾陰。"]'),
('1d4bc327-3f5e-4586-b447-20f98c7c7178','明遠即事','釋居簡','宋','宋诗','song-poetry','','[]','紅褪金罌子，芳騰金橘花。',48,'全唐诗/poet.song.180000.json','["紅褪金罌子，芳騰金橘花。", "物情閑態度，秋色澹韶華。", "燕老遲歸思，蜂慵早退衙。", "關心最幽事，輻湊在山家。"]'),
('8dab32ec-33b0-44e9-931e-92577893e94e','次李東遷寄婁雲西兩詩韻  其一','釋居簡','宋','宋诗','song-poetry','','[]','遠明雙白倦揩摩，鏡裏星星綠變皤。',64,'全唐诗/poet.song.180000.json','["遠明雙白倦揩摩，鏡裏星星綠變皤。", "凝不飛雲疑有蔕，潤潛分井信無波。", "鶴安屢空都忘去，鼠笑長貧絕見過。", "宛轉門前聽歌鳥，倚風疎柳正婆娑。"]'),
('a87a32c1-d4e2-4e82-b93d-61933676e081','次李東遷寄婁雲西兩詩韻  其二','釋居簡','宋','宋诗','song-poetry','','[]','綠漲菱荷一半空，殘零小隊試吳宮。',64,'全唐诗/poet.song.180000.json','["綠漲菱荷一半空，殘零小隊試吳宮。", "斷虹暝卷千峯雨，方塔凉吹四面風。", "遥夜河源和月曉，近秋溪影與天同。", "山林橫槊非長算，猶欲前驅挑兩翁。"]'),
('19d13ed2-5cb4-4497-ae17-4ba80e744a03','送姜貧樂赴陳華亭約  其一','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','僦屋傍西湖，湖光浸屋除。',48,'全唐诗/poet.song.180000.json','["僦屋傍西湖，湖光浸屋除。", "秋荷紉雨後，鄰米餉齋餘。", "句熟如圜轉，謀生似我疎。", "拙吟方巧宦，騷雅費甾畬。"]'),
('2aa22c0c-695e-4696-92e8-ba56f29abf46','送姜貧樂赴陳華亭約  其二','釋居簡','宋','宋诗','song-poetry','','[]','見說華亭政，平夷似太丘。',48,'全唐诗/poet.song.180000.json','["見說華亭政，平夷似太丘。", "適時寬勝猛，幾月很成柔。", "袖刺方徂歲，敲弦倏借秋。", "尺書頻寄意，君豈致書郵。"]'),
('a8967d68-96c1-4fff-b51c-36e74c50b6c8','次超果寺見遠亭韻','釋居簡','宋','宋诗','song-poetry','','[]','寺古巧經營，橫飛水上亭。',48,'全唐诗/poet.song.180000.json','["寺古巧經營，橫飛水上亭。", "港分秋練練，雲合暮青青。", "暝樹雨收畫，殘沙晴射星。", "苹蕪舒晚眺，障日恨山屏。"]'),
('c3df7da8-62b3-4616-bcab-6e9e1d41c6bf','立秋','釋居簡','宋','宋诗','song-poetry','','[]','清苕早試秋，便作練光浮。',48,'全唐诗/poet.song.180000.json','["清苕早試秋，便作練光浮。", "雨褪荷花瘦，風生蓼葉愁。", "一聲離岸櫓，幾箇入城舟。", "惆悵田鳥響，關心卒歲憂。"]'),
('02b722a6-623f-416a-be4d-b065d638c01d','六月廿九神林寺池上荷花','釋居簡','宋','宋诗','song-poetry','','[]','凉沼承芳薰，急雨壓炎暑。',120,'全唐诗/poet.song.180000.json','["凉沼承芳薰，急雨壓炎暑。", "葉葉蚌觸碎，頃刻萬斛許。", "痕玉臉能薄，著得許多雨。", "駢頭如有愬，低簪欲相語。", "摧拉翡翠翼，零亂鴛鴦羽。", "賸擬牋老天，細意冩心膂。", "約束誅雲師，前驅卷晴宇。", "紅酣盡扶起，綠摇並搴舉。", "蘋末風亦好，人間暍隨愈。", "太一泠然舟，著我歌白苧。"]'),
('cc0f60e7-11b5-43f8-8c4c-6e83c04446ee','懷歸四首  其一','釋居簡','宋','宋诗','song-poetry','','[]','姓名何必上傳燈，破釜難諧大呂聲。',64,'全唐诗/poet.song.180000.json','["姓名何必上傳燈，破釜難諧大呂聲。", "信脚半生惟舌在，策勳九轉到丹成。", "强知晴雨憐鳩拙，擬葺茆茨似燕營。", "見說千金曾賣賦，不堪容易賦閑情。"]'),
('e2a8f680-26a3-41b8-83ec-fbc4ea41f8b2','懷歸四首  其二','釋居簡','宋','宋诗','song-poetry','','[]','富貴還鄉頗稱懷，謂之晝錦亦宜哉。',64,'全唐诗/poet.song.180000.json','["富貴還鄉頗稱懷，謂之晝錦亦宜哉。", "過家曾說分符去，持節旋聞諭蜀來。", "皎皎月規前夜缺，悠悠淵水有時回。", "車輪未必都生角，只合橫推不竪推。"]'),
('0697787c-44c0-40ce-95b2-2756ce9b04ac','懷歸四首  其三','釋居簡','宋','宋诗','song-poetry','','[]','可能無地著蒲團，自把行藏一破顔。',64,'全唐诗/poet.song.180000.json','["可能無地著蒲團，自把行藏一破顔。", "試問飛來華表柱，何如生入玉門關。", "角纔扣罷尋煙棹，馿倒騎歸看華山。", "處士故廬霜月古，欲將全璧伴東還。"]'),
('89f96984-faf3-46d4-b0b5-938dca9b2469','懷歸四首  其四','釋居簡','宋','宋诗','song-poetry','','[]','何須騎鶴與腰纏，欲傍家山問一廛。',64,'全唐诗/poet.song.180000.json','["何須騎鶴與腰纏，欲傍家山問一廛。", "任是五經俱掃地，可容四海欠彌天。", "白砂自養真鉛汞，玄草重紉斷簡編。", "更絇梅花窗外樹，曲肱聽雨聽風眠。"]'),
('8d90ce73-ad7e-446e-ba15-8c429bf21af1','淀山三姑新錫廟額曰會靈仍爲作記','釋居簡','宋','宋诗','song-poetry','','[]','有德難藏用，惟功易及民。',120,'全唐诗/poet.song.180000.json','["有德難藏用，惟功易及民。", "封嘉從巨宋，寵賁逮先秦。", "鼎足分靈躅，波心據要津。", "水連天共遠，湖與泖爲隣。", "盛事千年閟，幽光一日伸。", "典刑開祀事，季孟舊彝倫。", "天上絲綸美，山中雨露新。", "嫩凉生暑晝，老火變陽春。", "肸蠁先群望，豐凶在一身。", "不知閑草木，何事亦精神。"]'),
('20dee7dd-2ad2-4139-9496-6adcec0b3dbb','艤篷','釋居簡','宋','宋诗','song-poetry','','[]','幻得江天小，陰晴便合宜。',48,'全唐诗/poet.song.180000.json','["幻得江天小，陰晴便合宜。", "未將紅蓼種，先報白鷗知。", "貼水雲千點，闚簷月半規。", "歸僧敲竹戶，只作扣舷疑。"]'),
('6b405af5-b6f2-4105-90c9-21228bf7a3d7','酬嘉興別駕謝司直','釋居簡','宋','宋诗','song-poetry','','["\u592a\u6e56"]','攙春藝蘭茝，采采山之阿。',120,'全唐诗/poet.song.180000.json','["攙春藝蘭茝，采采山之阿。", "雪砌拓餘地，華風日編摩。", "芳潔漸可冀，榛莽常婆娑。", "紫牙茁新馥，薰蕕相錯磨。", "引類聯根株，圖蔓費斧柯。", "何補種殖勤，苦心忘鬢皤。", "九畹與百畮，恨少不恨多。", "薿薿廣庭玉，比德元同科。", "餘光燭槜李，散彩摇清波。", "太湖跨三州，如此明月何。"]'),
('65ddd50c-44eb-464c-bb6b-7429b980774c','蓬居梵竺卿詩藁','釋居簡','宋','宋诗','song-poetry','','[]','維舟吊竺卿，寒日暗丹青。',48,'全唐诗/poet.song.180000.json','["維舟吊竺卿，寒日暗丹青。", "俗惡眼中屑，離騷身後經。", "畦芳催蜜熟，圃藥試方靈。", "零落三千偈，關防在六丁。"]'),
('80d4c80f-a49b-4e84-8c66-376b0ee28c27','次韻惠寺丞見寄','釋居簡','宋','宋诗','song-poetry','','[]','雁塔名題久不知，新吟忽遣好風吹。',64,'全唐诗/poet.song.180000.json','["雁塔名題久不知，新吟忽遣好風吹。", "易推未畫本無畫，計已出奇何有奇。", "孔雀屏開金錯落，蟾蜍玉冷墨淋漓。", "故家舊有傳衣句，跨竈衝樓足尉思。"]'),
('bdd0235e-e94f-49e0-be6e-1dcba9332df1','大雅堂','釋居簡','宋','宋诗','song-poetry','','[]','少陵何人斯，曰似司馬遷。',240,'全唐诗/poet.song.180000.json','["少陵何人斯，曰似司馬遷。", "太史牛馬走，於此何有焉。", "瞢者瞢不理，知言超言前。", "政如春在花，春豈必醜妍。", "又如發清彈，意豈必在絃。", "悠悠雲出山，滔滔水行川。", "雲水山川行，莫測何能然。", "不知其誰知，軟語黄庭堅。", "庭堅語弗軟，壯折灧澦顛。", "盡冩劍硤詩，不數金薤篇。", "密付草玄後，夜光寒燭天。", "扁作大雅堂，醉墨猶明鮮。", "至今百歲後，此意惟心傳。", "炎宋諸王孫，傳癖不復痊。", "閉戶閲宗派，尚友清社賢。", "呂韓儼前列，芳蠟然金蓮。", "三洪偕二謝，病可携瘦權。", "奪胎換骨法，妙處尤拳拳。", "疏越正始音，細取麟角煎。", "亦有老斲輪，堂下時蹁躚。"]'),
('25d76cc4-70ef-459f-82d5-b3a3949eaa31','槎浦南翔寺','釋居簡','宋','宋诗','song-poetry','','[]','荒破齊梁地，宏開釋梵家。',48,'全唐诗/poet.song.180000.json','["荒破齊梁地，宏開釋梵家。", "令威新化鶴，博望舊停槎。", "風嫋經幢石，芳騰品觀花。", "同聲六萬字，羊鹿換牛車。"]'),
('89be91ec-2fbc-4360-9ebd-9cb310c6d117','南翔九品觀','釋居簡','宋','宋诗','song-poetry','','[]','清泰重開國，芬陁便滿池。',48,'全唐诗/poet.song.180000.json','["清泰重開國，芬陁便滿池。", "高風追晉社，餘地拓蕭規。", "玉甃承丹堊，璇題漾碧漪。", "西之真捷徑，舍此復何之。"]'),
('b7301b95-3e23-437e-a5b6-1f3a314d4241','華亭孫丞迎侍道州使君','釋居簡','宋','宋诗','song-poetry','','[]','老人端似老人星，五馬精明舊典刑。',64,'全唐诗/poet.song.180000.json','["老人端似老人星，五馬精明舊典刑。", "故事新看廳壁記，華堂舊有德威銘。", "數州棠樹應垂地，四世萊衣又過庭。", "騷雅故家仍大手，可無清警賦華亭。"]'),
('6616ea7a-471e-42f5-a8e5-cca7bf80f610','八月廿七風雨大浸','釋居簡','宋','宋诗','song-poetry','','[]','左扼飛廉吭，右拊巽二背。',168,'全唐诗/poet.song.180000.json','["左扼飛廉吭，右拊巽二背。", "謂云如何其，坐使六鷁退。", "亦有司雨工，馽如繫單于。", "不卷油然雲，自欲干剪屠。", "鄉來不鳴條，塊亦不曾破。", "卿雲千點明，華月半天墮。", "衮衣徂東山，拔木仍偃禾。", "至今東山詩，千載猶詠歌。", "悠然啟金縢，風反雨亦止。", "是中果何書，頃刻變天紀。", "流言久弗作，狐亦不復疑。", "至誠動真宰，風雨胡不知。", "風雨不我以，我稼已墮水。", "不知十日淫，滴碎田父心。"]'),
('0fec01a4-d03e-43c7-bbbd-00c0716603bd','秋潦歎','釋居簡','宋','宋诗','song-poetry','','[]','疾雷振秋杪，急雨動旬浹。',120,'全唐诗/poet.song.180000.json','["疾雷振秋杪，急雨動旬浹。", "風中三重茅，露卧且病涉。", "四郊漫漫空湧波，田叟田嫗鵜在河。", "陣頭雨過陣頭起，濕稼不多潢潦多。", "風雨聲中哭聲苦，泪眼不晴多似雨。", "不憂饑殍更流移，憂欠今年縣官賦。", "縣官勤儉知歲饑，定有德音來撫綏。", "老姦黠胥能巧詆，莫將白紙欺黄紙。"]'),
('88bfd73c-9919-452a-806f-81465f1c5c0e','八月大風大水  其一','釋居簡','宋','宋诗','song-poetry','','[]','十日溪頭鷁退飛，相逢那暇問雄雌。',32,'全唐诗/poet.song.180000.json','["十日溪頭鷁退飛，相逢那暇問雄雌。", "不如二月春風好，草木無情亦去思。"]'),
('5682e91d-5f28-4e13-9039-72cb404f8aa2','八月大風大水  其二','釋居簡','宋','宋诗','song-poetry','','[]','零落茅茨水半扉，媼顰翁蹙小兒啼。',32,'全唐诗/poet.song.180000.json','["零落茅茨水半扉，媼顰翁蹙小兒啼。", "老雞不管豐凶事，獨自將雛樹上棲。"]'),
('549db13e-fc31-4edf-a6a5-230a5bf8611b','贈丁相士','釋居簡','宋','宋诗','song-poetry','','[]','張雪湖家苜蓿盤，坐中著眼恐應難。',64,'全唐诗/poet.song.180000.json','["張雪湖家苜蓿盤，坐中著眼恐應難。", "似華表鶴仍同姓，與華山人不兩般。", "客舍須尋佳處住，熱官多是冷時觀。", "却須索我形骸外，莫作三支一等看。"]'),
('0253dd43-7cd3-4d6c-9172-8d53083997c0','余尸巾山苦誅求而去缽無舂糧寓公范公偉質衣以贐西笑曰亂邦不居行矣','釋居簡','宋','宋诗','song-poetry','','[]','廉士難於俗吏并，質衣猶及送僧行。',64,'全唐诗/poet.song.180000.json','["廉士難於俗吏并，質衣猶及送僧行。", "惠惟適用偏多感，施及無求益見情。", "弱羽敢辭三足妬，伏雌常與九包爭。", "故家逸韻難諧俗，共作台州一段清。"]'),
('bb80b0ea-2322-4f71-8d89-724e76df45e8','赤城六章章四句  其一','釋居簡','宋','宋诗','song-poetry','','[]','赤城峩峩，霞摽錯摩。',20,'全唐诗/poet.song.180000.json','["赤城峩峩，霞摽錯摩。", "篤生斯人，絕超凡科。"]'),
('e43b81f3-2941-45d9-8917-1c0d1382105c','赤城六章章四句  其二','釋居簡','宋','宋诗','song-poetry','','[]','峩峩赤城，磅礴九地。',20,'全唐诗/poet.song.180000.json','["峩峩赤城，磅礴九地。", "斯人篤生，水瘦石悴。"]'),
('82ff333a-aa44-4540-8586-cba56b6c8573','赤城六章章四句  其三','釋居簡','宋','宋诗','song-poetry','','[]','念昔三輔，湖獨紛委。',20,'全唐诗/poet.song.180000.json','["念昔三輔，湖獨紛委。", "逮公來斯，苕霅涇渭。"]'),
('f4e83063-4fd8-4a1b-a613-b3ee8e405a6f','赤城六章章四句  其四','釋居簡','宋','宋诗','song-poetry','','[]','千里壽公，禱公壽康。',20,'全唐诗/poet.song.180000.json','["千里壽公，禱公壽康。", "惠洽兆庶，日飛百觴。"]'),
('81093b71-f19a-42c8-a5ca-24f0087ed961','赤城六章章四句  其五','釋居簡','宋','宋诗','song-poetry','','[]','伊我無酒，注彼觩兕。',20,'全唐诗/poet.song.180000.json','["伊我無酒，注彼觩兕。", "願公華衮，式昌厥嗣。"]'),
('4e51f298-91dd-4668-8e1e-0c91bc336244','赤城六章章四句  其六','釋居簡','宋','宋诗','song-poetry','','[]','亦復願公，嘯吟紫微。',20,'全唐诗/poet.song.180000.json','["亦復願公，嘯吟紫微。", "㑭我紫微，嬉其莞而。"]'),
('6e5ea43d-4bda-4e2a-9afe-96170eabbeb4','酬竹岩賦行春橋翁媼摘白','釋居簡','宋','宋诗','song-poetry','','[]','恨霜點鬢諱言霜，誰敢從翁話鬢蒼。',64,'全唐诗/poet.song.180000.json','["恨霜點鬢諱言霜，誰敢從翁話鬢蒼。", "每見丹林楓剪剪，只云青女陳堂堂。", "所餘不足供彈鑷，既往徒嗟易斷腸。", "惆悵行春橋下水，無朝無暮只滄浪。"]'),
('0164cf03-b211-4ca2-9ee8-d20847c7490f','西菩中暉堂乃參寥辨才所居','釋居簡','宋','宋诗','song-poetry','','[]','門外青山自作雙，簷前松韻瀉秋江。',64,'全唐诗/poet.song.180000.json','["門外青山自作雙，簷前松韻瀉秋江。", "半規皎皎暾重霧，一點晶晶洞八窗。", "用晦不曾欺暗室，鑿隣何必借殘釭。", "儉存元祐規模小，曾著光明兩勝幢。"]'),
('3dfcac7a-b652-4da7-95cf-2941665f8396','吊楊尚書哭子未幾復鼓盆','釋居簡','宋','宋诗','song-poetry','','[]','壽域富萬彙，楚楚惟靈椿。',120,'全唐诗/poet.song.180000.json','["壽域富萬彙，楚楚惟靈椿。", "彭固不可儕，聃亦虞遘迍。", "天高杳難問，請以意自陳。", "大年豈知止，小知寧無贏。", "况夫朝有聞，幻變可得嬰。", "君家老孟光，及與膝上英。", "洞窺天地先，一視蜾與蛉。", "居然因其小，其餘贊經綸。", "青青脩梧枝，尚有五色翎。", "相參星辰履，共爲黄河清。"]'),
('3431df04-9ed4-4a08-a982-885cd4133a9d','送楊文昌帥瀘南','釋居簡','宋','宋诗','song-poetry','','[]','鄉心動如翼，勇去挽不還。',120,'全唐诗/poet.song.180000.json','["鄉心動如翼，勇去挽不還。", "長年卷百丈，疾飛三峽船。", "東西跬步間，勳業唾手耳。", "貂蟬出兜鍪，了不二初志。", "瀘川控井絡，衿喉翰西徼。", "貔貅擁玉帳，萬竈聽吟嘯。", "蜀相入不毛，赤地方流金。", "至今龍門江，透底如此心。", "公乎同此心，印水復印天。", "我恐席未煖，又下瞿塘船。"]'),
('bcf60b00-66d2-4183-bf2d-dde9d4a8cb18','題沖老廉博士古木','釋居簡','宋','宋诗','song-poetry','','[]','離奇磊砢廉宣妙，幻出川僧屋角頭。',32,'全唐诗/poet.song.180000.json','["離奇磊砢廉宣妙，幻出川僧屋角頭。", "風雨夜遥龍不寐，聽他天籟自颼飀。"]'),
('1b6c5cdb-4a89-4fc7-9f2f-4ee6e57f5463','次韻吳主簿初度供佛','釋居簡','宋','宋诗','song-poetry','','[]','未愜響朝陽，卑棲枳棘傍。',48,'全唐诗/poet.song.180000.json','["未愜響朝陽，卑棲枳棘傍。", "剛柔非吐茹，衰弱倚清强。", "避酒來蕭寺，思親拜渭陽。", "平生番襪法，背俗細平章。"]'),
('6024111d-b032-4b43-a011-ea61270b5fdb','山居次盧玉堂見寄','釋居簡','宋','宋诗','song-poetry','','[]','旋十村墟舊縛茅，夜深雲唄薄江郊。',64,'全唐诗/poet.song.180000.json','["旋十村墟舊縛茅，夜深雲唄薄江郊。", "更無可借文書處，只好相尋野逸交。", "落葉自隨流水去，閑門盡倒破囊抄。", "故人遞迭青雲去，誰與山人賦解嘲。"]'),
('84cf481d-471f-4826-8be3-7b23cc105a81','寄秋塘陳敬甫','釋居簡','宋','宋诗','song-poetry','','[]','華風豈不聲，默與靜者吹。',156,'全唐诗/poet.song.180000.json','["華風豈不聲，默與靜者吹。", "凉月自入袖，默許靜者知。", "風乎豈必爾，月亦聽所之。", "靜者亦若是，弗與俗子期。", "俗方日日浮，靜豈忍詭隨。", "山林隘乾坤，小大各有宜。", "思君令人老，一見動歲時。", "下塘通上塘，一葦何遠而。", "疇曩北山日，皂蓋松間飛。", "澄潜二三子，喜迓見睫眉。", "著翁泉上亭，泉石訝久違。", "透閘觀濤瀾，雪濺冰玉澌。", "激翁技癢處，洶湧翻文辭。"]'),
('187cbce9-6eba-4d18-bcd9-adf25182b18e','墨荔支','釋居簡','宋','宋诗','song-poetry','','[]','老坡曾比江瑶柱，或謂江瑶柱不如。',32,'全唐诗/poet.song.180000.json','["老坡曾比江瑶柱，或謂江瑶柱不如。", "擬寫釵頭皺紅小，斷魂蠻雨瘴煙疎。"]'),
('dde7fd2f-b11b-47d7-b71c-8dcca7446e12','道場山兩題  其一','釋居簡','宋','宋诗','song-poetry','','[]','鑿地潴寒碧，泠泠湛弗摇。',48,'全唐诗/poet.song.180000.json','["鑿地潴寒碧，泠泠湛弗摇。", "方奩開素鏡，闊幅剪生綃。", "甃古天爲底，杯深雪漲潮。", "俗交濃若醴，一滴也難消。"]'),
('4c26ece5-9c9f-4f4c-a354-d22ad7a07187','道場山兩題  其二','釋居簡','宋','宋诗','song-poetry','','[]','岩隙带痕雲，涓涓不受塵。',48,'全唐诗/poet.song.180000.json','["岩隙带痕雲，涓涓不受塵。", "漥尊元自淺，欹器不須盈。", "鏡徹雙明碧，花浮少許春。", "漢宮分燭後，新潔試清清。"]'),
('ad6b7b2b-b8dd-46e6-968d-1642d0921f92','送顧哦松柬祁門尉  其一','釋居簡','宋','宋诗','song-poetry','','[]','角轉城頭曉，風回麥脚斜。',48,'全唐诗/poet.song.180000.json','["角轉城頭曉，風回麥脚斜。", "清明都冷落，陰翳趲韶華。", "飯了長亭黍，來分野寺茶。", "到家三月暮，恰好送鶑花。"]'),
('9c383747-dc4c-4ad1-b4fc-462fdb95fe5d','送顧哦松柬祁門尉  其二','釋居簡','宋','宋诗','song-poetry','','[]','已矣吳門市，祁門問阿連。',48,'全唐诗/poet.song.180000.json','["已矣吳門市，祁門問阿連。", "有書聊話舊，無累不須仙。", "蜀叟思長計，苕溪縛數椽。", "不知雙璧外，誰與辦腰纏。"]'),
('bd3fb18b-5b24-4bf3-88b2-464c9a91cae9','丹霞張府博入夏蔬食','釋居簡','宋','宋诗','song-poetry','','[]','不爲長齋綉佛前，欲酬芳瀣伴風蟬。',64,'全唐诗/poet.song.180000.json','["不爲長齋綉佛前，欲酬芳瀣伴風蟬。", "川奔直恐頹難障，灰死何曾溺不然。", "冷帳弗生騎鶴夢，清才合友跨鯨仙。", "幾時卜築紅泉上，只尺丹霞小有天。"]'),
('14630f2d-d247-4328-b9f0-74e82526d35d','代宣石橋謝兩淛部使者','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','丙寅端午前三日，南宕西湖酒一巵。',64,'全唐诗/poet.song.180000.json','["丙寅端午前三日，南宕西湖酒一巵。", "趁此昌蒲新釀熟，看君棠棣燕歌遲。", "春風玉筍分班處，夜雨金閨對榻時。", "蛙在秋池分部曲，小須叔季奏塤箎。"]'),
('a79cebbf-5c93-48c3-9df5-477834667259','張萱作妃子夜游圖子由謂之秦虢並驅爭先圖文潞公司馬公東坡兄弟一時名勝洎宣和宸翰在焉藏諸御府後歸紹興權倖家復爲開禧權倖所有更化後景獻仲兄得之','釋居簡','宋','宋诗','song-poetry','','[]','孰揮若木枝，日馭不可勒。',184,'全唐诗/poet.song.180000.json','["孰揮若木枝，日馭不可勒。", "志士分寸惜，長繩繫不得。", "忽觀此圖使我傷，使我痛憤嗟三郎。", "三郎飛入月中去，回首不知宮漏長。", "金羈金勒控紫韁，玉花玉面下采床。", "天階夜色浄如洗，宮彎促𩍐相抵當。", "十家三國歸模冩，不冩漁陽閙胡馬。", "較來不畫亦不妨，冏冏莫掩張曲江。", "宣和宸奎獨爛爛，元祐名卿題得滿。", "既歸天上誇襲藏，又落人間作奇玩。", "沉思惡衣菲飲食，過門不子呱呱泣。", "張萱已矣倘可呼，爲我只作塗山圖。"]'),
('4a0dc543-d7c8-436c-87a5-1798e9722768','武侯廟','釋居簡','宋','宋诗','song-poetry','','[]','黑柏森森舊息陰，錦官城北到如今。',64,'全唐诗/poet.song.180000.json','["黑柏森森舊息陰，錦官城北到如今。", "雖生仲達猶難料，更十曹丕豈易禁。", "曾過南陽尋故俗，偶思梁甫擬高吟。", "外江三硤霜蟾老，蚤識先生遡硤心。"]'),
('a4ddd5d3-bef5-4e1f-ab91-30514a078d8f','林君筦榷上巴河蘄黄亂離僅以身免','釋居簡','宋','宋诗','song-poetry','','[]','話到蘄黄只永歎，不知心作食梅酸。',64,'全唐诗/poet.song.180000.json','["話到蘄黄只永歎，不知心作食梅酸。", "斷頭自是無降將，嚙指終能媿賀蘭。", "變弗知權生亦媿，動纔適義死何難。", "多君逆旅觀浮俗，尸素墦間一等看。"]'),
('6ddb6dec-936c-49fa-9b6d-cac76fdd67f5','送任大卿出知漢州','釋居簡','宋','宋诗','song-poetry','','[]','就列行初志，專城亦此心。',144,'全唐诗/poet.song.180000.json','["就列行初志，專城亦此心。", "玉蟾卿月滿，金雁景星臨。", "知舊玄裳鶴，從游綠綺琴。", "歌風琴在御，夢草鶴同吟。", "梁甫誰同調，高山自賞音。", "往來三硤險，森布萬靈欽。", "信是婁師德，慙非釋道林。", "華風一披拂，小草竟蕭森。", "不賦空懷土，無枝勇惜陰。", "房湖開綠幕，祇樹砌黄金。", "駟馬雖難駐，雙旌倘可尋。", "逍遥堂舊話，領話望公深。"]'),
('7c5471e7-e0ec-4310-b4ec-5b3452423185','種桑','釋居簡','宋','宋诗','song-poetry','','[]','無衣可柰何，桑樹百餘窠。',48,'全唐诗/poet.song.180000.json','["無衣可柰何，桑樹百餘窠。", "拙計不及此，瘠田誰種它。", "綠荷供楚製，白苧入吳歌。", "金谷雖佳麗，知誰所得多。"]'),
('9669f3e0-d068-40dc-94a8-f2126196a5ba','摘茶','釋居簡','宋','宋诗','song-poetry','','[]','苦莫苦於荼，回甘薺不如。',48,'全唐诗/poet.song.180000.json','["苦莫苦於荼，回甘薺不如。", "瘠叢嗔重歛，睡眼喜豐儲。", "未雨試芳潔，殘春空緒餘。", "丁寧加惠養，竭澤恐無魚。"]'),
('40df60ec-12db-4769-af7a-b3d2582daed7','贈御前梁宮幹','釋居簡','宋','宋诗','song-poetry','','[]','梁楷惜墨如惜金，醉來亦復成漓淋。',144,'全唐诗/poet.song.180000.json','["梁楷惜墨如惜金，醉來亦復成漓淋。", "天籟自響或自瘖，族史閣筆空沉吟。", "前日去尋子趙子，道院水亭秋色裏。", "幻成趙子騎蹇馿，瀟洒不減騎鯨魚。", "又冩深衣跨牛客，雲生谷口耕阡陌。", "按圖絕叫喜欲飛，棹筆授我使我題。", "我方拄眼孤山西，岑樓殘碧澹掃眉。", "見成一段詩中畫，宜雨宜晴四時挂。", "輸與滕王蛺蝶圖，坐收少室山人賈。"]'),
('5b6246ae-254c-48aa-9b4f-91287d911a25','元日送客歸西湖','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','采筆春消御柳邊，櫂歌忽聽采菱船。',32,'全唐诗/poet.song.180000.json','["采筆春消御柳邊，櫂歌忽聽采菱船。", "三賢見說遷居了，只寄梅花問水仙。"]'),
('7afa1e08-0f05-4abb-90b1-56357c6d54d7','題扇暍圖','釋居簡','宋','宋诗','song-poetry','','[]','忠厚文傳武，吾寧未釋疑。',48,'全唐诗/poet.song.180000.json','["忠厚文傳武，吾寧未釋疑。", "能扇行路暍，不療采薇饑。", "酷在炎炎處，凉生習習時。", "白團替黄鉞，宜畫不宜詩。"]'),
('e0d95bbd-c51f-4886-a9b5-d708dac7c02d','琉璃燈中魚子','釋居簡','宋','宋诗','song-poetry','','[]','玄珠透水明，玉鱲弄晶晶。',48,'全唐诗/poet.song.180000.json','["玄珠透水明，玉鱲弄晶晶。", "躍礙冰痕薄，潜疑月色新。", "器宏斯可樂，水淺易持盈。", "歸趁燒燈後，蘋洲拍拍春。"]'),
('494e5612-19dd-4e69-8b5f-6563d9ba6692','風琴贈選上人','釋居簡','宋','宋诗','song-poetry','','[]','萬籟甫消聲，鏘然忽自鳴。',48,'全唐诗/poet.song.180000.json','["萬籟甫消聲，鏘然忽自鳴。", "獨宜風力小，雙與月華清。", "歷歷諧三疊，玲玲叶九成。", "宮商雖斷續，何處不分明。"]'),
('ba921ff9-1d88-43e6-92ed-38426ee02fb9','寄宣城使君陳中書兼簡謝別駕林叔恭  其一','釋居簡','宋','宋诗','song-poetry','','[]','森戟凝香賦夜嚴，酲開玉色判厭厭。',64,'全唐诗/poet.song.180000.json','["森戟凝香賦夜嚴，酲開玉色判厭厭。", "荼雖小苦還如薺，梅抑微酸必俟鹽。", "壽富拓成千里域，光榮飛上一規蟾。", "道樞却在環中轉，賸馥殘膏亦溉沾。"]'),
('57b6ce26-fc73-4974-93df-7ca76cf0df27','寄宣城使君陳中書兼簡謝別駕林叔恭  其二','釋居簡','宋','宋诗','song-poetry','','[]','樂讎稽古暫專城，孰愈金蓮夜直頻。',64,'全唐诗/poet.song.180000.json','["樂讎稽古暫專城，孰愈金蓮夜直頻。", "風月平分與宏放，江山多助到清新。", "鄉來素練江猶浄，近日芳池草又春。", "想見尊前酬別乘，武夷山下付衣人。"]'),
('4a85ca41-196a-4437-80d8-17fa8d7f279a','吊志老宿','釋居簡','宋','宋诗','song-poetry','','[]','浮休不足籌，遺恨黯難收。',48,'全唐诗/poet.song.180000.json','["浮休不足籌，遺恨黯難收。", "死草起新馥，落梅添古愁。", "一龕遲日月，百歲老春秋。", "獨有舊名氏，不隨溪水流。"]'),
('34bc2f5e-99bf-49d4-b7a3-73a5a3eb4376','溪行','釋居簡','宋','宋诗','song-poetry','','[]','夭夭拍拍漲桃花，葑未全青荻已芽。',32,'全唐诗/poet.song.180000.json','["夭夭拍拍漲桃花，葑未全青荻已芽。", "兩行若無楊柳樹，看來無處著韶華。"]'),
('a3d6dcfb-0e56-4b26-9a31-b24db920c8e9','寄江東趙料院兼簡倉使','釋居簡','宋','宋诗','song-poetry','','[]','江遠天低月透沙，嚴城佳處艤仙槎。',64,'全唐诗/poet.song.180000.json','["江遠天低月透沙，嚴城佳處艤仙槎。", "明分象緯占群玉，巍峙岑樓仰九華。", "棋局旋收歸靜勝，吟疆寬拓戰淫哇。", "春回水驛分新句，更寄南枝一兩花。"]'),
('dcdce3f4-fc8c-4781-97db-9fa4730c2df0','謝葉文昌二首  其一','釋居簡','宋','宋诗','song-poetry','','[]','星履聲中識典刑，洗空浮俗快雙明。',64,'全唐诗/poet.song.180000.json','["星履聲中識典刑，洗空浮俗快雙明。", "四朝孰愈德耆艾，九鼎曷如身重輕。", "只作尋常高步武，安知咫尺是鈞衡。", "沖和一點關埏埴，噫欠春風六合生。"]'),
('00593def-9966-416f-99b2-530a75bdc3ff','謝葉文昌二首  其二','釋居簡','宋','宋诗','song-poetry','','[]','鏡裏津津喜上眉，人情瘦瘠遁心肥。',64,'全唐诗/poet.song.180000.json','["鏡裏津津喜上眉，人情瘦瘠遁心肥。", "環中小復事虛應，方外敢忘求實歸。", "客好潔羞南澗藻，家常草具北山薇。", "難消閑裏舒長日，脩綆何須絆落暉。"]'),
('71eb2770-7a4c-4615-adc7-583c89ff2483','杜侍郎坐上得彝字','釋居簡','宋','宋诗','song-poetry','','[]','春事三分二分了，策勳淑景還宜早。',128,'全唐诗/poet.song.180000.json','["春事三分二分了，策勳淑景還宜早。", "野桃官柳嫌春少，却笑上林鶑易老。", "豈知老榦空斗南，七八千歲春酣酣。", "無人聞此不大笑，有口只與莊生談。", "金鐘大鏞在東序，瑚璉陸離雜雕俎。", "歌工在列樂在懸，更復明堂須柱礎。", "一枝老我苕水湄，煮字不充亭午饑。", "丹崖蒼壁信手題，詠歌事業銘鼎彝。"]'),
('55c31c97-f4f3-4029-a20a-6a6a99383122','萼菴魏紫','釋居簡','宋','宋诗','song-poetry','','[]','華風織翠裾，紫綬更紛敷。',48,'全唐诗/poet.song.180000.json','["華風織翠裾，紫綬更紛敷。", "屑玉嫩成糝，縷金齊撚鬚。", "妖饒嗟易歇，落托醉難扶。", "舊日沈香北，傾都只此姝。"]'),
('586f9a73-a524-4c0a-ae37-13d8e53269b5','督錢肖岩教子','釋居簡','宋','宋诗','song-poetry','','[]','曾過竹巖幽，岩前正晚秋。',48,'全唐诗/poet.song.180000.json','["曾過竹巖幽，岩前正晚秋。", "養廉忘節苦，種德俟芽抽。", "橫翠新如染，澄瀾凝不流。", "丁寧庭砌玉，及早事雕鎪。"]'),
('91c9c826-96f0-4d07-ba49-24e9d07a4fc5','移斑竹','釋居簡','宋','宋诗','song-poetry','','[]','蒭堯撓歲寒，巍節笑多艱。',48,'全唐诗/poet.song.180000.json','["蒭堯撓歲寒，巍節笑多艱。", "露濕添新綠，苔封減舊斑。", "龍雛分竺寺，帝子泣湘山。", "無限蒼梧思，清風便往還。"]'),
('6176717d-ba05-4505-8515-93c22b2af038','酬謝司直晦齋寄宋湖州見柬  其一','釋居簡','宋','宋诗','song-poetry','','[]','春無十日好，又是去堂堂。',48,'全唐诗/poet.song.180000.json','["春無十日好，又是去堂堂。", "柳借鵞黄重，花消蝶粉香。", "清和宜晚步，零落課殘芳。", "北牖華風煖，朝來尚寵光。"]'),
('e57aa983-8548-4df7-9154-005d5483f41a','酬謝司直晦齋寄宋湖州見柬  其二','釋居簡','宋','宋诗','song-poetry','','[]','清苕春事早，三月已無花。',48,'全唐诗/poet.song.180000.json','["清苕春事早，三月已無花。", "歲澇塍猶缺，田低水再車。", "遠懷難盡寄，近况却全佳。", "也似雲臺吏，生涯未有涯。"]'),
('1120838c-8152-45fb-ab2c-bcf26e81f746','鳳鳴寺十八應真乃日本國所製密印僧典於沈氏沈施於鳳鳴','釋居簡','宋','宋诗','song-poetry','','[]','木素上金泥，雲衣整稻畦。',48,'全唐诗/poet.song.180000.json','["木素上金泥，雲衣整稻畦。", "曾充僧典質，未到佛階梯。", "領衆三韓北，分身兩淛西。", "一龕老風雨，誰與振幽棲。"]'),
('dcedb295-bfd2-4ca1-ae1e-7ca344759bae','酬季敬父清明見寄','釋居簡','宋','宋诗','song-poetry','','[]','半雨陰陰復半晴，芳郊紫徑厭塵輕。',64,'全唐诗/poet.song.180000.json','["半雨陰陰復半晴，芳郊紫徑厭塵輕。", "飛花逐旋將春去，續綆尋思繫日傾。", "夢苦流鶑呼得覺，愁嫌啼鴂喚教生。", "頻搔短髮臨寒水，添了星星幾點明。"]'),
('d0056d9a-bd7d-4462-b9df-245a87319cc4','盧直院大監挽辭','釋居簡','宋','宋诗','song-poetry','','[]','客葬柰貧何，無山無薜蘿。',48,'全唐诗/poet.song.180000.json','["客葬柰貧何，無山無薜蘿。", "近分南宕小，遠勝北邙多。", "不與貂蟬老，空將琬琰磨。", "丁寧燕許手，遺事細蒐羅。"]'),
('975889ab-de3b-490b-8cbd-bbbc780f5410','送宋使君呈光祿','釋居簡','宋','宋诗','song-poetry','','[]','解紱宜新渥，催帆挂曉晴。',48,'全唐诗/poet.song.180000.json','["解紱宜新渥，催帆挂曉晴。", "宿陰消岸趾，初日動簾旌。", "班近尋鵷鷺，親怡燕弟兄。", "老人躔次近，同傍紫微明。"]'),
('45b035cc-4662-4fae-93a9-837df4038689','送林府教英發','釋居簡','宋','宋诗','song-poetry','','[]','元化鈞陶鑄，先生獨鑄顔。',48,'全唐诗/poet.song.180000.json','["元化鈞陶鑄，先生獨鑄顔。", "不祥麾躍冶，至藴剖藏山。", "幌冷雲垂地，名脩玉綴班。", "圜橋儼冠带，鵠立望公還。"]'),
('99e7ba4d-99da-4c33-811c-e7decc15d3d6','碧銜霞行','釋居簡','宋','宋诗','song-poetry','','[]','雙銜金勒明霞碧，暗花隠起雲如刺。',208,'全唐诗/poet.song.180000.json','["雙銜金勒明霞碧，暗花隠起雲如刺。", "霜零燕澗草根甜，長鳴振鬣飛無跡。", "一朝群空十二閑，在圖八駿亦靦顔。", "鄉令生並人間世，躑躅吞聲敢伸喙。", "真人開國宗承祖，猶有幽燕兩抔土。", "要須馬上駕群雄，九重跨出蒼玉虹。", "短鞚長驅當峻坂，却後伸前如履坦。", "紫駝峯薦碧琳腴，餘瀝婁分明玉瓚。", "圉人太僕不敢侮，爪剔爬搔謹程度。", "屹立亭亭時却顧，趯嚙誰能犯其怒。", "鄉聞天馬曾作歌，大宛西極都蒐羅。", "鳳膺龍脊非凡駟，馬肝遂誤文成死。", "遂使劉郎葬茂陵，不到昆臺十二層。"]'),
('10e39de7-ed34-4116-b643-95823da39ff2','桃花犬行','釋居簡','宋','宋诗','song-poetry','','[]','非玄非黄花蒙茸，炫晝不減原上紅。',192,'全唐诗/poet.song.180000.json','["非玄非黄花蒙茸，炫晝不減原上紅。", "無功指蹤走原野，兔盡倘可逃災凶。", "禁林都是秋聲樹，滿身何處沾紅雨。", "苔痕玉砌卧斜陽，又誤零霞低薄暮。", "楓宸紫闕芳霧濛，長門永巷泠泠風。", "夜嚴不聲白晝永，羊車所至隨從容。", "鬼瞰高明目不瞬，勾連狸怪狐妖逞。", "百步雖無檻虎威，雙睛何用軒轅鏡。", "熙陵以西一鉏地，寸金寸土君王賜。", "平分只與碧銜霞，生死恩榮略相似。", "相如飛轍自蜀都，初因狗監誦子虛。", "四夷來王亦典麗，御考自稱前進士。"]'),
('9429bbcd-1c59-43a7-ac15-6288093e1503','趙侯遥碧軒','釋居簡','宋','宋诗','song-poetry','','[]','一峯中雄酋，兩峯拱而立。',120,'全唐诗/poet.song.180000.json','["一峯中雄酋，兩峯拱而立。", "嶄然入雲表，煙開翠鬟濕。", "佳山如佳士，可望不可及。", "詩人覷天巧，妙處歸眼力。", "新營稱華扁，收此一寸碧。", "婆娑在其下，繾綣與之習。", "嗟哉塵土中，膏火日煎急。", "青層但坐對，皓首未暇識。", "趨舍各有適，枘鑿不相入。", "何當山上頭，裴回瞰原隰。"]'),
('82054e65-1d8f-406b-9273-977758263b82','止止閣','釋居簡','宋','宋诗','song-poetry','','[]','回闌浄如拭，古竈寒不煙。',192,'全唐诗/poet.song.180000.json','["回闌浄如拭，古竈寒不煙。", "宿之用彌壯，渟則澄以鮮。", "鄉來矜襄陵，今焉碧淵淵。", "鄉來觀燎原，今也不復然。", "激湍反其性，靜則知其天。", "抑炎弗用智，智燭天地先。", "悠然百不理，複簷飛畫船。", "拍闌撫寥泬，倚楹鑑清漣。", "山黛渺茫綠，水花先後妍。", "原隰煙雨時，萬變了目前。", "汎觀塵土中，搏攫如烏鳶。", "婁藏滿籝金，更聚百屋錢。", "亡弓苦妄冀，去劍疑將還。", "擬分芭蕉鹿，去饁虞芮田。", "營營復營營，萬緒膏火煎。", "何如歌吉祥，亹亹樂者全。"]'),
('19e9d1ab-1419-409e-8e65-604fcabfe843','謝宣城朱長官','釋居簡','宋','宋诗','song-poetry','','[]','飛來何處山，秀整連鳳池。',132,'全唐诗/poet.song.180000.json','["飛來何處山，秀整連鳳池。", "絕勝一鉏地，天地不得私。", "朣朣斗牛間，明玉生華滋。", "凜姿歲寒後，蕭洒觀孫枝。", "出宰山水縣，小謝城東陲。", "琴瑟日在御，箠楚不苟施。", "春風河陽花，次第芳菲菲。", "屈指九十日，日日把酒巵。", "玉山不須扶，百里皆酣嘻。", "行扳星辰履，頡頏叢霄蜚。", "故家厚培㙲，衮綉看傳衣。"]'),
('e18a2a63-66cf-489d-98ba-e9dfd888db0c','天台宋紫薇光祿挽章','釋居簡','宋','宋诗','song-poetry','','[]','閑適與康寧，山林只一人。',144,'全唐诗/poet.song.180000.json','["閑適與康寧，山林只一人。", "風流兩晉舊，翰墨四朝新。", "五袴歌宣化，三盤載縯綸。", "垂楊閑意緒，華頂老精神。", "廣樂千齡會，溟波幾度塵。", "壺中留白日，庭下擁朱輪。", "荷嫩衣重製，蘭馨佩更紉。", "玉頹千日釀，俗蛻百年身。", "賦裏尋詞客，橋邊問應真。", "靈光猶在魯，商嶺謾逃秦。", "入社宜歸洛，休耕不起莘。", "騎箕渺何許，長嘯玉樓春。"]'),
('f121e1b6-c6db-4749-86d0-33ed2166bf60','山行即事','釋居簡','宋','宋诗','song-poetry','','[]','吹到隄邊絮，春菲處處空。',48,'全唐诗/poet.song.180000.json','["吹到隄邊絮，春菲處處空。", "苦滋荼葉雨，野韻刺花風。", "荷貼平池綠，榴苞露井紅。", "忽聞淮麥熟，且願似崆峒。"]'),
('121814aa-0eaf-4b63-8775-1e02d141ed71','次韻陳右史賞醉落托','釋居簡','宋','宋诗','song-poetry','','[]','羅幙低開護曲闌，嬌紅落托醉扶難。',32,'全唐诗/poet.song.180000.json','["羅幙低開護曲闌，嬌紅落托醉扶難。", "朝來嫩日疎雲淡，縱有些風儘耐寒。"]'),
('a714c566-7b60-48b5-becb-c99b75a0dcd8','送王寧國','釋居簡','宋','宋诗','song-poetry','','[]','習習凉薰至自南，詩人官滿策歸驂。',64,'全唐诗/poet.song.180000.json','["習習凉薰至自南，詩人官滿策歸驂。", "腰纏簡短聊遵約，家法森嚴貴不貪。", "政入民謠歌得一，月臨山驛賦成三。", "獨餘尋丈鳴弦地，儀表江東古子男。"]'),
('95d7ca4a-01d1-4ad2-8f49-c7673c8b69c4','謝人餉蕨','釋居簡','宋','宋诗','song-poetry','','[]','瓦盂亭午未聞歌，少負心初負腹多。',32,'全唐诗/poet.song.180000.json','["瓦盂亭午未聞歌，少負心初負腹多。", "薇蕨不侵耕鑿地，八珍柰此屬饜何。"]'),
('74afc3af-5051-4c51-9344-42a2b429acea','秦權','釋居簡','宋','宋诗','song-poetry','','[]','自程文法較錙銖，汗竹韋編付燼餘。',32,'全唐诗/poet.song.180000.json','["自程文法較錙銖，汗竹韋編付燼餘。", "倒置重輕矜縝密，不知三十六年疏。"]'),
('6025f62a-7536-4191-a5cc-89d84997f264','鶑','釋居簡','宋','宋诗','song-poetry','','[]','最堪聽在綠陰陰，緩緩歌酬細細吟。',32,'全唐诗/poet.song.180000.json','["最堪聽在綠陰陰，緩緩歌酬細細吟。", "別院曉聲知幾許，田巴抵死只梟音。"]'),
('8bd3321d-3dfb-4d6f-9074-45c10e4cbce3','芳渚秋零小卷','釋居簡','宋','宋诗','song-poetry','','[]','沙明石老水收痕，零露寒生宿莽根。',32,'全唐诗/poet.song.180000.json','["沙明石老水收痕，零露寒生宿莽根。", "欲盡夕陽秋態度，莫添白鳥破烟昏。"]'),
('ebaed7bc-b548-4150-a2b4-14c48af0a803','彰教山茶敵勝宣城','釋居簡','宋','宋诗','song-poetry','','[]','吟壓宣城小杜陵，忍紅紅擬白頭吟。',32,'全唐诗/poet.song.180000.json','["吟壓宣城小杜陵，忍紅紅擬白頭吟。", "丹滋曉滴珊瑚重，闖戶春寒翠幄深。"]'),
('065679ff-6d60-4e96-ba23-3f972343063e','時齋','釋居簡','宋','宋诗','song-poetry','','[]','易去苦難追，知幾勇不疑。',48,'全唐诗/poet.song.180000.json','["易去苦難追，知幾勇不疑。", "梭纔起雷澤，魚已奮天池。", "夜冷梅粘雪，秋零桂著枝。", "風雲與人會，先不與人期。"]'),
('e3ff69cb-ede8-42fd-8ab6-70bd07bb7f37','臘初雪至月末','釋居簡','宋','宋诗','song-poetry','','[]','四野靜無塵，崇卑砌得勻。',48,'全唐诗/poet.song.180000.json','["四野靜無塵，崇卑砌得勻。", "不才添臃腫，瘦節耻輪囷。", "亂委無非瑞，才消便是春。", "多年聞混沌，今日見純真。"]'),
('f47a83c0-614e-495b-97a0-6b7d92b98e3f','梁太子釣臺','釋居簡','宋','宋诗','song-poetry','','[]','晴拂雙鬟曉未開，先驅寸碧渡江來。',32,'全唐诗/poet.song.180000.json','["晴拂雙鬟曉未開，先驅寸碧渡江來。", "傷心舊日垂綸地，幾度江春去又回。"]'),
('4f7ab32a-3df1-4a59-8e45-0b9f1af09315','清泉得名於真大參','釋居簡','宋','宋诗','song-poetry','','[]','清者畏人知，泉胡不病茲。',48,'全唐诗/poet.song.180000.json','["清者畏人知，泉胡不病茲。", "土疏分石脈，砂淺靜風漪。", "薇腹應同潔，茶勳亦振奇。", "出山嗟渾渾，三嚥起余思。"]'),
('ee779d03-c09e-473d-976d-b141d06ff0b1','九華山','釋居簡','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','九華宜带雪，故故仲冬來。',48,'全唐诗/poet.song.180000.json','["九華宜带雪，故故仲冬來。", "翠掃忺梳洗，玄冥未剪裁。", "驟觀疑舊識，近看若新開。", "曾說壺中玩，多應小有才。"]'),
('013ce815-e524-4a16-9f03-78ddf7a3edeb','老融牛  其一','釋居簡','宋','宋诗','song-poetry','','[]','一戰長驅七十城，可無餘勇替春耕。',32,'全唐诗/poet.song.180000.json','["一戰長驅七十城，可無餘勇替春耕。", "歸來不作凌煙夢，只寫清溪瘦影明。"]'),
('38e74834-ea27-4d99-8bcd-ed9336763201','老融牛  其二','釋居簡','宋','宋诗','song-poetry','','[]','力穡工夫畫裏看，閔勞念舊只長歎。',32,'全唐诗/poet.song.180000.json','["力穡工夫畫裏看，閔勞念舊只長歎。", "斷魂千載荆州市，尸素甘心飽阿瞞。"]'),
('b5e7383c-cb9c-4726-b25d-42724e57ad41','雪航','釋居簡','宋','宋诗','song-poetry','','[]','九逵埃壒點人衣，踏土何如踏浪兒。',32,'全唐诗/poet.song.180000.json','["九逵埃壒點人衣，踏土何如踏浪兒。", "爛熳溪頭千樹玉，風蓑月笛興闌時。"]'),
('e66e1cf5-9224-4570-8439-4703bd48e9af','放閘','釋居簡','宋','宋诗','song-poetry','','[]','截住泠泠碧透沙，放開衮衮怒飛花。',64,'全唐诗/poet.song.180000.json','["截住泠泠碧透沙，放開衮衮怒飛花。", "石疑初裂蓬婆麓，鯨擬洪奔海若家。", "殷地賈餘翻霹靂，噴岩用壯激谽谺。", "憑闌小佇觀流止，不獨觀瀾一笑譁。"]'),
('df2d1c0d-e040-4716-b978-e3b73095a2b1','下竺朱桐花一根出石上見之四十餘年','釋居簡','宋','宋诗','song-poetry','','[]','綠柄高扶絳玉開，層層萼萼染猩裁。',32,'全唐诗/poet.song.180000.json','["綠柄高扶絳玉開，層層萼萼染猩裁。", "嶧陽曾止青鸞翼，無此奇葩更不來。"]'),
('de57fb4a-2914-4f37-aea8-699629999399','嚴山人餉蒲萄漿','釋居簡','宋','宋诗','song-poetry','','[]','翠朵搴藤剪綠垂，小槽新壓水晶澌。',32,'全唐诗/poet.song.180000.json','["翠朵搴藤剪綠垂，小槽新壓水晶澌。", "凉州亦有楊州鶴，惆悵山人只要詩。"]'),
('481f2a59-9461-4c55-b7f0-63eed2d909ea','送心上人歸琴川','釋居簡','宋','宋诗','song-poetry','','[]','五道川流似五弦，綠窗朱戶照明鮮。',32,'全唐诗/poet.song.180000.json','["五道川流似五弦，綠窗朱戶照明鮮。", "飛來峯下僧歸去，髣髴華亭落照船。"]'),
('2e6f96f1-02bf-4561-9c12-eef63200df10','煙竹','釋居簡','宋','宋诗','song-poetry','','[]','林疏略見兩三分，不是嵐光不是雲。',32,'全唐诗/poet.song.180000.json','["林疏略見兩三分，不是嵐光不是雲。", "亟展生綃輕著墨，幻成初日度晴熏。"]'),
('7d27a9cc-3d7a-45f8-873b-bf261f927d09','秋夜','釋居簡','宋','宋诗','song-poetry','','[]','嫩凉細意入簾櫳，禁樹秋聲未擊蒙。',32,'全唐诗/poet.song.180000.json','["嫩凉細意入簾櫳，禁樹秋聲未擊蒙。", "展盡綠蕉心寸寸，幾時消息到梧桐。"]'),
('e9a188bf-8552-4d31-9735-260604f20f7c','天竺兩峰堂待月','釋居簡','宋','宋诗','song-poetry','','[]','朣朣如水洗新秋，到兩峯前凝不流。',32,'全唐诗/poet.song.180000.json','["朣朣如水洗新秋，到兩峯前凝不流。", "曾似丈人祠下看，丹梯飛步玉華樓。"]'),
('679ea9ea-0244-4ad5-a2b4-74d1dfc80a6d','代人上魏左史','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','榜下盡橫飛，龍頭尚立螭。',120,'全唐诗/poet.song.180000.json','["榜下盡橫飛，龍頭尚立螭。", "穹崇方善下，謹厚孰逾卑。", "制作雖師古，經綸盍制宜。", "迥超千丈俗，密契九重知。", "北海客常滿，西湖雨亦奇。", "文傳仁者壽，用適聖之時。", "數道甘棠詠，叢霄湛露詩。", "未移騏驥步，已在鳳凰池。", "紫橐荷芬馥，巍冠佩陸離。", "橐中雲錦段，拈出解人頤。"]'),
('191d8885-df94-4d99-a5db-0d55ec60f4aa','水月菴','釋居簡','宋','宋诗','song-poetry','','[]','心蟾光朣朣，性靜湍不起。',120,'全唐诗/poet.song.180000.json','["心蟾光朣朣，性靜湍不起。", "悠哉小天地，萬化渺無蔕。", "清苕半洚水月菴，碧蟾夜夜先清涵。", "曩曾借榻坐凉樹，細數秋毫闚夜潭。", "猶來清圓捉不得，何地容茲老豪逸。", "脩名與月俱不死，衮衮東流幾時息。", "鄉來萬州賦此詩，寥寥百歲無此奇。", "詩在天西錦官寺，珠璧照人覺形穢。"]'),
('547f0a7a-5738-4fba-acf3-7f33e58eefbe','劉寺庭犀盛開','釋居簡','宋','宋诗','song-poetry','','[]','鳳井庭犀玉載腴，樓前樓後著花初。',64,'全唐诗/poet.song.180000.json','["鳳井庭犀玉載腴，樓前樓後著花初。", "不須素幌縈檀篆，只放鮮風入綺疏。", "恨弗同尋姑射住，却疑僦得廣寒居。", "露零夜老秋衣薄，獨自裴回繞屋除。"]'),
('e15e441a-aee0-4ed7-ae7c-319e1466b29d','直院盧蒲江爲余作壽木怪石','釋居簡','宋','宋诗','song-poetry','','[]','草枯藍田山，飲羽誤入神。',144,'全唐诗/poet.song.180000.json','["草枯藍田山，飲羽誤入神。", "歸來落清夢，起冩贋虎真。", "槎牙虎邊樹，霜虬蛻脩鱗。", "鄉來一寸根，今者千歲苓。", "凍雪壓不低，華風吹不春。", "落子大蔽牛，婁起厦屋傾。", "日月弗知老，保此堅與貞。", "年年姚家黄，角逐魏紫榮。", "十里春風香，走殺陌上人。", "夭妍極遠到，不得一月程。", "居然事顔色，只與朝菌盟。", "安知有耆艾，落落仍亭亭。"]'),
('2c035503-89fe-45a4-964c-f7574052ef2d','江西定上人梅','釋居簡','宋','宋诗','song-poetry','','[]','眼明不識春風影，收拾風煙入夢思。',32,'全唐诗/poet.song.180000.json','["眼明不識春風影，收拾風煙入夢思。", "一笑自知天下白，墨名烏足累冰姿。"]'),
('954f87b1-413f-4414-8a22-843651ab1ad0','老融放耕圖皇甫都護雁圖二絕  其一','釋居簡','宋','宋诗','song-poetry','','[]','蓑笠從衡觳觫蕃，暝歸晨作俟豐年。',32,'全唐诗/poet.song.180000.json','["蓑笠從衡觳觫蕃，暝歸晨作俟豐年。", "誅求莫撓雞豚社，春雨春寒苦最先。"]'),
('9769524f-311a-4b5b-b11b-7344ac19ce41','老融放耕圖皇甫都護雁圖二絕  其二','釋居簡','宋','宋诗','song-poetry','','[]','邕邕何處一聲秋，杜若汀連宿莽洲。',32,'全唐诗/poet.song.180000.json','["邕邕何處一聲秋，杜若汀連宿莽洲。", "米熟菰蒲隨分飽，危機多是稻粱謀。"]'),
('166e8865-a719-4ede-9790-eb278c01b390','木犀著雨','釋居簡','宋','宋诗','song-poetry','','[]','空山雨淫秋，妬我庭中犀。',204,'全唐诗/poet.song.180000.json','["空山雨淫秋，妬我庭中犀。", "犀敷粟玉英，浸漬仍葳蕤。", "有如春方中，名品嗟淋漓。", "因依海棠泪，著此霜蟾枝。", "聞此輒掩耳，代犀前致辭。", "燕脂怨無香，姿色獨媚時。", "烘晴睡未足，已驚胡馬嘶。", "彫零怕隨雨，嫣然成愴悽。", "鮮明擅韶華，不足較等夷。", "自憐宮樣黄，不結春風知。", "木蘭固可友，宿莽亦可師。", "正色俗子憎，濃馥天風吹。", "苔痕浄如染，綠展承霏霏。", "故家換骨法，降真合傳衣。", "大山與小山，騷雅同衿期。", "至今百世下，猶有薌林詩。", "何心與物競，有泪無從揮。"]'),
('719d47f8-43fd-4457-bc70-fce79a6e8dd2','秦時石酒缸','釋居簡','宋','宋诗','song-poetry','','[]','臃腫窺秦制，曾聞釀酒來。',48,'全唐诗/poet.song.180000.json','["臃腫窺秦制，曾聞釀酒來。", "腹如包括脹，口作并吞開。", "北築饑難療，東巡醉不回。", "痕雲疑瀲灧，餘瀝暈蒼苔。"]'),
('770a3015-fbd1-4d68-9bbf-92dac843feb9','九日還山中','釋居簡','宋','宋诗','song-poetry','','[]','去年佳約負東籬，鳳井丹犀彷彿知。',32,'全唐诗/poet.song.180000.json','["去年佳約負東籬，鳳井丹犀彷彿知。", "便使山靈先勒駕，明朝更擬北山移。"]'),
('4c44487c-fcb3-4c93-85d7-6b42edcfed5f','虞美人草','釋居簡','宋','宋诗','song-poetry','','[]','君恩如海海不深，妾義如鐵利斷金。',160,'全唐诗/poet.song.180000.json','["君恩如海海不深，妾義如鐵利斷金。", "舍生取義我所欲，忍死織室羞同心。", "春姿忽作秋蓬委，一寸剛明曾不死。", "明年原上野花繁，一枝自託華風起。", "裊裊娉娉不成艷，態度淺深生色染。", "向人欲訴却無言，寂寞千年恨誰掩。", "芳郊遊女宛轉歌，倚春拍手看婆娑。", "露晞初日枝頭墜，猶有君王別時泪。", "翻劉覆楚知幾何，大風竟作還鄉歌。", "淮南區區欲爲帝，淮陰堂堂賀陳狶。"]'),
('a04c091f-2589-4865-803d-8d597fd856d4','蒼苔','釋居簡','宋','宋诗','song-poetry','','[]','濕带秋痕綠可庭，花陰竹色借鮮明。',64,'全唐诗/poet.song.180000.json','["濕带秋痕綠可庭，花陰竹色借鮮明。", "簪抽翠筍愁穿破，茵拓青絲喜剪成。", "戶外倚筇遮俗屨，樓頭橫玉襯寒英。", "平陽不惜黄金埒，稠疊蒙茸四畔生。"]'),
('a0694a3e-9573-433a-b78f-d0cd81051259','漁父','釋居簡','宋','宋诗','song-poetry','','[]','謀生與俗違，一葉浪中蜚。',48,'全唐诗/poet.song.180000.json','["謀生與俗違，一葉浪中蜚。", "水易分團月，雲難隠少微。", "雁沙眠晚照，鷗渚櫂晴霏。", "見說蓬萊淺，尋津問釣磯。"]'),
('d232d2a7-4d78-45be-b8ab-41275828309a','裝冬後不速之客來','釋居簡','宋','宋诗','song-poetry','','[]','綻裘紉絮辦冬和，羽化其如獨冷何。',32,'全唐诗/poet.song.180000.json','["綻裘紉絮辦冬和，羽化其如獨冷何。", "藕蕩欲搴霜後葉，曉來零落更無多。"]'),
('0d719b71-52d6-47b6-af9f-4f95f557df1f','王總卿季和歸自關西','釋居簡','宋','宋诗','song-poetry','','[]','關西長慮獨兢兢，萬竈分屯感慨深。',64,'全唐诗/poet.song.180000.json','["關西長慮獨兢兢，萬竈分屯感慨深。", "不易制如巫硤水，最難得是蜀人心。", "撥灰忍見俱焚玉，銘鼎徐看小篆金。", "欲倚籌邊開玉帳，共觀城外柏森森。"]'),
('b09d0acc-305e-4b97-a44a-32b0bd8c0b48','耕谷','釋居簡','宋','宋诗','song-poetry','','[]','屨痕不印步虛壇，欲事鉏犁恐亦難。',32,'全唐诗/poet.song.180000.json','["屨痕不印步虛壇，欲事鉏犁恐亦難。", "雲子熟時還自飽，不知沆瀣與誰餐。"]'),
('45405c03-1b21-4a87-920e-3af34c9e46a1','識全','釋居簡','宋','宋诗','song-poetry','','[]','占得沙邊柳外春，更專吟嘯管陰晴。',32,'全唐诗/poet.song.180000.json','["占得沙邊柳外春，更專吟嘯管陰晴。", "延祥觀後茅茨老，月旦工夫子細評。"]'),
('635739a9-5765-494b-9466-bfd90dea3ff3','石亭','釋居簡','宋','宋诗','song-poetry','','[]','蒼壁痕雲煖不消，午陰花影共林臯。',32,'全唐诗/poet.song.180000.json','["蒼壁痕雲煖不消，午陰花影共林臯。", "丹藏亭樹無人守，付與縣枝雪色猱。"]'),
('224ab73c-b741-425f-b29d-021df35cca32','秋塘報陳提刑訃','釋居簡','宋','宋诗','song-poetry','','[]','宏博曾聞鼎足無，脚纔實處即榮途。',64,'全唐诗/poet.song.180000.json','["宏博曾聞鼎足無，脚纔實處即榮途。", "恰觀次第行初志，冀懋神明振後圖。", "齒失半唇忘屏翰，棣聯雙萼更紛敷。", "鄉來少戇煩公笑，却憶公言誚故吾。"]'),
('e8fefa33-edcc-44e5-ae97-78aa24808c62','送傅兄歸江西簡諸宋諸黄','釋居簡','宋','宋诗','song-poetry','','[]','沖和正脈到江西，中有千岩萬壑奇。',64,'全唐诗/poet.song.180000.json','["沖和正脈到江西，中有千岩萬壑奇。", "百鍊易成終切玉，一炊難辦必精糜。", "艾蕭雜處芝蘭馥，風土殊方枳橘移。", "鐵石故家清婉賦，盍臨疎影寄予思。"]'),
('40094f74-8c81-41c3-ba21-3d7cb424a986','題高髯墨菊枕屏','釋居簡','宋','宋诗','song-poetry','','[]','欲種團枝香，無地著蔓延。',48,'全唐诗/poet.song.180000.json','["欲種團枝香，無地著蔓延。", "密化移春霏，零露生秋妍。", "非金亦非玉，采采仍田田。", "餐英不成夢，喚起西窗眠。"]'),
('87102fc2-1b98-4824-9dcf-8745db8fb3c8','題高髯詩藁','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','翻水千篇未足哦，不酬一語亦同科。',64,'全唐诗/poet.song.180000.json','["翻水千篇未足哦，不酬一語亦同科。", "若非身世相忘久，應是江山得助多。", "旬月有人加鍛鍊，壺觴無地不婆娑。", "西湖南蕩相尋處，門斷紅塵接翠蘿。"]'),
('1ca2cc70-54d5-458b-b2d2-8e204e9a61a2','接虞稅院貫卿遺書','釋居簡','宋','宋诗','song-poetry','','[]','盡心如善射，百步中彌親。',48,'全唐诗/poet.song.180000.json','["盡心如善射，百步中彌親。", "不競與閑契，尊生爲死隣。", "關譏千古恨，日計兩眉顰。", "一卷花嚴易，心知更幾人。"]'),
('7576eaef-43c9-4b10-8d56-616c93dfb1f0','甘園尋梅  其一','釋居簡','宋','宋诗','song-poetry','','[]','疎枝重複裹莓苔，護得寒英煖未開。',32,'全唐诗/poet.song.180000.json','["疎枝重複裹莓苔，護得寒英煖未開。", "料理不關元化事，翠華長是雪前來。"]'),
('638a2015-c432-45c7-a047-156cf9544cb3','甘園尋梅  其二','釋居簡','宋','宋诗','song-poetry','','[]','楮幌春生斗底房，不知冰結夜來霜。',32,'全唐诗/poet.song.180000.json','["楮幌春生斗底房，不知冰結夜來霜。", "無因領略黄昏月，只遣疎鐘管暗香。"]'),
('eb25945a-5c8c-4172-9fc2-53304291a727','松御座','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','偃蓋交柯坐亦宜，春風翠輦憇逶迤。',32,'全唐诗/poet.song.180000.json','["偃蓋交柯坐亦宜，春風翠輦憇逶迤。", "大夫寂寞山陰道，不見西湖鼎盛時。"]'),
('9999d309-9fd6-4740-b4c1-1c4759378b8d','雲','釋居簡','宋','宋诗','song-poetry','','[]','自是無心物，依稀似有心。',48,'全唐诗/poet.song.180000.json','["自是無心物，依稀似有心。", "因風纔冉冉，釀雨忽沉沉。", "一末紳朝嶺，重簷帽晚岑。", "丁寧休蔽日，我欲耀陽林。"]'),
('4f96a7e4-6a3e-488d-adf6-8f5896a6749c','趣徐無競作水仙','釋居簡','宋','宋诗','song-poetry','','[]','抱獨貧如我，飄然更我憐。',48,'全唐诗/poet.song.180000.json','["抱獨貧如我，飄然更我憐。", "親思文度瘦，婦笑伯鸞顛。", "混混污成俗，朣朣碧覷天。", "肯移羅襪步，薦菊些林仙。"]'),
('f186a1a4-1e2a-4845-8ec2-b7962ecbe564','雪湖池上新築','釋居簡','宋','宋诗','song-poetry','','[]','疏綺闖冰池，苔封老石磯。',48,'全唐诗/poet.song.180000.json','["疏綺闖冰池，苔封老石磯。", "魚方深避釣，鷗亦早忘機。", "滌研融殘雪，觀書競夕霏。", "春風長似舊，還趁雪中歸。"]'),
('fc82406b-8bbe-43b8-8c06-35200d5c6b57','曹瀘南得思陵舊賜張魏公琴曰播雲','釋居簡','宋','宋诗','song-poetry','','[]','岷峩豁塵昏，舊賜出播雲。',204,'全唐诗/poet.song.180000.json','["岷峩豁塵昏，舊賜出播雲。", "不知落人間，蝦蟆幾虧盈。", "晦顯固靡常，數豈逃冥冥。", "想當風雨時，破壁應有聲。", "懷璧戒匹夫，呵護煩百神。", "一朝得所託，倏若屈蠖伸。", "人以器圖舊，器以人懷新。", "玉軫黄金徽，爛爛奎畫明。", "魏公藹名氏，千載如丹青。", "歌風調舜弦，感物懷堯仁。", "扶日昌中興，四海同一雲。", "載維艱難初，事與得失并。", "萬竈嘉陵江，飲此一掬清。", "悠然一再彈，萬里懷長城。", "雲絮初無根，勇變嘲哳鳴。", "捕蟬冩真意，弦外無人聽。", "空嗟易水寒，遺恨崆峒平。"]'),
('e7c8d443-5b06-43a1-9f08-01a4114ed6b8','杜侍郎之遂寧','釋居簡','宋','宋诗','song-poetry','','[]','寧爲輕以清，抑爲重而填。',156,'全唐诗/poet.song.180000.json','["寧爲輕以清，抑爲重而填。", "重輕惟時中，舉輒麗吾正。", "誠齋振家學，本末盡誠敬。", "所施見倫次，所矚洞遐隠。", "喧啾雄地籟，靜勝了天定。", "一經早授受，吳霜未侵鬢。", "精明紫荷橐，所藴固未盡。", "玉堂與天遠，仙槎向人近。", "旌旄屋頭州，維翰倚東屏。", "歛此一道惠，徒引兆庶領。", "泉山跨鰲碧，橫江秀而整。", "吾親在其下，枌榆接封畛。", "家有老吟僧，河海借餘潤。"]'),
('ec907891-4395-4180-85a9-f07f7cbeed90','喜曹安撫還自瀘南','釋居簡','宋','宋诗','song-poetry','','[]','蜀道因仍漲燧煙，煩公玉節照山川。',64,'全唐诗/poet.song.180000.json','["蜀道因仍漲燧煙，煩公玉節照山川。", "省闈三見文衡正，邊柝雙兼武備全。", "傳自老成需代去，不知威惠倩誰宣。", "回頭半壁西南地，不是尋常刺史天。"]'),
('2d0a78c0-4f29-4c04-98a8-08f5997d23ca','盧直院挽章','釋居簡','宋','宋诗','song-poetry','','[]','玉堂雲氣鎖空濛，回首泠然跨閬風。',64,'全唐诗/poet.song.180000.json','["玉堂雲氣鎖空濛，回首泠然跨閬風。", "紙貴又騰身後賈，騷亡舊策眼前功。", "蝸緣竺磵題名石，鷺憶吳江載酒篷。", "零落九華三四帖，朣朣猶在破囊中。"]'),
('2a98fa86-b654-4404-943a-ef06a0fcd0ef','宋左曹湖州宣諭','釋居簡','宋','宋诗','song-poetry','','[]','皇華萬斛下苕溪，夾道甘棠映綠漪。',64,'全唐诗/poet.song.180000.json','["皇華萬斛下苕溪，夾道甘棠映綠漪。", "爲問只今回首處，曷如它日勸耕時。", "恩光纔洽腥風靜，烽火初消化日遲。", "士不明經無足用，鄉來殷侑亦如斯。"]'),
('cd0735d8-2aa4-4d66-87f4-ca019f1d1379','永嘉壁書記携諸公詩卷索語','釋居簡','宋','宋诗','song-poetry','','[]','草思含芳夢亦疑，芬陁擢秀自枝枝。',64,'全唐诗/poet.song.180000.json','["草思含芳夢亦疑，芬陁擢秀自枝枝。", "人間萬事醉瞇眼，江上數峯青到眉。", "多暇湖山分晝永，少晴風日共春遲。", "一春幽事從頭了，先破蒼苔吊紫芝。"]'),
('aa79cd94-b0a6-4d45-90f9-0845cce96859','和寒泉春日兒童三詠  其一','釋居簡','宋','宋诗','song-poetry','','[]','爭跨迎侯彩竹新，相呼回策巧如縈。',32,'全唐诗/poet.song.180000.json','["爭跨迎侯彩竹新，相呼回策巧如縈。", "一鞭看是誰先著，穉子群中覓祖生。"]'),
('11cb998e-f8f7-4d46-96ba-4e30befe243b','和寒泉春日兒童三詠  其二','釋居簡','宋','宋诗','song-poetry','','[]','縱輪不卷只嫌低，高處安知鷁退飛。',32,'全唐诗/poet.song.180000.json','["縱輪不卷只嫌低，高處安知鷁退飛。", "弱縷不禁兒輩掣，斷鳶弗下斷雲歸。"]'),
('5c188808-478f-48ac-a73d-a0f5b670654d','和寒泉春日兒童三詠  其三','釋居簡','宋','宋诗','song-poetry','','[]','煖響烏𣡶二月初，調高不作小單于。',32,'全唐诗/poet.song.180000.json','["煖響烏𣡶二月初，調高不作小單于。", "年年陌上兒童戲，嚼徵含商盡不如。"]'),
('5781281d-f51b-4c20-ac3c-3982d211999e','酬寒泉牡丹','釋居簡','宋','宋诗','song-poetry','','[]','見說姚家與魏家，紫瓊黄玉剪紛葩。',64,'全唐诗/poet.song.180000.json','["見說姚家與魏家，紫瓊黄玉剪紛葩。", "亭亭貴重推名輩，歲歲清明賞大花。", "日褪曉晴連影好，露添夜冷並枝斜。", "一從婁舞霓裳徧，憔悴春風怨物華。"]'),
('004f886b-90eb-41ea-82c4-9f00441cf3ea','上巳日','釋居簡','宋','宋诗','song-poetry','','[]','龍飛乙酉三三日，節物催春睡不知。',64,'全唐诗/poet.song.180000.json','["龍飛乙酉三三日，節物催春睡不知。", "便作花殘鶑老態，略無天朗氣清時。", "麗人行欠高吟續，禊帖碑從贋本欺。", "逸興不隨今古盡，振衣千仞赴心期。"]'),
('8a83cf16-ce4a-4d07-b7da-4f61c56884e8','柳絮','釋居簡','宋','宋诗','song-poetry','','[]','滿城漠漠看飛揚，百鍊剛非賀老腸。',64,'全唐诗/poet.song.180000.json','["滿城漠漠看飛揚，百鍊剛非賀老腸。", "褪雨不忺知醖藉，倚風無力信行藏。", "可曾著意隨流急，竟亦何心作許狂。", "酒似海留春不住，爲春回雪薦離觴。"]'),
('8469895c-4a45-43c5-be64-d3756fdd5559','杯中魚子','釋居簡','宋','宋诗','song-poetry','','[]','眇如絲粟便悠然，漥玉深中淺注泉。',64,'全唐诗/poet.song.180000.json','["眇如絲粟便悠然，漥玉深中淺注泉。", "再暈不知前夜月，纔生便樂此中天。", "群分自笑如兒戲，聚育誰偏得母憐。", "罔罟不來斯可樂，洋洋何必泳長川。"]'),
('813bbd94-8025-43bf-b0f0-4c24a2b28ab3','悼陸秘讀','釋居簡','宋','宋诗','song-poetry','','[]','諸老騎箕上太微，仲謀不似景升兒。',64,'全唐诗/poet.song.180000.json','["諸老騎箕上太微，仲謀不似景升兒。", "廢尋蹊隧千年古，光奮胸襟一段奇。", "直敢昧尋嗟枉尺，方寧適義不成規。", "泠然差早終無媿，安俟名垂竹帛爲。"]'),
('745083fb-882f-4edd-b3cb-3cf59d73b769','三賢堂','釋居簡','宋','宋诗','song-poetry','','[]','彈壓風煙盍鼎分，一新丹碧耀層層。',64,'全唐诗/poet.song.180000.json','["彈壓風煙盍鼎分，一新丹碧耀層層。", "異時三鳳鳴還止，舊約群鷗喚得應。", "船繞砌雲尋水步，葑侵簷影似田塍。", "關心夜老梅花瘦，別有孤山樹上僧。"]'),
('369ad122-0212-43bd-a967-fe4d9eaac475','題煥少章墨菊','釋居簡','宋','宋诗','song-poetry','','[]','采薇不療餐英瘦，著眼無從到朵頤。',32,'全唐诗/poet.song.180000.json','["采薇不療餐英瘦，著眼無從到朵頤。", "秋露染毫餘曉馥，便成畫餠亦忘饑。"]'),
('2cfb58c1-ddaa-440a-bdcb-1920c217a4d7','謝疏寮高祕書同常博王省元見過  其一','釋居簡','宋','宋诗','song-poetry','','[]','友生朱與葛，月旦說疏寮。',48,'全唐诗/poet.song.180000.json','["友生朱與葛，月旦說疏寮。", "老錫思投越，春江夢趁潮。", "句新哦易熟，燈喜剪難消。", "聞道搴旗鼓，山林不寂寥。"]'),
('5d292c94-3a3b-4c2c-9620-af93cd0d14ab','謝疏寮高祕書同常博王省元見過  其二','釋居簡','宋','宋诗','song-poetry','','[]','不縱青雲步，行間著得麽。',48,'全唐诗/poet.song.180000.json','["不縱青雲步，行間著得麽。", "官居最華要，吟似老頭陁。", "行輩今差少，聲名早厭多。", "猶將三萬軸，清夜答弦歌。"]'),
('cbf0b793-cf9e-4223-9f5e-47aaa889812f','刀鑷工','釋居簡','宋','宋诗','song-poetry','','[]','彈鑷何曾款俗扃，清晨且了夜來經。',64,'全唐诗/poet.song.180000.json','["彈鑷何曾款俗扃，清晨且了夜來經。", "匣非臺鏡人誰鑒，閲少年頭雪易零。", "老葛句留身後貴，顛僧髮燼死前靈。", "白崖薙罷還來薙，饒得長安兩獨醒。"]'),
('b927104c-9939-418c-9815-a7c4b7d607df','智遷晝牛','釋居簡','宋','宋诗','song-poetry','','[]','力敵難教死鬭心，墨輕毫淡柳陰陰。',32,'全唐诗/poet.song.180000.json','["力敵難教死鬭心，墨輕毫淡柳陰陰。", "莫將觝角迂奇思，只寫洪川扣角吟。"]'),
('ab74aca7-1275-42cc-afe5-9e99b526d016','盧玉堂枯木怪石','釋居簡','宋','宋诗','song-poetry','','[]','礧砢不坡陁，非才謝伐柯。',48,'全唐诗/poet.song.180000.json','["礧砢不坡陁，非才謝伐柯。", "相看如我瘦，想見閲人多。", "譽笑丹青俗，工如水墨何。", "經營盤礴際，天地困搜羅。"]'),
('2953bce5-e470-452b-9c16-e8eb44454972','十四夜竹間對月客有說丹霞張郡博已還豫章','釋居簡','宋','宋诗','song-poetry','','[]','華玉初痕隴樹顛，朣朣俄頃散澄鮮。',64,'全唐诗/poet.song.180000.json','["華玉初痕隴樹顛，朣朣俄頃散澄鮮。", "已無纖翳浄如洗，猶有些兒修未全。", "竺友嘯聞青嶂外，胡床移近綠筠邊。", "懷人長恨千山隔，雲淡天低鶴未眠。"]'),
('3e68d523-82b2-4b4f-9c92-d93e7be21f1e','定平懷墨梅','釋居簡','宋','宋诗','song-poetry','','[]','南昌梅少府，人道是梅仙。',48,'全唐诗/poet.song.180000.json','["南昌梅少府，人道是梅仙。", "不療疎枝瘦，安知壞色妍。", "春歸天上去，真自鏡中傳。", "同出吟機杼，無聲亦自賢。"]'),
('c0e1d62a-0b5f-4860-a07c-3da7ecf2cb4c','次周和州韻  其一','釋居簡','宋','宋诗','song-poetry','','[]','綠水繞園廬，花無一日虛。',48,'全唐诗/poet.song.180000.json','["綠水繞園廬，花無一日虛。", "柳橋閑研席，竹嶼小籃輿。", "惡草防滋蔓，新篁戒剪梳。", "不堪奇字累，酬接費分疎。"]'),
('1ef03f04-d45e-490f-8506-c5dd899f65b2','次周和州韻  其二','釋居簡','宋','宋诗','song-poetry','','[]','抔土銘騏駿，詼如柳子騷。',48,'全唐诗/poet.song.180000.json','["抔土銘騏駿，詼如柳子騷。", "滌新藏缺研，愍舊惜殘毫。", "射石懲年少，聞雞仄枕高。", "雲低鴻翼遠，弋者不償勞。"]'),
('62ee5ad4-51e0-4b75-9b99-69fc35042e1b','圖翁瓜圃出故淮東使者方詩境所藏楊補之三友','釋居簡','宋','宋诗','song-poetry','','[]','畫壽詩中境，人修地下文。',48,'全唐诗/poet.song.180000.json','["畫壽詩中境，人修地下文。", "金蘭三友合，涇渭兩邊分。", "凍壑層欹蓋，炎天獨欠君。", "莫嫌疎影瘦，及與欠清芬。"]'),
('56ce664a-8f61-4c2f-9af3-3d2b8a7e7e2c','落日汎舟拉趙寒泉劉成道','釋居簡','宋','宋诗','song-poetry','','[]','雨添湖滿綠浮堤，高柳摇青接葑低。',32,'全唐诗/poet.song.180000.json','["雨添湖滿綠浮堤，高柳摇青接葑低。", "覓得晚凉船便住，背斜陽處聽蟬嘶。"]'),
('1f8b5814-a27e-4f84-a0aa-53483dd2a493','送潔老歸碧雲新居','釋居簡','宋','宋诗','song-poetry','','[]','小小如巢便稱懷，隣無百萬買洪崖。',64,'全唐诗/poet.song.180000.json','["小小如巢便稱懷，隣無百萬買洪崖。", "炊雲子熟呼仙餉，借雪精游與俗乖。", "禪謬分燈傳口耳，耕寧合耦外形骸。", "田中大義休提掇，定與諸方打不諧。"]'),
('bc65eddf-2b47-40a6-8d47-e9be5f39dbd8','宋兄安卿墨梅','釋居簡','宋','宋诗','song-poetry','','[]','清婉渾非鐵石姿，故家別調合傳衣。',32,'全唐诗/poet.song.180000.json','["清婉渾非鐵石姿，故家別調合傳衣。", "華風不療春痕瘦，可是工夫不造微。"]'),
('d519f224-16fc-4e9d-97d5-1123bb831b2d','鳳泉初月','釋居簡','宋','宋诗','song-poetry','','[]','一痕隠隠介亭西，庾亮樓頭未醉時。',32,'全唐诗/poet.song.180000.json','["一痕隠隠介亭西，庾亮樓頭未醉時。", "多是團團深夜看，可曾見此巧如眉。"]'),
('1ce8fd38-0f44-4a40-b0c8-9cb5f3af0d4f','臨安長官趙兩山約觀將軍木石鏡玲瓏水浄土寺  其一','釋居簡','宋','宋诗','song-poetry','','[]','逐鹿區區百戰酣，道邊誰掩大夫慙。',32,'全唐诗/poet.song.180000.json','["逐鹿區區百戰酣，道邊誰掩大夫慙。", "錦山錦野幽尋地，獨對將軍憶召南。"]'),
('43e8a24e-dbb3-49fe-ae36-cbb9ba44c7c2','臨安長官趙兩山約觀將軍木石鏡玲瓏水浄土寺  其二','釋居簡','宋','宋诗','song-poetry','','[]','堅中素藴獨晶晶，異質潛分付目成。',32,'全唐诗/poet.song.180000.json','["堅中素藴獨晶晶，異質潛分付目成。", "泐盡燒痕猶反照，菱花多是用常明。"]'),
('8457e0f5-a4d8-4179-9290-3f1e066458a7','臨安長官趙兩山約觀將軍木石鏡玲瓏水浄土寺  其三','釋居簡','宋','宋诗','song-poetry','','[]','斷崖飛磴徧題名，刻盡玲瓏老石英。',32,'全唐诗/poet.song.180000.json','["斷崖飛磴徧題名，刻盡玲瓏老石英。", "欲寫苔痕酬勝踐，偶然天籟不曾鳴。"]'),
('c1934b34-6efd-44a4-a3d0-a67a51439378','臨安長官趙兩山約觀將軍木石鏡玲瓏水浄土寺  其四','釋居簡','宋','宋诗','song-poetry','','[]','觳觫何如款段騎，襪頭番著副絇絲。',32,'全唐诗/poet.song.180000.json','["觳觫何如款段騎，襪頭番著副絇絲。", "胸中天地無人識，只有橋邊白鷺鷥。"]'),
('8169b0d3-e5e3-4fb4-b228-2b3174cb7245','威德方丈桂著花長官趙兩山相過','釋居簡','宋','宋诗','song-poetry','','[]','舉子忙時節，秋庭桂子春。',48,'全唐诗/poet.song.180000.json','["舉子忙時節，秋庭桂子春。", "暫分餐菊伴，來款種花人。", "密影窺簷小，繁英趁月新。", "發硎盤錯外，樹下看修輪。"]'),
('58e71b09-95a8-4d96-9645-6a36f7ca25b5','臨安長官號兩山','釋居簡','宋','宋诗','song-poetry','','[]','小築難謀似燕營，卷簾容燕賀新成。',64,'全唐诗/poet.song.180000.json','["小築難謀似燕營，卷簾容燕賀新成。", "綠抽萬玉醫人俗，青出雙螺闖戶明。", "家與宦貧寧免仕，猨教鶴伴不須驚。", "紫荆花下庭萱老，濁酒狂歌燕弟兄。"]'),
('6adfc3cf-f51e-469a-be69-a26d74c39896','雲天瑞所藏李唐風雨圖','釋居簡','宋','宋诗','song-poetry','','[]','砲車卷東南，白晝沙石昏。',204,'全唐诗/poet.song.180000.json','["砲車卷東南，白晝沙石昏。", "悠然隘西北，頃刻潭湫翻。", "晴窗展李畫，靉靆迷江村。", "乃知筆有神，巧剔造物根。", "信意潑濃墨，了不見墨痕。", "但見平林黯黯木欲折，輥底怒浪掀天渾。", "平地十步九蹉跌，奈此倚岸舟如盆。", "得非折天柱，恐是顛崑崙。", "不然於菟髑髏下，巨浸潜蛟勇鬭濤山崩。", "空江冥冥不知曉，更無一箇閑鷗鳥。", "斷岸微茫水亭小，三兩重茅都卷了。", "灕洒雲陰陰，翻然如惜金。", "西子宜淺粧，濃抹尤清深。", "於戲此妙不可尋，百金一筆不足臨，掩卷袖手空沉吟。"]'),
('d9a9e389-4176-4ce6-918e-507c08750755','送侍左秘書高疏寮得處州  其一','釋居簡','宋','宋诗','song-poetry','','[]','一水分吳越，幽思可得分。',48,'全唐诗/poet.song.180000.json','["一水分吳越，幽思可得分。", "軟紅援汩汩，堅白掃紜紜。", "富卷投囊草，芳餘辟蠹芸。", "傍池雙宿鷺，留得水邊雲。"]'),
('3c0c7c36-bb66-4545-b221-e837bac1c784','送侍左秘書高疏寮得處州  其二','釋居簡','宋','宋诗','song-poetry','','[]','詩人去作州，需次小遲留。',48,'全唐诗/poet.song.180000.json','["詩人去作州，需次小遲留。", "風物忺題品，江山怕攪搜。", "竹凉深處榻，荈釅醉時甌。", "見說三巖好，因書話勝游。"]'),
('d73812f2-8e05-4e47-8ca3-f96421d0e3a6','送宋左曹得溫州  其一','釋居簡','宋','宋诗','song-poetry','','[]','翁居藩輔久，叔年又相先。',48,'全唐诗/poet.song.180000.json','["翁居藩輔久，叔年又相先。", "萬石不足數，一燈無別傳。", "家聲青瑣闥，風味赤城仙。", "好是猿啼處，霞標最近天。"]'),
('853c7f8d-d034-4928-8879-0c6ba0469360','送宋左曹得溫州  其二','釋居簡','宋','宋诗','song-poetry','','[]','數峯江上青，宜雨亦宜晴。',48,'全唐诗/poet.song.180000.json','["數峯江上青，宜雨亦宜晴。", "著意畫難就，助人吟易成。", "縣官懷近郡，郎署暫專城。", "况是烹鮮手，襦歌屢有聲。"]'),
('cd3970fd-7cb4-46bf-a27f-5543604f4a9a','寄安撫曹觀使  其一','釋居簡','宋','宋诗','song-poetry','','[]','君子不宜閑，閑中有節文。',48,'全唐诗/poet.song.180000.json','["君子不宜閑，閑中有節文。", "檢方醫竹瘦，圖蔓發蘭薰。", "見說新添鶴，頻留欲去雲。", "應無浮俗事，嘈雜玷清聞。"]'),
('9d428a14-3641-472c-a536-906cfc235901','寄安撫曹觀使  其二','釋居簡','宋','宋诗','song-poetry','','[]','篔簹抱節癯，風味似樓居。',48,'全唐诗/poet.song.180000.json','["篔簹抱節癯，風味似樓居。", "自是宦情薄，容教杯酒疎。", "掃除新築室，收拾舊觀書。", "何必陶元亮，斜陽自荷鉏。"]'),
('f69e86db-56fe-49f6-b992-0a0514d04320','孤山彭高士借榻','釋居簡','宋','宋诗','song-poetry','','[]','萬籟笙鏞一枕秋，幌雲垂地月痕收。',32,'全唐诗/poet.song.180000.json','["萬籟笙鏞一枕秋，幌雲垂地月痕收。", "偶然做得還鄉夢，夢見鴻濛與道游。"]'),
('b08234f4-e80d-47de-89d0-8c2ab0453339','月渚','釋居簡','宋','宋诗','song-poetry','','[]','秀色老千岩，窗虛小鬰藍。',48,'全唐诗/poet.song.180000.json','["秀色老千岩，窗虛小鬰藍。", "水明收晚照，沙暝展晴嵐。", "野餉隠淪共，清游名勝談。", "中秋無好友，舉酒便成三。"]'),
('4398ffd1-dfe6-4d48-98dc-0beb839cefba','寄福州李伯達','釋居簡','宋','宋诗','song-poetry','','[]','江漢歸來重訪尋，貂裘未弊亦塵侵。',64,'全唐诗/poet.song.180000.json','["江漢歸來重訪尋，貂裘未弊亦塵侵。", "碧眸憎俗重扃戶，白羽扇凉一援琴。", "池草易生苕水夢，蓴羹難老故鄉心。", "有書若問東陽瘦，記遣神林問惠琳。"]'),
('a286ccb0-f0ec-4418-9a53-4f1eebb46fb4','輝船窗見過','釋居簡','宋','宋诗','song-poetry','','[]','北宕戒壇纔稅駕，過湖問路扣吾廬。',64,'全唐诗/poet.song.180000.json','["北宕戒壇纔稅駕，過湖問路扣吾廬。", "櫂侵葑畛輕於葉，策盡松陰緩當車。", "圖上衆香和露寫，袖中經卷殺金書。", "飛來更踐重來約，莫遣山靈訝闊疎。"]'),
('9c3ba6fa-7e30-402b-87f5-072cb23de18a','送魏貳卿之靜州','釋居簡','宋','宋诗','song-poetry','','[]','一其所二一成非，揆以人情萃必睽。',64,'全唐诗/poet.song.180000.json','["一其所二一成非，揆以人情萃必睽。", "鏡豈有心私應物，楚如不衆敢咻齊。", "瘦欹雪萼難諧俗，勁錯霜根弗肯低。", "岣嶁芳塵猶可襲，賸收赤箭就刀圭。"]'),
('b6adad82-9d02-43e4-9371-7c093a290576','春柳睡鵲鴝鵒圖','釋居簡','宋','宋诗','song-poetry','','[]','麴塵縷縷鵲深棲，寫出章臺二月時。',32,'全唐诗/poet.song.180000.json','["麴塵縷縷鵲深棲，寫出章臺二月時。", "幽響不知何處喜，一聲鴝鵒聖先知。"]'),
('e8cb799e-0ac8-4441-9ed2-6b722f43d951','破山高僧塔','釋居簡','宋','宋诗','song-poetry','','[]','寺倚四僧傳，僧今已蛻蟬。',48,'全唐诗/poet.song.180000.json','["寺倚四僧傳，僧今已蛻蟬。", "塔隨蓁棘老，德與苾蒭全。", "翠滴添衣重，雲低染屨鮮。", "何年山脊斷，飛去玉蜿蜒。"]'),
('18d91836-3af1-4dda-91a3-cc45e8ef368e','破山瓔珞檜','釋居簡','宋','宋诗','song-poetry','','[]','雪枝新縱縱，霜子舊玲玲。',48,'全唐诗/poet.song.180000.json','["雪枝新縱縱，霜子舊玲玲。", "漙露煩添綴，縈風緩剪零。", "貫珠煩蟻度，編貝倩誰經。", "瑶草隨山盡，來尋千歲苓。"]'),
('f5e933c8-c17e-458b-8a26-bcf11b7bdf98','酬趙西里游虎丘  其一','釋居簡','宋','宋诗','song-poetry','','[]','相携上鬰峩，舟似葉隨波。',48,'全唐诗/poet.song.180000.json','["相携上鬰峩，舟似葉隨波。", "寺壓秋痕瘦，雲沉古跡多。", "遠舒高處望，清遞隔船歌。", "盡寫吳中勝，新吟細濯磨。"]'),
('3c713c5f-c635-4737-97b0-9c060390a249','酬趙西里游虎丘  其二','釋居簡','宋','宋诗','song-poetry','','[]','曾說劍池游，風煙入校讎。',48,'全唐诗/poet.song.180000.json','["曾說劍池游，風煙入校讎。", "臺孤頭點石，窞迥趾翻鰌。", "彩鷁山前棹，青鸞水上樓。", "暮關須小待，款曲盡觥籌。"]'),
('b6963556-2d31-48d2-805c-239274c7777a','蠡口','釋居簡','宋','宋诗','song-poetry','','[]','未謀人國已謀身，往事無從問水濱。',64,'全唐诗/poet.song.180000.json','["未謀人國已謀身，往事無從問水濱。", "游鹿諄諄猶在耳，平湖淼淼忽揚塵。", "寺明丹堊低簷古，樹飽風霜老節新。", "又理闔閭城外櫂，更無鷗鳥傍青綸。"]'),
('5f082384-c1da-49e2-a2a6-706bf5ff8565','楓橋酬張季思','釋居簡','宋','宋诗','song-poetry','','[]','欲喚扁舟一訪尋，開窗同揖小猊岑。',64,'全唐诗/poet.song.180000.json','["欲喚扁舟一訪尋，開窗同揖小猊岑。", "風晴墮葉聲應燥，目遠孤鴻影易沉。", "餐爲菊英聊緩带，醉因雪萼小低簪。", "隔溪半夜疎鐘到，定有清新入短吟。"]'),
('38e275b8-cc7a-4ba2-a6b7-13f2482c4983','分題畫策得山茶','釋居簡','宋','宋诗','song-poetry','','[]','綠枝丹葉未春回，生色潛隨采筆開。',32,'全唐诗/poet.song.180000.json','["綠枝丹葉未春回，生色潛隨采筆開。", "欲伴高文歸大冊，道山延閣小蓬萊。"]'),
('d6534c60-82a8-483f-9811-61b30370de8d','寄三衢使君趙寺丞','釋居簡','宋','宋诗','song-poetry','','[]','刺史天開卷暝雲，凜姿如玉照人明。',64,'全唐诗/poet.song.180000.json','["刺史天開卷暝雲，凜姿如玉照人明。", "蓬萊地近異塵世，箕潁風高凝古情。", "度外峻超千文俗，春來又勸一年耕。", "屏藩王室皆同姓，况是金甌覆姓名。"]'),
('7008bc5d-2702-46ec-ab8a-42784e2d6d58','續賦祥鑒義梅花','釋居簡','宋','宋诗','song-poetry','','[]','香國開樓居，桃李合戍邊。',96,'全唐诗/poet.song.180000.json','["香國開樓居，桃李合戍邊。", "移根賞奇怪，屢舞却錦纏。", "靜聞竺友吟，粲若春雪妍。", "暗馥騰鶴膝，蒼蘚腥蝸涎。", "既明紅紫倫，更秉薰蕕權。", "壠樹寒自零，苑柳暖自眠。", "逶蛇木蘭後，揖遜凌波前。", "凌波不忍去，步月時蹁躚。"]'),
('54e211f9-54a6-48be-b832-476e328a6dd1','復老歸東嘉予亦治還蜀之裝賦別湖上','釋居簡','宋','宋诗','song-poetry','','[]','華風不常煖，華月豈常曜。',240,'全唐诗/poet.song.180000.json','["華風不常煖，華月豈常曜。", "泠泠弗鳴條，冏冏自反照。", "野馬空瞇目，爝火謾騰耀。", "誰結螢囊口，寒原並秋燒。", "誰枵土囊腹，夜壑哀萬竅。", "向邇雖暫熱，憑力亦易悄。", "悠然付靜勝，了不直一笑。", "山林隠君子，浮俗固殊調。", "華風起蘋末，華月挂林表。", "既安雲霾妬，疇忍塵雜擾。", "角嘆一麟足，鶚洗百鷙少。", "弱水三萬里，蓬萊眼中小。", "况夫左傳癖，舉世不足樂。", "亦復烟霞痼，沉綿頗相肖。", "云胡去留柄，坐困佞壬褭。", "揮手從此別，掉頭莫回眺。", "愛惜雙眉厖，脫略萬事了。", "龍翔解懸榻，雁宕拓吟徼。", "摩挲送鴻目，擲棄連鰲釣。", "雲來寄心思，臨風一長嘯。"]'),
('c1d4a35f-6ac4-40b5-ad10-114acecd1a9d','書六一居士歸田圖','釋居簡','宋','宋诗','song-poetry','','[]','賦田中樂駕言歸，勇决如何得似詩。',32,'全唐诗/poet.song.180000.json','["賦田中樂駕言歸，勇决如何得似詩。", "詩後退之盤谷序，畫成猶是未歸時。"]'),
('1c28dde7-2387-46b2-a8de-250afea07e20','孤山後','釋居簡','宋','宋诗','song-poetry','','[]','采鷁浮春皓齒歌，延祥觀後晚偏多。',32,'全唐诗/poet.song.180000.json','["采鷁浮春皓齒歌，延祥觀後晚偏多。", "可無人物如張緒，只是垂楊不似他。"]'),
('cf224b4e-35c1-4944-864b-a6cfeaa4902e','石林諸孫葉子雲左手法二王逸蹟不下右手','釋居簡','宋','宋诗','song-poetry','','[]','桐軒法鍾王，人鮮出其右。',180,'全唐诗/poet.song.180000.json','["桐軒法鍾王，人鮮出其右。", "出奇左運腕，亦復龍蛇走。", "悠然伸勁畫，壯甚紫鐵鈕。", "番然變道古，古藤瘦牽糾。", "輕墨蔓如縷，大者大如斗。", "故家翰墨場，有此擅場手。", "星星滿青鏡，入眼未始有。", "四支同一初，視聽有常守。", "執捉與踐履，造次各先後。", "云何互其用，落落便相偶。", "猶來幽人心，冏冏浄不垢。", "衡從一機透，衆妙俱輻輳。", "逢原蓋自得，左右均去取。", "枝葉隨根本，股肱副元首。", "一身小天地，默窺元化母。"]'),
('7c16456d-e929-4d2e-aa08-ef588cdeaf49','盧次夔下第','釋居簡','宋','宋诗','song-poetry','','[]','得失見君心，令人恨滿膺。',48,'全唐诗/poet.song.180000.json','["得失見君心，令人恨滿膺。", "諸賢品華玉，四字獨蒼蠅。", "留取攙前步，來居向上層。", "趁將春未去，載酒嘯吟明。"]'),
('89b3dfa3-df1b-4d03-9984-6bab25175686','杜鵑','釋居簡','宋','宋诗','song-poetry','','[]','舊草堂東水竹西，年年只與落花期。',32,'全唐诗/poet.song.180000.json','["舊草堂東水竹西，年年只與落花期。", "長亭今夜聲連曉，愁似經年病拾遺。"]'),
('5bfb457c-2abd-4223-88bd-a7f6449d68b4','橫翠閣','釋居簡','宋','宋诗','song-poetry','','[]','闌干曲曲西，待得夕陽遲。',48,'全唐诗/poet.song.180000.json','["闌干曲曲西，待得夕陽遲。", "展畫真成贅，無詩却不宜。", "鴻雖供晚眺，月欠掃新眉。", "安得泠然御，來觀烟雨時。"]'),
('a7a21c19-2a81-456b-a633-2962568a2db7','太守陳中書問彰教近况','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','徐君舊剪茅，小小亦堪巢。',120,'全唐诗/poet.song.180000.json','["徐君舊剪茅，小小亦堪巢。", "野客便招隠，閑情賦解嘲。", "村疎難得友，葵熟易爲庖。", "鼓吹分蛙部，琅玕長竹梢。", "瘦尋殘火種，冗剔故書抄。", "北崦雖移檄，西湖未絕交。", "貧優寧似負，推固不如敲。", "自審如衡石，誰能較斗筲。", "曲池風力皺，缺甃蘚文凹。", "曾枉行春旆，芳題滿近郊。"]'),
('64563eae-6b40-4157-8b72-8fc85fb56e16','陪陳中書游兩仙堂','釋居簡','宋','宋诗','song-poetry','','[]','透雲兩鴻鵠，何年忽卑飛。',276,'全唐诗/poet.song.180000.json','["透雲兩鴻鵠，何年忽卑飛。", "指爪泥上留，弗與歲月移。", "大聲疾璆琳，萬竅不敢嘶。", "琅然答空山，玲然震清溪。", "俯仰半千載，日日春菲菲。", "緒餘及草木，草木竟莫知。", "坐令萬金産，不直五字奇。", "江左數六謝，選中輒見推。", "清新輩阿連，亦豈媿客兒。", "開元天寶間，有客償心期。", "玉頹沈香北，健筆揮珠璣。", "天威不可奪，人爵不可縻。", "此邦非故鄉，每至輒倦歸。", "樓居寄逸想，更較先後爲。", "有美池上仙，凜凜岩壑姿。", "轍飛兩公後，惄若饑渴思。", "作堂肖公像，疊嶂雙溪西。", "幻出天上人，對峙玉羽衣。", "乾坤浩蕩春，盎盎在兩眉。", "清冰照人冷，恍如吟嘯時。", "泠泠氣欲仙，擬馽游龍騎。", "世隘烏足容，才大不得施。", "至今騷雅流，臨風揮涕洏。"]'),
('79e6eaf8-3c76-446b-98ee-40beab02f181','淡墨水仙梔子  其一','釋居簡','宋','宋诗','song-poetry','','[]','爍石流金記曝根，古壺疏插煮泉溫。',32,'全唐诗/poet.song.180000.json','["爍石流金記曝根，古壺疏插煮泉溫。", "翠扶柔玉春無力，獨與華風伴月痕。"]'),
('d725539b-922f-41b8-b8ec-573d4006eb79','淡墨水仙梔子  其二','釋居簡','宋','宋诗','song-poetry','','[]','六萼敷腴透玉明，六柧垂實趁秋零。',32,'全唐诗/poet.song.180000.json','["六萼敷腴透玉明，六柧垂實趁秋零。", "衆香醖藉須彈壓，笑挽凌波賦鶺鴒。"]'),
('a25707f4-230d-4ec2-aa10-9175bfcbb2a1','陳紫微赴召  其一','釋居簡','宋','宋诗','song-poetry','','[]','帝輟詞臣重撫綏，次邊尤軫大江陲。',64,'全唐诗/poet.song.180000.json','["帝輟詞臣重撫綏，次邊尤軫大江陲。", "百篇斗酒玩萬物，十雨五風終四朞。", "謠頌不遺纖悉美，形容難盡許多奇。", "縱龜放鶴朝天去，豈獨江東列郡師。"]'),
('b3876234-4e02-45b1-acde-05e94bde8e70','陳紫微赴召  其二','釋居簡','宋','宋诗','song-poetry','','[]','苦心如檗凜於冰，贏得衝冠雪一簪。',64,'全唐诗/poet.song.180000.json','["苦心如檗凜於冰，贏得衝冠雪一簪。", "千載四明登陸處，三生五月度瀘心。", "清泠烈暑生秋思，諧協凉薰入正音。", "今日憚公如憚黯，試看塞柝夜沈沈。"]'),
('272efc66-50b8-4902-8f9a-e847548e9f99','陪陳紫微麻姑觀','釋居簡','宋','宋诗','song-poetry','','[]','不憚朱砂九轉遲，絕憐岣嶁令君癡。',32,'全唐诗/poet.song.180000.json','["不憚朱砂九轉遲，絕憐岣嶁令君癡。", "一抔幻出新舂玉，更聽人言狡獪爲。"]'),
('3aaeb2e8-d2e8-4242-bc5e-3a58fbbcc3f4','題粲姪峴山秋晚','釋居簡','宋','宋诗','song-poetry','','[]','分明寫出峴山詩，隴樹初寒晚照低。',32,'全唐诗/poet.song.180000.json','["分明寫出峴山詩，隴樹初寒晚照低。", "掩卷只思人墮泪，不思量到白銅鞮。"]'),
('3d5553d9-f853-463f-b3e7-dac9de20774b','續當涂別駕林率菴賦謫仙李翰林','釋居簡','宋','宋诗','song-poetry','','[]','齪齪復齪齪，未死如未生。',156,'全唐诗/poet.song.180000.json','["齪齪復齪齪，未死如未生。", "公去月明在，留得青山塋。", "青山倚公高，屹立千載英。", "翠巘拓吟壘，飛瀑按酒兵。", "行客一仰止，折幾鄙吝萌。", "狂歌長短吟，邁古日月明。", "俊逸兼鮑謝，麗則儕雲卿。", "驊騮博艷姬，土苴群方兄。", "節峻玄霜嚴，義重紫禁輕。", "酹土土長燥，雷魁何由平。", "生男禁多才，此話聞阿庚。", "真才棄如土，大厦誰支傾。", "不用謝安石，大雅空垂名。"]'),
('f775ef09-6ae4-4a72-8a80-f744cfa0eb79','白荷花','釋居簡','宋','宋诗','song-poetry','','[]','數畮澄漪不用耕，移根玉井不曾耘。',32,'全唐诗/poet.song.180000.json','["數畮澄漪不用耕，移根玉井不曾耘。", "羽衣何處霓裳徧，翠蓋參差踏水雲。"]'),
('a58a2fcd-82d7-4518-91d9-14f9be83cee1','白蓮雨後漸衰','釋居簡','宋','宋诗','song-poetry','','[]','曉池芳柄褭殘馨，褪雨欹風鷺委翎。',32,'全唐诗/poet.song.180000.json','["曉池芳柄褭殘馨，褪雨欹風鷺委翎。", "碧展一奩秋練練，似憐玉色鏡中零。"]'),
('82ca005e-548d-41da-877a-5ebd0adfa549','送趙丞','釋居簡','宋','宋诗','song-poetry','','[]','歸裝又逐西凉去，輕省還如赴上時。',64,'全唐诗/poet.song.180000.json','["歸裝又逐西凉去，輕省還如赴上時。", "廉者固宜疎住計，富哉只有送行詩。", "貼天自與鵷鴻舉，鉗紙誰容雁鶩欺。", "它日宣城廳壁記，巋然一樣斗山思。"]'),
('060f396d-7447-41e8-bd42-ea5c36bd8643','三角亭','釋居簡','宋','宋诗','song-poetry','','[]','成規與俗殊，鼎足外無餘。',48,'全唐诗/poet.song.180000.json','["成規與俗殊，鼎足外無餘。", "曲是從前惡，圓非近日疎。", "神山分檻小，槐影直簷虛。", "要識其中趣，明明舉一隅。"]'),
('f320a774-30cc-4bef-86ad-8ad41032b6ad','憶水芙蓉木芙蓉寄西湖諸友  其一','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','竹凉池館綠荷風，同看吳宮小隊紅。',32,'全唐诗/poet.song.180000.json','["竹凉池館綠荷風，同看吳宮小隊紅。", "少却亂紅深處櫂，西陵橋北斷橋東。"]'),
('5e693bc0-8d31-46fc-b4f3-4d13de09d5be','憶水芙蓉木芙蓉寄西湖諸友  其二','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','花滿秋城闖水明，鏡中滴露掌中零。',32,'全唐诗/poet.song.180000.json','["花滿秋城闖水明，鏡中滴露掌中零。", "曾讎新詠游花下，寫寄城中石與丁。"]'),
('42e482c1-da82-43cd-acb4-ed5f9cb1e39a','灞橋風雪圖','釋居簡','宋','宋诗','song-poetry','','[]','橋滑馿僵噤不嘶，詩窮弗死反窮詩。',32,'全唐诗/poet.song.180000.json','["橋滑馿僵噤不嘶，詩窮弗死反窮詩。", "華山也是吟疆土，更欲煩君寫倒騎。"]'),
('f788f0c0-322c-47e2-87f6-b30949e119aa','次韻林別駕  其一','釋居簡','宋','宋诗','song-poetry','','[]','官分長貳榮，樂事勝專城。',48,'全唐诗/poet.song.180000.json','["官分長貳榮，樂事勝專城。", "避俗如僧定，尋仙結伴行。", "吟疆寬處拓，醉玉醒時傾。", "擬叶塤箎響，邯鄲步不成。"]'),
('9f61a0b9-cc5c-4e16-9f56-de3e687a3a8b','次韻林別駕  其二','釋居簡','宋','宋诗','song-poetry','','[]','往住溪頭寺，曾陪太一舟。',48,'全唐诗/poet.song.180000.json','["往住溪頭寺，曾陪太一舟。", "港收天影縮，橋礙浦雲流。", "練石聲聲月，丹楓片片秋。", "砌蛩添苦思，吟動瀼西愁。"]'),
('c2dca1c7-6c2f-48ba-bc44-cb768a376c88','次韻謝學士','釋居簡','宋','宋诗','song-poetry','','[]','凜姿行復偉衣冠，螭亦何曾恥暫蟠。',64,'全唐诗/poet.song.180000.json','["凜姿行復偉衣冠，螭亦何曾恥暫蟠。", "入夢少曾忘博約，得書多是報平安。", "雪零短髮新尤甚，盟近黄花舊不寒。", "肯入亂山相勞苦，密雲香鬰破團團。"]'),
('cbf5aafc-1abf-4883-825c-4511e3200658','對菊寄王常博','釋居簡','宋','宋诗','song-poetry','','[]','鮮風嫩日養芳新，來會閑人九日盟。',64,'全唐诗/poet.song.180000.json','["鮮風嫩日養芳新，來會閑人九日盟。", "相澤畔吟騰曉馥，就花中隠著脩名。", "碧浮賸嗅茱萸醁，黄落誰摇沆瀣英。", "商素雅爲仁者壽，薦甘𣂏碧輔清明。"]'),
('2321d0cd-1774-45c1-b87a-3b0c47ca86bc','題張雪湖吳山煖曖','釋居簡','宋','宋诗','song-poetry','','[]','山藏晻靄樹藏雲，十駕難追欲去春。',32,'全唐诗/poet.song.180000.json','["山藏晻靄樹藏雲，十駕難追欲去春。", "鱗砌古愁千萬緒，因君開卷又重新。"]'),
('6a292e23-63ba-4cd0-b554-ec104297f14d','次韻玉堂盧蒲江省中木犀','釋居簡','宋','宋诗','song-poetry','','[]','一種分蟾各自知，人間不似省中枝。',64,'全唐诗/poet.song.180000.json','["一種分蟾各自知，人間不似省中枝。", "繁英盡委開仍好，幽馥先來去又遲。", "雨後莫忘秋曉步，風鮮曾約夜凉吹。", "小山縱有淮南賦，可是蓬山欠景差。"]'),
('a16bf879-690a-4dbd-b512-225978033f7d','盧蒲江雪夜約同直省中出示采菊讀書煎茶種橘四詩索危秘書諸名勝同賦  其一','釋居簡','宋','宋诗','song-poetry','','[]','拙須務速巧須遲，盡巧依稀與拙宜。',32,'全唐诗/poet.song.180000.json','["拙須務速巧須遲，盡巧依稀與拙宜。", "除却藝蘭紉楚佩，反騷只有落英詩。"]'),
('5c4499cc-b3b9-4081-aa12-8f67ee00be9b','盧蒲江雪夜約同直省中出示采菊讀書煎茶種橘四詩索危秘書諸名勝同賦  其二','釋居簡','宋','宋诗','song-poetry','','[]','糝葵負腹媿便便，偶上蓬萊借榻眠。',32,'全唐诗/poet.song.180000.json','["糝葵負腹媿便便，偶上蓬萊借榻眠。", "夢過子雲還問字，夢醒龍液冷無煙。"]'),
('a02c010b-a5e4-45aa-8814-87f9a167e3ab','盧蒲江雪夜約同直省中出示采菊讀書煎茶種橘四詩索危秘書諸名勝同賦  其三','釋居簡','宋','宋诗','song-poetry','','[]','亭亭古砌剪霜苔，密瑣疎櫺冷不開。',32,'全唐诗/poet.song.180000.json','["亭亭古砌剪霜苔，密瑣疎櫺冷不開。", "紗帽籠頭防俗客，小團新錫上方來。"]'),
('87fa73a7-b8f9-4c38-9454-29acfef9748e','盧蒲江雪夜約同直省中出示采菊讀書煎茶種橘四詩索危秘書諸名勝同賦  其四','釋居簡','宋','宋诗','song-poetry','','[]','青壓低枝欲破香，秋遲風燥未曾霜。',32,'全唐诗/poet.song.180000.json','["青壓低枝欲破香，秋遲風燥未曾霜。", "枳蕃江北令人笑，更試仙山與道鄉。"]'),
('6be18ec7-34b4-4603-bc12-8b20d213adcc','聞雪湖張簽判訃','釋居簡','宋','宋诗','song-poetry','','[]','嘉興陸長官，遺我尺素書。',212,'全唐诗/poet.song.180000.json','["嘉興陸長官，遺我尺素書。", "報云鈞天詔九地，奪我好友張雪湖。", "雪湖翩翩上天去，下眎塵滓知何如。", "因依未去時，泠然山澤癯。", "萬象困搜攪，撚斷蒼髯鬚。", "十年不調閉戶居，鐵石不受煙火腴。", "辟俗如辟豕負塗，後來稍稍低簪裾，百步掩鼻猶反趨。", "官高金多嬌妻奴，蠛蠓亂眼才斯須。", "填門只有長者車，北海尊酒無時無。", "明朝一飯欠宿儲，印泥指爪嗟鴻鵠。", "精明定化爲蘭菊，紉稱騷人陸離佩，英泛綠尊澆魁雷。", "騷人之腹秋蟬清，吐芳騰馥日日新。", "紛紛郁郁仍輪囷，散爲天地無邊春。"]'),
('f3eef63b-011c-4857-8734-b8de1b586e7f','吳提幹之官淛東','釋居簡','宋','宋诗','song-poetry','','[]','叔季振華裾，晶晶照上都。',48,'全唐诗/poet.song.180000.json','["叔季振華裾，晶晶照上都。", "對床風送雨，隔岸越分吳。", "池草冰澌煖，庭萱玉色腴。", "綵帆飛曉鏡，拂拭賀家湖。"]'),
('05531a6a-4597-4dba-aed2-dc9910544b7c','吳狀元赴闕屬陳兼僉催送行語','釋居簡','宋','宋诗','song-poetry','','[]','細把前朝聖政推，婁教龍首到黄扉。',64,'全唐诗/poet.song.180000.json','["細把前朝聖政推，婁教龍首到黄扉。", "自南渡後從頭數，比舊京時過眼稀。", "磊砢固當爲世用，風雲端不與人違。", "采薇只在丁山下，亟佇青鸞入翠微。"]'),
('d81720c9-d8bd-4abc-adc4-8867616c785d','白藕花寄袁狀元倉使','釋居簡','宋','宋诗','song-poetry','','[]','澄練徹山脈，玉透山池沙。',48,'全唐诗/poet.song.180000.json','["澄練徹山脈，玉透山池沙。", "老火奮殘爍，凜姿燉不瑕。", "方方秋一奩，彈壓紅萬葩。", "安得濂溪叟，來賦東林花。"]'),
('d61c6774-9e67-412b-9a32-046bc8fa1f90','立秋前一日蛩響','釋居簡','宋','宋诗','song-poetry','','[]','火孕金英眇未抽，學吟先報短檠秋。',32,'全唐诗/poet.song.180000.json','["火孕金英眇未抽，學吟先報短檠秋。", "傍窗褭褭清如縷，明日西風一樣愁。"]'),
('d2b99908-7227-4b04-a30e-2413673bf68e','寧國奉聖寺有許渾舊題','釋居簡','宋','宋诗','song-poetry','','[]','題擅玉臺賓，山名益著聞。',48,'全唐诗/poet.song.180000.json','["題擅玉臺賓，山名益著聞。", "禽珍騰逸響，草異薦奇芬。", "壁可曾留錫，簷栖欲去雲。", "塵囂避三舍，不度碧溪濆。"]'),
('54372c42-2ed6-4946-a5e1-c2693d738c9d','次復齋奚左藏補陁岩寺韻寺有象鼻岩渴霓皆佳致','釋居簡','宋','宋诗','song-poetry','','[]','當年聚石賦全提，斷處飛梁險處梯。',64,'全唐诗/poet.song.180000.json','["當年聚石賦全提，斷處飛梁險處梯。", "鐵展霓腰疑水竭，玉伸象準卷雲低。", "危於漢使回車坂，深似秦人避亂溪。", "鐘梵殷床連夜旦，相忘猿鳥各安棲。"]'),
('1022cc37-d871-4f9a-a30a-77a7a16dfef7','石如虹至水際余名之曰渴霓','釋居簡','宋','宋诗','song-poetry','','[]','直舒千尺怒谽谺，高貼雲根枕水涯。',32,'全唐诗/poet.song.180000.json','["直舒千尺怒谽谺，高貼雲根枕水涯。", "水竭欲飛仍小住，砰轟欲跨阿香車。"]'),
('2b892d5c-195f-4082-9c45-2ac37d3c4d17','復齋墳前左顧石龜','釋居簡','宋','宋诗','song-poetry','','[]','寬罾密罔斷江流，好在雲藏莫浪游。',32,'全唐诗/poet.song.180000.json','["寬罾密罔斷江流，好在雲藏莫浪游。", "我欲黄金如斗大，斬新左顧鑄餘不。"]'),
('e02f4f93-1fcd-4310-b433-4a8e8c49e81e','清隠寺乳泉','釋居簡','宋','宋诗','song-poetry','','[]','脈通九地各東西，洗缽曾分牧女糜。',32,'全唐诗/poet.song.180000.json','["脈通九地各東西，洗缽曾分牧女糜。", "萬斛從來不擇地，試看一滴汎華池。"]'),
('3c1c5b44-7ae7-4fdc-bc14-4363bb61f09a','仁壽堂','釋居簡','宋','宋诗','song-poetry','','[]','闊開蕩蕩城中天，朝菌靈椿總大年。',32,'全唐诗/poet.song.180000.json','["闊開蕩蕩城中天，朝菌靈椿總大年。", "鑿井耕田皆帝力，不知誰黨復誰偏。"]'),
('953a7ebc-fcb6-4d85-b0a0-bd60defdf39b','奉聖寺江閣','釋居簡','宋','宋诗','song-poetry','','[]','散衣江閣撫疎簷，吹徹西凉已屬饜。',32,'全唐诗/poet.song.180000.json','["散衣江閣撫疎簷，吹徹西凉已屬饜。", "得隴未終還望蜀，半規更待月纖纖。"]'),
('30ae8a9e-7d64-4fe1-bf53-603d471bb318','隠山','釋居簡','宋','宋诗','song-poetry','','[]','小嶺明明屬小支，傍山論價與山違。',32,'全唐诗/poet.song.180000.json','["小嶺明明屬小支，傍山論價與山違。", "巢由去後箕山老，夜夜天雲隠少微。"]'),
('edff6c41-0245-4f5e-8e88-ed941baad0fe','酬當涂何戶曹畏齋金陵三篇見寄兼柬餉臺上幕許從道  其一','釋居簡','宋','宋诗','song-poetry','','[]','山木凌秋似鬢蒼，靜觀浮俗飽炎凉。',64,'全唐诗/poet.song.180000.json','["山木凌秋似鬢蒼，靜觀浮俗飽炎凉。", "喚回猨鶴彈三疊，話到陳隋笑幾場。", "雲度閑情疑路斷，草生奇馥染林香。", "莫乘殘照催歸騎，白下留門慣漏長。"]'),
('ff89e45b-7596-4497-a32f-966b3b7dece9','酬當涂何戶曹畏齋金陵三篇見寄兼柬餉臺上幕許從道  其二','釋居簡','宋','宋诗','song-poetry','','[]','筆耕白首不逢年，間得新題似得仙。',64,'全唐诗/poet.song.180000.json','["筆耕白首不逢年，間得新題似得仙。", "磨透鐵泓空費力，吟殘金薤弗成篇。", "未忘陋巷希瞠若，不信長虹死浩然。", "小駐行雲聊寄恨，莫爲愁雨濕吳天。"]'),
('4a9ea0e2-73e4-4182-a87e-99647d33ffba','酬當涂何戶曹畏齋金陵三篇見寄兼柬餉臺上幕許從道  其三','釋居簡','宋','宋诗','song-poetry','','[]','松根葛藟亟扳緣，勢極青冥恨不前。',64,'全唐诗/poet.song.180000.json','["松根葛藟亟扳緣，勢極青冥恨不前。", "鶑閟好音春不響，鶴嫌遺臭夜移眠。", "回頭華表一千載，開眼檀蘿十九年。", "想見息陰羞惡木，斷魂嶺海吊諸賢。"]'),
('bc04d9a8-7eb1-4c41-9e89-91c7834eb251','克己齋','釋居簡','宋','宋诗','song-poetry','','[]','罔念聖爲狂，醫狂亦有方。',48,'全唐诗/poet.song.180000.json','["罔念聖爲狂，醫狂亦有方。", "正逵遵穩審，私孽殄微茫。", "蛻俗嗟封殻，耘心破畛疆。", "它山石攻玉，日用細平章。"]'),
('43b3aff0-bac4-4a1e-bf45-2b8a9dbbb3ff','雪屋','釋居簡','宋','宋诗','song-poetry','','[]','霰集夜來寒，樓寬楮幌鮮。',48,'全唐诗/poet.song.180000.json','["霰集夜來寒，樓寬楮幌鮮。", "花溫新換水，栗爆舊存氊。", "夢草疑非蝶，吟肩凍聳鳶。", "蓬婆界天白，皎皎五雲連。"]'),
('332eb896-ff0b-47b9-b897-44cf226354fa','麗雲閣','釋居簡','宋','宋诗','song-poetry','','[]','零雲閑占地，飛閣小侵天。',48,'全唐诗/poet.song.180000.json','["零雲閑占地，飛閣小侵天。", "目與孤鴻去，帆驅短艇還。", "綠蕪秋野外，烏戍夕陽邊。", "只尺闌干曲，丹青色色全。"]'),
('3b20cb36-80cf-4803-aac8-59c7cc1a6b06','西菩寺三題  其一','釋居簡','宋','宋诗','song-poetry','','[]','蹱息如龜小作巢，霜零竺子綠雲交。',32,'全唐诗/poet.song.180000.json','["蹱息如龜小作巢，霜零竺子綠雲交。", "六爻動著如雲變，輒莫其中動一爻。"]'),
('fe4836df-b655-4382-be20-ecc94c7abfb4','西菩寺三題  其二','釋居簡','宋','宋诗','song-poetry','','[]','本來無垢亦無塵，塵垢皆從洗處生。',32,'全唐诗/poet.song.180000.json','["本來無垢亦無塵，塵垢皆從洗處生。", "衮衮潢流湛華月，朣朧無夜不鮮明。"]'),
('a0f871c8-1e47-4e02-9504-49c94f6b1171','西菩寺三題  其三','釋居簡','宋','宋诗','song-poetry','','[]','蚤覺元龍不足豪，泠然步武老嫌高。',32,'全唐诗/poet.song.180000.json','["蚤覺元龍不足豪，泠然步武老嫌高。", "刺天婁見群蜚下，欲駟晴霓看抃鰲。"]'),
('68b115af-23fd-4426-877c-d32b8cd48adf','江東李倉使節制移淛東倉使','釋居簡','宋','宋诗','song-poetry','','[]','千輻紋邊著意深，龍門檀越讖重臨。',64,'全唐诗/poet.song.180000.json','["千輻紋邊著意深，龍門檀越讖重臨。", "旋螺數髮爲公壽，卍字捫胸印此心。", "玉節生風淮岸曲，金輪碾霧越山陰。", "誠明空覺曾無間，磁石巖巖一寸針。"]'),
('0d6fd188-5b62-4f3c-8474-03a4ae8dafaa','喜雪賀趙守  其一','釋居簡','宋','宋诗','song-poetry','','[]','不見鮮明剪綠漪，焦勞夙夜動精祈。',64,'全唐诗/poet.song.180000.json','["不見鮮明剪綠漪，焦勞夙夜動精祈。", "臘殘雖缺三回白，歲閏何妨十日遲。", "孰謂天高催不得，自知心感弗曾疑。", "靜中覷破玄冥巧，留作新春第一奇。"]'),
('cb853e96-fa3b-46fb-bd40-3d811aa24522','喜雪賀趙守  其二','釋居簡','宋','宋诗','song-poetry','','[]','擬絮因風又擬鹽，只今此話可曾拈。',64,'全唐诗/poet.song.180000.json','["擬絮因風又擬鹽，只今此話可曾拈。", "待將巧思形容盡，合避新條比類嫌。", "褪煖已先雲懵澒，挾寒相次雨廉纖。", "落梅聲裏渾如晝，冏冏橫陳透玉蟾。"]'),
('c6646e6d-af40-471a-8a04-856e36e32ffd','送春','釋居簡','宋','宋诗','song-poetry','','[]','曆頭恰恰三月小，銷減欲去未行春。',32,'全唐诗/poet.song.180000.json','["曆頭恰恰三月小，銷減欲去未行春。", "祖帳不知春去處，清苕拍拍柳晶晶。"]'),
('b8c7be9e-713e-4802-b935-85a738749a71','開田','釋居簡','宋','宋诗','song-poetry','','[]','曩說琛師邁往賢，不將大義答開田。',64,'全唐诗/poet.song.180000.json','["曩說琛師邁往賢，不將大義答開田。", "欲懲後世人尸素，敢昧前修自棄捐。", "把似誕謾規信施，何如勤苦佐豐年。", "钁頭邊事超今古，僥倖逢年是偶然。"]'),
('9da5f6e0-81a1-483d-945c-c2789c8af73a','孺子祠堂','釋居簡','宋','宋诗','song-poetry','','[]','鈎黨開端慘弗舒，懸知隠逸未全疎。',64,'全唐诗/poet.song.180000.json','["鈎黨開端慘弗舒，懸知隠逸未全疎。", "姦諛孔熾吾何與，名節雖高弊不除。", "盟鷺相忘尋水宿，冥鴻那復死巢居。", "瀾翻平地渾漂汩，柰此悠然一葉虛。"]'),
('d8be539f-b51e-4c53-837c-97ed7c549f05','竹里','釋居簡','宋','宋诗','song-poetry','','[]','一畝摇湘綠，漪漪與靜宜。',48,'全唐诗/poet.song.180000.json','["一畝摇湘綠，漪漪與靜宜。", "避人酬橘隠，延月賦襟期。", "鶴至自華表，客來歌竹枝。", "謝家蘭玉富，不似錦綳兒。"]'),
('b12d4acc-6cb1-4b87-81ba-cfb1431d49ea','酬盧直院新荷','釋居簡','宋','宋诗','song-poetry','','[]','愛此青錢小，移舟傍淺湄。',48,'全唐诗/poet.song.180000.json','["愛此青錢小，移舟傍淺湄。", "團青迎浴佛，脆綠未巢龜。", "翠幄鈿孤鏡，瑶田葑四維。", "微風翻嫩紫，半捲欲開時。"]'),
('c2606186-9526-4f13-a32c-41a5dcdbdfcd','泣楊承奉','釋居簡','宋','宋诗','song-poetry','','[]','車纔閉戶成，輪未碾青冥。',48,'全唐诗/poet.song.180000.json','["車纔閉戶成，輪未碾青冥。", "蘭夭騰餘馥，蕭榮獨欠馨。", "方看過秦手，續草太玄經。", "早惜黄陳死，無人哭小邢。"]'),
('1ad51ec8-af28-4733-83f5-b9ac454d1d6e','任大卿出龍眠度水羅漢','釋居簡','宋','宋诗','song-poetry','','[]','故家尋釣鰲，遺俗問佛世。',180,'全唐诗/poet.song.180000.json','["故家尋釣鰲，遺俗問佛世。", "喜逢十六人，不聞四句偈。", "風姿如隠槃，服御乃古制。", "開卷發遐想，瞪目得熟睨。", "絕溪將安之，深厲淺則揭。", "岸登植瘦策，石踞整壞毳。", "預流逮無學，勸進憚勞勩。", "巋然望等妙，迢遞苦跋疐。", "悠悠馬不前，亹亹駕輒稅。", "弗悟燕安毒，遂失遠大計。", "雙林受遺託，久視不得逝。", "豈知古龍象，所向必超詣。", "弗踐極則處，弗到弗小憇。", "朅來吊形影，相與話情契。", "丁寧勇著鞭，同振木方袂。"]'),
('8977a4e9-c8b9-4911-9dfa-a15cf5329ee9','出入韻寄陸溧陽','釋居簡','宋','宋诗','song-poetry','','[]','溧陽令尹果誰歟，陸少蓬翁小伯魚。',64,'全唐诗/poet.song.180000.json','["溧陽令尹果誰歟，陸少蓬翁小伯魚。", "佳客來時須問字，丈人好處略瞻烏。", "俸錢撙節開家集，官事那容讀父書。", "獨欠舊時窮少府，琴堂相對撚吟鬚。"]'),
('fc39a5ff-46f4-43b8-ba66-6c14ea4b5d40','插田','釋居簡','宋','宋诗','song-poetry','','[]','秧撒纔成後，溝塍蒞事初。',48,'全唐诗/poet.song.180000.json','["秧撒纔成後，溝塍蒞事初。", "淺車防岸缺，密插趁行疎。", "處處隣相饁，喬喬莠旋除。", "夕陽歸牧豎，牛背數舂鉏。"]'),
('45c3b3d1-c597-428c-b88b-5d413b0a916e','刈麥','釋居簡','宋','宋诗','song-poetry','','[]','恨入崆峒渺，偏於麥熟時。',48,'全唐诗/poet.song.180000.json','["恨入崆峒渺，偏於麥熟時。", "謬將勤補拙，愧在素仍尸。", "仰識陰陽足，豐酬餠餌思。", "秋高禾黍實，不與宿根期。"]'),
('6ecbd04a-9660-49ec-a572-5e8baa589061','靈隠方丈新閣接泗洲妙崧毀之','釋居簡','宋','宋诗','song-poetry','','[]','鄉來屋老拊巖稜，欲上看山謝不能。',64,'全唐诗/poet.song.180000.json','["鄉來屋老拊巖稜，欲上看山謝不能。", "衡跨半天開複道，直從平地到危層。", "上方近聽嬰兒語，前塔遥分竺寺燈。", "昨晚亂雲收急雨，憑高如望海濤崩。"]'),
('fcef2d60-948c-4e09-b02b-50dd2d3089d4','長興大雄寺陳朝檜','釋居簡','宋','宋诗','song-poetry','','[]','霜皮重複裹莓苔，不見君王過沛來。',64,'全唐诗/poet.song.180000.json','["霜皮重複裹莓苔，不見君王過沛來。", "好處莫非前輩道，後生知是幾時栽。", "陰分背鄉青如舊，心愈剛明死弗灰。", "却恐登壇騷雅絕，亭亭似把碧油開。"]'),
('2d9f8d86-da79-44c2-a615-01cd5984fbcc','泣錢長官竹岩  其一','釋居簡','宋','宋诗','song-poetry','','[]','十年同約故園歸，指點雲西鳳翥奇。',64,'全唐诗/poet.song.180000.json','["十年同約故園歸，指點雲西鳳翥奇。", "錦綉裹山懷舊俗，琅玕披腹吐新詩。", "更無人悼淹翔屈，只有天爲慷慨知。", "令尹子丈三已矣，悠然喜慍不曾移。"]'),
('db39e98c-7943-48d8-a420-aee4c6fc3136','泣錢長官竹岩  其二','釋居簡','宋','宋诗','song-poetry','','[]','掉鞅英躔並雋游，大巫皇恤小巫羞。',64,'全唐诗/poet.song.180000.json','["掉鞅英躔並雋游，大巫皇恤小巫羞。", "未將所學酬知己，先與他人作忌囮。", "譛舌不中投虎兕，絡頭長恨死驊騮。", "山林獨有男兒泪，可是無情涕泗流。"]'),
('d8a04059-1947-4c87-9775-52f99114ee0f','寄趙仁和','釋居簡','宋','宋诗','song-poetry','','[]','劇繁迎刃聽裁剸，化自京師守令宣。',64,'全唐诗/poet.song.180000.json','["劇繁迎刃聽裁剸，化自京師守令宣。", "處默有聲長殷殷，所聞無善不拳拳。", "戚聯閶闔天雖近，下若滄溟德更淵。", "任是靈椿根力淺，也應凡草不齊年。"]'),
('7e95c6ff-27f3-4966-aa3e-077c0b8dcfa8','即事','釋居簡','宋','宋诗','song-poetry','','[]','竹扉半掩不須敲，掠面融風著柳梢。',32,'全唐诗/poet.song.180000.json','["竹扉半掩不須敲，掠面融風著柳梢。", "燕子不知春寂寞，自銜泥補去年巢。"]'),
('403c75f9-1780-4458-ac9d-9281fcd0e3dd','一菴','釋居簡','宋','宋诗','song-poetry','','[]','太極含三示極談，初無一字可名菴。',32,'全唐诗/poet.song.180000.json','["太極含三示極談，初無一字可名菴。", "明明未畫前消息，才落思惟便別參。"]'),
('0463f77a-9f83-4755-ba7c-6c16afb9c673','和睡翁鞏仲至賦頤蒙齋贈澄元妙','釋居簡','宋','宋诗','song-poetry','','[]','靜倚松門掩夕霏，不知求己去求誰。',64,'全唐诗/poet.song.180000.json','["靜倚松門掩夕霏，不知求己去求誰。", "翳花旋掃無留蔕，蒙吝纔消即善頤。", "彖象尚堪明古意，茅茨聊復傍寒漪。", "是中餘地藏緘默，何處人間更有詩。"]'),
('f34e00c9-574f-4802-89e0-c66b6cf00e26','竹岩賦孫谷橋墦間圖人徒知獻諛可罪竹岩取受諛者併按','釋居簡','宋','宋诗','song-poetry','','[]','寧圖豕負塗，毋寫乞墦圖。',204,'全唐诗/poet.song.180000.json','["寧圖豕負塗，毋寫乞墦圖。", "枉著迂奇思，徒將媿賤夫。", "矯情工諂媚，失計墮闚閾。", "逐鹿身忘反，亡羊口謾糊。", "飽雖令己王，饑解把人驅。", "毫髮無新計，朝晡只故吾。", "有如扳佞倖，寧復顧揶揄。", "竭澤先崇貨，傾城後進姝。", "匿瑕彰外潔，飾詐護中洿。", "豕燎難逃虱，城崩孰縱狐。", "知幾屬明哲，先物在斯須。", "寵數占忘醴，歸心憶膾鱸。", "東籬懷醉令，故態舍狂奴。", "鴻聽雲沈跡，龜寧尾曳塗。", "盍觀薇蕨瘦，弗與割烹殊。", "不智方能諂，非愚肯受諛。", "欲邀天爵貴，廉恥乃菑畬。"]'),
('41c3c913-ed1c-4837-a96c-f0244016f29d','拙齋','釋居簡','宋','宋诗','song-poetry','','[]','大巧曾聞竊得靈，主司關籥鎮隨身。',32,'全唐诗/poet.song.180000.json','["大巧曾聞竊得靈，主司關籥鎮隨身。", "巧還有盡無如拙，却笑天孫未識真。"]'),
('93779281-4aaa-4ac1-a09c-720ff3cb9e66','盧玉堂報遣人問訊水心','釋居簡','宋','宋诗','song-poetry','','[]','用舍見人物，抑見天地心。',132,'全唐诗/poet.song.180000.json','["用舍見人物，抑見天地心。", "生人於此時，所繫亦以深。", "時哉薄其祐，全力吾不任。", "向來鄒魯人，抱此空沉吟。", "此身眇如芥，列國紛於鍼。", "芥鍼求抵當，機括常差參。", "沒身雖不遭，道在終不沉。", "朣朣千丈光，照耀不啻今。", "公乎鄒魯傳，軒冕如山林。", "我亦山中人，不忍鳳鳥瘖。", "加餐爲公禱，以答天地心。"]'),
('fe7c0a83-766b-4770-958b-dc02d9f12dd7','聞謝司直晦齋赴闕','釋居簡','宋','宋诗','song-poetry','','[]','謝老久不見，引領谿雲隅。',120,'全唐诗/poet.song.180000.json','["謝老久不見，引領谿雲隅。", "想隨鵷鷺行，華簪小踟躕。", "薄俸不暇給，素約不願餘。", "棋局消日長，局終還擁書。", "書中有何好，剔抉排根株。", "飛電老逾碧，分毫惜居諸。", "一燈伊洛傳，冏冏分庭除。", "鄉來鯨吸川，今也川泳魚。", "靖節老止酒，亦復自荷鉏。", "悠然羲皇上，不知今何如。"]'),
('f40220ef-a025-473a-b836-be00deb869e6','謝晦齋倅嘉興','釋居簡','宋','宋诗','song-poetry','','["\u592a\u6e56"]','春風藝蘭茝，采采山之阿。',120,'全唐诗/poet.song.180000.json','["春風藝蘭茝，采采山之阿。", "廣庭拓餘地，華風日編摩。", "芳潔漸可冀，榛莽常婆娑。", "紫芽茁新馥，薰蕕相錯摩。", "引類連根株，圖蔓費斧柯。", "何知種植勤，苦心忘鬢皤。", "九畹與百畮，恨少不恨多。", "薿薿謝庭玉，比德元同科。", "餘光燭槜李，散采摇清波。", "太湖跨三州，如此明月何。"]'),
('466b1aee-00da-43fb-9e83-aa43e1210057','浄照律師葬母塚上生芝十二莖關子長縯倚松饒德操賦詩後九十餘載余亦賦','釋居簡','宋','宋诗','song-poetry','','[]','尸羅爲源孝爲根，一根豈止十二莖。',96,'全唐诗/poet.song.180000.json','["尸羅爲源孝爲根，一根豈止十二莖。", "沉香亭北爛繒綺，浪花浮蘂爭欣榮。", "喑喑泪滴塚上土，只有天知此心苦。", "地靈薦瑞天不靳，付與千人萬人覩。", "詩人史法語不浮，旌孝筆端回萬牛。", "紫芝不老亦不槁，兩公之詩更新好。"]'),
('3873a081-1ec5-4bfe-b8a5-280414d57f0b','櫂歌','釋居簡','宋','宋诗','song-poetry','','[]','後夜朣朧魄載生，官塘猶自有人行。',32,'全唐诗/poet.song.180000.json','["後夜朣朧魄載生，官塘猶自有人行。", "十年滴盡征人泪，不盡彎彎月子聲。"]'),
('cf275af6-1697-4d7b-96c4-025ee7f7dd74','悼志首座','釋居簡','宋','宋诗','song-poetry','','[]','花雨散初筵，歸來耨寸田。',48,'全唐诗/poet.song.180000.json','["花雨散初筵，歸來耨寸田。", "行空梁複道，拓地閣諸天。", "木槁春長在，爐冰火不然。", "旦評溪上寺，猶自說耆年。"]'),
('456d4329-4d96-42e9-84e3-6f47f4fd9235','送趙栖巖分司池陽總幹','釋居簡','宋','宋诗','song-poetry','','[]','九華空衆山，尤物在塵寰。',48,'全唐诗/poet.song.180000.json','["九華空衆山，尤物在塵寰。", "迥出雲雨上，朝來眉睫間。", "有人皆毓勝，無豹不藏斑。", "官舍軒楹豁，憑闌莫掩關。"]'),
('3c16a87a-423c-4d2a-98c9-1727093ab1c8','鳳翥行','釋居簡','宋','宋诗','song-poetry','','[]','破輿不窗簾不旌，短長後先白四丁。',128,'全唐诗/poet.song.180000.json','["破輿不窗簾不旌，短長後先白四丁。", "旋牽毳衲裹秋鬢，月露點滴垂青冥。", "平明驅入三家市，市人驚見左右視。", "笑云非病亦非狂，不與人同與人異。", "抑非湖海空橘陳，不老不死亦不靈。", "不然天台石橋寺，丹碧剝落泥應真。", "須臾一棹脩門去，却遣破輿歸鳳翥。", "謂言只借此樣僧，非此樣僧莫借與。"]'),
('e5f9c72d-95e0-46c7-8c8b-023ee9b49af7','於潛尉陳時齋獲賊','釋居簡','宋','宋诗','song-poetry','','[]','小隊氣晶晶，平常白面生。',48,'全唐诗/poet.song.180000.json','["小隊氣晶晶，平常白面生。", "沈冤資大勇，凶膽折先聲。", "山鬼晨猶寐，隣厖夜不驚。", "歷陽窮少府，此話恐難并。"]'),
('800a769c-a294-4cc2-84e8-8d37914c59fb','九日','釋居簡','宋','宋诗','song-poetry','','[]','西風只識黄花面，不識登臨吊古心。',32,'全唐诗/poet.song.180000.json','["西風只識黄花面，不識登臨吊古心。", "空打孟嘉烏帽落，挂人唇齒到如今。"]'),
('f74ea40d-4c10-4074-b241-de1380a11fa2','寄寒泉','釋居簡','宋','宋诗','song-poetry','','[]','貧則安之豈病焉，乘桴未暇况箋天。',64,'全唐诗/poet.song.180000.json','["貧則安之豈病焉，乘桴未暇况箋天。", "翰林足避將軍污，內史灰從廷尉然。", "口伐固應無大敵，筆耕元自有豐年。", "講明人爵君何欠，只欠蘇司業酒錢。"]'),
('eb6fd8dc-181b-43a3-9661-b3b8718f8980','後潘','釋居簡','宋','宋诗','song-poetry','','[]','後潘水上竺仙家，領客來分竹裏茶。',32,'全唐诗/poet.song.180000.json','["後潘水上竺仙家，領客來分竹裏茶。", "明日歸時須記取，白蘋賸采半開花。"]'),
('01d7cf28-5ff3-485c-b93b-a0f51b2c4df2','前彎','釋居簡','宋','宋诗','song-poetry','','[]','反關蓬蓽了殘書，弗到前彎一月餘。',32,'全唐诗/poet.song.180000.json','["反關蓬蓽了殘書，弗到前彎一月餘。", "不見蓼花紅照水，安知秋色到西余。"]'),
('b7ec49c3-8224-46f4-b2a2-37d11a0a8f82','九日','釋居簡','宋','宋诗','song-poetry','','[]','瓦鼎松聲漲苦荼，替杯中物泛茱萸。',32,'全唐诗/poet.song.180000.json','["瓦鼎松聲漲苦荼，替杯中物泛茱萸。", "白衣不識緇衣客，自擷寒英插古壺。"]'),
('572b90c7-49c2-423a-afa8-fb96cf560010','霜曉','釋居簡','宋','宋诗','song-poetry','','[]','江楓霜後醉痕朝，商略隨風趁落潮。',32,'全唐诗/poet.song.180000.json','["江楓霜後醉痕朝，商略隨風趁落潮。", "勾引梧桐三四樹，不留一葉到今朝。"]'),
('ca683871-be72-4ce1-bbd2-7ca39544a173','廣教不厭亭','釋居簡','宋','宋诗','song-poetry','','[]','眼挂層巒醉益青，旋疑身是出山雲。',32,'全唐诗/poet.song.180000.json','["眼挂層巒醉益青，旋疑身是出山雲。", "一泉一石忘情地，都作鴻溝與俗分。"]'),
('fc51e1e3-2d56-4302-a278-b512861fc8f5','趙府錄官滿  其一','釋居簡','宋','宋诗','song-poetry','','[]','平反固盡情，此話久彌新。',48,'全唐诗/poet.song.180000.json','["平反固盡情，此話久彌新。", "動以中爲的，居嫌恕寡隣。", "暗螢方自照，屈蠖倩誰伸。", "好在庭前樹，長懷雪後春。"]'),
('14e8b4b3-ed3b-4299-bfcc-19363d5265de','趙府錄官滿  其二','釋居簡','宋','宋诗','song-poetry','','[]','蕭洒宣城掾，仙源似布韋。',48,'全唐诗/poet.song.180000.json','["蕭洒宣城掾，仙源似布韋。", "欲疏伊洛正，不與父兄違。", "霧隠雖如晦，胎仙弗願肥。", "暮雲無限思，金溜一竿微。"]'),
('6d3a4ba1-cf77-4bdd-96b5-d87e6b42fc87','送沈少卿','釋居簡','宋','宋诗','song-poetry','','[]','懷哉小隠侯，如水秋練練。',96,'全唐诗/poet.song.180000.json','["懷哉小隠侯，如水秋練練。", "又若廉泉廉，練江靦言面。", "一介不取人，振滯亦賑貧。", "秉彜不可奪，實德無虛名。", "我欲借寇君，九虎限天海。", "不知穹壤間，誰是寇君代。", "行行拜新渥，新紉紫荷橐。", "何以爲雙壽，楊州一雙鶴。"]'),
('cd3e2307-cb78-4d52-ac90-e9ef425ea09c','按曲圖','釋居簡','宋','宋诗','song-poetry','','[]','八繭蠶抽獨繭絲，舞衣嫌重要纖絺。',32,'全唐诗/poet.song.180000.json','["八繭蠶抽獨繭絲，舞衣嫌重要纖絺。", "君王自按霓裳曲，直到坡前駐馬時。"]'),
('8619515b-8c69-4577-82a3-3ae590d7eba7','移梅','釋居簡','宋','宋诗','song-poetry','','[]','雪消時候带花移，花笑移遲不振奇。',32,'全唐诗/poet.song.180000.json','["雪消時候带花移，花笑移遲不振奇。", "今歲弗須嫌早計，趁它一點未開時。"]'),
('239aa1d8-a5a3-4119-b657-b2e93bad6bde','移梅竹謝彰教寺事','釋居簡','宋','宋诗','song-poetry','','[]','蒼玉根連白玉條，濕雲冉冉碧蕭蕭。',64,'全唐诗/poet.song.180000.json','["蒼玉根連白玉條，濕雲冉冉碧蕭蕭。", "花含鼎實宜先發，節笑心空貴後凋。", "友此雙清同日種，聽它六出幾時飄。", "不如楊柳江邊樹，惠淺恩疎怨不消。"]'),
('f6137de2-cd18-4629-a0a0-cb8dee7de0cb','畫虎行','釋居簡','宋','宋诗','song-poetry','','[]','是中毒厲無停輈，更復外爲物我謀。',96,'全唐诗/poet.song.180000.json','["是中毒厲無停輈，更復外爲物我謀。", "汝寧殘暴我寧爾，爪距銛利何從投。", "形與氣侔天所命，陽盪陰摩成厥性。", "劃然殘暴反其初，一瞬回頭如失影。", "影不隨形竟何有，直與太虛爲戶牖。", "李生解衣盤礴時，筆端別有百步威。"]'),
('f6aee2ea-ed44-4367-a5e2-ece6a4f603a6','代人挽竹岩錢長官','釋居簡','宋','宋诗','song-poetry','','[]','絕筆走龍蛇，光寒瘴水涯。',48,'全唐诗/poet.song.180000.json','["絕筆走龍蛇，光寒瘴水涯。", "賦寧爲問鵩，騷不反懷沙。", "秋老半巖竹，春歸三縣花。", "誅姦埋古鐵，英識欠張華。"]'),
('4dbe95aa-ee47-4031-bb57-1af9fdf1c862','代人與趙倉使','釋居簡','宋','宋诗','song-poetry','','[]','江淮倚襄沔，兩紀當分拏。',288,'全唐诗/poet.song.180000.json','["江淮倚襄沔，兩紀當分拏。", "皇天憗一老，一正遺萬差。", "長城蔽江漢，雙駿騰渥洼。", "英靈萃千載，智勇出一家。", "以德不以威，以靜不以譁。", "以信不以欺，以儉不以奢。", "躋人上衽席，含哺相咿啞。", "胡馬飲江水，獰飈掃蒹葭。", "月明戍樓嘯，風急秋城笳。", "邊勳一夔老，史筆五色花。", "遺烈在伯仲，奎畫崇褒嘉。", "遞迭吹塤箎，嘈雜空淫哇。", "玉節飛先聲，一道爭傳誇。", "單騎造閶闔，三舍日未斜。", "野䔩飯山舘，龜手疲馬檛。", "霰雪皴衣稜，敢憚千里遐。", "雙旌與五馬，所至弓刀遮。", "慘舒出顧盼，輝光生齒牙。", "笑公後其樂，白日無精華。", "次邊隔江東，糴湧無從賒。", "赫炎苗不蘇，瀲灧圬不芽。", "紫葵圃不畦，黄粟山不畬。", "扶携及襁褓，顛踣如蓬麻。", "相看盡菜色，槁立疑帝豝。"]'),
('f3ba0c3a-80b1-4fa1-a7d1-7d670b2850ef','聞澗泉韓仲止訃','釋居簡','宋','宋诗','song-poetry','','[]','霣團華月鎖重雲，底處朣朣魄載新。',64,'全唐诗/poet.song.180000.json','["霣團華月鎖重雲，底處朣朣魄載新。", "空使霜蟾同轉轂，不容玉斧伴修輪。", "身雖全節扃泉戶，天亦何心死谷神。", "窗外竹間梅數樹，爲誰消減雪中春。"]'),
('7ed71aa6-16b0-469e-af07-ef86e6d92e37','謝江東丘少卿漕使','釋居簡','宋','宋诗','song-poetry','','[]','宣城阡陌連當涂，山田瘦瘠圬田腴。',192,'全唐诗/poet.song.180000.json','["宣城阡陌連當涂，山田瘦瘠圬田腴。", "築塍作圬九十四，頻年風水圬爲湖。", "圬中饑氓水入戶，私迫公催猛如虎。", "三分更索水花苗，名色創聞氓不諭。", "流移轉徙道邊泣，併日不能謀一食。", "有生誰弗惜天年，望望誰寬倒懸急。", "江東使者愁上眉，惄然軫懷若調饑。", "疾呼官吏訪田里，蠲租除賦甦顛隮。", "勸糶開倉賑寒餓，氓命垂垂出湯火。", "貪殘俗吏漫窺窬，狡獪猾胥成㦬懡。", "家家禱公願公壽，千億子孫天地久。", "宣城彰教住山人，斐然相此歌謠聲。"]'),
('20a2eb04-e6a6-4999-b5e0-d6f222deb2e5','別宣城元僚府掾二趙柬諸名勝三十韻','釋居簡','宋','宋诗','song-poetry','','[]','大緘遣吏牘，小緘手自抄。',288,'全唐诗/poet.song.180000.json','["大緘遣吏牘，小緘手自抄。", "兩緘九鼎重，只覓一把茅。", "把茅住山人，莫識所以然。", "或云爾當去，雲毳風翩翩。", "問之何因爾，拱默俟風旨。", "就列乃陳力，尸素輒屏棄。", "靜推尸素元，展轉竟未安。", "一日不自營，一日不敢餐。", "竹疎不肯蕃，梅瘦不肯肥。", "豆瘠不加實，菊瘁不受醫。", "種植係勤墮，肥瘠繄天時。", "極力敢不勉，强智終奚爲。", "年年縣官租，急不啻星火。", "今年水粘天，經冬首陽餓。", "人言爾何愚，冉冉霜茁顱。", "料不閲墳典，豈暇觀奇書。", "所學昧日損，區區使人忿。", "不識諸方玄，况復衆妙本。", "列剎鼓鍾沸，四方走檀施。", "問爾胡不然，我則異於是。", "孄安只牧牛，琛師獨種田。", "老農與老圃，聖智願學焉。", "日日洗缽盂，吾豈尸吾廬。", "丁寧勿它斥，只斥山澤癯。"]'),
('567b0e87-e814-4b97-bd08-c0af8f4721b5','百喜圖','釋居簡','宋','宋诗','song-poetry','','[]','比翼飛梁跨碧潯，玉繩低轉夜沈沈。',32,'全唐诗/poet.song.180000.json','["比翼飛梁跨碧潯，玉繩低轉夜沈沈。", "一年一度叢霄去，却下人間送好音。"]'),
('5428c21a-5a21-43c9-abcc-a8785ec362ae','謝權府惠府判辨祖相死於邸中非商賈者  其一','釋居簡','宋','宋诗','song-poetry','','[]','跼蹐復跼蹐，何以昌山林。',48,'全唐诗/poet.song.180000.json','["跼蹐復跼蹐，何以昌山林。", "華風日遄邁，謬恐山不深。", "層巢墮孤鶵，一壺藐千金。", "苦心念惸獨，霣涕翻秋淫。"]'),
('fe197572-7935-4fa1-b111-5e78431efeea','謝權府惠府判辨祖相死於邸中非商賈者  其二','釋居簡','宋','宋诗','song-poetry','','[]','天書少室價，賈豎晞天恩。',48,'全唐诗/poet.song.180000.json','["天書少室價，賈豎晞天恩。", "一錢一滴蜜，不甜雲水僧。", "冰檗寧苦寒，貨殖其何能。", "炎岡鎮烈烈，玉石難分明。"]'),
('b686af70-a54f-4ac2-b0bc-58b8821b0e57','二月十三大雪','釋居簡','宋','宋诗','song-poetry','','[]','婁慶嘉平白，中春入眼疎。',48,'全唐诗/poet.song.180000.json','["婁慶嘉平白，中春入眼疎。", "玄冥疑倒置，古史豈忘書。", "凍抑花慵笑，顰嗟柳不舒。", "物稀端是瑞，瑞應不宜虛。"]'),
('4a801884-7e0c-44d7-a479-531a49e1fbd2','送江西倉使魏奏院','釋居簡','宋','宋诗','song-poetry','','[]','養廉便似挂衣冠，數米晨炊度百囏。',64,'全唐诗/poet.song.180000.json','["養廉便似挂衣冠，數米晨炊度百囏。", "一節易爲千里別，萬金難售十年閑。", "舊從石筍曾招隠，新種梅花試住山。", "老去益高華玉價，區區少室謾追攀。"]'),
('25db5d0b-f698-4784-a593-efbf64b72067','題水仙梨花菊蒲萄梔子  其一','釋居簡','宋','宋诗','song-poetry','','[]','澄鮮無地著樓居，自惜娉婷鏡碧虛。',32,'全唐诗/poet.song.180000.json','["澄鮮無地著樓居，自惜娉婷鏡碧虛。", "青女不知華玉煖，綠扶綽約翠霞裾。"]'),
('c7210939-508a-4901-9478-320dc6aea95f','題水仙梨花菊蒲萄梔子  其二','釋居簡','宋','宋诗','song-poetry','','[]','楚楚冰綃霧縠裳，鉛華消盡弗忺粧。',32,'全唐诗/poet.song.180000.json','["楚楚冰綃霧縠裳，鉛華消盡弗忺粧。", "曉雲不入朝雲夢，賦入閑居亦擅芳。"]'),
('12bce018-c8ac-477e-939d-ffff12fde315','題水仙梨花菊蒲萄梔子  其三','釋居簡','宋','宋诗','song-poetry','','[]','蕭爽花中舊隠淪，名齊宿莽著騷經。',32,'全唐诗/poet.song.180000.json','["蕭爽花中舊隠淪，名齊宿莽著騷經。", "殘英只傍枝頭老，收拾芳鮮飽獨醒。"]'),
('85946e51-e6ef-4853-86ea-1bb993f14453','題水仙梨花菊蒲萄梔子  其四','釋居簡','宋','宋诗','song-poetry','','[]','藤搴翠朵剪輕柔，小壓涓涓翠玉流。',32,'全唐诗/poet.song.180000.json','["藤搴翠朵剪輕柔，小壓涓涓翠玉流。", "一石可償千日醉，凉州未必似楊州。"]'),
('5228c7f0-0156-4a60-8d4a-af9946e26116','題水仙梨花菊蒲萄梔子  其五','釋居簡','宋','宋诗','song-poetry','','[]','嫩玉溫柔浄弗瑕，凉雲綴葉借春華。',32,'全唐诗/poet.song.180000.json','["嫩玉溫柔浄弗瑕，凉雲綴葉借春華。", "水風池閣簾櫳靜，小試微薰著一花。"]'),
('f938e689-20a2-4944-9512-5f3f7cd7bff7','采石吊古','釋居簡','宋','宋诗','song-poetry','','[]','高情付酒巵，心事洗咸池。',48,'全唐诗/poet.song.180000.json','["高情付酒巵，心事洗咸池。", "醉誤飛蟾急，吟嗟取日遲。", "竟天鵬不展，酌海蠡奚爲。", "風月三千首，何須竹帛垂。"]'),
('091360f1-7698-49e1-89f9-4a0711e2b73f','就以道池上假山','釋居簡','宋','宋诗','song-poetry','','[]','數朵忽橫翔，雲生午樹凉。',48,'全唐诗/poet.song.180000.json','["數朵忽橫翔，雲生午樹凉。", "恍如江上畫，移向澤中藏。", "絮落魚翻影，花飛蝶趁香。", "却疑閑日月，只在此間長。"]'),
('52c5b44f-8afc-48fb-851e-9e98d0dcb4f3','送碧雲菴主歸江西','釋居簡','宋','宋诗','song-poetry','','[]','碧雲獨擅香城勝，近與唐朝處士隣。',64,'全唐诗/poet.song.180000.json','["碧雲獨擅香城勝，近與唐朝處士隣。", "舊出山來空蕙帳，今回首去厭京塵。", "菊荒尚有霜前馥，荼老寧無雨後新。", "勞苦玉泓清淺了，解嘲怨鶴斷猨嗔。"]'),
('ebb19956-aa43-4ad7-9de5-1a642395eafe','賀曹秘監','釋居簡','宋','宋诗','song-poetry','','[]','隴蜀歸來寵更隆，舊盟鷗鷺望鵷鴻。',64,'全唐诗/poet.song.180000.json','["隴蜀歸來寵更隆，舊盟鷗鷺望鵷鴻。", "一時父子俱佳士，異代師生各少蓬。", "芸不用防新蠹損，腹須頻曬曉曈矓。", "道山自是樓居樣，還與岷峨一笑同。"]'),
('3ddae45d-67c9-4753-a559-11431773dcfe','謝陳紫薇致香秔一再寵和仍次韻  其一','釋居簡','宋','宋诗','song-poetry','','[]','精瓊老瓦汰沉沙，蜂掠殘零晚未衙。',64,'全唐诗/poet.song.180000.json','["精瓊老瓦汰沉沙，蜂掠殘零晚未衙。", "功謝囊中餐玉法，鉢分天上縯綸家。", "蔓雖引去徐留蔕，鞭欲行來嫩挑芽。", "野蔌衆多煩飣餖，敢從一筯萬錢誇。"]'),
('82910078-b7a6-40f0-8705-50245c4f9387','謝陳紫薇致香秔一再寵和仍次韻  其二','釋居簡','宋','宋诗','song-poetry','','[]','一掬甘泉煮白沙，群峯秀整似排衙。',64,'全唐诗/poet.song.180000.json','["一掬甘泉煮白沙，群峯秀整似排衙。", "無錢買帖臨求米，背俗論交類喪家。", "續遣新吟欺白雪，又如活火剪黄芽。", "海商不惜兼金價，傳向雞林國裏誇。"]'),
('3af5d96e-819f-44ab-95ab-d0b7a0e005ca','謝陳紫薇致香秔一再寵和仍次韻  其三','釋居簡','宋','宋诗','song-poetry','','[]','可能擲米化丹砂，更記人間早晚衙。',64,'全唐诗/poet.song.180000.json','["可能擲米化丹砂，更記人間早晚衙。", "腰欲直伸輕五斗，供慙素餐漫千家。", "清新變雅多奇態，鄙吝消它幾許芽。", "不是鳳池提此話，紛紛浮俗浪傳誇。"]'),
('d6d1868a-6dac-484d-9054-73d060cf385a','送趙西里官滿歸永嘉','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','宣城歸到西湖寺，朋舊如沙散不收。',64,'全唐诗/poet.song.180000.json','["宣城歸到西湖寺，朋舊如沙散不收。", "盟鷺又隨西里遠，驚猿空伴北山愁。", "同途好友須題品，可意佳篇便獻酬。", "摘得甘花煩見寄，趁它大火未西流。"]'),
('aee5fb70-13ef-47c6-852f-5b6e03299dee','寄處州高使君疎寮','釋居簡','宋','宋诗','song-poetry','','[]','鑄劍湖東景緯明，蜿蜒飛去水猶腥。',64,'全唐诗/poet.song.180000.json','["鑄劍湖東景緯明，蜿蜒飛去水猶腥。", "欲從正脈疏清鏡，不信同流有濁涇。", "千騎道山僊部曲，三岩畫幅老丹青。", "一帆送客供吟眺，數盡長亭與短亭。"]'),
('55c7eba1-c9fb-4b5e-8e44-de855a2798d5','石窗','釋居簡','宋','宋诗','song-poetry','','[]','凝厭綺疎塵，玲瓏沓數櫺。',48,'全唐诗/poet.song.180000.json','["凝厭綺疎塵，玲瓏沓數櫺。", "櫺風隨絮入，隙月带雲零。", "煖靄寒猶重，秋聲夜不扃。", "掃除平整處，欲了客兒經。"]'),
('ace8cda5-6173-490d-a1d5-16370e247960','枝巢','釋居簡','宋','宋诗','song-poetry','','[]','欲掃囂塵跡，枚條自改門。',48,'全唐诗/poet.song.180000.json','["欲掃囂塵跡，枚條自改門。", "籟虛秋斷續，花冷月黄昏。", "鳩拙休相笑，鴻冥倘可捫。", "逍遥與齊物，一等不須論。"]'),
('89adb952-304a-460e-ba5a-d5c27617b73d','史孟博作軒','釋居簡','宋','宋诗','song-poetry','','[]','崔嵬方駿奔，斗次又鵬騫。',48,'全唐诗/poet.song.180000.json','["崔嵬方駿奔，斗次又鵬騫。", "紫翠新如染，青巉俯可援。", "雲低天漸近，雷怒雨隨翻。", "變化才俄頃，何須問化元。"]'),
('c88f6915-7496-41d1-a93c-27d71b09fb32','寄嚴州陸使君','釋居簡','宋','宋诗','song-poetry','','[]','新棠陰接舊棠陰，獨向千峯榭上吟。',64,'全唐诗/poet.song.180000.json','["新棠陰接舊棠陰，獨向千峯榭上吟。", "厚俗工夫聊變雅，無弦音響付知心。", "雲開老兔纔飛上，塵避靈犀不敢侵。", "老釣磯前清可鏡，星星應未點華簪。"]'),
('e8099515-0ee9-4470-b4fa-a189e381101b','曲肱室','釋居簡','宋','宋诗','song-poetry','','[]','妄覬或逢周，華胥掉鞅游。',48,'全唐诗/poet.song.180000.json','["妄覬或逢周，華胥掉鞅游。", "戰蝸甘死敵，蝑蟻竟生侯。", "白晝嘲便腹，清談到枕流。", "無人在陋巷，誰識黑甜羞。"]'),
('dbf24122-1dd4-4b0e-9a34-6af7af368a79','贈鄭尊聖','釋居簡','宋','宋诗','song-poetry','','[]','束髮親前輩，三朝習舊聞。',48,'全唐诗/poet.song.180000.json','["束髮親前輩，三朝習舊聞。", "橐虛藏缺研，刻斷綴殘文。", "耆古尋無跡，嗟今獨有君。", "憐君貧似我，分贈只溪雲。"]'),
('483c42b1-50c6-49c0-9307-d0ae04738eaf','唁趙恕可府錄丁母夫人憂  其一','釋居簡','宋','宋诗','song-poetry','','[]','江東尋勝日，月幌怕寒侵。',48,'全唐诗/poet.song.180000.json','["江東尋勝日，月幌怕寒侵。", "步轉屏陰玉，花挑蘂盡金。", "區區留客意，的的愛兒心。", "有子母不死，因君感更深。"]'),
('87f7a167-151e-42bf-ae69-4be64186591a','唁趙恕可府錄丁母夫人憂  其二','釋居簡','宋','宋诗','song-poetry','','[]','懿質閑貞訓，宗閨著令儀。',48,'全唐诗/poet.song.180000.json','["懿質閑貞訓，宗閨著令儀。", "子蕃知必貴，隣好爲頻移。", "素節尊勤儉，彤椽吐倔奇。", "滔滔東注恨，何日是還期。"]'),
('8c98c886-9a08-485b-b1dc-532dee0b446c','菊磵卜居','釋居簡','宋','宋诗','song-poetry','','[]','王師且願休，小爲蕺山留。',48,'全唐诗/poet.song.180000.json','["王師且願休，小爲蕺山留。", "五月凉時過，千岩勝處游。", "子耕無父業，弟唱有兄酬。", "好在牛腰軸，丁寧莫暗投。"]'),
('ac08e69c-d947-451f-9172-6e1daec4d154','次韻盤隠陸別駕先賢堂下月夜見寄','釋居簡','宋','宋诗','song-poetry','','[]','自與先賢分不生，酒船隙地鶴隨行。',64,'全唐诗/poet.song.180000.json','["自與先賢分不生，酒船隙地鶴隨行。", "橋闌架碧疑虹跨，葑畛圍香擬岸橫。", "凉度綠雲花不寐，盡餘紅淚燭須更。", "明朝秋思誰先得，笑聽蘋花與蓼爭。"]'),
('b539f2f1-8982-4df5-992c-ac6d332e1a59','劉誠道訪疎寮','釋居簡','宋','宋诗','song-poetry','','[]','歸途弗辨處州詩，大雅遺音鑒賞稀。',64,'全唐诗/poet.song.180000.json','["歸途弗辨處州詩，大雅遺音鑒賞稀。", "先自有田皆種秫，豈應無子不傳衣。", "華緘不貴中朝士，草具甘分北宕薇。", "老矣菟裘何許問，摇摇心與去帆飛。"]'),
('da008dd1-7a77-477d-9d2a-fe7ac3cfcb76','題北山雨餘南屏春曉兩手卷  其一','釋居簡','宋','宋诗','song-poetry','','[]','晴拂孤山破曉陰，暝煙猶在柳邊深。',32,'全唐诗/poet.song.180000.json','["晴拂孤山破曉陰，暝煙猶在柳邊深。", "試從淡墨微茫外，商略青層到碧潯。"]'),
('2a6c380c-f4da-42ed-bf02-46302dab4ccc','題北山雨餘南屏春曉兩手卷  其二','釋居簡','宋','宋诗','song-poetry','','[]','綺疏新響囀綿蠻，綠重紅輕尚带寒。',32,'全唐诗/poet.song.180000.json','["綺疏新響囀綿蠻，綠重紅輕尚带寒。", "老去倦舒南宕嘯，更將橫幅與誰看。"]'),
('eccb8ef6-d879-4bd4-95b8-6147571841b9','贈四明言上人','釋居簡','宋','宋诗','song-poetry','','[]','太玄譏太白，淡掃却清新。',48,'全唐诗/poet.song.180000.json','["太玄譏太白，淡掃却清新。", "紙上忽垂實，鏡中如寫真。", "荔丹晴態度，桃暈雨精神。", "說與鉛黄手，緇雲不受塵。"]'),
('48c45696-577e-4eca-b278-cb06f2b273a3','南屏春曉圖','釋居簡','宋','宋诗','song-poetry','','[]','塔穎透雲天影曙，水塍分畛葑痕青。',32,'全唐诗/poet.song.180000.json','["塔穎透雲天影曙，水塍分畛葑痕青。", "鷺鷥睡起忺初日，瘦立樓東柳外汀。"]'),
('27591a8d-a5ab-461f-8cd2-68924d7d12b9','懷趙府錄','釋居簡','宋','宋诗','song-poetry','','[]','知義稱仲子，義豈仲子明。',228,'全唐诗/poet.song.180000.json','["知義稱仲子，義豈仲子明。", "康章果何事，其如通國人。", "國人眼芒羊，眇視終不親。", "悠悠鹿爲馬，擾擾丹成青。", "軻豈好辯哉，隠若不得平。", "斥矯如斥羊，子孝俾孝信。", "高風既偃草，雄辯如建瓴。", "真固易爲贋，贋亦難逃真。", "至今百世下，粲粲日與星。", "向來宣城掾，趙擅梁楚聲。", "束書甫言歸，議者紛而紜。", "番騰巧如織，萋菲駢相新。", "老我若病瘖，不覺勇自鳴。", "掾自仙源來，世襲清流盟。", "家法凜雪霜，厥緒方振振。", "諸父相頡頏，渭陽更輪囷。", "佞賢决雄雌，霄壤與渭涇。", "軻死雖無傳，此舌死不泯。", "不與智者道，此道誰商評。"]'),
('8fcd1b02-54be-421a-a4eb-b78b9eb41145','送常倅陸盤隠','釋居簡','宋','宋诗','song-poetry','','[]','昔人未强仕，不食太官粟。',96,'全唐诗/poet.song.180000.json','["昔人未强仕，不食太官粟。", "悠然於此時，已展籋雲足。", "人生五馬貴，入手弗轉矚。", "我恐州縣間，不足峙鸞鵠。", "蜀仙負郭田，二頃舊鉏玉。", "千年玉不槁，丁寧戒芻牧。", "陶山元祐家，文采世相屬。", "它日訪襟期，需君玉田熟。"]'),
('a2735324-4a36-40f2-b68e-c58ca4cf5f38','四香花圖','釋居簡','宋','宋诗','song-poetry','','[]','虛空講得四花飛，更著鮮風款曲吹。',32,'全唐诗/poet.song.180000.json','["虛空講得四花飛，更著鮮風款曲吹。", "直至如今無復見，笑憑子墨寫新奇。"]'),
('1c6446ed-10e9-4ccb-a122-ceebe0ea52ce','茤谷','釋居簡','宋','宋诗','song-poetry','','[]','賦就垂天起隠淪，鶩飛難並鵠亭亭。',64,'全唐诗/poet.song.180000.json','["賦就垂天起隠淪，鶩飛難並鵠亭亭。", "池塘早已騰春馥，龍麝何煩亂德馨。", "虛應有神元不死，靜觀無物不長靈。", "雙眸弗見南州士，莫作西山雨後青。"]'),
('0d2547de-9b1e-438f-a4b2-08de629ac89b','續茤谷楊兄枯荷行','釋居簡','宋','宋诗','song-poetry','','[]','水冷秋不痕，鏡我雙蓬絲。',80,'全唐诗/poet.song.180000.json','["水冷秋不痕，鏡我雙蓬絲。", "舉頭見池葉，惄若絲不滋。", "美人空谷歌無衣，問秋霣葉胡不思。", "葉紉成衣弗堪著，老洲宿渚無蘅若。", "冰冷可煮枯可然，蕙風撚指浮碧漣，脆綠嫩紫仍田田。"]'),
('fb00c660-0a62-4367-985a-d4d178f4622c','洗苧歌','釋居簡','宋','宋诗','song-poetry','','[]','白水浣白苧，濯濯霜不如。',80,'全唐诗/poet.song.180000.json','["白水浣白苧，濯濯霜不如。", "亭勻揀經緯，霜澌寒疎疎。", "天質本無玷，况復隨時染。", "秋陽曝皜皜，不受紅紫諂。", "丹茸碧縷明相掩，玉手苧紗秋瀲瀲。", "拜了穿針樓上月，細與天孫話新潔。"]'),
('37c7343c-b1b0-4d27-952d-7aea9c2d3de5','白苧歌','釋居簡','宋','宋诗','song-poetry','','[]','經紗纔上機，梭飛玉攕攕。',72,'全唐诗/poet.song.180000.json','["經紗纔上機，梭飛玉攕攕。", "怕君尋春遲，落機寬裁衫。", "春心亂如蓬，冉冉隨春霏。", "芳逕曉沾露，軟塵紅上衣。", "歸來恨塵污，湔衣浣紗處。", "難湔芳露痕，易湔衣上塵。"]'),
('3f2abff7-f878-44e9-b499-d04e144342bb','毗陵三題  其一','釋居簡','宋','宋诗','song-poetry','','[]','闖簷起淵潛，濤怒欲翻壁。',152,'全唐诗/poet.song.180000.json','["闖簷起淵潛，濤怒欲翻壁。", "兩雄競厥壯，跼領勇舒脊。", "令人未見神先悸，如見當年李生醉。", "醉鄉汗漫渺無津，墨蜚素壁風蜚腥。", "驤雲掀霧妙入神，不特神妙尤奪真。", "鄉來識真人已朽，所見不知如此否。", "或謂此兒鱗介胄，幻作人間寫生手。", "坐令五月六月間，商羊起舞旱魃走。", "客窗夜老聞天籟，逸響琅然風雨晦。", "曉入西游柱史家，因知壁有蜿蜒沕。"]'),
('399c98dd-df3f-4b67-afdd-8ede63e7d939','毗陵三題  其二','釋居簡','宋','宋诗','song-poetry','','[]','太平寺壁滄煙浦，亭勻剪得尋丈許。',176,'全唐诗/poet.song.180000.json','["太平寺壁滄煙浦，亭勻剪得尋丈許。", "初驚洶洶欲掀天，熟視方方不踰矩。", "潛珍毓怪疑無數，又疑勇鬭鯨鵬聚。", "掩歛光芒不呈露，定在崩奔漩澓處。", "三江既入九派分，南江北江相與隣。", "中泠一滴渾不得，滔滔清徹岷山脈。", "故家門掩岷山雲，送江入海闚蓬灜。", "山遥海闊三萬里，一芥不浮長止止。", "六鰲不動風不摇，爛銀城闕明霞起。", "回頭觀此破屋壁，千濤萬浪尋無跡。", "鄉來有術只觀瀾，只今觀畫寧無術。"]'),
('ab8ba641-673f-44b7-bf13-0057d7bbd957','毗陵三題  其三','釋居簡','宋','宋诗','song-poetry','','[]','故國有喬木，獨孤去思處。',180,'全唐诗/poet.song.180000.json','["故國有喬木，獨孤去思處。", "陳祠後庭曠，落落肆蟠踞。", "輪囷平地起，婆娑半天去。", "亭亭若爲高，滴翠重於霧。", "冰雪不知凜，春秋不知數。", "雲仍今幾何，梁棟亦云婁。", "攀可梯天雲，涉可航海具。", "玄鶴問耆壽，老鳳停孤翥。", "前年雷破山，裂木如折筯。", "俯觀數州地，屹立障瀾柱。", "雖云不附麗，亦豈無佽助。", "百圍振虛籟，言嗟漆園誤。", "溜雨四十圍，詩史誕彌著。", "鏘然古柏行，誰領末後句。", "一畮蔽蒼苔，回顧空蕃庶。"]'),
('ac264af1-a013-48f7-9ff4-8ff0330120a0','毗陵三題  其四','釋居簡','宋','宋诗','song-poetry','','[]','獨孤手自種，操與獨孤雙。',48,'全唐诗/poet.song.180000.json','["獨孤手自種，操與獨孤雙。", "風怒掀秋幹，濤翻響暮江。", "卷它新步障，開此碧油幢。", "千載東歸鶴，時來話舊邦。"]'),
('916c7a07-b845-4445-9fc1-303bfff0b7a6','惠山歸晚辭縣齋小集','釋居簡','宋','宋诗','song-poetry','','[]','癯冰瘠雪凝霜澌，凍澀苔痕老更奇。',32,'全唐诗/poet.song.180000.json','["癯冰瘠雪凝霜澌，凍澀苔痕老更奇。", "旅雁退飛寒力勁，水邊雲冷出山遲。"]'),
('6b424706-a60b-4f01-a1b3-a0a210ac7a75','偃金竹','釋居簡','宋','宋诗','song-poetry','','[]','抉石霜虬小，金膚欠玉鱗。',48,'全唐诗/poet.song.180000.json','["抉石霜虬小，金膚欠玉鱗。", "若虛終踐實，寧屈不求伸。", "瘦卷輪囷操，寒低傴僂身。", "篔簹舊模寫，無此老精神。"]'),
('741960cf-ad91-4fe1-8ea3-3bf1733016cc','聽紹上人琴','釋居簡','宋','宋诗','song-poetry','','[]','悠然勇變劃然鳴，古恨沉沉易水生。',32,'全唐诗/poet.song.180000.json','["悠然勇變劃然鳴，古恨沉沉易水生。", "短髮不禁愁觸緒，恰如猿叫第三聲。"]'),
('76d928e5-14ff-4c81-9ce4-ff604497eca9','賀陳中書除夕郎','釋居簡','宋','宋诗','song-poetry','','[]','小舟回櫂清苕曲，林下新傳拜夕郎。',64,'全唐诗/poet.song.180000.json','["小舟回櫂清苕曲，林下新傳拜夕郎。", "品固自高庸借重，官非因夭始騰芳。", "人都不到天游處，馬尚能尋夜直堂。", "只尺鈞衡住無屋，萬間庇士可曾忘。"]'),
('d92b3374-1330-4f14-8247-141b5828fca3','醉農圖','釋居簡','宋','宋诗','song-poetry','','[]','楚袖回旋趁楚歌，曲終無策庇青娥。',32,'全唐诗/poet.song.180000.json','["楚袖回旋趁楚歌，曲終無策庇青娥。", "番嗟隆準當時樂，少似雞豚社裏多。"]'),
('77618117-8319-41fb-bbd9-b68a809f8832','老仙平沙落鴈','釋居簡','宋','宋诗','song-poetry','','[]','楚天如紙字橫斜，紙闊行疎對落霞。',32,'全唐诗/poet.song.180000.json','["楚天如紙字橫斜，紙闊行疎對落霞。", "傳得夜來沙上影，不傳書信伴梅花。"]'),
('113dc206-93d7-4cf4-b3e6-727b8e2bf4e0','台州使君趙寺丞致饋','釋居簡','宋','宋诗','song-poetry','','[]','滔滔銀浦寒颼飀，一涓一滴皆清流。',64,'全唐诗/poet.song.180000.json','["滔滔銀浦寒颼飀，一涓一滴皆清流。", "向來却立望雲漢，朣朣華月縣高秋。", "霞標一萬八千丈，雪兔霜蟾在其上。", "光分四海凉如水，小試丹丘一千里。"]'),
('735a359c-03b7-4c54-a5c1-2bf0961c352e','寄黄巖趙長官','釋居簡','宋','宋诗','song-poetry','','[]','昔住白雲城裏寺，清標曾揖兩巖高。',64,'全唐诗/poet.song.180000.json','["昔住白雲城裏寺，清標曾揖兩巖高。", "叢卑舊憶曾棲棘，縣壯新傳略奏刀。", "把似山林今日看，弗須湖海向來豪。", "時人只識鳴弦手，不識無弦似醉陶。"]'),
('4a4ca97f-dc44-4898-a8aa-6c339a0db332','贈因長老','釋居簡','宋','宋诗','song-poetry','','[]','金猊鐵脊鐵腰頑，趁鼠隨狐屈折難。',32,'全唐诗/poet.song.180000.json','["金猊鐵脊鐵腰頑，趁鼠隨狐屈折難。", "因是正因須自信，避些炎熱耐些寒。"]'),
('2a75699e-314b-45da-9838-17d7f30dc09a','次曹少蓬梅花韵','釋居簡','宋','宋诗','song-poetry','','[]','澗邊尋得壓殘枝，遠寄蓬仙換得詩。',64,'全唐诗/poet.song.180000.json','["澗邊尋得壓殘枝，遠寄蓬仙換得詩。", "闖水花多凝雪重，漱冰香透出山遲。", "笑從秘府朱顔索，潔與緇雲素幌宜。", "簷隙一痕華月墮，伴蟾蜍玉惜貞姿。"]'),
('9397a701-f11e-4ed9-b1aa-ed730f490725','別陳給事諸公赴陸府判盤隠之約','釋居簡','宋','宋诗','song-poetry','','[]','挂包妃子墓田居，餘地無錢買一鉏。',64,'全唐诗/poet.song.180000.json','["挂包妃子墓田居，餘地無錢買一鉏。", "隣寺笑貧稀住計，孤山嫌怪索離書。", "鴻雖自去何須送，鷗不曾親儘不疎。", "亟欲寄聲尋便武，只煩三十六鱗魚。"]'),
('010da379-c0ae-4808-95e4-100bd7784731','吊猿','釋居簡','宋','宋诗','song-poetry','','[]','巫硤第三聲，無愁亦怕聽。',48,'全唐诗/poet.song.180000.json','["巫硤第三聲，無愁亦怕聽。", "養鉛煩護鼎，獻果伴看經。", "失樹難忘返，投籠不畏扃。", "舊銘曾瘞鶴，猿瘞亦宜銘。"]'),
('3b1a0db8-14aa-4751-a1e1-238fb04e0e96','太守勸耕別駕有詩子弟賓客皆和','釋居簡','宋','宋诗','song-poetry','','[]','華風煖入勸耕巵，後苑詞頭欲下時。',64,'全唐诗/poet.song.180000.json','["華風煖入勸耕巵，後苑詞頭欲下時。", "父老怕公歸覲速，鶑花惜日燕歌遲。", "肥生鴨頂痕遵渚，嫩學鵝兒蔓染絲。", "好是東郊元祐寺，兩年千騎駐旌旗。"]'),
('6a0d2ce8-9f56-4465-b629-5b6c75a5ebcc','次韻盤隠新亭','釋居簡','宋','宋诗','song-poetry','','[]','管領風煙一半閑，池南池北畫闌間。',64,'全唐诗/poet.song.180000.json','["管領風煙一半閑，池南池北畫闌間。", "紅添蜀綺漸成韻，綠間湘瓊過得斑。", "待燕欲歸簾盡卷，惜猨蜚去柵猶關。", "種花先課園丁最，看到叢犀賦小山。"]'),
('edb8760e-64e6-4a4c-b1d5-e4e07749beba','梯飈','釋居簡','宋','宋诗','song-poetry','','[]','凉腋拊岧嶤，可捫叢玉霄。',48,'全唐诗/poet.song.180000.json','["凉腋拊岧嶤，可捫叢玉霄。", "一層高步武，千仞拔塵囂。", "明月秦簫斷，雕盤古篆消。", "天漿幾時熟，款曲試芳瓢。"]'),
('c9c05ace-8f9d-4499-8bdd-71d617017f17','石上坐忘歸','釋居簡','宋','宋诗','song-poetry','','[]','獵獵并閭起暮寒，秋聲隠隠落秋湍。',32,'全唐诗/poet.song.180000.json','["獵獵并閭起暮寒，秋聲隠隠落秋湍。", "偶然石上聞天籟，橫膝焦梧不足彈。"]'),
('ff31777d-7844-4c6a-9937-2a20c4fe7a19','書壁圖','釋居簡','宋','宋诗','song-poetry','','[]','雨澀蒼崖墨色鮮，長安猶自犬羊羶。',32,'全唐诗/poet.song.180000.json','["雨澀蒼崖墨色鮮，長安猶自犬羊羶。", "試臨舊刻思天寶，末上先題十四年。"]'),
('a1359305-7bfe-40c2-99ec-afea19909004','送俞司戶','釋居簡','宋','宋诗','song-poetry','','[]','落日東郊寺，春風北固橈。',48,'全唐诗/poet.song.180000.json','["落日東郊寺，春風北固橈。", "三年控吳楚，幾度到金焦。", "岸綠晴初重，汀紅雨後消。", "蒲牢鳴夜半，款曲度楓橋。"]'),
('4759c823-612f-4dd3-9f08-89296306e10c','王寺丞後圃','釋居簡','宋','宋诗','song-poetry','','[]','不獨甘棠茂午陰，浄如止水照人心。',64,'全唐诗/poet.song.180000.json','["不獨甘棠茂午陰，浄如止水照人心。", "樓通閶闔天垂斗，雲鎖蜿蜒鼎篆金。", "袖裏有春還自樂，尊前無客不能吟。", "古菱花裏青青鬢，半點吳霜不敢侵。"]'),
('db82e811-6f61-4ba0-bd72-81b24fbed353','强齋高使君假山','釋居簡','宋','宋诗','song-poetry','','[]','呼猿洞口冷泉灣，盡把天真作假看。',64,'全唐诗/poet.song.180000.json','["呼猿洞口冷泉灣，盡把天真作假看。", "低切一峯庭際立，屹如九仞坐中寒。", "閑來不覺留連久，好處方知鬭砌難。", "尤物移人易成趣，莫嗔强健懶彈冠。"]'),
('637244ed-fee7-4eb2-b17e-28210a8ca508','題張於潜畫軸五首  其一','釋居簡','宋','宋诗','song-poetry','','[]','百尾誰傳觳觫真，淺緇輕拂替丹青。',32,'全唐诗/poet.song.180000.json','["百尾誰傳觳觫真，淺緇輕拂替丹青。", "逸群大武如曾見，不見當時挂角經。"]'),
('e7760ee3-0526-4546-881a-6cf83cee797d','題張於潜畫軸五首  其二','釋居簡','宋','宋诗','song-poetry','','[]','昭陽燕子一雙飛，涎涎隨風懶哺兒。',32,'全唐诗/poet.song.180000.json','["昭陽燕子一雙飛，涎涎隨風懶哺兒。", "可是劉郎無醖藉，不教嬪御讀周詩。"]'),
('0b3f1b9b-d535-49c8-9754-c61d0587b6f9','題張於潜畫軸五首  其三','釋居簡','宋','宋诗','song-poetry','','[]','老髮鬅鬙兩髻丫，天台山裏老煙霞。',32,'全唐诗/poet.song.180000.json','["老髮鬅鬙兩髻丫，天台山裏老煙霞。", "閭丘別後無蹤跡，又在蘭陵故相家。"]'),
('a47f9813-ef99-4131-86aa-d970cb7a643c','題張於潜畫軸五首  其四','釋居簡','宋','宋诗','song-poetry','','[]','玉虎嘶蟾噎萬鼉，五雲低處湧蓬婆。',32,'全唐诗/poet.song.180000.json','["玉虎嘶蟾噎萬鼉，五雲低處湧蓬婆。", "平生海若嫌模寫，如此梁生狡獪何。"]'),
('47ef1cc1-730d-4776-83bc-93b2b82aec13','題張於潜畫軸五首  其五','釋居簡','宋','宋诗','song-poetry','','[]','飈生凉腋策茶勳，欲御剛風度海雲。',32,'全唐诗/poet.song.180000.json','["飈生凉腋策茶勳，欲御剛風度海雲。", "任是蓬萊更高處，叫蒼生苦有誰聞。"]'),
('a62bd044-689c-4bf8-a3e9-63387c82eac2','送王寺丞','釋居簡','宋','宋诗','song-poetry','','[]','公來蘭陵州，舊俗如解酲。',168,'全唐诗/poet.song.180000.json','["公來蘭陵州，舊俗如解酲。", "封中小草木，薿薿皆精神。", "鄉來矜陸梁，今也猿鳥馴。", "鄉來矜巧詆，今也伏不伸。", "扊扅謹夜戶，兩載俱撤扁。", "舟車集大賈，庠序登秀民。", "外則倉廩實，內則府庫盈。", "此特餘事耳，外此請具陳。", "時方尚武力，習閲鋒選精。", "黄金不愛惜，中的咸賞勤。", "重信不重金，貔貅肝膽傾。", "悠然一寸丹，秋水風泠泠。", "脫使玷如粟，孰掩離婁明。", "離婁寂無覩，只賦荆谿清。"]'),
('4d5949a5-ff24-45b2-a76c-814c3c0701a4','送郡齋兩客  其一','釋居簡','宋','宋诗','song-poetry','','[]','五馬尊前客，長沙太傅雙。',48,'全唐诗/poet.song.180000.json','["五馬尊前客，長沙太傅雙。", "疆侵過秦論，騷反度湘江。", "晞露紉春佩，留蟾款曙窗。", "束書還小隠，靜勝掃紛厖。"]'),
('700033a5-4f17-45ba-9c44-0abbd9e8876a','送郡齋兩客  其二','釋居簡','宋','宋诗','song-poetry','','[]','賓主在蘭陵，清哉勝挾冰。',48,'全唐诗/poet.song.180000.json','["賓主在蘭陵，清哉勝挾冰。", "弈機明揖遜，酒令旋番騰。", "池草春雖度，溪藤價益增。", "梯飈十二曲，曲曲款吟朋。"]'),
('581162b0-267c-4435-a936-f5e9876e9899','酬盤隠別駕  其一','釋居簡','宋','宋诗','song-poetry','','[]','早悟玄元一曰慈，持身有本是無私。',64,'全唐诗/poet.song.180000.json','["早悟玄元一曰慈，持身有本是無私。", "戒將重帚傷螻蟻，弗買生魚餵鷺鷥。", "桂實松高宜壽此，竹清梅瘦亦如斯。", "吟成換得神仙骨，不枉憑闌撚斷髭。"]'),
('f3c2d3f9-b693-4113-a236-a8fff5d94322','酬盤隠別駕  其二','釋居簡','宋','宋诗','song-poetry','','[]','隨官曾讀頌中興，符竹將分第二燈。',64,'全唐诗/poet.song.180000.json','["隨官曾讀頌中興，符竹將分第二燈。", "一氣所鍾清似鏡，十成相肖澹於僧。", "紅栽水玉不多日，碧數霧鬟無數層。", "臺上只教猿自嘯，秦簫雖美弗同登。"]'),
('6130ebd2-587d-418f-bf33-54cc516d4a7b','求圖記古字於何老漁','釋居簡','宋','宋诗','song-poetry','','[]','古意蕩不反，古聲今亦亡。',48,'全唐诗/poet.song.180000.json','["古意蕩不反，古聲今亦亡。", "一期甜畫貴，幾箇淡交長。", "馬去有時反，豹饑無處藏。", "劉郎鬢先老，猶得訪何郎。"]'),
('07eb7565-d182-41d2-836b-85defa44c1d9','泣瓜廬薛景石','釋居簡','宋','宋诗','song-poetry','','[]','夢與瓜廬別，平明見又玄。',48,'全唐诗/poet.song.180000.json','["夢與瓜廬別，平明見又玄。", "偏傍蕃手校，奇正想心傳。", "穀賤煩豐豕，風酸噎瘦蟬。", "阿伶墳上土，滴不到重泉。"]'),
('411425eb-350a-424e-82db-98a2ab4bf266','新竹','釋居簡','宋','宋诗','song-poetry','','[]','嫩青霣籜未禁摇，細字何煩扈碧綃。',32,'全唐诗/poet.song.180000.json','["嫩青霣籜未禁摇，細字何煩扈碧綃。", "乘月露梢須點滴，少留墨色到明朝。"]'),
('aac653d9-2d72-456c-b144-c0f6866e0aa3','贈筆工','釋居簡','宋','宋诗','song-poetry','','[]','散捉紫毫新脫穎，玄泓渴飲淬鋒寒。',32,'全唐诗/poet.song.180000.json','["散捉紫毫新脫穎，玄泓渴飲淬鋒寒。", "將軍翰墨場中老，避槊方知奪槊難。"]'),
('0d1cc9cf-9930-458c-aac8-855fe4aab82f','菊磵蘭石松菊手卷','釋居簡','宋','宋诗','song-poetry','','[]','髯高江漢歸，化作木石妖。',84,'全唐诗/poet.song.180000.json','["髯高江漢歸，化作木石妖。", "槁樹怪槎枿，俱趁毫端朝。", "蒼蘚並砌泣，老棘傷秋彫。", "篠簜霜不蕃，蘭茝春方饒。", "抵死蘭茝傍，不肯著艾蕭。", "坡陁數片石，仙袂拂不消。", "定知何處見，五老前山椒。"]'),
('07572216-f327-41f2-bd42-07a80c8cea3c','酬盤隠總餉園中之什','釋居簡','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','總餉園中賦詠佳，可曾誤指玉鈎斜。',64,'全唐诗/poet.song.180000.json','["總餉園中賦詠佳，可曾誤指玉鈎斜。", "煙鬟闖戶青浮玉，羽蓋亭雲綠護花。", "瘦竹引風留客旆，長江流月去誰家。", "暮天漾漾隨潮展，彷彿西興渡口沙。"]'),
('359c5f42-0273-4b20-9e8d-23d1b7104374','舟中貽趙野雲之官三衢','釋居簡','宋','宋诗','song-poetry','','[]','笑君吟似飲中歌，船貼清溪翠卷羅。',64,'全唐诗/poet.song.180000.json','["笑君吟似飲中歌，船貼清溪翠卷羅。", "夢枕熟時忺晝永，午陰團影得凉多。", "官非奉禮寧如賀，家豈楊州舊姓何。", "試問柯山棋一局，不知曾爛幾人柯。"]'),
('2f6c3b65-3f0e-403c-8c8f-9e60221bca8b','酬盤隠別駕七夕','釋居簡','宋','宋诗','song-poetry','','[]','水風池舘濯明粧，兩袖澄鮮竚晚香。',64,'全唐诗/poet.song.180000.json','["水風池舘濯明粧，兩袖澄鮮竚晚香。", "金注月波秋未滿，銀開星渚夜生凉。", "素憐醉客陽辭酒，纔就新題略舉觴。", "拙不可窮安用巧，聽他乞得巧人忙。"]'),
('f389b56c-8c92-4c04-9987-9277e549ff27','逆風','釋居簡','宋','宋诗','song-poetry','','[]','劈面東風不肯西，西州客子莫顰眉。',32,'全唐诗/poet.song.180000.json','["劈面東風不肯西，西州客子莫顰眉。", "一從四國流言後，直至如今不反吹。"]'),
('ed947d40-4529-4285-9236-2a2fee4aa8c9','野雲赴三衢酒官','釋居簡','宋','宋诗','song-poetry','','[]','跌宕四十年，吳霜變玄髮。',168,'全唐诗/poet.song.180000.json','["跌宕四十年，吳霜變玄髮。", "卓然所不變，傲寒勇彌决。", "醉翰筆爲祟，狂歌酒作孽。", "煮字不療饑，袖手不求熱。", "囊羞一簪直，腰嫌五斗折。", "狼飽千里肉，豕卧半尋穴。", "於菟道邊窟，螻蟻夢中垤。", "驥困黄泥阪，駑踐黄金埒。", "臣朔漫詼謔，侏儒笑明哲。", "生女不生男，跨竈亦超絕。", "安得徑尺蟬，冠此半簪雪。", "縣官嚴榷酤，一官弗徒設。", "安知滌器時，已有諭蜀節。", "莫羨白頭吟，自看柯山月。"]'),
('5a45b07f-3740-4d6e-92a6-4e58d57fea55','送湯少瞻見疎寮','釋居簡','宋','宋诗','song-poetry','','[]','而翁扣竹扃，拈出兩詩新。',48,'全唐诗/poet.song.180000.json','["而翁扣竹扃，拈出兩詩新。", "凉柄駸駸置，秋檠隠隠親。", "年勞須制勝，日益是刊陳。", "翰長淵源地，山陰試問津。"]'),
('835eb865-f3d3-4686-af8f-94a4d7c99a4d','寄寬堂趙左藏','釋居簡','宋','宋诗','song-poetry','','[]','玉壺飲湖淥，决眥連雲根。',144,'全唐诗/poet.song.180000.json','["玉壺飲湖淥，决眥連雲根。", "霜蟾駕飛轍，萬頃秋不痕。", "懷哉壺中仙，弗鑑行潦渾。", "一衿洞冰澌，三舍祛塵昏。", "玉盌勺冷瀣，瓊佩經芳蓀。", "賸擷書傳香，鮮騰水花芬。", "愛閑受遠次，負郭成荒村。", "廣文飯不足，北海酒滿樽。", "弗春長熙熙，弗約常存存。", "氣餒貴益賤，道在卑逾尊。", "安知忘情地，豈在炙手門。", "只與白鷗說，莫與俗子論。"]'),
('eb26779e-a198-4409-aff6-d0277ca24efd','送范主簿','釋居簡','宋','宋诗','song-poetry','','[]','考績果何如，三年上上書。',48,'全唐诗/poet.song.180000.json','["考績果何如，三年上上書。", "官箴小能大，俸給少常餘。", "款客壺觴靜，尋僧水竹虛。", "麥船容借便，石浦訪樓居。"]'),
('8e39e771-18a8-4b44-b6a2-99e15371dbe0','寄陳給事','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','別元龍了別西湖，到得蘭陵二月初。',64,'全唐诗/poet.song.180000.json','["別元龍了別西湖，到得蘭陵二月初。", "沉想金閨隨夢熟，楷書玉楮問安疎。", "傍人燕子新巢小，得友鶑雛煖翼舒。", "落落環中有餘地，道樞旋斡看虛邪。"]'),
('523ce373-0de7-475a-b4bd-50d4cc0fa42e','送趙司理','釋居簡','宋','宋诗','song-poetry','','[]','未報金陵大閫書，鵲聲猶自繞庭除。',64,'全唐诗/poet.song.180000.json','["未報金陵大閫書，鵲聲猶自繞庭除。", "若非尚德嘉同姓，應是蒐才副所如。", "寒日鷺洲千點雪，舊時燕壘幾番雛。", "江東可是無諸葛，不記于家有小千。"]'),
('8c0ca110-9321-4881-a5cf-237ec759794d','送滿上座','釋居簡','宋','宋诗','song-poetry','','[]','文公住處兒時到，尚記崔嵬紫翠聯。',64,'全唐诗/poet.song.180000.json','["文公住處兒時到，尚記崔嵬紫翠聯。", "隔岸土封劉氏藁，它山石刻杜陵篇。", "天開雙闕凌飛霧，經注千名富近年。", "倘有異時陳伯玉，潸然爲我作欣然。"]'),
('9959cd8b-8847-44a2-bb71-3160eed4c54f','芙蓉盛開','釋居簡','宋','宋诗','song-poetry','','[]','霣霜槁百卉，拒霜獨開花。',144,'全唐诗/poet.song.180000.json','["霣霜槁百卉，拒霜獨開花。", "寒驅煖消落，秋借春韶華。", "酣酣羅珍姿，表表駢翠葩。", "晴雲剪新綺，落日明丹砂。", "瀣冷褪宿艷，葉散摘零霞。", "離騷比君子，城闕藏山家。", "二月三月時，紅紫相矜誇。", "西風一摇落，亂委隨蓬麻。", "花中障頹瀾，晚節禮有加。", "芳潔以類從，薰蕕分等差。", "梅追元氣回，菊制暮景斜。", "弗使四時氣，斷續令人嗟。"]'),
('cca80709-b3f2-438a-b808-2d562dba7f2a','泣瓜圃翁應叟','釋居簡','宋','宋诗','song-poetry','','[]','不幸人誰免，如公孰不嗟。',48,'全唐诗/poet.song.180000.json','["不幸人誰免，如公孰不嗟。", "母憐它姓子，金潤別人家。", "行義窮尤著，持身死不差。", "寸田猶可圃，圖蔓勿傷瓜。"]'),
('17c8b506-4635-45c5-af6d-3874dcd9936f','黄凝雲歸張公洞','釋居簡','宋','宋诗','song-poetry','','[]','洞在深雲裏，仙畦茂藥苗。',48,'全唐诗/poet.song.180000.json','["洞在深雲裏，仙畦茂藥苗。", "偶隨山下水，來泊寺前橈。", "瀣泠長凝頰，丹輕不墜瓢。", "多應久離索，老鬢各蕭蕭。"]'),
('17d557b3-c227-488c-a90e-da4b0294eea3','寒泉赴趙建康辟','釋居簡','宋','宋诗','song-poetry','','[]','辟書纔下了，節節闖挐音。',48,'全唐诗/poet.song.180000.json','["辟書纔下了，節節闖挐音。", "一日偶它適，尺書煩重尋。", "似回浮雪棹，來作訪僧吟。", "夢草相忘地，於君憶更深。"]'),
('2d160335-b091-4224-9af1-b398585f4b29','酬盤隠別駕雪','釋居簡','宋','宋诗','song-poetry','','[]','臺空罷講經，底事雨花零。',48,'全唐诗/poet.song.180000.json','["臺空罷講經，底事雨花零。", "雞誤中宵白，山迷昨日青。", "槎牙渾欲死，和煦便通靈。", "怕壓疎疎竹，寒敲不忍聽。"]'),
('61ebb66d-2599-4bf2-beae-f8711a56986d','盤隠別駕修龜山祠','釋居簡','宋','宋诗','song-poetry','','[]','商今藐人物，振墜起先賢。',48,'全唐诗/poet.song.180000.json','["商今藐人物，振墜起先賢。", "俸薄知難集，財輕覺易捐。", "便成新氣象，頓醒舊風煙。", "撙節昌頹俗，何心食萬錢。"]'),
('84e6e390-6a68-4548-b4ae-1240f814897f','承天萬佛閣','釋居簡','宋','宋诗','song-poetry','','[]','覩史何年宮，飛跨雙峨眉。',180,'全唐诗/poet.song.180000.json','["覩史何年宮，飛跨雙峨眉。", "又如聽經塔，湧出踞地維。", "不然鈞天人，來下觀闕隨。", "去年曾此游，入眼未始窺。", "西風一回首，峭峙凌煙霏。", "璇題翬萬椽，雕礎逾十圍。", "神速藐鬼工，莫知爲者誰。", "或曰金泉僧，短髮霜披披。", "信孚全吳地，幻此一段奇。", "胸中楚澤小，簷外吳天低。", "舉手斗可捫，縱脚雲可梯。", "江窮水屈折，港盡天畛畦。", "因知廣大量，不爲狹隘移。", "閣中優缽花，萬朵秋不萎。", "天子壽萬年，一年開一枝。"]'),
('325bf593-4704-4cf8-96cb-db7c31c44f08','竹風亭','釋居簡','宋','宋诗','song-poetry','','[]','盡鉏菑翳了，華構繞篔簹。',48,'全唐诗/poet.song.180000.json','["盡鉏菑翳了，華構繞篔簹。", "矗矗半簷綠，疎疎六月凉。", "雪林聽響玉，粉節暈零霜。", "話到楊州鶴，無非俗肺腸。"]'),
('7170c4e3-8bc0-407c-935d-834ea338b40d','平江太守李寶謨移漕荆湘  其一','釋居簡','宋','宋诗','song-poetry','','[]','荆溪溪上傳，接畛使君賢。',48,'全唐诗/poet.song.180000.json','["荆溪溪上傳，接畛使君賢。", "行旅歸如市，羈游亟受廛。", "豐儲優郡計，薄歛裕民天。", "誰似山陰叟，臨行贈一錢。"]'),
('50f821f0-d15c-45ec-8211-7f37227b5a32','平江太守李寶謨移漕荆湘  其二','釋居簡','宋','宋诗','song-poetry','','[]','不據喉衿地，如何展壯圖。',48,'全唐诗/poet.song.180000.json','["不據喉衿地，如何展壯圖。", "一麾移使節，三楚即全吳。", "鸚鵡春常早，貔貅信必孚。", "不知坐上客，更有禰生無。"]'),
('60efe4d9-6dc4-4a48-97c8-06d8c31d6cae','葛菴阻雪  其一','釋居簡','宋','宋诗','song-poetry','','[]','城中倦酬接，小泊在同涇。',48,'全唐诗/poet.song.180000.json','["城中倦酬接，小泊在同涇。", "竹已休教醉，梅方喚得醒。", "山嫌時畫俗，天滿古壺青。", "怕有歸來鶴，柴門夜不扃。"]'),
('794bb45f-363a-4f1c-9433-04bf85aa3cc7','葛菴阻雪  其二','釋居簡','宋','宋诗','song-poetry','','[]','天上花如席，門前逕擁樵。',48,'全唐诗/poet.song.180000.json','["天上花如席，門前逕擁樵。", "全葩不到地，零蔕謾齊腰。", "梅笑竹先裂，柏隨松後雕。", "燒痕漫滅盡，黄獨更無苗。"]'),
('a1f3ddaf-f04b-47ac-a1d7-9635c0b40b29','張荃翁赴浦江丞而喪耦唁荃翁謝穫軒見寄  其一','釋居簡','宋','宋诗','song-poetry','','[]','藍田廳壁記，又向浦江鎸。',48,'全唐诗/poet.song.180000.json','["藍田廳壁記，又向浦江鎸。", "棋壘須延敵，吟疆旋拓邊。", "鏡空鸞獨舞，幌冷鶴先眠。", "八詠弦難續，麒麟角可煎。"]'),
('c94daae8-5c00-48eb-bf85-f2bc835d5aa3','張荃翁赴浦江丞而喪耦唁荃翁謝穫軒見寄  其二','釋居簡','宋','宋诗','song-poetry','','[]','絕笑諸郎似乃翁，荃翁又自去哦松。',64,'全唐诗/poet.song.180000.json','["絕笑諸郎似乃翁，荃翁又自去哦松。", "捄焚賞必先焦額，欲雨香非後土龍。", "徵調苦多忘惜日，燮調傷煖不成冬。", "吳江短楫華亭月，稱副莖虀藐萬鍾。"]'),
('07443ef0-61a3-42d9-9af1-1438afd00cf4','正月初一酬盤隠陸別駕再雪得封字初三夜醮遇風得涇字  其一','釋居簡','宋','宋诗','song-poetry','','[]','前回滴未融，密洒又重重。',48,'全唐诗/poet.song.180000.json','["前回滴未融，密洒又重重。", "半刺慶三白，載歌賡四封。", "獵圍尋跡去，吟思爲誰供。", "沉想山陰夜，來如去興濃。"]'),
('7324bc56-051e-4508-840b-a4914f4bbd2b','正月初一酬盤隠陸別駕再雪得封字初三夜醮遇風得涇字  其二','釋居簡','宋','宋诗','song-poetry','','[]','巽二胡爲爾，喧豗不可聽。',48,'全唐诗/poet.song.180000.json','["巽二胡爲爾，喧豗不可聽。", "弗摧山墜地，必輥渭成涇。", "窗俟東方白，燈留冷幌青。", "想應遵帝命，弱水送飛軨。"]'),
('1301f607-6641-46b3-b3ff-4ed261958bc8','立春前三日雪','釋居簡','宋','宋诗','song-poetry','','[]','旦夕灰吹律，漣漪尚剪新。',48,'全唐诗/poet.song.180000.json','["旦夕灰吹律，漣漪尚剪新。", "雖正猶是臘，差晚不傷春。", "夜戶凝朝彩，生柴代熟薪。", "老僧眉最白，寒鏁玉津津。"]'),
('2d6349ec-d334-4fa5-acf9-3a3339ff0551','武進趙哦松吐茹異流俗雪中與邦人頌而餞之','釋居簡','宋','宋诗','song-poetry','','[]','自拔千尋俗，瀾從砥柱回。',48,'全唐诗/poet.song.180000.json','["自拔千尋俗，瀾從砥柱回。", "炎驅旱魃死，凉似故人來。", "梅待春開眼，歌催雪薦杯。", "荆溪鏡纖悉，是豈負丞哉。"]'),
('9200653b-026e-41bc-95b1-513383f536ab','立春前四日天大雷電以雨','釋居簡','宋','宋诗','song-poetry','','[]','霹靂如春雨似秋，蘭陵冬夜憶黄州。',32,'全唐诗/poet.song.180000.json','["霹靂如春雨似秋，蘭陵冬夜憶黄州。", "茂陵封禪期身後，恰恰營成小竹樓。"]'),
('acf98484-488d-42f3-a2e5-256e087809ed','次薛叔載石泉韻','釋居簡','宋','宋诗','song-poetry','','[]','石泉曾未面，泉石舊忘情。',48,'全唐诗/poet.song.180000.json','["石泉曾未面，泉石舊忘情。", "不與滔滔競，常懷止止清。", "渭非涇醖藉，貪是惡聲名。", "自潔憐他濁，憑誰吊屈平。"]'),
('9faaa9e4-349f-4e63-82ba-14cd7ade2e66','惠山泉','釋居簡','宋','宋诗','song-poetry','','[]','源遠涵山錫，風高遜甲科。',48,'全唐诗/poet.song.180000.json','["源遠涵山錫，風高遜甲科。", "論於前輩定，重似別泉多。", "清泚停無滓，扶摇盪不波。", "澹交從古小，如此一杯何。"]'),
('ea8c38a6-36ba-4104-a0d4-bc3716ce2b62','寄湖州故舊','釋居簡','宋','宋诗','song-poetry','','[]','夢憶湖州舊，樓臺畫不如。',48,'全唐诗/poet.song.180000.json','["夢憶湖州舊，樓臺畫不如。", "溪從城裏過，人在鏡中居。", "閉戶防驚鷺，開窗便釣魚。", "魚沈猶有雁，弗寄一行書。"]'),
('b326c497-a2d4-41b9-bda3-e418360bb778','次韻盤隠別駕偕抱獨作詩相勞苦  其一','釋居簡','宋','宋诗','song-poetry','','[]','小奚雲錦重來地，時與山人尉寂寥。',32,'全唐诗/poet.song.180000.json','["小奚雲錦重來地，時與山人尉寂寥。", "妃子墓前苔砌綠，風煙商略到前朝。"]'),
('f976a68f-1810-4824-9918-47bfa54c61a8','次韻盤隠別駕偕抱獨作詩相勞苦  其二','釋居簡','宋','宋诗','song-poetry','','[]','逕縈蛇腹不嫌紆，花蔓玲瓏畫不如。',32,'全唐诗/poet.song.180000.json','["逕縈蛇腹不嫌紆，花蔓玲瓏畫不如。", "太子布金祇樹老，一鉏無地可藏愚。"]'),
('e904ef91-42ba-42c0-89da-75dfb69e6fb6','代農答別乘勸耕  其一','釋居簡','宋','宋诗','song-poetry','','[]','敢忘百拜與三行，非賈非工只得耕。',64,'全唐诗/poet.song.180000.json','["敢忘百拜與三行，非賈非工只得耕。", "舊不便民毋助長，新非怫衆却休更。", "驗今多是迂扶曲，考古無非直勝橫。", "只把襦歌徵別乘，不從諫議問蒼生。"]'),
('4cf0c20a-7c5f-45d6-bc18-83c0392c3310','代農答別乘勸耕  其二','釋居簡','宋','宋诗','song-poetry','','[]','守令丁寧在必行，女當知織子知耕。',64,'全唐诗/poet.song.180000.json','["守令丁寧在必行，女當知織子知耕。", "課春蠶務從三月，聽夏雞聲起五更。", "畎澮滿時瞻日上，桔槔俯處候雲橫。", "調疎征省家才給，便買詩書教後生。"]'),
('c76e4023-331d-4ab8-92d4-6be1741f66fe','菊磵之宜興兼簡趙長官','釋居簡','宋','宋诗','song-poetry','','[]','伯氏如文舉，何煩仲氏書。',48,'全唐诗/poet.song.180000.json','["伯氏如文舉，何煩仲氏書。", "山陰溪上棹，灞岸雪中馿。", "耕豈無閑地，居仍有弊廬。", "看家老猿鶴，渠不爲貧疎。"]'),
('569fd97a-2234-4272-bd3f-1019d6d77207','閏月三日即事','釋居簡','宋','宋诗','song-poetry','','[]','星曆新傳誤，無人重講明。',48,'全唐诗/poet.song.180000.json','["星曆新傳誤，無人重講明。", "日中陰似夜，春半冷如正。", "柳欲眠還醒，花猶染不成。", "燕歸多日了，猶自未聞鶑。"]'),
('610d3197-2054-4a84-b382-0675b98b9dfd','橫山王八伯丹井','釋居簡','宋','宋诗','song-poetry','','[]','殿陰瓴甃古，汲向瓦爐煎。',48,'全唐诗/poet.song.180000.json','["殿陰瓴甃古，汲向瓦爐煎。", "甘拊惠山背，冽差簾谷肩。", "還丹非內外，餘瀝尚清漣。", "莫問井中影，盍窺天地先。"]'),
('c047156c-f935-4695-b8e1-15868d9fac30','寒食','釋居簡','宋','宋诗','song-poetry','','[]','纔見茅簷插柳條，便知寒食是今朝。',32,'全唐诗/poet.song.180000.json','["纔見茅簷插柳條，便知寒食是今朝。", "春應不恨相尋晚，應恨常陰一半消。"]'),
('107a65ba-56f5-4974-ac33-5f85f445156d','翟園  其一','釋居簡','宋','宋诗','song-poetry','','[]','廷尉園池傍柳塘，自携魏紫訪姚黄。',32,'全唐诗/poet.song.180000.json','["廷尉園池傍柳塘，自携魏紫訪姚黄。", "問它濯錦江頭路，共漢梁王醉幾場。"]'),
('e09eebfc-4436-4117-9009-00436dc55b60','翟園  其二','釋居簡','宋','宋诗','song-poetry','','[]','黄雀兒隨玉屑栽，兩行珠翠一般開。',32,'全唐诗/poet.song.180000.json','["黄雀兒隨玉屑栽，兩行珠翠一般開。", "桃花少似玄都觀，曾却仙都譜系來。"]'),
('7bdaec1d-bad8-4d76-8953-27626769ac9e','寬堂趙左藏泣子','釋居簡','宋','宋诗','song-poetry','','[]','廣寒秋思苦，桂霣最芳枝。',48,'全唐诗/poet.song.180000.json','["廣寒秋思苦，桂霣最芳枝。", "既失鸞膠助，寧忘獺髓醫。", "彭於殤有間，蒼與昊安知。", "不獨天難問，人間更問誰。"]'),
('95ffce06-e05d-426b-876a-5e50c7337285','盤隠別駕別造楊龜山祠堂拜奠於三月既望','釋居簡','宋','宋诗','song-poetry','','[]','導洛疏伊斷在茲，度溪湔祓振荒祠。',64,'全唐诗/poet.song.180000.json','["導洛疏伊斷在茲，度溪湔祓振荒祠。", "人心未泯猶知勸，事力雖殫豈憚爲。", "清似山陰修禊後，煖於沂上詠歸時。", "熊羆祥叶期豐報，應有南康別駕兒。"]'),
('0bce482d-bb7a-46a6-bc23-a507fa425700','張別駕饒州之任','釋居簡','宋','宋诗','song-poetry','','[]','絮飛無跡送行舟，春樹江雲共獻酬。',64,'全唐诗/poet.song.180000.json','["絮飛無跡送行舟，春樹江雲共獻酬。", "國子先生爲太守，碧山學士作監州。", "晴開廬阜微茫曉，籟挾芝山汗漫秋。", "華月光風在懷袖，同吟同歗莫鴻溝。"]'),
('162d8fde-c430-48a3-b122-dfc990166ba5','林國博自興化軍得饒州','釋居簡','宋','宋诗','song-poetry','','[]','盍綴蓬仙向上班，烹鮮不鄙作州難。',64,'全唐诗/poet.song.180000.json','["盍綴蓬仙向上班，烹鮮不鄙作州難。", "醉眸尚带壺雲碧，吟筆疑翻璧浪乾。", "名著金閨方善下，春生玉樹不知寒。", "明年全榜登科記，莫把尋常舉送看。"]'),
('33c8c59d-68a1-4ccc-8a5f-23747f3eaa04','慈感寺蚌珠尊者閣新成','釋居簡','宋','宋诗','song-poetry','','[]','部勒溪山勝，橫陳壓麗譙。',48,'全唐诗/poet.song.180000.json','["部勒溪山勝，橫陳壓麗譙。", "老蟾栖峭峙，饑蜃吐岧嶤。", "蘋潔翻波碎，塵紅到岸消。", "蚌珠方廣士，瘦影落清苕。"]'),
('2454e21f-0c77-4965-bb02-d1cb90336f7b','夜泊三高亭','釋居簡','宋','宋诗','song-poetry','','[]','蓴絲鱸膾不如施，歌散雖工又带譏。',32,'全唐诗/poet.song.180000.json','["蓴絲鱸膾不如施，歌散雖工又带譏。", "牆壁年時俱有耳，莫嗔鷗鷺往來稀。"]'),
('800bb10f-6bed-48d0-865e-6c5f4c6546d9','趙昌折枝芍藥','釋居簡','宋','宋诗','song-poetry','','[]','韶光欲盡伴荼蘼，收拾華風在一枝。',32,'全唐诗/poet.song.180000.json','["韶光欲盡伴荼蘼，收拾華風在一枝。", "不惜丹鉛和露寫，惜它姚魏不同時。"]'),
('872b9d7b-1c16-4850-b4b0-cc03affbe7b0','酬盤隠別駕','釋居簡','宋','宋诗','song-poetry','','[]','出門騎無馿，擬馽剛風騎。',72,'全唐诗/poet.song.180000.json','["出門騎無馿，擬馽剛風騎。", "問之何因爾，蜚度弱水涯。", "弱水三萬里，風煙接蓬趾。", "仰止蓬山雲，青紅濕窗几。", "煌煌華玉枝，采采黄金芝。", "瀣零濯鮮好，歸來賦三島。"]'),
('91aae69e-a5d6-45e9-a6ef-4cc24cc16d4c','搗紙','釋居簡','宋','宋诗','song-poetry','','[]','萬杵不爲輕，丁寧玉汝成。',48,'全唐诗/poet.song.180000.json','["萬杵不爲輕，丁寧玉汝成。", "忽聞敲月響，誤作搗衣聲。", "整整雲添薄，方方雪更明。", "沉思過秦手，古恨滿箋生。"]'),
('1a65c9d4-f634-418e-bd68-160734eb7b14','趙宜興訃至  其一','釋居簡','宋','宋诗','song-poetry','','[]','千緒亂紜紜，今才整得清。',48,'全唐诗/poet.song.180000.json','["千緒亂紜紜，今才整得清。", "泉羞廉不污，鏡笑醜嫌明。", "方聽棠陰頌，俄傳薤露聲。", "半規華月老，冏冏又東生。"]'),
('b2a4b964-6d34-45df-81c5-5f1cd30c84d5','趙宜興訃至  其二','釋居簡','宋','宋诗','song-poetry','','[]','百里寄豐凶，休仍與戚同。',48,'全唐诗/poet.song.180000.json','["百里寄豐凶，休仍與戚同。", "小心三日婦，宏略九年弓。", "犢用刀償價，人疑蔀發蒙。", "來年花滿縣，何似去年紅。"]'),
('07d14bcb-5548-4771-92fa-fe6ed4e1caf8','次韻郡博士賀龜山祠新成  其一','釋居簡','宋','宋诗','song-poetry','','[]','經術修明可保邦，凜然冠佩陳堂堂。',64,'全唐诗/poet.song.180000.json','["經術修明可保邦，凜然冠佩陳堂堂。", "競傳溪上諸賢聚，漸得門前一水香。", "疎剪新篁看抱節，誅鋤惡草戒侵牆。", "美輪美奐從人頌，潜德雖幽愈耿光。"]'),
('7ab888d2-4d77-4f36-a043-a3dc60867ed6','次韻郡博士賀龜山祠新成  其二','釋居簡','宋','宋诗','song-poetry','','[]','肅瞻老屋話因依，再振工夫豈浪施。',64,'全唐诗/poet.song.180000.json','["肅瞻老屋話因依，再振工夫豈浪施。", "學士賤秦麟妄出，老天祚宋鳳來儀。", "崇儒允叶休明運，溢美宜刪賦詠詞。", "弗待文興自今古，源源未必不由茲。"]'),
('90bc40e6-54e0-447b-86e5-f19eac5c4b82','次韻郡博士賀龜山祠新成  其三','釋居簡','宋','宋诗','song-poetry','','[]','業從師授巧無師，孟子何曾負子思。',64,'全唐诗/poet.song.180000.json','["業從師授巧無師，孟子何曾負子思。", "華月不從修處缺，景星還自望中垂。", "僞從所惡生成黨，判自持方不中規。", "欲扣兩端今已矣，忘言獨與故吾期。"]'),
('51ea76c1-6533-409c-8f83-3d2750c4dc17','劉練師歸綿州','釋居簡','宋','宋诗','song-poetry','','[]','掾署生賢夢，君生幾歲知。',48,'全唐诗/poet.song.180000.json','["掾署生賢夢，君生幾歲知。", "江圍帝子閣，蘚暈海棕詩。", "鉛豈無成日，筇須有化時。", "怕揮天寶泪，莫話浴妃池。"]'),
('4f9510a7-77b3-43ab-9b31-44e233a148ee','荆山劉成道相過','釋居簡','宋','宋诗','song-poetry','','[]','繫船敲竹戶，剝啄異常聲。',48,'全唐诗/poet.song.180000.json','["繫船敲竹戶，剝啄異常聲。", "燈醒夜來喜，猿因晨起驚。", "葵英和露熟，雲子與秋明。", "恨殺西風急，如何駐水程。"]'),
('fc8cfb1e-f562-4e32-b132-b8db61495117','張公洞','釋居簡','宋','宋诗','song-poetry','','[]','仙蹊九地更深層，捫磴扳崖謝瘦藤。',64,'全唐诗/poet.song.180000.json','["仙蹊九地更深層，捫磴扳崖謝瘦藤。", "候徹鼎芽抽薿薿，滴殘鍾乳綴稜稜。", "詭形象物疑成怪，虛處存神喚得應。", "惆悵石馿鞭不起，弗如雞犬解騫騰。"]'),
('d096d5c1-0564-4d75-8199-c89e84874297','白馬金砂洞','釋居簡','宋','宋诗','song-poetry','','[]','準擬朝餐洞口霞，更窮泓碧漲桃花。',64,'全唐诗/poet.song.180000.json','["準擬朝餐洞口霞，更窮泓碧漲桃花。", "可曾石罅潴成玉，多是金邊揀得沙。", "符說有靈尋漢篆，人因鑑止見胡麻。", "依稀似入天台路，不屬劉家與阮家。"]'),
('b961e222-b67a-474b-863f-a4c8cc096490','善拳洞','釋居簡','宋','宋诗','song-poetry','','[]','一山三洞幽，兩洞碧通流。',48,'全唐诗/poet.song.180000.json','["一山三洞幽，兩洞碧通流。", "龍占層淵沕，魚憑四足遊。", "遠舒雲際望，凉愜水邊留。", "更卜重來約，岩前石點頭。"]'),
('1435eb71-29dc-4ce4-bd7d-a1c116205699','祝英臺墓在善拳寺後','釋居簡','宋','宋诗','song-poetry','','[]','作奇男子事，博約訪名流。',48,'全唐诗/poet.song.180000.json','["作奇男子事，博約訪名流。", "只似深閨住，爰從斷柬求。", "窗低延月入，幌冷爲雲留。", "只好尋班謝，泉臺約雅遊。"]'),
('8a8f523c-b5f1-46f2-8ceb-c542ed7cf5c2','何監宮雲凹','釋居簡','宋','宋诗','song-poetry','','[]','凹處移將凸處填，悠悠填滿亂山顛。',32,'全唐诗/poet.song.180000.json','["凹處移將凸處填，悠悠填滿亂山顛。", "是中自有從龍便，勿謂春風不偶然。"]'),
('3b149d34-db28-4da0-9d58-976a2156622e','吳秀州自通判即真','釋居簡','宋','宋诗','song-poetry','','[]','鄉來風月渺鴻溝，已屬而今第一流。',64,'全唐诗/poet.song.180000.json','["鄉來風月渺鴻溝，已屬而今第一流。", "九轉可曾圖速效，雙旌何足嘆遲留。", "暫紆青綬宣新化，應對黄花動古愁。", "倘有無人耕處地，欲投瘦策問菟裘。"]'),
('1b27f517-e278-49d0-8dc4-81df86d2a84a','九月十四日自壽  其一','釋居簡','宋','宋诗','song-poetry','','[]','九月明朝望，思親到鶺鴒。',48,'全唐诗/poet.song.180000.json','["九月明朝望，思親到鶺鴒。", "不曾生日醉，未必死時醒。", "有命羞同甲，無錢喜放丁。", "六千三萬夕，款曲度殘零。"]'),
('528c1ef5-7ee7-42fc-a316-86ab1fd91fc1','九月十四日自壽  其二','釋居簡','宋','宋诗','song-poetry','','[]','簷外無多地，秋芳以類從。',48,'全唐诗/poet.song.180000.json','["簷外無多地，秋芳以類從。", "負暄存愛敬，趲課策疎慵。", "勺月酬閑燕，留雲備綴縫。", "莫言太早計，吾欲御玄冬。"]'),
('c838945a-684d-4f9c-b548-83b845e9884d','送鄂渚秋官陳伯奇兼柬阮廣文','釋居簡','宋','宋诗','song-poetry','','[]','榮如李郭舟，小爲蜀僧留。',48,'全唐诗/poet.song.180000.json','["榮如李郭舟，小爲蜀僧留。", "江漢渺何許，琴書占上游。", "貪程人易別，勞勸酒難酬。", "黄鶴風煙古，何曾怕攪搜。"]'),
('d3efadd5-d523-4f54-8d1a-74588dbd099d','相士雷舌','釋居簡','宋','宋诗','song-poetry','','[]','盡道雷無舌，雷無舌可乎。',48,'全唐诗/poet.song.180000.json','["盡道雷無舌，雷無舌可乎。", "不曾藏霹靂，又自笑喑嗚。", "菊減霜前馥，筠添雪後腴。", "莫同姚魏看，姚魏望秋殂。"]'),
('12a52d11-f937-4b00-9d95-260d5177bd68','王司理之官南徐','釋居簡','宋','宋诗','song-poetry','','[]','南徐非古徐，或云古徐州。',144,'全唐诗/poet.song.180000.json','["南徐非古徐，或云古徐州。", "鄉來徐州牧，亦有大耳劉。", "手携紫髯生，分踞很石籌。", "不知何所籌，楚醪相獻酬。", "石無一日轉，名有千年留。", "石很不足道，人很寧弗瘳。", "君掾南徐官，盍爲南徐謀。", "誠開金石堅，德舉毫忽輶。", "鄙薄久自化，强矯終當柔。", "平反惟厥中，此外吾何求。", "君家老卿月，威惠半九疇。", "悠然豁斯道，付與諸郎由。"]'),
('82bb8f4f-58ea-433e-8aba-362f55020bf4','宋賢良見過','釋居簡','宋','宋诗','song-poetry','','[]','莫登百尺樓，豈無湖海豪。',240,'全唐诗/poet.song.180000.json','["莫登百尺樓，豈無湖海豪。", "莫揮北海尊，豈無老風騷。", "風騷脆霜葉，鄭衛壯虎牢。", "齷齪勝宏放，昆吾避鉛刀。", "競利黷奇貨，遇士輶纖毫。", "妄冀款段馳，不使鸞鵠高。", "弱羽與微類，聚族喧林皋。", "殘粒酬渴饑，墮葉爭爬搔。", "忽乘吹送起，遂記蔭翳翱。", "因風不知反，墮地寧償勞。", "顛頓失故步，悲叫尋叢蒿。", "擊搏恐不免，彈射安得逃。", "仰窺扶摇翮，俯媿腹背毛。", "美人隔秋水，煖靄明春袍。", "訪舊溪上寺，泊我寺外濠。", "開端問戒鼠，次及銘瘞獒。", "堅窮與壯老，指摘仍繹繅。", "玉石體自異，瑕纇寧容韜。", "清評盍用恕，白戰惡足鏖。", "試請避三舍，大弨方載櫜。"]'),
('1fb05e3f-9d98-476f-809c-c11ddba2f395','寄石龜翁總幹','釋居簡','宋','宋诗','song-poetry','','[]','龜靈詩亦靈，鐵甕渺江城。',48,'全唐诗/poet.song.180000.json','["龜靈詩亦靈，鐵甕渺江城。", "爆得風騷兆，鏗爲琬琰聲。", "看如容易得，吟却最難成。", "只有蘭陵月，知余入細評。"]'),
('aa7bd683-199a-4646-9709-3ee1b4f12bb7','高教授訃至','釋居簡','宋','宋诗','song-poetry','','[]','競俗奔奔急，潜窺却步難。',48,'全唐诗/poet.song.180000.json','["競俗奔奔急，潜窺却步難。", "退知藏用密，居得秉彜安。", "有襪常番著，無弦敢廢彈。", "謝城空冷帳，回首一汍瀾。"]'),
('e0fd6eec-b894-4a63-bff1-3804a66f5abe','陸別駕解組','釋居簡','宋','宋诗','song-poetry','','[]','不平容赴愬，無枉不相關。',48,'全唐诗/poet.song.180000.json','["不平容赴愬，無枉不相關。", "契託今州牧，官同舊筍班。", "騷情吟未盡，樂府載將還。", "况是平分手，新聲課小蠻。"]'),
('efdc3165-1118-4309-aee3-dbc4e3f65b07','蔡提幹卜居','釋居簡','宋','宋诗','song-poetry','','[]','男兒胸中奇，忍作懷土羞。',228,'全唐诗/poet.song.180000.json','["男兒胸中奇，忍作懷土羞。", "冒榮復素食，矧乃羞之尤。", "謾令兒女曹，欣戚相喧啾。", "東家新買隣，百萬未易酬。", "鄰人何人斯，百萬蒱博儔。", "婁叱九折馭，朗吟三硤秋。", "結客盡群玉，稅駕半九州。", "疪存萬間志，資乏三徑謀。", "長沙與吳會，豈必真菟裘。", "濯足門前溪，泛月溪上舟。", "有客共吟嘯，有書同校讎。", "有時鼓瑟琴，亦復飛觥籌。", "論士笑浮俗，得失令人愁。", "重官不重名，不約常相侔。", "鄉來飛將軍，渠豈不足侯。", "名落天地間，迥覺天地遒。", "謬侯紛如蟻，千古衆楚咻。", "至今謬與賢，渭與涇殊流。", "高名獨不死，天地同悠悠。"]'),
('6d73b3c9-83cf-4b26-bab4-623514a091bc','續鐵鑪步志寄平江太守','釋居簡','宋','宋诗','song-poetry','','[]','惟虛不競實，薄俗崇虛名。',192,'全唐诗/poet.song.180000.json','["惟虛不競實，薄俗崇虛名。", "豈其鄉來實，虛課今日成。", "因依鐵爐步，自昔聞題評。", "橐籥廢已久，百鍊餘晶晶。", "大而函牛鼎，小而割雞刃。", "刀也玉如泥，錐也囊脫穎。", "箕裘既失緒，族屬庸振領。", "區區欲就鑄，水滸方接軫。", "譬彼趙善戰，奢抗狼虎秦。", "括也讀父書，言外欠發明。", "奢死括駕趙，兩眼空無人。", "全提四十萬，一窖埋長平。", "括固不足道，謬甚用括者。", "用名弗核實，鑄錯敗良冶。", "曩時闔閭城，呻吟滿四野。", "忽聞襦袴歌，一日變風雅。"]'),
('6deed286-204d-4426-8b12-4b89c754c021','歌太湖迓常守王寺丞','釋居簡','宋','宋诗','song-poetry','','["\u592a\u6e56"]','伊誰量太湖，三萬六千頃。',136,'全唐诗/poet.song.180000.json','["伊誰量太湖，三萬六千頃。", "天圍幾何寬，滿湖不畦畛。", "或疑湖底天可田，箋天亟問縣官請。", "况復周家有成法，盡底均作八家井。", "鯨鵬蛟鰐俱幽屏，藻荇糵爲禾黍穎，公田利與私田準。", "坐令虞芮俗，化作西伯境。", "野田無哭聲，夜厖亦不驚。", "晏眠早作日以寧，已輸再輸毋婁征。", "循良在上如西京，媚長牙爪俱逡逡。"]'),
('943cbae5-528e-4a22-b045-2c2daaa42813','檥舟黄叔向部綱南徐','釋居簡','宋','宋诗','song-poetry','','[]','三顧凄凉後，今誰抱膝吟。',48,'全唐诗/poet.song.180000.json','["三顧凄凉後，今誰抱膝吟。", "有人皆肉食，無舌變梟音。", "穎脫三千客，囊空四萬金。", "孤舟猶繫岸，江碧柳陰陰。"]'),
('3c62407b-49fd-43da-9e21-75cd7250ee9a','柳  其一','釋居簡','宋','宋诗','song-poetry','','[]','江春欲到最先知，次到南枝次北枝。',32,'全唐诗/poet.song.180000.json','["江春欲到最先知，次到南枝次北枝。", "不信樓頭觀旖旎，嫰金勻徧去年絲。"]'),
('13ebb295-4bdc-426f-bb17-a0920f808941','柳  其二','釋居簡','宋','宋诗','song-poetry','','[]','奈爾縈晴殢雨何，靜時常少動時多。',32,'全唐诗/poet.song.180000.json','["奈爾縈晴殢雨何，靜時常少動時多。", "初無惱亂春風意，却是春風惱亂它。"]'),
('5319edc0-383f-4f04-b2b6-ff2d2cb55cb8','贈製香蠟茶者','釋居簡','宋','宋诗','song-poetry','','[]','玄質團團玉不如，翠鈿小切試昆吾。',32,'全唐诗/poet.song.180000.json','["玄質團團玉不如，翠鈿小切試昆吾。", "文園病酒文君老，盍薦芳甘瀹道腴。"]'),
('42ca56fc-f57b-4a24-86f9-d18a30ae0a30','周漕泊舟寺前','釋居簡','宋','宋诗','song-poetry','','[]','見說淮東使者歸，耄鯢都作小兒啼。',64,'全唐诗/poet.song.180000.json','["見說淮東使者歸，耄鯢都作小兒啼。", "暫閑綠野停鴻鵠，小俟青冥驟駃騠。", "度外二三皆勝策，胸中十萬未全提。", "浯溪尚有嶄天石，頌德歌功儘可題。"]'),
('7603e054-39f1-40b9-aa78-2526e0721393','金山  其一','釋居簡','宋','宋诗','song-poetry','','[]','彈壓奔鯨障怒飛，削成峭峙不分支。',64,'全唐诗/poet.song.180000.json','["彈壓奔鯨障怒飛，削成峭峙不分支。", "自簷滴外水爲地，於海潮中石湧坻。", "蜀浪春肥浮棹急，淮雲曉濕度江遲。", "中泠一滴清如玉，弗與滔滔混濁移。"]'),
('1e837cc9-5d74-445e-a7ad-8fded08a3df2','金山  其二','釋居簡','宋','宋诗','song-poetry','','[]','不占南徐地，遥分北固天。',48,'全唐诗/poet.song.180000.json','["不占南徐地，遥分北固天。", "削瓊標巨浸，堅壁下長川。", "城柝偏遥夜，淮烽直近壖。", "建炎天子聖，翠輦到層顛。"]'),
('64f0a1c0-5827-4f00-8e2f-46191b1f5b71','秋塘陳敬父挽章','釋居簡','宋','宋诗','song-poetry','','[]','百尺樓頭卧，傍無一寸梯。',48,'全唐诗/poet.song.180000.json','["百尺樓頭卧，傍無一寸梯。", "談知秋鬢苦，豪壓暮潮低。", "白璧羞瓴甋，青絲老駃騠。", "不能回晚照，相與就刀圭。"]'),
('789b964a-3dfb-4ab7-8597-ec104d64d3f4','即事','釋居簡','宋','宋诗','song-poetry','','[]','一點春深燕子泥，卷簾不記燕歸時。',32,'全唐诗/poet.song.180000.json','["一點春深燕子泥，卷簾不記燕歸時。", "牡丹又逐朝霞散，亟課殘經更不知。"]'),
('f2fbb049-0485-4ffc-9250-3fc395831ded','石龜廨宇可山','釋居簡','宋','宋诗','song-poetry','','[]','城中闚寸碧，益遠益難真。',48,'全唐诗/poet.song.180000.json','["城中闚寸碧，益遠益難真。", "簷外開荒壘，天涯見似人。", "驟觀雖小有，側看亦橫陳。", "蠟屐隨山眂，幽尋謾苦辛。"]'),
('1718a391-3234-47b7-94d6-f9489c129f4a','於潛張長官榮上','釋居簡','宋','宋诗','song-poetry','','[]','岞崿峰前古子男，萬家喜氣接浮嵐。',64,'全唐诗/poet.song.180000.json','["岞崿峰前古子男，萬家喜氣接浮嵐。", "許曾蛻俗今留跡，坡爲尋僧舊駐驂。", "養志不違宜膝下，去天差近似城南。", "明年一縣花如錦，日日春風伴燕酣。"]'),
('8aef9697-3d0b-4812-b7b3-22e1930fa2b5','米知縣之官建平','釋居簡','宋','宋诗','song-poetry','','[]','凜然晉宋美風姿，又似君家古少儀。',64,'全唐诗/poet.song.180000.json','["凜然晉宋美風姿，又似君家古少儀。", "劇縣一經名輩作，春江相與白鷗宜。", "盤根小試難藏利，剖竹喬遷勿復疑。", "雞犬相聞纔隔岸，日邊書到欲先知。"]'),
('a12bac97-4089-4556-b36b-2c51feb8b29f','酬滕主簿','釋居簡','宋','宋诗','song-poetry','','[]','帆開得便風，從事果何從。',48,'全唐诗/poet.song.180000.json','["帆開得便風，從事果何從。", "研滑磨穿底，毫銛賈勇鋒。", "三千篇謾與，十四字休封。", "歲晚論交地，由來淡勝濃。"]'),
('a351039f-e426-4739-a3aa-cf4aabed7382','張令人誦經','釋居簡','宋','宋诗','song-poetry','','[]','沉思何處雨花零，彷彿靈山會上曾。',64,'全唐诗/poet.song.180000.json','["沉思何處雨花零，彷彿靈山會上曾。", "不媿後來成佛女，宛如前輩在家僧。", "翳花去眼空無蔕，老玉勝春瘦弗稜。", "相伴靈椿歲寒操，共看兩幹又傳燈。"]'),
('5cf541d5-b0a7-4401-8e5d-b8d625c40b6b','荆山','釋居簡','宋','宋诗','song-poetry','','[]','隠不知山淺，端如璞在荆。',48,'全唐诗/poet.song.180000.json','["隠不知山淺，端如璞在荆。", "草滋皆玉色，松籟作江聲。", "莽莽嫌吟俗，滔滔笑渭清。", "莫將雲錦橐，容易小能名。"]'),
('bd1f1a07-05e1-40e1-9962-88e83199dfe8','劉母墓','釋居簡','宋','宋诗','song-poetry','','[]','怒虎跑雲此處傳，到今知是幾何年。',64,'全唐诗/poet.song.180000.json','["怒虎跑雲此處傳，到今知是幾何年。", "一彎碧似回珠浦，數曲青藏瘞玉田。", "彤管旋添今日史，白華何補鄉來篇。", "誄辭盡出騷人社，行橐猶能得細詮。"]'),
('ab2edc91-7b7a-46cb-9d7c-4af5f9132e26','次宜興謝長官借榻韻','釋居簡','宋','宋诗','song-poetry','','[]','挂帆來迓新邦伯，不與郵亭計短長。',64,'全唐诗/poet.song.180000.json','["挂帆來迓新邦伯，不與郵亭計短長。", "舊習澹如黄閣老，騷情閑寄碧雲房。", "空濛得處花生筆，灧瀲斟時月滿觴。", "想見客氊寒不寐，自將宿火撥殘香。"]'),
('c2e0824f-c07f-4164-9fce-14dcd779288e','胡子安見漫堂','釋居簡','宋','宋诗','song-poetry','','[]','一與慈湖別，懷君十五年。',48,'全唐诗/poet.song.180000.json','["一與慈湖別，懷君十五年。", "衣曾知密付，人不是虛傳。", "氣老凌秋爽，詩成指日僊。", "相逢卯金子，應有碧雲箋。"]'),
('a5cec4a8-cf5f-4dbb-bf23-e76b07eb54a2','胡子安荷花','釋居簡','宋','宋诗','song-poetry','','[]','出水依稀带露痕，采毫羞澀媿旌能。',32,'全唐诗/poet.song.180000.json','["出水依稀带露痕，采毫羞澀媿旌能。", "細思語不經人道，揖遜安州食蜜僧。"]'),
('4259388b-1fb8-47d9-98cf-dfb961fef4b0','贈皓律師','釋居簡','宋','宋诗','song-poetry','','[]','皓也毘尼學，精於玉帳嚴。',48,'全唐诗/poet.song.180000.json','["皓也毘尼學，精於玉帳嚴。", "蟻酣停掃砌，燕乳記勾簾。", "茶鼎敲冰煮，花壺漉水添。", "夢回池草綠，忍踐綠纖纖。"]'),
('66f21eed-0f8a-4129-9131-a458dc448512','寄徽州謝使君密齋','釋居簡','宋','宋诗','song-poetry','','[]','新安産最良，引類赴文房。',48,'全唐诗/poet.song.180000.json','["新安産最良，引類赴文房。", "太守五四友，管城三二王。", "水分千里月，春滿六州棠。", "丹穴皆鮮羽，叢霄看頡頏。"]'),
('1d26b956-c8bb-4f50-a4b8-c30927d02108','孫氏封禪碑如囤俗呼囤碑','釋居簡','宋','宋诗','song-poetry','','[]','拆裂金刀地，三分得一分。',48,'全唐诗/poet.song.180000.json','["拆裂金刀地，三分得一分。", "干戈未奠枕，封禪已刊文。", "符瑞規前謬，勳勞詫後聞。", "水中龍欲下，矯首蜀江濆。"]'),
('0155b40c-4a03-4a4a-83ec-5f8b46d32b81','修玉樓','釋居簡','宋','宋诗','song-poetry','','[]','故郡樓居者，宜州太史家。',48,'全唐诗/poet.song.180000.json','["故郡樓居者，宜州太史家。", "浦寒雲掩鏡，研冷筆生花。", "月砌亭亭玉，風籤獵獵牙。", "合簪酬大雅，一戰冡淫哇。"]'),
('5c03b506-7cc4-44e6-b4d7-c6a1afbf5f7a','漲水嘆','釋居簡','宋','宋诗','song-poetry','','[]','去年水爲祟，數州害田稚。',220,'全唐诗/poet.song.180000.json','["去年水爲祟，數州害田稚。", "今年逾去年，低陌吞高阡。", "天時杳難度，耕者虞溝壑。", "問天如何其，天空無磴梯。", "蒼然不可詰，試詰天所司。", "司方責公田，皇暇恤我私。", "率先盈囷倉，又欲豐盛粢。", "長呼天不聞，問司胡不思。", "反裘惜奇毳，裏盡毳孰資。", "司云心是豐凶本，帝哀爾氓亂方寸。", "遂令腐爛不可支，甚若秦皇齊威尸。", "佞壬矯誑至於此，天橫傷殘乃其自。", "濤翻天上第一禪，所感召者誠宜然。", "或譏浮圖事吟牋，法當勿用浮圖言。", "少陵琳琅千萬篇，留人間者百不一。", "亦師粲可縛禪寂，不知此話何從出。"]'),
('a9749fd8-c90d-475f-9edd-e9ac913924d0','聞沈宏父訃','釋居簡','宋','宋诗','song-poetry','','[]','雲裘未換貂，鬢已幾莖彫。',48,'全唐诗/poet.song.180000.json','["雲裘未換貂，鬢已幾莖彫。", "璞美宜穹售，樓成或下招。", "生無金潤屋，死有玉蕃苗。", "欲酹余不土，天漿弗滿瓢。"]'),
('150a368e-7717-4d2b-821c-1ca00fdeac25','晚牧圖','釋居簡','宋','宋诗','song-poetry','','[]','寸繩尺箠亂山深，節制安知豎子心。',32,'全唐诗/poet.song.180000.json','["寸繩尺箠亂山深，節制安知豎子心。", "老子看牛如相馬，微茫淡墨賞遺音。"]'),
('58c10d8b-39f7-4373-ba89-23ec16135549','贈吳兄仲孚','釋居簡','宋','宋诗','song-poetry','','[]','策慵推病枕，刺字忽來前。',48,'全唐诗/poet.song.180000.json','["策慵推病枕，刺字忽來前。", "未說名瓜子，先傳姓口天。", "鴻蜚煩送目，蛩響動吟肩。", "窮與窮相值，秋風已颯然。"]'),
('b3508841-e5c7-4a3b-9192-e45d0bc240c2','蟠松','釋居簡','宋','宋诗','song-poetry','','[]','肯爲人低首，非因米折腰。',48,'全唐诗/poet.song.180000.json','["肯爲人低首，非因米折腰。", "曲何慚九地，直恐礙叢霄。", "雪虐知擎重，風酸不怕摇。", "喬林多裂幹，弗後歲寒彫。"]'),
('e5a89f53-5ce3-4ba5-a36d-fb7c723029cc','泣姜貧樂謝長興長趙可齋  其一','釋居簡','宋','宋诗','song-poetry','','[]','葬近陳朝檜，傷心絕筆吟。',48,'全唐诗/poet.song.180000.json','["葬近陳朝檜，傷心絕筆吟。", "家餘乞米帖，囊盡擲蛙金。", "語戇貧難屈，名羶死弗沉。", "王孫種花縣，何似古藤陰。"]'),
('8873792c-c933-402e-b481-de0c58be44a9','泣姜貧樂謝長興長趙可齋  其二','釋居簡','宋','宋诗','song-poetry','','[]','金盡驊騮死，交遊散似雲。',48,'全唐诗/poet.song.180000.json','["金盡驊騮死，交遊散似雲。", "五窮逐不去，百拙巧難分。", "竹唁梅疎友，鷗隨鷺吊群。", "未銘先傳散，勒徧霅川濆。"]'),
('9564d875-f49b-41d2-ad95-de765422a1f8','仁壽敬行可開兩池曰雙照','釋居簡','宋','宋诗','song-poetry','','[]','照與照者，影沈蹟絕。',132,'全唐诗/poet.song.180000.json','["照與照者，影沈蹟絕。", "爾如何其，自起途轍。", "傍睨語我毋庸疑，倚櫺爲我賦兩池。", "謂言物物皆吾詩，絕憐思苦槁弗滋。", "不忍污此清漣漪，不然小需載生魄，碧瀲不摇皆玉色。", "一池各有一眉新，眉間喜氣浮津津。", "悠然散作無邊春，輾輪半仄朣朣蘸，明透方方兩團鑑。", "更徵此義吾無說，莫問清池問明月。"]'),
('d831d8f9-c817-4738-8bb5-ba47c22fada5','吳江塔寺登閣觀太湖','釋居簡','宋','宋诗','song-poetry','','["\u592a\u6e56"]','十華藏海藐涔蹄，便作涔蹄爲物移。',32,'全唐诗/poet.song.180000.json','["十華藏海藐涔蹄，便作涔蹄爲物移。", "富貴不須開帝網，只開萬頃碧玻璃。"]'),
('6036ac20-e1b3-4025-af2c-6cfdccd554fb','雪','釋居簡','宋','宋诗','song-poetry','','[]','集霰夜才分，繽霏曉更零。',48,'全唐诗/poet.song.180000.json','["集霰夜才分，繽霏曉更零。", "未乘風洒洒，先挾雨冥冥。", "窗失三更黑，山無一寸青。", "有船非剡櫂，誰去扣吟扃。"]'),
('22ce5670-7526-41da-92f2-9d97a3e4aed0','聞杜子野訃','釋居簡','宋','宋诗','song-poetry','','[]','嘉泰開禧後，人傳伯仲文。',48,'全唐诗/poet.song.180000.json','["嘉泰開禧後，人傳伯仲文。", "縯綸宜掌制，草檄謾從軍。", "楚塞沈秋警，江雲黯暮曛。", "舊題湖上石，蘚暈濕苔紋。"]'),
('a9f9c8b8-8f3e-424f-99cd-5e97be44bed9','問傅菴海棠消息  其一','釋居簡','宋','宋诗','song-poetry','','[]','光風欲透錦燕脂，數點忺晴已薦奇。',32,'全唐诗/poet.song.180000.json','["光風欲透錦燕脂，數點忺晴已薦奇。", "惆悵一雙新燕子，年年不見未開時。"]'),
('1afcb35e-39cf-4a9f-8339-4d31d94cd013','問傅菴海棠消息  其二','釋居簡','宋','宋诗','song-poetry','','[]','紅雲煖壓草玄池，宮燭傳榆夜更奇。',32,'全唐诗/poet.song.180000.json','["紅雲煖壓草玄池，宮燭傳榆夜更奇。", "空掩沉香亭北恨，玉環宿酒未醒時。"]'),
('6bd58be6-69ab-456f-8227-d1c010a45571','讀賈太傅傳  其一','釋居簡','宋','宋诗','song-poetry','','[]','諸老先生總未言，一言中的已先聞。',32,'全唐诗/poet.song.180000.json','["諸老先生總未言，一言中的已先聞。", "守成天子恭沉默，不妬多功重少文。"]'),
('7b09009c-72f2-4b34-9f68-9316949f494c','讀賈太傅傳  其二','釋居簡','宋','宋诗','song-poetry','','[]','七日平城戒覆車，不容年少係單于。',32,'全唐诗/poet.song.180000.json','["七日平城戒覆車，不容年少係單于。", "用賢勿貳君知否，不用何須歎不如。"]'),
('2080077e-5ec6-4182-8441-b0e4df5d218f','趙都廂見過','釋居簡','宋','宋诗','song-poetry','','[]','彷彿巴東縣，空橫盡日船。',48,'全唐诗/poet.song.180000.json','["彷彿巴東縣，空橫盡日船。", "晴占收麥候，寒似養花天。", "嵐濕窗紗重，雲明幌楮鮮。", "商星與參子，相別動經年。"]'),
('db5e3b60-d027-43af-886a-e7261be7efae','訪葉海鹽不值','釋居簡','宋','宋诗','song-poetry','','[]','綠葉未幄春正遲，看看雪煖開荼蘼。',160,'全唐诗/poet.song.180000.json','["綠葉未幄春正遲，看看雪煖開荼蘼。", "丁寧密意謝紅藥，掎角緩放韶華歸。", "一芳一菲尋版蕩，更無可砥狂瀾漲。", "惠風迤邐索蒲葵，約束凉薰小相讓。", "棠梨雨褪燕脂蔫，來禽效顰相後先。", "主人朝天未回韉，軟紅沒屨東華前。", "飲湖山綠方頹玉，水遶山圍南宕北。", "起來却憶故園春，園中四時花木新。", "詩人眉苦閑情皺，不怕天知怕天瘦。", "遂令真宰妬冥搜，無人不恨古藤州。"]'),
('1aadc8b0-49df-4951-a5e4-4cc358618587','入邑阻風  其一','釋居簡','宋','宋诗','song-poetry','','[]','鬭風鷁退不忺飛，還似當年過宋時。',32,'全唐诗/poet.song.180000.json','["鬭風鷁退不忺飛，還似當年過宋時。", "又似雪舟人興盡，歸時却是順風吹。"]'),
('2ff086b4-6a32-4c7f-af56-cf8a3d45f6e7','入邑阻風  其二','釋居簡','宋','宋诗','song-poetry','','[]','見時無事去還思，往往來參去不辭。',32,'全唐诗/poet.song.180000.json','["見時無事去還思，往往來參去不辭。", "弗是山林傲軒冕，澹臺有請獨無私。"]'),
('f657e518-0d03-4d59-9730-13267530bb51','長興長趙憲可說閩帥王方岩逸事','釋居簡','宋','宋诗','song-poetry','','[]','勳業在青編，貂蟬負雪顛。',168,'全唐诗/poet.song.180000.json','["勳業在青編，貂蟬負雪顛。", "巍科幾望月，定見不回川。", "用小才嫌大，時危德忌全。", "上天尋白傅，表海問蓬仙。", "心在方巖上，天游委羽先。", "十連茂棠蔭，一橐老鈞天。", "濁水因珠潔，清風被物鮮。", "孤芳觀晚節，善賈考初年。", "吟速甘存拙，文疎耻競妍。", "鄭莊真好客，王衍不言錢。", "謬我奚爲者，煩公辱贈篇。", "初無曇穎契，終說項斯賢。", "大雅皆傳響，楞嚴未訖箋。", "新阡小溪曲，華玉反藍田。"]'),
('402165a8-12f0-4e9b-b479-afac6d216378','四明陸韓二佳友登科  其一','釋居簡','宋','宋诗','song-poetry','','[]','龍虎榜頭千佛名，亂山寸碧起雙明。',64,'全唐诗/poet.song.180000.json','["龍虎榜頭千佛名，亂山寸碧起雙明。", "預吟新句雖三首，莫放臚傳第二聲。", "得意馬蹄須款曲，吐花兔穎看崢嶸。", "平生兩眼人嫌白，青爲君家好弟兄。"]'),
('02f15e86-4a81-46b4-b236-e649d1344d59','四明陸韓二佳友登科  其二','釋居簡','宋','宋诗','song-poetry','','[]','江上得書纔半月，漕闈旋與計偕初。',64,'全唐诗/poet.song.180000.json','["江上得書纔半月，漕闈旋與計偕初。", "荐聞得第喜何似，縱不嗣音曾弗疎。", "別院苦難應有助，大庭賈勇可無餘。", "首呼名氏須相報，雁若慵來亟遣魚。"]'),
('89140748-b976-4c8f-8528-7ba25a4ab818','盤隠瘞猿','釋居簡','宋','宋诗','song-poetry','','[]','寸土如寸金，恩殊帷蓋深。',48,'全唐诗/poet.song.180000.json','["寸土如寸金，恩殊帷蓋深。", "病思罹穽日，死恨出林心。", "殘橡停朝賦，空樊絕夜吟。", "六窗呼不應，雲冷月沉沉。"]'),
('676dad93-7542-4d4a-a122-9a2ffbaf3b47','張公洞得響石','釋居簡','宋','宋诗','song-poetry','','[]','漢張燒煉處，切得一痕雲。',48,'全唐诗/poet.song.180000.json','["漢張燒煉處，切得一痕雲。", "土蝕爊金液，苔皴截鐵文。", "響非弦脆雜，清浣俗紛紜。", "袖裏東溟小，羅浮不足云。"]'),
('beccb938-6420-4fc1-843d-5a4538fae08f','酬盧玉堂','釋居簡','宋','宋诗','song-poetry','','[]','溪友弗來過，幽栖欠濯磨。',48,'全唐诗/poet.song.180000.json','["溪友弗來過，幽栖欠濯磨。", "眼饑嫌睡少，竹醉惜移多。", "雛燕駢爭乳，慵鶑噤弗歌。", "窗低雲不掃，零亂儘從它。"]'),
('2de88cfa-862d-4df6-bd21-6bdb690c828d','陳襄陽歸長興  其一','釋居簡','宋','宋诗','song-poetry','','[]','玉帳擁貔貅，朝天爽借留。',48,'全唐诗/poet.song.180000.json','["玉帳擁貔貅，朝天爽借留。", "勳庸收素定，江漢耻橫流。", "傳有當時癖，池無暇日游。", "貂蟬倘來耳，又見出兜鍪。"]'),
('f6c7c706-bdbf-4543-8d2d-27ae2455f66e','陳襄陽歸長興  其二','釋居簡','宋','宋诗','song-poetry','','[]','巾子山前寺，曾分華頂薇。',48,'全唐诗/poet.song.180000.json','["巾子山前寺，曾分華頂薇。", "去尋龍首約，因些客兒歸。", "白羽精戎律，黄金緩带圍。", "孔融傾座處，西望幾斜暉。"]'),
('c4a6f4f8-4552-4c5e-859e-a08750c310ba','項別駕訃臨','釋居簡','宋','宋诗','song-poetry','','[]','清約筋骸別，雲泥俗肺腸。',48,'全唐诗/poet.song.180000.json','["清約筋骸別，雲泥俗肺腸。", "酌貪廉不污，鑑正醜難藏。", "貴藥無錢買，沉痾有死償。", "若爲千駟馬，得似蕨薇香。"]'),
('1c1687b8-8e59-41a2-bc53-b87f36c2b192','玉樹曲','釋居簡','宋','宋诗','song-poetry','','[]','翠袖薄，霞裾飄，盈盈不動金步摇。',72,'全唐诗/poet.song.180000.json','["翠袖薄，霞裾飄，盈盈不動金步摇。", "步摇金扶翠翹玉，只知今夕歡難足，不知明日歡難續。", "瑶姬自是能吟女，璧合知還舊躔度。", "古菱花試小龍文，雙鸞舞處亭亭分。"]'),
('31a5ff16-7b3c-4014-ab79-dc71a424617e','巫山高','釋居簡','宋','宋诗','song-poetry','','[]','陽臺晴霞煖生纈，削玉六雙雲嵽嵲。',96,'全唐诗/poet.song.180000.json','["陽臺晴霞煖生纈，削玉六雙雲嵽嵲。", "白鹽赤甲秋未零，側樹欹巖妥鱗𩧆。", "霧轂煙軿兩朱鳳，紫瓊鋃鐺碧瑶鞚。", "轍飛不點九地泥，泥滓各諧螻蟻夢。", "蘭臺詞客詞詭奇，諷微勸廣胡不思。", "更欲張儀聘燕趙，却嫌鄭袖黄金少。"]'),
('e5ad28f8-ae72-4386-995f-1f339ed157bd','蓮塘曲','釋居簡','宋','宋诗','song-poetry','','[]','錦帆涇淺花如玉，苧羅女兒更明淑。',64,'全唐诗/poet.song.180000.json','["錦帆涇淺花如玉，苧羅女兒更明淑。", "纖柔擥花映芳臉，綠皺不摇秋湛染。", "嫣然闖影一笑新，笑花解笑不解顰。", "扁舟五湖一痕月，照見顰吳更顰越。"]'),
('3157df5f-b5dc-4f1e-994d-301a224e0d24','古鏡行','釋居簡','宋','宋诗','song-poetry','','[]','一奩古碧涵冷秋，泓澄紺滑凝不流。',96,'全唐诗/poet.song.180000.json','["一奩古碧涵冷秋，泓澄紺滑凝不流。", "開奩拂拭辨款識，認得軒轅在時事。", "軒轅昔游廣寒殿，取太陰精酬百鍊。", "冏冏妖蹤怪影消，夜哭空郊曉奔竄。", "菱花亂古亦亂真，識真考古今無人。", "黄金寧可買不死，難買張華兩眸子。"]'),
('90be5793-82fe-4689-b810-b30bf0f1178e','傅家林','釋居簡','宋','宋诗','song-poetry','','[]','樵斧響晴雷，平林頃刻摧。',48,'全唐诗/poet.song.180000.json','["樵斧響晴雷，平林頃刻摧。", "兔亡三穴徙，猿弔一枝哀。", "桑梓思前輩，松杉惜上林。", "養林如養德，萬木盍重栽。"]'),
('15bcebc5-b9a6-4040-a5c9-9bacee53c57b','次韻鄭大參浄慈雙井','釋居簡','宋','宋诗','song-poetry','','[]','山展鳳膺仍歛翮，東井碧通西井白。',176,'全唐诗/poet.song.180000.json','["山展鳳膺仍歛翮，東井碧通西井白。", "井花婁欲策茶勳，長恨眼中無此客。", "夔州病渴夜迢迢，阿段透雲分湱湱。", "胡爲金錫卓山泉，小倚銀床問庭柏。", "一杯盍爲龍象供，數尋自是蜿蜒宅。", "萬斛滔滔隨地出，九地茫茫不須擇。", "淺清盈甃玉痕圓，深浄鏡空雲影拆。", "江淮行地自南北，河漢如人同血脈。", "舉瓢高謝滄浪濁，吹簫去覓浮丘伯。", "遂令天水不違行，洞明爻象元同畫。", "更將康谷細商評，一笑自知肩可拍。"]'),
('e6c5c269-e4fd-48ae-b6a9-0b54b20cba0f','哀三城','釋居簡','宋','宋诗','song-poetry','','[]','歲逢虎牛禍折萌，蕩蕩蜀道猶可評。',352,'全唐诗/poet.song.180000.json','["歲逢虎牛禍折萌，蕩蕩蜀道猶可評。", "嗾姦反正善其計，振槁拉枯徒爾勤。", "初雖覆杯可撲滅，終焉决海難爲平。", "智人三尺眼前暗，明玉一玷磨弗晶。", "因仍擾擾不知了，殘金欲灺連韃人。", "武功夙著沖與寔，貂蟬貴欲兜牟成。", "孽成孤鳳鳥不度，守有可死生無因。", "兩公氣節固相類，又類射虎飛將軍。", "西和寅仲出儒素，開禧總餉先垂名。", "太丘是父有是子，衝樓跨竈前無倫。", "話頭講明有定見，不與姦諂相因循。", "犬戎日衆我日寡，貔貅乍屈還乍信。", "賀蘭飽鮮方醉醇，嚙指不讎南霽雲。", "慟哭秦庭不肯援，有嚴玉帳無分兵。", "借令空弮可持滿，飛鏑已盡風中鳴。", "三城父兄一時陷，况復骨肉懷親親。", "有生必死死有所，此死可羞尸素群。", "矜韜衒略謾蠢蠢，妬功嫉效徒逡逡。", "幸災之跡弗容掩，不掉之尾何足云。", "鄉來益昌倡大義，阿源流芳千載榮。", "勝天倘可恃人衆，公道莫於行路聽。", "後先忠節貫日星，野史孰愈良史真。"]'),
('3968ea45-9c3b-4025-a939-358ad9f4d0da','九日寄宜興謝長官','釋居簡','宋','宋诗','song-poetry','','[]','射蛟溪上黄花酒，灝氣浮溪靜弗瀾。',64,'全唐诗/poet.song.180000.json','["射蛟溪上黄花酒，灝氣浮溪靜弗瀾。", "素羽已忘秋後熱，紫萸不怕夜來寒。", "軫裁彫玉鳴焦尾，屏掩涂金炷博山。", "步武自高吟自適，何須鼓吹上層巒。"]'),
('7c9263f3-c0ec-47fa-9840-4af20045858b','苦雨','釋居簡','宋','宋诗','song-poetry','','[]','尺潦翻階怒輥沙，沉陰物物殞精華。',64,'全唐诗/poet.song.180000.json','["尺潦翻階怒輥沙，沉陰物物殞精華。", "最憐萬畝傷禾穎，忘却重陽對菊花。", "原上有苗皆委地，水中無穗不生芽。", "占晴夜夜觀西北，一縷何曾見暮霞。"]'),
('3ddb6848-0f51-44fb-a6cc-1705b1b0c0a1','贈天台權上人','釋居簡','宋','宋诗','song-poetry','','[]','老荷紉綴晚秋前，冷榻曾無坐客氊。',32,'全唐诗/poet.song.180000.json','["老荷紉綴晚秋前，冷榻曾無坐客氊。", "旋剪玉蟲觀細字，欲分半芋且遲眠。"]'),
('3dd093c6-6e11-469f-8e35-cc647810aa3c','箬溪樓製錦堂長興長官趙可齋新製  其一','釋居簡','宋','宋诗','song-poetry','','[]','步武弗忺低，闌干俯峭巍。',48,'全唐诗/poet.song.180000.json','["步武弗忺低，闌干俯峭巍。", "霜鴻天外去，簷翼水邊飛。", "勝踐西風老，幽尋晚照微。", "賀成先燕雀，宏略在沉機。"]'),
('5aa56b9b-8904-4a0d-b5df-6cb50fb78c93','箬溪樓製錦堂長興長官趙可齋新製  其二','釋居簡','宋','宋诗','song-poetry','','[]','古製宜藏巧，吾寧十目窺。',48,'全唐诗/poet.song.180000.json','["古製宜藏巧，吾寧十目窺。", "弗將青鏡掩，誰兆白鷗疑。", "雁鶩方群散，罝罦各自施。", "悠然機杼別，無媿召南思。"]'),
('bc102543-15ea-4d5e-a2ee-e674b37f27dc','大雄寺陳朝檜','釋居簡','宋','宋诗','song-poetry','','[]','託根陳土隋風煙，送盡鯉魚蜚上天。',128,'全唐诗/poet.song.180000.json','["託根陳土隋風煙，送盡鯉魚蜚上天。", "六騑度江又如許，老彭社櫟將齊年。", "彭自有商觀五伯，區區社櫟奚爲者。", "君乎幹老舊時天，剛中紫鐵青銅堅。", "一年一年看妖妍，年年死在秋風前。", "輪囷孤頂鸞停翼，脫略霜皮蛟露脊。", "自古才難人弗惜，江東酒壺澆柱石。", "夜深風雨卷潭湫，霹靂一聲天地秋。"]'),
('106db18e-8143-4b37-8924-f097129ea2fc','月谿','釋居簡','宋','宋诗','song-poetry','','[]','光動群陰歛，朣朣古岸斜。',48,'全唐诗/poet.song.180000.json','["光動群陰歛，朣朣古岸斜。", "緣空冰碾霧，分影璧沉沙。", "圓轉剛非缺，虛靈浄弗瑕。", "修輪紛血指，玉斧在山家。"]'),
('0922897f-4cf1-4825-936b-b3cf2ba256e9','十月初三四雪','釋居簡','宋','宋诗','song-poetry','','[]','霰集三秋後，花飛十月初。',48,'全唐诗/poet.song.180000.json','["霰集三秋後，花飛十月初。", "更添兩度白，併作一年書。", "稻疃齊生耳，麰田爛弗鉏。", "寒敲君子竹，壓折怕林疎。"]'),
('8673f457-6624-4f45-9c84-dfef40a4e1d9','墨藕花  其一','釋居簡','宋','宋诗','song-poetry','','[]','紅鋪不是芬陁利，綠卷無非菡萏秋。',32,'全唐诗/poet.song.180000.json','["紅鋪不是芬陁利，綠卷無非菡萏秋。", "以色媚人寧壞色，不隨榮謝鏡中羞。"]'),
('eda815b1-77ac-440c-8f3c-9dbd7b578558','墨藕花  其二','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西子湖陰錦掞雲，水風池閣度晴熏。',32,'全唐诗/poet.song.180000.json','["西子湖陰錦掞雲，水風池閣度晴熏。", "影窺明王生綃薄，分外精神一兩分。"]'),
('67087e9c-730a-44f9-955a-06472848e06e','松圖  其一','釋居簡','宋','宋诗','song-poetry','','[]','李懷仁畫雙龍後，活在蘭陵道士家。',32,'全唐诗/poet.song.180000.json','["李懷仁畫雙龍後，活在蘭陵道士家。", "水墨工夫能幻巧，變成霜幹老槎牙。"]'),
('27437937-9b69-4377-98d4-422bc98b137b','松圖  其二','釋居簡','宋','宋诗','song-poetry','','[]','斷橋之西石橋北，忘世忘年寄幽獨。',32,'全唐诗/poet.song.180000.json','["斷橋之西石橋北，忘世忘年寄幽獨。", "千仞干雲險絕攀，瘦影何時落橫幅。"]'),
('a2b975c4-fc35-4abf-b15d-2eb848ca775e','秋雨連冬雪寄常平使者王郎中','釋居簡','宋','宋诗','song-poetry','','[]','九月十月閏月雨，陰晶陽采雲霾𢾅。',192,'全唐诗/poet.song.180000.json','["九月十月閏月雨，陰晶陽采雲霾𢾅。", "十旬朝夕漏涔涔，豈應漏處無人補。", "準擬書雲須少霽，破鏡上天猶未已。", "田家屋老半閒茅，带雨旋抽仍數米。", "雨中集霰初廉纖，雪中更把來麰占。", "麰今一粒不入土，倘有些小黄厭厭。", "春耕仰麥今無麥，欲驅秧馬饑無策。", "富人露廩矗如林，價高少室山人索。", "貪夫相時爲利謀，耕夫食力毋過求。", "無求尚有豐凶憂，更憂螟螣蠈與蟊。", "常平使者深長慮，少戇安知汲長孺。", "開倉振粟勇不疑，救焚孰與先救饑。"]'),
('b22bf796-b9dc-4b98-a2b9-8cbaf6b63988','劉漫塘寄謝宜興三詩屬宜興索和  其一','釋居簡','宋','宋诗','song-poetry','','[]','醫俗無如退，榮身豈俟官。',48,'全唐诗/poet.song.180000.json','["醫俗無如退，榮身豈俟官。", "不知狙喜怒，聊問竹平安。", "惡曲麾圓器，希同即異端。", "十虛無四壁，冷眼要人看。"]'),
('5e3cd654-bce2-407d-bd6a-f2832f90147d','劉漫塘寄謝宜興三詩屬宜興索和  其二','釋居簡','宋','宋诗','song-poetry','','[]','美政喧隣壤，新詩致漫翁。',48,'全唐诗/poet.song.180000.json','["美政喧隣壤，新詩致漫翁。", "新聲能峭眇，嘉實對清空。", "藥苦終成效，言甘恐害忠。", "不逢丈人行，爭識古人風。"]'),
('8bd17b09-74c6-4294-9808-2066f908e4df','劉漫塘寄謝宜興三詩屬宜興索和  其三','釋居簡','宋','宋诗','song-poetry','','[]','泳飛樓上吟，記賞竹巖深。',48,'全唐诗/poet.song.180000.json','["泳飛樓上吟，記賞竹巖深。", "鶴已幾番子，棠仍千樹陰。", "名隨北斗上，刻笑峴山沉。", "獨欠巖翁些，交游尚挂心。"]'),
('9fe318a2-46da-4a64-92c1-5a3dc423e568','張南雄之官','釋居簡','宋','宋诗','song-poetry','','[]','一麾梅嶺下，征旆踏春妍。',48,'全唐诗/poet.song.180000.json','["一麾梅嶺下，征旆踏春妍。", "響鄭尚書履，收王大令氊。", "阜財昌國本，裕食佐民天。", "來歲花如雪，芳枝記驛傳。"]'),
('568a4765-3b02-4dd7-91ac-f1525276b4e2','薛藍田','釋居簡','宋','宋诗','song-poetry','','[]','藍田新續記，蓮幕又登賢。',48,'全唐诗/poet.song.180000.json','["藍田新續記，蓮幕又登賢。", "次遲初潜地，榮如利見年。", "熊飛占吉夢，綵侍未華顛。", "天予先成佛，無庸緩著鞭。"]'),
('9e9f390e-01f0-4f12-ac86-e8a8ca855d0f','陪方江陰宗諭勸耕過宋景文墓田次日得其唐書草并侍郎誥','釋居簡','宋','宋诗','song-poetry','','[]','千騎精明振物華，麥畦分處槿籬斜。',64,'全唐诗/poet.song.180000.json','["千騎精明振物華，麥畦分處槿籬斜。", "山雖有盡春無際，李竟不言桃自花。", "綠漲新添前夜雨，青歸不減去年畬。", "酒盃弗酹劉伶土，重爲斯文一歎嗟。"]'),
('f72cd285-9d12-4bcc-90aa-68743bcb5854','君山弔古','釋居簡','宋','宋诗','song-poetry','','[]','梏足晶熒佩陸離，無人從事一丸泥。',64,'全唐诗/poet.song.180000.json','["梏足晶熒佩陸離，無人從事一丸泥。", "謀疎與國迷同體，恨逐東流竟噬臍。", "俗好永懷兄弟遜，金多盍媿斗牛齊。", "潮來只打君山脚，渺渺江空宇宙低。"]'),
('81786b21-a81f-4756-9ed8-5ae914c810e2','梁楷畫鍾馗并引鶴歸雲際携琴過澗西三題  其一','釋居簡','宋','宋诗','song-poetry','','[]','華清橫玉落梅愁，不寤人謀蔽鬼謀。',32,'全唐诗/poet.song.180000.json','["華清橫玉落梅愁，不寤人謀蔽鬼謀。", "白面書生名字貴，還如版築夢中求。"]'),
('cbf11721-781e-4ca1-8ac0-34d9f26b90ac','梁楷畫鍾馗并引鶴歸雲際携琴過澗西三題  其二','釋居簡','宋','宋诗','song-poetry','','[]','喚起胎仙細問伊，幾時華表柱頭歸。',32,'全唐诗/poet.song.180000.json','["喚起胎仙細問伊，幾時華表柱頭歸。", "一編玄草都收拾，種玉田東伴采薇。"]'),
('bdd2222f-eb20-426c-87d8-21fbee77c0c5','梁楷畫鍾馗并引鶴歸雲際携琴過澗西三題  其三','釋居簡','宋','宋诗','song-poetry','','[]','不是忘彈閟古音，怕人誤賞玷琴心。',32,'全唐诗/poet.song.180000.json','["不是忘彈閟古音，怕人誤賞玷琴心。", "雲西六六峯前去，挂壁梧桐槁弗瘖。"]'),
('10f47b41-c8a9-488e-889e-617c7ed4f500','楊園四題  其一','釋居簡','宋','宋诗','song-poetry','','[]','草薰薰，木欣欣，海棠昨日隨雨零。',112,'全唐诗/poet.song.180000.json','["草薰薰，木欣欣，海棠昨日隨雨零。", "牡丹欲放金紫新，餘芳各自爭鮮明。", "小圃日涉不日成，品分目署月旦評。", "是家當年駕盧駱，祖烈亭亭相博約。", "振陋鉏荒十畝餘，坐看鳶飛與魚躍。", "奇奇怪怪幻玲瓏，白白紅紅相雜錯。", "小竚人間日月長，更拓胸中小丘壑。"]'),
('ce9f3156-5c4c-4367-8ffd-19b8e24e7df3','楊園四題  其二','釋居簡','宋','宋诗','song-poetry','','[]','凉自紅酣起，香從靜勝聞。',48,'全唐诗/poet.song.180000.json','["凉自紅酣起，香從靜勝聞。", "虹梁雖可跨，龍液不須焚。", "天作池中底，風成水上文。", "倚楹閑意緒，只與月平分。"]'),
('0e4d6e15-7570-47b3-9736-28eafa5a62b5','楊園四題  其三','釋居簡','宋','宋诗','song-poetry','','[]','壍斷垣頹井不移，秀盤古色尚依稀。',32,'全唐诗/poet.song.180000.json','["壍斷垣頹井不移，秀盤古色尚依稀。", "興亡千載誰相委，華表柱頭丁令威。"]'),
('be8cc323-6f6d-4b3c-ab27-067945903c7e','楊園四題  其四','釋居簡','宋','宋诗','song-poetry','','[]','直從平地矗崔嵬，南向群山斗次來。',64,'全唐诗/poet.song.180000.json','["直從平地矗崔嵬，南向群山斗次來。", "盡此半春留客醉，莫愁一日不花開。", "水從綠野前頭遶，竹向芳菲缺處栽。", "目送斷鴻天外去，問它更是幾時回。"]'),
('ddde4b17-93d9-466f-9685-141e51116bc4','燕歸','釋居簡','宋','宋诗','song-poetry','','[]','舊巢新補畫梁西，趁得蘭塘雨後泥。',32,'全唐诗/poet.song.180000.json','["舊巢新補畫梁西，趁得蘭塘雨後泥。", "莫憶年年歸去路，蜃樓高處海雲低。"]'),
('d7fc693b-f99e-481c-aad5-b4919b38f5e3','三月三十日','釋居簡','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','笑賈長江惜語離，苦留春到五更時。',32,'全唐诗/poet.song.180000.json','["笑賈長江惜語離，苦留春到五更時。", "怕傷懷似陽關別，何似悠然睡莫知。"]'),
('4f6bf315-31f4-423d-a5d2-68edb791d960','聞盤隠府判換闕','釋居簡','宋','宋诗','song-poetry','','[]','兩考在官當有俸，三年待次已無餘。',64,'全唐诗/poet.song.180000.json','["兩考在官當有俸，三年待次已無餘。", "驥雖暫展淹州佐，鵷欲成行盍內除。", "湖上玄猿嗟宿草，帳中丹頂喜新雛。", "青冥脚脚平如砥，浩蕩滄江興弗疎。"]'),
('c70a8f0e-b06b-48a4-9ae9-43a092bc17cb','次韻謝盤隠府判','釋居簡','宋','宋诗','song-poetry','','[]','秋簷去年約，夜色正中旬。',48,'全唐诗/poet.song.180000.json','["秋簷去年約，夜色正中旬。", "月墮水中影，沙明鏡裏人。", "杜鵑移樹怨，蝙蝠抵簾嗔。", "誰報明朝喜，燈花剪剪春。"]'),
('631ef7fa-787d-4962-a50e-84b442315be1','王守除本路倉使','釋居簡','宋','宋诗','song-poetry','','[]','把茅著在深雲裏，亦有殘畬近水邊。',64,'全唐诗/poet.song.180000.json','["把茅著在深雲裏，亦有殘畬近水邊。", "不作山人沽善價，更饕司業養廉錢。", "皇華未遠難爲別，倦翮嫌高弗足憐。", "來歲小團新錫賚，從公酌第四橋泉。"]'),
('d3740ee2-0da7-45f7-919e-69374fdd6be8','周氏小閣漫堂名之曰燕超','釋居簡','宋','宋诗','song-poetry','','[]','蜂懶蜜脾香，將雛燕子忙。',48,'全唐诗/poet.song.180000.json','["蜂懶蜜脾香，將雛燕子忙。", "種萍翻盡絮，蕃稻浸成秧。", "梅子雨初溽，蘋花風未凉。", "卯金天祿閣，芳墨浩淋浪。"]'),
('288f3e46-9d64-4c60-98d9-4ac390a36c3a','蜀葵滿庭','釋居簡','宋','宋诗','song-poetry','','[]','鬘綴薰風舞袂凉，依稀五竺飯空王。',64,'全唐诗/poet.song.180000.json','["鬘綴薰風舞袂凉，依稀五竺飯空王。", "未哦玉唾三千偈，先列金釵十二行。", "桂殿冷滋分素潔，魏家新紫擬芬芳。", "華林錦綉連銅雀，葉葉傾斜背太陽。"]'),
('59b3e2b3-0eae-4bfc-bb4d-cba649ab0fad','立秋日贈竹隣陳上舍','釋居簡','宋','宋诗','song-poetry','','[]','秋夏纔交事，征輪勇欲飛。',48,'全唐诗/poet.song.180000.json','["秋夏纔交事，征輪勇欲飛。", "有詩上行卷，無地扣吟扉。", "梅雪玲瓏瘦，瓜藤蔓延肥。", "侯鯖易充悅，不似北山薇。"]'),
('ee2a0a05-de71-4a0a-96fe-0c1d809178d3','搗藥禽','釋居簡','宋','宋诗','song-poetry','','[]','大藥何年竊得靈，廣寒去伴月長生。',32,'全唐诗/poet.song.180000.json','["大藥何年竊得靈，廣寒去伴月長生。", "至今弱羽沾餘瀝，猶作當時杵臼聲。"]'),
('73727dff-7d2b-40bc-9473-0315e25e4677','嘯雲','釋居簡','宋','宋诗','song-poetry','','[]','月下悠然洞杳微，弗諧琴筑與塤箎。',32,'全唐诗/poet.song.180000.json','["月下悠然洞杳微，弗諧琴筑與塤箎。", "不知林谷鵷鴻響，何似南陽抱膝時。"]'),
('d72dac63-1974-4dcd-bcaa-ebc89724eabd','貧女觀音','釋居簡','宋','宋诗','song-poetry','','[]','雪藕銖衣不自珍，人間絲枲謾紛紜。',32,'全唐诗/poet.song.180000.json','["雪藕銖衣不自珍，人間絲枲謾紛紜。", "何如小白花山上，別剪彤霞與白雲。"]'),
('71cf043e-86b2-406e-a99c-f8cd2093951c','茂書記歸閩  其一','釋居簡','宋','宋诗','song-poetry','','[]','出嶺新吟問老銛，丹青費盡笑無鹽。',32,'全唐诗/poet.song.180000.json','["出嶺新吟問老銛，丹青費盡笑無鹽。", "磵陰雪立寒更盡，纔識元戎玉帳嚴。"]'),
('ac8f4bba-8ef8-4109-a0ee-02f8c64b794a','茂書記歸閩  其二','釋居簡','宋','宋诗','song-poetry','','[]','淡學梅花不受粧，酷嫌脂澤綴詞章。',32,'全唐诗/poet.song.180000.json','["淡學梅花不受粧，酷嫌脂澤綴詞章。", "漢粧更在青山外，留得華風管暗香。"]'),
('96ae233c-8cac-44e2-a025-1f3cc45f7f72','苕溪新上人石窗','釋居簡','宋','宋诗','song-poetry','','[]','太白巖空夜弗扃，好風不約滿疏櫺。',32,'全唐诗/poet.song.180000.json','["太白巖空夜弗扃，好風不約滿疏櫺。", "舊題寂寞無人管，散作苕溪水上雲。"]'),
('5b75211c-2e3a-4002-bd43-18016cb0f09b','顧寺簿雲伯挽章','釋居簡','宋','宋诗','song-poetry','','[]','黄巖二松下，別調聽新吟。',48,'全唐诗/poet.song.180000.json','["黄巖二松下，別調聽新吟。", "尋說丑羊去，寄聲雙鯉沉。", "班空華玉笋，弦絕斷文琴。", "宿草春重綠，傷心日更深。"]'),
('e0ea3106-9e02-4b85-9137-0d3889ebe9ab','施當涂東洲見寄','釋居簡','宋','宋诗','song-poetry','','[]','騷吟富名流，東洲敏風雨。',72,'全唐诗/poet.song.180000.json','["騷吟富名流，東洲敏風雨。", "小低縯綸手，聯作石鼎語。", "真龍得人畏，况復射真虎。", "妖蹤與怪跡，三舍亟避去。", "出如一角麟，貴若五色羽。", "不然六月息，扶摇快摶舉。"]'),
('026fc29d-f2ee-4ca9-9e62-89cd72d8d2a7','長興趙可齋辟楊州別駕','釋居簡','宋','宋诗','song-poetry','','[]','清俯箬溪流，裴回水上樓。',48,'全唐诗/poet.song.180000.json','["清俯箬溪流，裴回水上樓。", "同心獨陳檜，別乘半楊州。", "斗酌江分暝，輪空月碾秋。", "瓊花難驛寄，花露記珍投。"]'),
('9a7a0ac9-0585-458e-951e-921f511344cc','漫塘名陳內機小齋曰能止','釋居簡','宋','宋诗','song-poetry','','[]','莫闚殽與函，峭絕青錯磨。',168,'全唐诗/poet.song.180000.json','["莫闚殽與函，峭絕青錯磨。", "可無濟勝具，振衣披峩峩。", "更復游呂梁，虎眼漩作渦。", "堂堂濟深涉，如此忠信何。", "游子聽我語，審聽毋媕婀。", "通都橫九逵，平平非仄頗。", "並駕方崢嶸，輻輳相駢羅。", "嗜進弗知了，十步九跌蹉。", "何如反吾轅，自少不自多。", "怡然事天全，盎然毓天和。", "倦翼安故林，歸雲仍中阿。", "曉猿時自吟，好鳥時自歌。", "凉樹坐茂密，醉石眠坡陁。", "何須鶉奔奔，靜勝超凡科。"]'),
('34d2309a-3835-4a3f-b4a3-1655ba933d8b','船窗蕙萱  其一','釋居簡','宋','宋诗','song-poetry','','[]','國香旖旎霣林扉，依約華風變雅遲。',32,'全唐诗/poet.song.180000.json','["國香旖旎霣林扉，依約華風變雅遲。", "冩出一莖三四萼，紫毫零瀣冷涵滋。"]'),
('1a45da50-8e4b-42c5-9def-86fb0cd42b93','船窗蕙萱  其二','釋居簡','宋','宋诗','song-poetry','','[]','小試凉薰四月初，芳心曾不與春疎。',32,'全唐诗/poet.song.180000.json','["小試凉薰四月初，芳心曾不與春疎。", "是中可托忘憂地，看睡鴛鴦傍母雛。"]'),
('39bb1740-dd0d-495c-8b22-6f74a3224fe9','瑞香','釋居簡','宋','宋诗','song-poetry','','[]','譜上先題五老名，宮袍雲錦舊爲隣。',32,'全唐诗/poet.song.180000.json','["譜上先題五老名，宮袍雲錦舊爲隣。", "華風似惜詩人老，一樣裁成紫綺新。"]'),
('7ed0a6ba-3e23-4e4a-869e-a18c98326267','月丹','釋居簡','宋','宋诗','song-poetry','','[]','展樣山茶染不如，宮黄齊撚牡丹鬚。',32,'全唐诗/poet.song.180000.json','["展樣山茶染不如，宮黄齊撚牡丹鬚。", "不忺宿雨曦晴露，玉袖垂紅護絳襦。"]'),
('f5e64d56-2e65-43ec-8bd3-f9d0f800e948','曹提舉榮上','釋居簡','宋','宋诗','song-poetry','','[]','鄉也纔聆謦咳聲，暗中摸索認輪囷。',64,'全唐诗/poet.song.180000.json','["鄉也纔聆謦咳聲，暗中摸索認輪囷。", "故家大雅元戎老，詞學清流使節新。", "直指大門標俗子，莫嫌高賈著山人。", "紫荷琳舘君諸父，說項斯賢不厭頻。"]'),
('6e8b3921-2d80-478e-8105-668bc71de66f','顔提舉之官','釋居簡','宋','宋诗','song-poetry','','[]','蘭陵曾頌隣州政，除却龔黄總不如。',64,'全唐诗/poet.song.180000.json','["蘭陵曾頌隣州政，除却龔黄總不如。", "又似澄江千尺練，只傳陋巷一編書。", "坐令季子昌遺俗，盡道丹山更好雛。", "老我林泉散樗櫟，守愚終不與賢疎。"]'),
('14a145b0-aaec-4e02-b0a9-60cd67d1f250','贈日本國僧順侍者','釋居簡','宋','宋诗','song-poetry','','[]','粟散王都藐莫知，星分棋布海中泜。',64,'全唐诗/poet.song.180000.json','["粟散王都藐莫知，星分棋布海中泜。", "三韓未遠須重譯，九土雖中共秉彜。", "但見神僧巍跨水，弗聞君子陋居夷。", "由余季札高千古，更復區區桀蹠爲。"]'),
('4639973b-33b0-45b6-9951-ed4e20f236c6','葛仙遷居圖','釋居簡','宋','宋诗','song-poetry','','[]','欲問丹砂不定居，絕憐岣嶁令君疎。',32,'全唐诗/poet.song.180000.json','["欲問丹砂不定居，絕憐岣嶁令君疎。", "弗教雞犬蜚騰去，猶看隨行挂角書。"]'),
('0007a37b-08ff-4347-8ee2-d3917fbacb2f','陳刑書問近况  其一','釋居簡','宋','宋诗','song-poetry','','[]','孤風晉東土，宿望魯靈光。',48,'全唐诗/poet.song.180000.json','["孤風晉東土，宿望魯靈光。", "跡恨山林阻，精馳研席傍。", "環中樞待轉，水上玉生凉。", "一點華風在，看看動八荒。"]'),
('6841ef61-5223-4c79-b6e9-db9d03dc3444','陳刑書問近况  其二','釋居簡','宋','宋诗','song-poetry','','[]','萬卉競春新，孤芳見老成。',48,'全唐诗/poet.song.180000.json','["萬卉競春新，孤芳見老成。", "鬭高紛曉蝶，遞巧響喬鶑。", "山染眉津綠，湘澄眼采明。", "東山謝安石，深意在蒼生。"]'),
('50c541e0-521b-46a4-9323-285ec0be4f81','洪御史','釋居簡','宋','宋诗','song-poetry','','[]','山林色色昧講明，不識更化云胡更。',128,'全唐诗/poet.song.180000.json','["山林色色昧講明，不識更化云胡更。", "或云鄉來立仗馬，畫然勇作朝陽鳴。", "邕邕逸響猶在耳，寵以官名只三字。", "昔人謾煮水銀銀，妄冀錙銖相比類。", "衮衮王言獨超絕，盤誥丁寧古無別。", "眼兩腰重不自榮，回向高堂一簪雪。", "只今又上四緊頭，準擬鈞天侍冕旒。", "彈壓風煙看制勝，取之左右皆相應。"]'),
('e6da21ae-427a-4afd-9e91-7da1fa4e1687','黄薔薇','釋居簡','宋','宋诗','song-poetry','','[]','窗風一綫度晴熏，晚韻繁香態度新。',32,'全唐诗/poet.song.180000.json','["窗風一綫度晴熏，晚韻繁香態度新。", "親壓屠蘇湛華玉，古壺斜插淺浮春。"]'),
('5d4f89d2-bdad-4cb0-b1f9-61c5905a53b6','舟中','釋居簡','宋','宋诗','song-poetry','','[]','物華雨後各矜晴，紅得晴多綠便爭。',32,'全唐诗/poet.song.180000.json','["物華雨後各矜晴，紅得晴多綠便爭。", "未與東風寫懷抱，綿蠻已作送春聲。"]'),
('5a9b5e16-4660-4f1a-9181-5de635f7e988','蘇叔黨所作蘭蕙','釋居簡','宋','宋诗','song-poetry','','[]','風雅傳衣到小坡，筆頭分外得春多。',32,'全唐诗/poet.song.180000.json','["風雅傳衣到小坡，筆頭分外得春多。", "佩寒帳冷空遺恨，澹寫孤芳續九歌。"]'),
('e264535b-7ce1-4951-aef7-ad16c829a4fc','雲山道人榴桃橙橘戯墨','釋居簡','宋','宋诗','song-poetry','','[]','造化工夫竟屬誰，墨花豈恨子生遲。',32,'全唐诗/poet.song.180000.json','["造化工夫竟屬誰，墨花豈恨子生遲。", "海榴不與山桃約，趁得橙黄橘綠時。"]'),
('80b49d7d-9230-44d9-8421-847912407a17','次陳中書木犀韻','釋居簡','宋','宋诗','song-poetry','','[]','一枝開月蘂，萬粟蛻風埃。',48,'全唐诗/poet.song.180000.json','["一枝開月蘂，萬粟蛻風埃。", "我欲乘風去，君須采月來。", "降真當換骨，甲第合班梅。", "蔌蔌都吹了，分香到綠苔。"]'),
('ff1cc44f-e7c8-4409-a4b4-7b519c0443fa','酬寧國陳中書勸耕','釋居簡','宋','宋诗','song-poetry','','[]','深閴禪扉未扣關，先將鸞尾掃層巒。',64,'全唐诗/poet.song.180000.json','["深閴禪扉未扣關，先將鸞尾掃層巒。", "貴於步屧狂工部，健勝遊山老謝安。", "靜裏韶華天宇大，笑中耆艾酒尊寬。", "獨餘繾綣林泉思，更爲山紅小倚闌。"]'),
('5820a46b-56e4-4c1c-a4a9-b6945332df36','包氏卧虎圖','釋居簡','宋','宋诗','song-poetry','','[]','猿臂將軍死弗侯，發機百中巧無酬。',32,'全唐诗/poet.song.180000.json','["猿臂將軍死弗侯，發機百中巧無酬。", "不逢肉醉眠山路，飲羽空嗟老石頭。"]'),
('f1ab3e39-12d5-4eea-87c4-a594f592d2aa','廉上人得玄暉活法','釋居簡','宋','宋诗','song-poetry','','[]','微抹岑樓不見尖，澹迷山閣不蜚簷。',32,'全唐诗/poet.song.180000.json','["微抹岑樓不見尖，澹迷山閣不蜚簷。", "一從蒙澒雲收後，活法知誰付阿廉。"]'),
('3b8224af-2186-44b8-aa0d-0f15e44f90b7','破琴行','釋居簡','宋','宋诗','song-poetry','','[]','軫折徽殘弦索亂，貼壁緣空暗塵滿。',112,'全唐诗/poet.song.180000.json','["軫折徽殘弦索亂，貼壁緣空暗塵滿。", "歷聲爆得黑髹皴，蛇腹庚庚成百斷。", "爨痕孰辨贋與真，古已往矣思古人。", "木雖就槁聲不槁，老龍弗吟誰解聽。", "得時鄭衛嘈雜鳴，泯默韶頀瘖咸英。", "南風不競慍若酲，林林俚耳安知此。", "寰天滿地浮俗子，還我知音子鍾子。"]'),
('e2eab7c0-6002-4332-9606-eacc6a805470','李帥新創溪山真趣','釋居簡','宋','宋诗','song-poetry','','[]','動者智之機，惟仁與靜宜。',48,'全唐诗/poet.song.180000.json','["動者智之機，惟仁與靜宜。", "天開真箇畫，誰識自然詩。", "水與雲相友，鷗馴鷺不疑。", "終南譏捷徑，有耳怕聞知。"]'),
('55ae8507-0d5b-4e0f-b8a4-f5cc2c81a1e2','大洞','釋居簡','宋','宋诗','song-poetry','','[]','纔入膚生粟，炎炎伏暑前。',48,'全唐诗/poet.song.180000.json','["纔入膚生粟，炎炎伏暑前。", "凹中元有路，虛處豈無天。", "待扣鐘非簴，將崩石架船。", "蜿蜒毋熟寐，我欲慶豐年。"]'),
('b12bd81c-faf6-4296-b240-8db025929a5a','續王黄州四皓贈答  其一','釋居簡','宋','宋诗','song-poetry','','[]','遮得冥冥翼，誰云漢網寬。',48,'全唐诗/poet.song.180000.json','["遮得冥冥翼，誰云漢網寬。", "劫謀飛隼疾，克愛拔山難。", "旒恐懸中斷，盂從覆處安。", "不如甘嫚駡，莫受子房謾。"]'),
('de9e0df4-1feb-437b-b4c5-4ede170661ca','續王黄州四皓贈答  其二','釋居簡','宋','宋诗','song-poetry','','[]','白眼看隆準，悠然見屈伸。',48,'全唐诗/poet.song.180000.json','["白眼看隆準，悠然見屈伸。", "奇功巍弗處，峻節退無隣。", "用則王非伯，潜嗟漢不純。", "雖亡秦日月，猶是避秦人。"]'),
('26f11116-72d0-4e1a-b1f3-7613d780e6e7','用前送行韻寄趙編修可齋','釋居簡','宋','宋诗','song-poetry','','[]','爍石與金流，懷人眺晚樓。',48,'全唐诗/poet.song.180000.json','["爍石與金流，懷人眺晚樓。", "忽聞提健筆，喜似得神州。", "稻粒不多日，窗疏相次秋。", "只分千里月，木李不中投。"]'),
('b70ca640-c25c-4086-8504-43f7f76468b1','寄盤隠府判','釋居簡','宋','宋诗','song-poetry','','[]','閑把新抽粉節題，疾邪字字賦心思。',64,'全唐诗/poet.song.180000.json','["閑把新抽粉節題，疾邪字字賦心思。", "溺非袖手無遺援，虐是專門忍助爲。", "山下水流花盡處，人間豕燎虱焦時。", "盈虛消息還來復，六月扶摇豈遠而。"]'),
('f9a66a0f-636a-4728-bf5e-a25227f61b3b','祠山解后陳舒州','釋居簡','宋','宋诗','song-poetry','','[]','盍步花磚草制書，尚煩丐外替中除。',64,'全唐诗/poet.song.180000.json','["盍步花磚草制書，尚煩丐外替中除。", "肯堂肯室五經笥，難弟難兄三鳳雛。", "家學不逃鍾鼎貴，野情弗與隠淪疎。", "乾坤肯負真宏博，聊爲斯文發緒餘。"]'),
('fb5bf318-1a2b-4b1b-8b75-f8620a062b8a','伯時二馬  其一','釋居簡','宋','宋诗','song-poetry','','[]','刁斗無聲苜蓿秋，不知猨臂未封侯。',32,'全唐诗/poet.song.180000.json','["刁斗無聲苜蓿秋，不知猨臂未封侯。", "尚堪汗滴沙場血，花結青絲恨絡頭。"]'),
('9a7e0ee8-1cc7-4649-ba22-8cb627fda34d','伯時二馬  其二','釋居簡','宋','宋诗','song-poetry','','[]','市駿爰從畫駿謀，何如脫鞅縱驊騮。',32,'全唐诗/poet.song.180000.json','["市駿爰從畫駿謀，何如脫鞅縱驊騮。", "青青許負雙眸子，不識驊騮只相牛。"]'),
('7009cfc7-34ee-4990-85cc-2830d52e9ed8','佛國白赴召劉侍郎無言與諸賢作供於報恩題壁以紀傍有隆茂宗所作古木怪石','釋居簡','宋','宋诗','song-poetry','','[]','白也度苕谿，諸賢重挽携。',48,'全唐诗/poet.song.180000.json','["白也度苕谿，諸賢重挽携。", "金刀眷良集，鐵畫粲芳題。", "神護藏書壁，鴻留印爪泥。", "阿隆霜幹老，附竝薄雲霓。"]'),
('d45495c4-d818-4d11-80ea-daae15ea806e','狀元袁府判作詩贈王司理其略云簡川號工詩只今在市鄽試呼一問之參寥師孰賢王索答酬以四十字','釋居簡','宋','宋诗','song-poetry','','[]','籍甚參寥子，臨平破夏歸。',48,'全唐诗/poet.song.180000.json','["籍甚參寥子，臨平破夏歸。", "弗經人道語，肯落箭鋒機。", "盤走珠無定，泥沾絮不飛。", "長公歸玉局，千載賞音稀。"]'),
('b7482159-1077-42d2-b9e7-9c94b1f61821','送伊侍者歸嘉興','釋居簡','宋','宋诗','song-poetry','','[]','伊纔十二三，便學善財參。',48,'全唐诗/poet.song.180000.json','["伊纔十二三，便學善財參。", "諱懶偏晨起，忘眠聽夜談。", "阮貧居道北，符學近城南。", "已壯貧如我，青青看出藍。"]'),
('7e7c2219-2f8b-4963-9291-0585f9637552','古松下禪僧圖','釋居簡','宋','宋诗','song-poetry','','[]','眼明千載老風烟，幽思悠然喜欲顛。',32,'全唐诗/poet.song.180000.json','["眼明千載老風烟，幽思悠然喜欲顛。", "疑在浣花詩裏見，只無松子落僧前。"]'),
('d6bf57bc-92a9-45e9-b9da-7b18cc4e58e8','米家平遠','釋居簡','宋','宋诗','song-poetry','','[]','樹豈無根瘦立，雲疑有蒂慵飛。',28,'全唐诗/poet.song.180000.json','["樹豈無根瘦立，雲疑有蒂慵飛。", "好處不經人道，一家父子傳衣。"]'),
('866402bd-a298-4c71-a5e9-a18e304c8133','聞曹侍郎訃唁太博大孝','釋居簡','宋','宋诗','song-poetry','','[]','去酌孤山六一泉，吟邀兩衲簉諸賢。',64,'全唐诗/poet.song.180000.json','["去酌孤山六一泉，吟邀兩衲簉諸賢。", "郎君拾芥登科後，老子懲姦去國前。", "鬢自侍郎班裏白，官從天子學中聯。", "半輪不死峩眉月，還鄉滄浪闊處圓。"]'),
('6523fe5f-d194-4423-ba37-57bc0d8dcf99','寄真尚書','釋居簡','宋','宋诗','song-poetry','','[]','京索風煙一日還，東山起了到西山。',64,'全唐诗/poet.song.180000.json','["京索風煙一日還，東山起了到西山。", "應知雅量渾相似，默藴沉機只等閑。", "棋妙勝於淮上捷，扇輕銘露管中斑。", "共爲天下蒼生賀，不爲蒼生亦破顔。"]'),
('2edaf2dd-322b-40bc-bc2c-ac6ad3b460a9','雪林李兄偕昌國長之官','釋居簡','宋','宋诗','song-poetry','','[]','潮漲家門雪，無風亦震雷。',48,'全唐诗/poet.song.180000.json','["潮漲家門雪，無風亦震雷。", "飽帆蜚百尺，饑蜃吐叢臺。", "綃展洴鮫室，珠明剖蚌胎。", "春城種花地，冷帳小蓬萊。"]'),
('f1776b6e-a47b-4f13-82ad-9abc77cf62e2','趙左廂再薦','釋居簡','宋','宋诗','song-poetry','','[]','勤苦佐豐年，成功只聽天。',48,'全唐诗/poet.song.180000.json','["勤苦佐豐年，成功只聽天。", "聊揮數寸管，不費一文錢。", "燈婁層葩剪，楊曾百步穿。", "宗藩大廷對，可惜兩名先。"]'),
('21a96680-beab-4235-9a53-c529653f2711','多景樓','釋居簡','宋','宋诗','song-poetry','','[]','好山可是登臨少，此地云胡應接多。',64,'全唐诗/poet.song.180000.json','["好山可是登臨少，此地云胡應接多。", "天自有初恢壯觀，人非無故輒悲歌。", "煙收三面平開鏡，雨後雙鬟對綰螺。", "欲辯南徐古徐話，忍將名刻細摩挲。"]'),
('984a3ebe-1f3d-40b3-b33a-d54b19ba5083','很石','釋居簡','宋','宋诗','song-poetry','','[]','石很與孫儔，安知很易柔。',48,'全唐诗/poet.song.180000.json','["石很與孫儔，安知很易柔。", "借州託强援，歸妹叶奇謀。", "蜀相死猶勝，晉宣生可偷。", "吞吳恨如海，微意似尊周。"]'),
('58639b3b-a4e0-456f-a5cb-502a25e264f1','蔡山在江陰北湖西相傳是蔡邕伯喈墓','釋居簡','宋','宋诗','song-poetry','','[]','身與東都孰重輕，至今猶擅蔡山名。',64,'全唐诗/poet.song.180000.json','["身與東都孰重輕，至今猶擅蔡山名。", "四圍深壍方方禁，千古英詞凜凜生。", "漢鼎已歸曹馬手，胡笳猶播管絃聲。", "傳家更有柯亭竹，曾作岐陽老鳳鳴。"]'),
('64e43c19-7e64-4994-b2e8-beafa592c044','三高亭','釋居簡','宋','宋诗','song-poetry','','[]','雪灘祠三高，高字累三子。',72,'全唐诗/poet.song.180000.json','["雪灘祠三高，高字累三子。", "故夫三子者，凜凜元不死。", "西風動歸思，不與歌散殊。", "用則謀人國，不用淪江湖。", "名節照勳庸，人與秋容潔。", "浩然天地中，朣朣湛華月。"]'),
('279583be-237c-446c-8d37-11cc5f9776e0','虎丘','釋居簡','宋','宋诗','song-poetry','','[]','門掩怕山移，稜稜塔填欹。',48,'全唐诗/poet.song.180000.json','["門掩怕山移，稜稜塔填欹。", "斷崖抽曉碧，死草借春滋。", "地狹樓蜚巧，雲低屋跨危。", "雨花臺上石，不似點頭時。"]'),
('94c1db20-6164-457e-b5f5-da60eaef44be','劍池','釋居簡','宋','宋诗','song-poetry','','[]','雲根無底竇，或謂水通溟。',48,'全唐诗/poet.song.180000.json','["雲根無底竇，或謂水通溟。", "下瞰幾千尺，高標第四名。", "鬼題孤獨字，劍沕屬鏤精。", "翠禿青殘處，黄州舊勒銘。"]'),
('57115fd5-b2ae-4ce9-9a5e-30155b0811e5','二月十五陳樞密席上','釋居簡','宋','宋诗','song-poetry','','[]','上苑春常早，北海尊難老。',96,'全唐诗/poet.song.180000.json','["上苑春常早，北海尊難老。", "朝來清鏡中，滿鏡朱顔好。", "回觀斗以南，如此能幾翁。", "秉彜固全德，數量齊崆峒。", "坐寢淮南謀，俯眂汲長孺。", "凜然老精神，折衝在尊俎。", "吟律行師嚴，四海巖巖瞻。", "莫袖春風手，膾炙天下口。"]'),
('50440c29-5037-4124-8c10-55b40c4ea63f','種梅','釋居簡','宋','宋诗','song-poetry','','[]','一枝春種水仙兄，著子先調老菜羹。',32,'全唐诗/poet.song.180000.json','["一枝春種水仙兄，著子先調老菜羹。", "鼎鉉工夫求近效，怕難得似黑衣卿。"]'),
('daddb4e4-6211-4fbb-ac10-15070c87cf5b','槃隠','釋居簡','宋','宋诗','song-poetry','','[]','考得幽棲地，怡然勝美除。',48,'全唐诗/poet.song.180000.json','["考得幽棲地，怡然勝美除。", "未歸已彭澤，不夢亦華胥。", "綠繞清分遠，紅稀碧間疎。", "漁樵莫爭席，不是野人居。"]'),
('7fe4767e-92ea-4d74-84a3-7e64a397de3c','秋壑','釋居簡','宋','宋诗','song-poetry','','[]','泠風在懷袖，何必借商弦。',48,'全唐诗/poet.song.180000.json','["泠風在懷袖，何必借商弦。", "就下識天巧，適安忘地偏。", "寒泓嫌雪暖，秋草似春鮮。", "見說蓬萊遠，依稀拄杖前。"]'),
('64adfdb8-0488-469e-99de-b088bf26288f','秋壑親迎','釋居簡','宋','宋诗','song-poetry','','[]','龜筮從元吉，征車慶禮成。',48,'全唐诗/poet.song.180000.json','["龜筮從元吉，征車慶禮成。", "駸駸近七夕，脈脈耿雙明。", "羽飲黄金的，雲翻紫玉泓。", "扇鸞蜚翰墨，誰不解卿卿。"]'),
('63439d69-ab7a-4c53-bd81-5b17af0cc138','王神童','釋居簡','宋','宋诗','song-poetry','','[]','夙慧雖無蔕，抽萌便不凡。',48,'全唐诗/poet.song.180000.json','["夙慧雖無蔕，抽萌便不凡。", "蘭薰騰玉砌，侯國薦冰銜。", "荷橐行須復，牙籤儘療饞。", "一經千佛字，先把客兒攙。"]'),
('2ff939e4-c1e1-4301-9db6-fab4c68cbc1c','杜鵑花','釋居簡','宋','宋诗','song-poetry','','[]','染得深紅剪萬葩，春歸獨自絢韶華。',32,'全唐诗/poet.song.180000.json','["染得深紅剪萬葩，春歸獨自絢韶華。", "丁寧莫受西風誤，誤使人看頃刻花。"]'),
('f7e1c11c-c3cf-42ce-befb-de3edbd9ccc8','丘監丞入新宅','釋居簡','宋','宋诗','song-poetry','','[]','朝日烏爰止，東家喜可占。',48,'全唐诗/poet.song.180000.json','["朝日烏爰止，東家喜可占。", "槐陰隨舊砌，柳色動新簷。", "圖史雖添富，田園僅養廉。", "清才少閒日，那復久相淹。"]'),
('6b13eaa6-f5c4-4c92-b299-4d9d860a6d98','爲老僧化衣褐','釋居簡','宋','宋诗','song-poetry','','[]','淅瀝寒生菡萏池，雪殘老藕不成絲。',32,'全唐诗/poet.song.180000.json','["淅瀝寒生菡萏池，雪殘老藕不成絲。", "老僧歲晚無衣褐，却遣靈均去問誰。"]'),
('0ab499e6-ab6c-4fb4-9891-a9c27da040b3','木犀著雨','釋居簡','宋','宋诗','song-poetry','','[]','擬續小山吟，庭犀漬弗禁。',48,'全唐诗/poet.song.180000.json','["擬續小山吟，庭犀漬弗禁。", "再花仍剪剪，十日苦涔涔。", "墮砌金難燥，隨溝玉不沈。", "安知廣寒殿，幾日掃重陰。"]'),
('494db65e-feac-4b6f-89b9-b7091d0749bc','木犀得晴','釋居簡','宋','宋诗','song-poetry','','[]','宿翳開新霽，繁枝耀淺黄。',48,'全唐诗/poet.song.180000.json','["宿翳開新霽，繁枝耀淺黄。", "還如醒滯思，又似整殘粧。", "碎影仍多態，晴天別是香。", "坐分花下石，勺月薦深凉。"]'),
('45e44009-040a-4e2c-b8c9-516a96ce185c','舟中中秋','釋居簡','宋','宋诗','song-poetry','','[]','樓外與樓頭，無如一葉舟。',120,'全唐诗/poet.song.180000.json','["樓外與樓頭，無如一葉舟。", "風輕隨月走，江遠與天流。", "好是今宵滿，新於曩日修。", "水雲相汗漫，襟袖獨颼飀。", "皓采通千隙，寒芒洞六幽。", "無枝空繞鵲，有約不驚鷗。", "漢掌仍承露，秦貂未換裘。", "弗須占蚌腹，已自壓江樓。", "欲放儀隣老，長隨蟾兔游。", "一年看晦朔，終不似中秋。"]'),
('667599b5-5fc5-47fe-9194-6ca2c5b3532c','靈巖','釋居簡','宋','宋诗','song-poetry','','[]','斷崖蒼玉削，四繞綠屏帷。',48,'全唐诗/poet.song.180000.json','["斷崖蒼玉削，四繞綠屏帷。", "無港不相接，有山如此稀。", "樹秋連石瘦，雲晚截湖歸。", "一點西風急，籧篨相趁飛。"]'),
('47b2f34b-c3fc-4d6e-9114-ed3be96f1415','夫差避暑宮','釋居簡','宋','宋诗','song-poetry','','[]','天塹連天付水犀，離宮表裏萬山圍。',32,'全唐诗/poet.song.180000.json','["天塹連天付水犀，離宮表裏萬山圍。", "越帆直指吳松落，猶在娃宮醉不歸。"]'),
('d97acd8c-7965-4c2e-9444-c321a664b022','楓橋夜泊','釋居簡','宋','宋诗','song-poetry','','[]','誰遣蒲牢吼夜闌，玉蟲剪盡玉脂乾。',32,'全唐诗/poet.song.180000.json','["誰遣蒲牢吼夜闌，玉蟲剪盡玉脂乾。", "高山流水易爲賞，求賞此聲人獨難。"]'),
('04e7add6-e2df-427c-9f2f-e7d4c5a02190','書雲後三日遊致道觀','釋居簡','宋','宋诗','song-poetry','','[]','九日同遊柱史家，野英羞澀未成花。',32,'全唐诗/poet.song.180000.json','["九日同遊柱史家，野英羞澀未成花。", "重來又是書雲後，剛德纔抽四日芽。"]'),
('bdba2d50-8417-464f-a5af-c8f3f903acd3','酬鍾省元','釋居簡','宋','宋诗','song-poetry','','[]','東華肥馬塵，雋遊浩如海。',241,'全唐诗/poet.song.180000.json','["東華肥馬塵，雋遊浩如海。", "擇交如觀瀾，滌濯百谷瀨。", "一瞬判清渾，三舍避狷怪。", "膝耻望塵金，簪愧側冠瑇。", "四三成朋曹，千百繁行輩。", "爬搔甚翎羽，嘲异常赴籠械。", "弗與衆接畛，亦復遠分界。", "知音丈人後，有玉無善價。", "哦詩山月傾，奏賦金馬待。", "青錢不俟選，白眼又焉浼。", "采筆雖暗投，雪曲獲佳配。", "朋來得分賞，客去但獨對。", "鮮明雲錦囊，名氏擅先載。", "壇想陶謝登，盟憶曹劉會。", "所交貴同德，所贈勝雜佩。", "一夔未鳴韶，族庖已芒背。", "悲凉弔楚騷，慨慷唁齊薤。", "寧方不爲卿，至圓在其內。", "圓方爲時中，俱付形骸外。", "三千風月篇，紛紛課誰最。"]'),
('682431f2-d7dc-403b-a37f-e1c3e582cea8','寄潼川東路李漕使','釋居簡','宋','宋诗','song-poetry','','[]','鄉來江西遊，見以旴水陰。',144,'全唐诗/poet.song.180000.json','["鄉來江西遊，見以旴水陰。", "博約劍津掾，亦復聆正音。", "轉眼貼天高，再見無路尋。", "把茅丹丘城，謝家蘭玉森。", "君家龍首兄，絳帳開沈沈。", "有時過蕭寺，借榻清風林。", "笑我泉石痼，示以膏肓針。", "欲彈廣陵散，惜無中散琴。", "欲上南陽疏，不如梁甫吟。", "琴以歌南風，吟以道古今。", "一鳴才邕邕，忍見鳳鳥瘖。", "朣朣垂景星，坤維長照臨。"]'),
('d976c601-053f-4599-bc48-761eca319394','小雪','釋居簡','宋','宋诗','song-poetry','','[]','入夜蕭蕭響，聲消恰轉更。',48,'全唐诗/poet.song.180000.json','["入夜蕭蕭響，聲消恰轉更。", "僅能酬節序，不足殄蝗螟。", "瓦縫何曾滿，庭凹亦未平。", "窗疎燈欲死，俱誤照書明。"]'),
('26b4897a-256d-40fb-848f-38258693f2e0','秋壑赴豫章倅','釋居簡','宋','宋诗','song-poetry','','[]','西山爽氣在眉睫，不在悠然得句時。',64,'全唐诗/poet.song.180000.json','["西山爽氣在眉睫，不在悠然得句時。", "髣髴長沙少年樣，清新瘦島晚唐詩。", "全提韜畧親分付，半倚軿星看設施。", "笑指貂蟬舊時物，自兜牟出恐成遲。"]'),
('643caa6e-d4f4-4da9-bcf2-c7015537fe0c','一陽生賀曹提舉','釋居簡','宋','宋诗','song-poetry','','[]','六陰纔伏便回春，剛德潜隨君子生。',64,'全唐诗/poet.song.180000.json','["六陰纔伏便回春，剛德潜隨君子生。", "白日舊從黄道正，使星今傍紫微明。", "冰霜不作三冬凜，權量行歌一道平。", "湖上詩人望歸節，御屏風上已題名。"]'),
('7119d83d-aceb-47ec-8dbe-226daacc9d81','書菊磵屏蘭','釋居簡','宋','宋诗','song-poetry','','[]','欲酬天問些靈均，九畹歸來活寫真。',32,'全唐诗/poet.song.180000.json','["欲酬天問些靈均，九畹歸來活寫真。", "采筆不知春去後，自芳元不爲無人。"]'),
('aae40292-5f48-4ce9-bcae-eae56df8752c','謝太守張都承','釋居簡','宋','宋诗','song-poetry','','[]','三吳富且庶，亦復多名流。',240,'全唐诗/poet.song.180000.json','["三吳富且庶，亦復多名流。", "比屋充棟書，千斛銜尾舟。", "季子有遺烈，列國古鮮儔。", "人生五馬貴，彈壓如此州。", "欲雨天作雲，欲晴雲翳收。", "幕府非無賢，大田今有秋。", "不知夫如何，夙夜常軫憂。", "稅畝濟楮幣，濟尠恐不周。", "刮剔錐刀餘，豈若仁義優。", "藏富當在民，富民安用侯。", "迤邐及間架，分毫相校讎。", "陵遲必哀痛，噬臍將誰尤。", "剝床既及膚，民瘼何時瘳。", "公乎小留聽，毋歛雙眉脩。", "唐虞有神算，禹臯相協謀。", "芝蘭擷無遺，杞梓畢見搜。", "四郊固多壘，豈在一己羞。", "何如勉加餐，緩带姑小留。", "道聽懷好音，後苑摛詞頭。", "未解潁川組，已覆黄金甌。"]'),
('35995665-a3e9-44b2-b41a-f105248e7c6a','題柏嶼水瘦屏','釋居簡','宋','宋诗','song-poetry','','[]','此妙伊誰得，能名惜不聞。',48,'全唐诗/poet.song.180000.json','["此妙伊誰得，能名惜不聞。", "痕收新漲水，瘦宿暝歸雲。", "煙靄疑無墨，鳧鷖不亂群。", "可堪擅毫素，幽討盍平分。"]'),
('f8ca86e3-65fa-41e6-b1a4-3934fdaefe87','題趙生著色兩厖','釋居簡','宋','宋诗','song-poetry','','[]','向來爾祖在西都，掌監同聞誦子虛。',32,'全唐诗/poet.song.180000.json','["向來爾祖在西都，掌監同聞誦子虛。", "直與吠堯群類別，短屏寫影護琴書。"]'),
('7d95f1c1-9b85-4395-a453-c5cc122fd638','贈婺女黄澹翁','釋居簡','宋','宋诗','song-poetry','','[]','掉牧羊鞭弗學仙，十年不轉舊星躔。',64,'全唐诗/poet.song.180000.json','["掉牧羊鞭弗學仙，十年不轉舊星躔。", "僦無鄭廣文官舍，醒欠蘇司業酒錢。", "前席對床偎死火，反騷續雅聒清眠。", "江湖事業掀天地，豈在纍纍六印邊。"]'),
('bf77bda3-cfc3-410e-bc39-07acaace1eb9','元宵晴呈倉使曹秘丞','釋居簡','宋','宋诗','song-poetry','','[]','元正霽雪卷陰機，做得晴如此夕稀。',64,'全唐诗/poet.song.180000.json','["元正霽雪卷陰機，做得晴如此夕稀。", "金菡新紅連夜發，玉輪初夜碾雲飛。", "漏隨冰泮生和暢，海湧山來抃峭巍。", "莫把笙鏞駐麾節，禁林樹樹響催歸。"]'),
('095d3a30-e9ea-4970-ab44-a6d2b6d59ae9','苔梅','釋居簡','宋','宋诗','song-poetry','','[]','苔衣槁榦起枚條，的皪生香韻更饒。',64,'全唐诗/poet.song.180000.json','["苔衣槁榦起枚條，的皪生香韻更饒。", "領袖鮮風高素節，精神華月凜清標。", "冷看不若同疎幌，煖熨何妨酌癭瓢。", "瞻望白雲天一角，年年思遠寄迢迢。"]'),
('f0d16d9c-e431-415d-b151-5774a31c7a50','足娛山亭觀梅','釋居簡','宋','宋诗','song-poetry','','[]','紫萼騰芳金撚鬚，一花破白萬花疎。',64,'全唐诗/poet.song.180000.json','["紫萼騰芳金撚鬚，一花破白萬花疎。", "若非參子黄昏後，應是華風邂逅初。", "樓上略停橫玉手，壠頭聊代故人書。", "潢流漫漫無清影，試瀹山泉導石渠。"]'),
('d4bbcb2d-a55b-4a6f-a7a4-48c52cb03d23','酬洪朝奉','釋居簡','宋','宋诗','song-poetry','','[]','樓居八十行地仙，兩脚踏土輕蹁躚。',144,'全唐诗/poet.song.180000.json','["樓居八十行地仙，兩脚踏土輕蹁躚。", "飲如長鯨食如虎，老齒不摇金石堅。", "年年正三二月天，花間幽討酬芳鮮。", "要續李杜三千篇，晚唐不足爭媸妍。", "歸來醉卧北窗下，靜照無私觀物化。", "孫枝生子又生孫，鼎來慶事前無聞。", "堂中衮繡方爛爛，門前桃李長紛紛。", "歛福錫民天所祚，吉德在躬如密付。", "要看壽富享天然，熏陶六極熙熙然。"]'),
('dfb3177a-dfd1-49ee-9e7c-1458eb1a55c8','破山','釋居簡','宋','宋诗','song-poetry','','[]','兩雄用壯勒不回，觸斷山脊青崔嵬。',128,'全唐诗/poet.song.180000.json','["兩雄用壯勒不回，觸斷山脊青崔嵬。", "挾風卷雨上方去，旱火擊翻平地雷。", "澗松盤拏俯巍跨，鐵榦銅柯闖雲罅。", "鮮風不斷瓔珞珠，檜老枝腴亂零挂。", "四老墓田樵牧踐，莽堙蓁塞無人剪。", "振古芳塵玉象高，印泥遺爪霜鴻遠。", "舊吟新扁皆珠璧，雕梁雪壁昏題蹟。", "水流山空春晝長，番令人憶賛公房。"]'),
('c7c58fbf-71cc-4cca-b103-0c6ebde50dde','泣凝雲高士','釋居簡','宋','宋诗','song-poetry','','[]','晦朔憐朝菌，誰云羽化非。',48,'全唐诗/poet.song.180000.json','["晦朔憐朝菌，誰云羽化非。", "鼎芽靈液煖，草露太陽晞。", "莫上楊州去，須尋華表歸。", "雲埋金粟路，盡日鏁春霏。"]'),
('7fd21343-6d50-4e2f-a8ed-1f354a86868e','送寬堂赴南外判宗','釋居簡','宋','宋诗','song-poetry','','[]','教欲明南國，無如小召公。',48,'全唐诗/poet.song.180000.json','["教欲明南國，無如小召公。", "塤箎後先奏，魯衛古今同。", "特操銀潢遠，清班玉笋空。", "洛陽潮雪外，脚脚是華風。"]'),
('5e3a34b6-4a5c-478a-8dd0-7133a0da20ad','黄薔薇','釋居簡','宋','宋诗','song-poetry','','[]','紫透紅殷態度陳，露葵生色借芳新。',32,'全唐诗/poet.song.180000.json','["紫透紅殷態度陳，露葵生色借芳新。", "春風便是黄金屋，羞殺黄金屋裏人。"]'),
('0a8913fd-8ae0-4393-830e-dbf31bf96bf5','芍藥','釋居簡','宋','宋诗','song-poetry','','[]','素瓊紅玉暈輕盈，落落層層傍砌明。',32,'全唐诗/poet.song.180000.json','["素瓊紅玉暈輕盈，落落層層傍砌明。", "大雅不收成謾與，定隨姿態昧脩名。"]'),
('3c597a3a-8eca-43a1-a46b-dfa524fcb677','喜雨美王長官','釋居簡','宋','宋诗','song-poetry','','[]','四月五月河港枯，下田上田龜拆塗。',128,'全唐诗/poet.song.180000.json','["四月五月河港枯，下田上田龜拆塗。", "山湫劍沕龍光閟，一呼便爲蒼生超。", "油然請命朝帝閽，觸翻玉女洗頭盆。", "女從帝傍輒大笑，紫金蛇掣暾重昏。", "田穉九死皆返魂，舳艫銜尾沙水渾。", "扣如虛谷有逸響，享以明德無繁文。", "去年老瓦雞豚酒，酒酣說尹終在口。", "屬聞今復辦多多，更聽醉農新詠歌。"]'),
('173b9014-a50a-4a39-b9e7-a414c452f3f4','竹岩名其弟別館曰山水窟','釋居簡','宋','宋诗','song-poetry','','[]','醉翁不在酒，似與老坡盟。',48,'全唐诗/poet.song.180000.json','["醉翁不在酒，似與老坡盟。", "同德裕仁智，如君難弟兄。", "可無經笥獵，亦有管城耕。", "喚起舊山賊，清吟入細評。"]'),
('7daf88c1-3ea6-4d6c-8f26-202419d6610f','崔中書家藏閻立本醉道士圖','釋居簡','宋','宋诗','song-poetry','','[]','頹簪墮髻鴻都叟，愛酒如金叵常有。',168,'全唐诗/poet.song.180000.json','["頹簪墮髻鴻都叟，愛酒如金叵常有。", "有時得輒止奔鯨，各開吞海谽谺口。", "不辭一醉一千日，千日芳鮮致無術。", "臨風大呼劉伯倫，欲分餘瀝洗濁涇。", "伯倫拍浮酒船裏，不信人間有涇渭。", "須臾酒醒騎馬歸，雪精玄犢顛倒騎。", "半醒僮僕相扶携，嵬岸混澒忘顛隮。", "狂態百出弗自知，畫手一笑盡得之。", "如鏡鑄像尤出奇，想當恁時百不理。", "道德五千風過耳，更復沉酣到六經，六經古人糟粕耳。"]'),
('d1d737dd-e663-4e87-b1c1-6cd9496cc6b1','連月閔雨倚閣稅畝令下一夕大霔','釋居簡','宋','宋诗','song-poetry','','[]','謂是洪羊雨，洪羊幾日烹。',48,'全唐诗/poet.song.180000.json','["謂是洪羊雨，洪羊幾日烹。", "天慳纔自破，田稚忽更生。", "漲溢重湖淥，懽騰萬籟聲。", "歛藏天下富，無廩不常平。"]'),
('be7fcb28-15bd-4983-8dd9-16f53961d8be','雨後復旱呼海嵎山龍浹旬復大霔  其一','釋居簡','宋','宋诗','song-poetry','','[]','龜田似大橫，剛燥不容耕。',48,'全唐诗/poet.song.180000.json','["龜田似大橫，剛燥不容耕。", "秧瘦無新思，舟膠阻去程。", "溽思梅雨後，寒厭麥秋晴。", "旱魃方爲虐，無容頃刻生。"]'),
('782fd17f-6b48-48d4-a811-d7ddc2c630f7','雨後復旱呼海嵎山龍浹旬復大霔  其二','釋居簡','宋','宋诗','song-poetry','','[]','久矣惟心禱，呼龍徇物情。',48,'全唐诗/poet.song.180000.json','["久矣惟心禱，呼龍徇物情。", "均沾四郊足，不負九推耕。", "蚌活沙頭脯，鶑新雨後聲。", "婁豐斯在望，老瓦醉秋成。"]'),
('81227075-f2d2-48dc-95e2-3e7fb4b93733','續東野銅斗歌送平江張都承  其一','釋居簡','宋','宋诗','song-poetry','','[]','拊斗答虛籟，和寡嗤笑多。',48,'全唐诗/poet.song.180000.json','["拊斗答虛籟，和寡嗤笑多。", "得時朱離淫，苟合終不和。", "悠然得遺響，如得金叵羅。", "還汝金叵羅，聽我銅斗歌。"]'),
('8782e4e8-d63c-49a8-9c79-500eba688343','續東野銅斗歌送平江張都承  其二','釋居簡','宋','宋诗','song-poetry','','[]','老我名銅斗，可糝亦可糜。',48,'全唐诗/poet.song.180000.json','["老我名銅斗，可糝亦可糜。", "旦旦數瓶粟，不飽亭午饑。", "層冰十萬錢，剖蚌黳鬢絲。", "宏功厚斯享，毋使宏功隳。"]'),
('28eb92ab-261f-4f75-8d9d-9d87b40a23e1','續東野銅斗歌送平江張都承  其三','釋居簡','宋','宋诗','song-poetry','','[]','斗也賤者事，拊擊諧吟謳。',48,'全唐诗/poet.song.180000.json','["斗也賤者事，拊擊諧吟謳。", "吟成襦袴歌，謂尹當借留。", "尹如黄潁川，又似韋蘇州。", "重臨亦不惡，領略滄江鷗。"]'),
('0cd387c0-bbb3-4e2e-aad0-9982fd147f3c','觀破山池白藕花','釋居簡','宋','宋诗','song-poetry','','[]','欲看芬陁利，攙凉曉入山。',48,'全唐诗/poet.song.180000.json','["欲看芬陁利，攙凉曉入山。", "毳宜松露馥，屨惜蘚文斑。", "蟄破淵靈去，腥隨澗雨還。", "歌禽破幽寂，深樹隠綿蠻。"]');
